window.SARAL_JYOTISH_DB = [{"topic":"Ashtamsha","text":"नमस्कार मित्रों आज मैं आपके\r\nसाथ एक बहुत ही महत्त्वपूर्ण वर्क कुंडली लेकर के आया हूं इस वर्क\r\nकुंडली को बहुत कम लोग देखते हैं क्योंकि इसका\r\nविश्लेषण बहुत डिफिकल्ट मुश्किल है और बहुत कम लोग उसको देखना पसंद करते\r\nहैं यह वर्ग चार्ट पराश्री में नहीं दिया गया\r\nहै यह वर्क जमनी सिस्टम में दिया गया है\r\nऔर इसको इसलिए हम जेमिनी से भी एनालाइज कर\r\nसकते हैं परंतु आज मैं इसको पराशर सिस्ट\r\nसे ही एनालाइज करूंगा उसी से हम इसका विश्लेषण\r\nकरेंगे जमनी का विश्लेषण हम अपनी आने वाली पुस्तक में जो\r\nसरल सेवन है उसमें देंगे और अभी पराशर का हम देखेंगे यह वर्ग\r\nचार्ट है अष्टांग या डी\r\nए आ भाव का विस्तार तो आठवे भाव से हम क्या क्या\r\nचीजें देख सकते हैं आठवे भाव से हम जो\r\nअचानक घटनाएं होती है उनको देखा जाता है यह क्रॉनिक डिजीज भी दे सकती\r\nहै और यह आठवा भाव छुपा हुआ भाव होता है टैलेंट का भी भाव है आपकी प्रतिभा भी\r\nदर्शा सकता है जो छुपी ई है मृत्यु का भाग\r\nपार्ट है और आपके जो जीवन में सडन इवेंट होती\r\nहै क्रॉनिक बीमारी होती है जिनसे पीछा नहीं\r\nछूटता और यह सब यहां से देखा जाता है अगर\r\nहम एक शब्द में कहे कि जिस इवेंट में जिस घटना में\r\nसरप्राइज अचानक का तत्व\r\nहो उसको इस चार्ट से देखा जाता है अब इस\r\nराश इस चार्ट बनाने के लिए प्रत्येक राशि के आठ भाग किए जाते\r\nहैं एक भाग न डिग्री 45 मिनट का होता है\r\nअब आपको इसमें याद आएगा कि आपने अगर अष्टक वर्ग पढ़ा है तो अष्टक वर्ग में भी एक\r\nभाग 3 डिग्री 45 मिनट का होता है और वहां\r\nवहां हम देखते हैं कहां बिंदु है कौन से भाग में र वह हमारा आज का टॉपिक नहीं है\r\nपरंतु वह एक भी एक महत्त्वपूर्ण बिंदु हो सकता है जिससे हम फलित कर सकते\r\nहैं उसके बिंदु देख कर तो आज हम डी ए की पहले व्याख्या करते\r\nहैं इसको कहते हैं भाई सडन इवेंट सरप्राइज एलिमेंट वाली जो\r\nअचानक से हो तो लगन हर वर्क का आवश्यक और सबसे\r\nमहत्त्वपूर्ण पॉइंट होता है वहां से हम हमेशा शुरू करते हैं अगर लगन बली\r\nहै लगन बली है तो आपके जीवन में अचानक घटनाएं\r\nहोंगी अब यह अच्छी भी हो सकती है बुरी भी हो सकती है उस पर भी\r\nआएंगे अगर आपके यह लगन को निर्बल लगन है तो भी\r\nअच्छा नहीं है भाई हर एक के जीवन\r\nमें कोई ना कोई घटना अचानक होती\r\nहै ठीक है और यह\r\nघटनाए एक हमें कमजोर जो लगन होता है उसमें हम विरुद्ध परिस्थितियों में अपनी दुख\r\nतकलीफ में लड़ नहीं सकते उसके उसमें हम रो देते हैं लड़ने की ताकत नहीं होती दूसरे\r\nनियम पर आते हैं के\r\nघटनाएं अशुभ होंगी या शुभ होंगी ज्यादा घटनाए देखिए शुभ शुभ दोनों\r\nहोनी है तो ज्यादा कौन सी होती है वोह\r\nउसके लिए डी ए का दशम भाव देखा जाता\r\nहै अगर दशम भाव बली है शुभ संबंध है तो घटनाए सुखद भी हो सकती\r\nहै और अगर केवल पाप संबंध है तो घटनाए\r\nज्यादातर अशुभ होंगी विचलित करने वाली अब इनको देखने के लिए एक रूल बहुत इंपॉर्टेंट\r\nहै उसको आप ध्यान में रखो तीन\r\nग्रह राहु केतु और शनि यह तीन ग्रह बड़ा बवंडर करते हैं इस\r\nचार्ट ठीक है जैसे मिसाल के तौर\r\nपर यदि जन्म कुंडली का छठे का स्वामी सिक्स\r\nहाउस का स्वामी शनि केतु या राहु से पीड़ित\r\nहै तो वह आपको बीमारियां दे सकता\r\nहै अब इसके लिए हम कहेंगे सीरियसनेस के लिए हमें दो पाप संबंध चाहिए एक पा संबंध\r\nहोगा तो आप उसको निकल जाएंगे उसको संभाल लेंगे और अगर\r\nएक पाप संबंध है और साथ में शुभ संबंध भी है तब तो आप बिल्कुल विजय प्राप्त कर\r\nलेंगे इसी तरह से आठवा भाव का स्वामी जन्म का आठवे भाव का स्वामी अगर इनसे पीड़ित हो\r\nजाए शनि राहु केतु वही दो अगर पीड़ा आ जाती है तो\r\nएक् सीरियस एक्सीडेंट दे सकते हैं परंतु शुभ ग्रह का संबंध फिर से कुछ ना कुछ\r\nउसमें हमें सांत्वना देता है कुछ उसको कम कर\r\nदेता है ठीक है अब यह कब होती है यह\r\nघटनाए दो तरह के ग्रह ज्यादा इन घटनाओं की\r\nको देते हैं अब मान लीजिए दशम भाव अब दशम भाव के\r\nसाथ भावेश भी देख लो तो ज्यादा अच्छा रहता है पर शास्त्रों में सिर्फ दशम भाव लिखा\r\nहै अगर दशम भाव में शुभ की संभावना है और कोई\r\nग्रह उच्च राशि का है स्वराशि का\r\nहै शुभ में बैठा है तो वह अच्छी घटनाओं को उन अपनी दशा में वो अच्छी घटनाओ को\r\nदेगा इसके विपरीत आप सोच सकते हैं\r\nअब एथ लड ऑफ अष्टांग अब उसको देखते हैं वह बिल्कुल\r\nआपकी आयु और इन घटनाओं को दिखाता है अगर वो बली है तो आपकी आयु भी\r\nहै अगर वह पीड़ित है गलत जगह पर बैठा हुआ है तो वह आयु में\r\nकमी लाता है एक और रूल देंगे दो और देने चलो एक और\r\nरूल देते हैं के एक वो ग्रह\r\nढूंढो कि जिसको शनि राहु या केतु पीड़ा पहुंचा रहे\r\nठीक है उनके साथ संबंध बना रहे हो युति हो एस्पेक्ट कर रहे राहु केतु का एस्पेक्ट तो मैं लेता नहीं हूं तो राहु\r\nकेतु की युति हो और शनि दृष्ट कर रहा हो जब मैं जेमिनी पर आऊंगा अगली पुस्तक\r\nमें उसमें राहु केतु की दृष्टि आती है क्योंकि वहां राशि दृष्टि है राहु केतु की\r\nदृष्टि नहीं है तो वो ग्रह को देखो\r\nअब उस ग्रह की कौन सी राशि\r\nहै किस ग्रह का व स्वामी है किस राशि का स्वामी है तो वह राशि जिस भाव में बैठी हो\r\nजन्म कुंडली में उस या जिस भाव का वह कारक है उसको\r\nपीड़ा पहुंचाएगा आगे हम अपने एग्जांपल चार्ट में\r\nभी देखेंगे एक और डीड से हम देख सकते हैं कन्फाइनमेंट\r\nमैंने बंधन पर दो वीडियो बनाए हैं तो एक य\r\nडी ए बंधन देखने का एक अच्छा नियम देता\r\nहै वहां पर हम क्या है जन्म कुंडली के द्वादश को देखें बवे\r\nभाव के स्वामी को और वो अगर डी आ में एफ्लिक्टेड\r\nहै तो वह बंधन योग दे सकता है चाहे वह बीमारी का हो चाहे जेल टर्म\r\nहो तो वह जो बंधन आता है वह वहां से देखा\r\nजा सकता है अब हम एक दो कुंडलियों पर इसको देखेंगे तो यही नियम है हमारे और याद रखना\r\nभाई लगन बली है लगने बली है तब तो अचानक\r\nघटनाए होंगी होगी फिर देखो कौन से\r\nग्रह उच्च राशि में है स्वराशि में है फिर देखो दशम\r\nभाव दशम भाव पीड़ित है या नहीं है उसके बाद\r\nदेखो के 12वां भाव बवे भाव का स्वामी आठवे भाव\r\nका स्वामी छठे भाव का स्वामी छ आ 12 वो जन्म लगन के क्योंकि जन्म लगन से वो\r\nदर्शाते हैं ठीक है जी अब हम कुंडिया एक दो शेयर\r\nकरेंगे यह भैया पहली कुंडली\r\nले रहे हैं यह नेहरू जी की पत्नी इंदिरा गांधी जी की मां उनकी कुंडली\r\nहै इसमें आप यह नोट कर लो बस कि भाई लगन क्या है तो 6 आ 12 के स्वामी अपने आप आ\r\nजाएंगे ठीक है जी तो यह हमने नोट कर लिया हम अब सिर्फ डी से ही करेंगे अपना काम अब\r\nनेक्स्ट कुंडली डी लेते इनका डी ो\r\nलगन में शनि और बृहस्पति विराजमान\r\nठीक है अब एक चीज आप देख रहे हैं के\r\nलग्नेश और नवमेश में स्थान परिवर्तन है राशि परिवर्तन है\r\nतो हम कह सकते हैं कि लगन बली है अच्छा योग बन रहा है य लग्नेश और नवमेश का\r\nतो लगन बली है तो अचानक घटनाएं इनके जीवन में होंगी\r\nदूसरा चीज अ हम देखते हैं दशम भाव दशम\r\nभाव राहु केतु एक्सस में केतु विराजमान है दशम भाव में जब भी राहु केतु इस चार्ट में\r\nराहु केतु एक साथ आते हैं तो जिस भी चार्ट में राहु केतु एक साथ\r\nआए तो केतु को राहु के सामने बैठा दीजिए सामने के भाव में बैठा दीजिए ठीक है जी\r\nअब यहां पर आप देखें कि दशम भाव प मंगल की\r\nदृष्टि है मंगल टश भी है शनि की दृष्टि है\r\nअष्टमेश भी है कोई शुभ संबंध नहीं है दशम भाव\r\nठीक है तो जीवन में अचानक घटनाएं जरूर\r\nहोंगी ठीक है अब एथ लॉर्ड जन्म कुंडली का\r\nएथ लॉर्ड था हमारा बृहस्पति और बृहस्पति यहां पर लगन में\r\nबैठे हुए हैं सप्तम भाव को देख रहे हैं\r\nतो यह आपको सीरियस प्रॉब्लम दे सकता है एथ लर्ड ऑफ लग तो इन और यह बृहस्पति शनि के\r\nसाथ तो हमारा राहु केतु शनि का व आ गया शनि यहां पर अष्टमेश भी है नवमेश भी\r\nहै तो इनको सीरियस प्रॉब्लम दे दी क्रॉनिक\r\nडिजीज जो इनको टीबी बहुत ज्यादा टीबी थी\r\nवह इनको दे दी उसके बाद एक और नियम हम देखते\r\nहैं जन्म लगन का द्वादश वह मंगल\r\nहै अब मंगल भी यहां पीड़ित है राहु के\r\nसाथ दशम भाव ने कहा था भाई तो मैं अच्छी घटना तो दूंगा नहीं और कुछ ना कुछ तो\r\nअच्छा हो ही जाता है अब यह मंगल ने इनको और ज्यादा कन्फाइनमेंट\r\nदे दी बैड रिटन कितने सालों यह सैनिटोरियम में बैठी\r\nरही पड़ी रही और यहां पर कौन-कौन पीड़ित ज्यादा हो रहा है टेंथ लॉर्ड पीड़ित हो रहा\r\nहै मंगल पीड़ित हो रहा है तो इनकी जो मृत्यु\r\nहुई वो बृहस्पति मार्स में हुई बृहस्पति मंगल की\r\nदशा में इनकी मृत्यु हो गई तो यहां से अचानक घटनाओं का यह बहुत\r\nबड़ा उदाहरण है यहां पर आप देखेंगे सूर्य बली\r\nहै और इन सूर्य भी शनि से दृष्ट है\r\nमंगल भी राहु के साथ है तो इन दोनों जिस भाव के ये स्वामी\r\nहै उनको पीड़ा पहुंचा रहे शनि तीसरे भाव\r\nमतलब य डीट के तीसरे के स्वामी है और जन्म कुंडली के चौथे भाव के स्वामी तो घर में\r\nसुख में अशांति दी मां को कष्ट दिया\r\nऔर एकादश भाव के स्वामी हैं जन्म लगन से वो द्वादश के स्वामी\r\nहैं और सप्तम के स्वामी तो शुक्र जो है वोह आपके लगन में\r\nबैठे हैं लग्नेश हैं यहां पर लग्नेश लगन में बैठ गए तो खुद को दुख दिया गनीमत यह\r\nहै कि इसमें शनि राहु या केतु की दृष्टि\r\nनहीं आ रही ठीक है जी अब नेक्स्ट कुंडली लेते हैं\r\nभाई यह कुंडली हमने ली है नेलसन\r\nमंडेला कितने साल यह प्रिजन में\r\nरहे परंतु अचानक घटनाए भी बहुत इनकी घटी प्रेसिडेंट भी बन\r\nगए यह तक हुआ और अचानक 80 साल उम में शादी नहीं\r\nकी तो यहां भी आप लगन नोट कर लीजिए लगन धनु है हम इसी का इस्तेमाल आगे करेंगे अब\r\nइनका हम डी देखते सबसे पहले डीट\r\nमें हम देखते हैं लगन को लगन मंगल से दृष्ट है\r\nलगन मंगल से दृष्ट है और\r\nलग्नेश वह उच्च राशि में नवम भाव में बैठे तो लगन को मैं बलि मानूंगा क्योंकि\r\nलग्नेश उच्च के ठीक है और लग्नेश प केवल शुभ संबंध\r\nआ मंगल भी दृष्ट कर रहे हैं सूर्य को पर मंगल सूर्य के डिस्पोजिटर है तो वो उसको\r\nऔर बल दे रहे हैं तो सूर्य बहुत बली हो गए हैं लगन बली हो गई है तो अचानक घटनाएं\r\nहोंगी ठीक है जी अब हम दशम भाव को देखते दशम\r\nभाव 8\r\nडी ए मंगल उच्च राशि के मंगल डी दशम भाव के\r\nस्वामी को दृष्ट कर रहे हैं और दशम भाव मंगल से\r\nदृष्ट सॉरी चंद्रमा से दृष्ट शुभ ग्रह से\r\nदृष्ट तो दोनों तरह की घटनाएं हो अशुभ भी शुभ भी क्योंकि वीनस फिर से राहु के साथ\r\nहै चंद्रमा पर शनि की दृष्टि है तो दशम भाव पर यह सब मिक्सड इन्फ्लुएंस\r\nआ रहा है ठीक है जी अब इसके बाद हम देखते\r\nहैं जन्म कुंडली का छठे भाव का\r\nस्वामी जन्म कुंडली के छठे भाव के स्वामी शुक्र\r\nहै और शुक्र पर राहु के साथ है मंगल से\r\nदृष्ट मंगल की दृष्टि इन्ह थोड़ा बचा रही है राहु केतु शनि के\r\nइलावा तो इनको बहुत बीमारियां रही कई ऑपरेशन हुए ऑपरे हॉस्पिटल कई दफे गए काफी\r\nबीमारियां इनको रही अब जो एथ लॉर्ड है जन्म कुंडली\r\nका जन्म कुंडली का एथ लॉर्ड जन्म कुंडली का एथ लॉर्ड हुआ\r\nचंद्रमा चंद्रमा को शनि दृष्ट कर\r\nरहे और शनि के इसके चंद्रमा के जो डिस्पोजिटर है वो उच्च\r\nहै अगर में डी ए की कुंडली की\r\nके अष्टमेश की बात करता हूं जिससे आयु देखते हैं यह अष्टमेश\r\nबुध के साथ है और लग्नेश से दृष्ट\r\nहै लग्नेश से दृष्ट है तो यह लंबी उम्र\r\nदिखाते हैं क्यों बृहस्पति का संबंध शनि राहु केतु से नहीं\r\nहै तो इनकी आयु अच्छी खासी रही 95 साल की\r\nउम्र तक यह जीवित रहे तो दशम भाव में हम अच्छा और बुरा\r\nदोनों दिखा दिया अब इनको और सुखद घटनाए क्या\r\nहुई ये जेल गए सन 64 में केतु की दशा\r\nमें मैं अगर बव भाव के स्वामी को देखता हूं जन्म के क्योंकि कन्फाइनमेंट के लिए\r\nहमने वो लिया था जेल के लिए तो वो है\r\nमंगल मंगल केतु के साथ है वही केतु को मंगल के पास ले जाओ\r\nभाई ठीक है और इस परे और कोई दृष्टि नहीं तो इनको जो जेल टर्म मिली वह केतु की दशा\r\nमें मिली पूरे केतु की दशा फिर पूरी शुक्र की\r\nदशा यह जेल में रहे और जब सूर्य की दशा आई क्योंकि अचानक\r\nघटना अच्छी भी देनी है और सूर्य हमने कहा था भाई उच का है यहां पर और यही अच्छी\r\nघटना देगा मंगल भी अच्छी घटना दे सकता है तो कन्फाइनमेंट में रहे और जब सूर्य की\r\nदशा शुरू हुई तो यह जेल से छूट के बाहर आ गए और प्रेसिडेंट बने साउथ अफ्रीका के\r\nप्रेसिडेंट बने इनको दो बड़े पुरस्कार मिले नोबल प्राइज और भारत\r\nरतन यह इनको सूर्य और चंद्रमा की दशा में मिले\r\nतो यह रिलीज हुए थे 1990 में सूर्य की\r\nदशा ठीक है जी तो डरना नहीं है इस चार्ट से सिवाय राहु केतु और शनि देख लो और उससे\r\nआप अंदाजा लगा सकते हैं ठीक है जी अब इसके बाद एक चार्ट और\r\nलेंगे यह अच्छी अच्छी घटनाओं का है यहां पर आप लगन नोट कर लीजिए खैर लगन\r\nबहुत बली है उच्च के शनि लगन में बैठे हुए हैं लग्नेश लगन में बैठे हुए हैं ठीक है\r\nपर हमारा मतलब है डी ए चार्ट से अब इनका डी ए चार्ट देखते\r\nहैं पहले लगन देखो भाई लगन पे किसी की दृष्टि नहीं है केवल\r\nजुपिटर बृहस्पति तो लगन पर शुभ संबंध\r\nहै ठीक है लग्नेश गवे भाव में चले\r\nगए और लग्नेश को भी बृहस्पति देख रहे हैं तो अचानक घटनाए तो यहां भी लिखी गई यह\r\nकिंग जॉर्ज की कुंडली है अचानक घटना है तो इनके एक दो पॉइंट लूंगा मैं एक्चुअली यह\r\nथा ये राजा बनने के लाइन में नहीं थे दूर दूर तक\r\nइनका नंबर नहीं आ रहा था परंतु क्या हुआ\r\nइनके बड़े भाई ने एबडीकेट कर दिया कि मैं राजा नहीं\r\nबनूंगा वह गद्दी के हकदार थे उन्होंने गद्दी छोड़ दी तो इनको गद्दी मिल\r\nग ठीक है इनको गद्दी मिल गई\r\nअब हम दशम भाव देखते हैं दशम भाव पर शुक्र और सूर्य की दृष्टि\r\nहै जो बड़े बली शुभ करतरी में है दोनों\r\nग्रह इन पर ना तो शनि का प्रभाव है ना राहु केतु का प्रभाव है बुध जो है इनकी\r\nतरफ आ रहा है शुक्र और स की तरफ बृहस्पति वक्री है वो भी इन दोनों की तरफ जा रहा है\r\nतो दो शुभ ग्रह की इनको कतरी मिल रही है बड़ा बली हो गई और इनका प्रभाव दशम\r\nभाव अब दूसरा देखो दशमेश\r\nएकादश शनि है शनि पर शनि तो खुद हम लेते हैं ना\r\nप्लेनेट शनि राहु केतु अभी शनि पे शनि भी राहु केतु के एक्सेस में आ\r\nगए और शनि एकादश है तो इनके बड़े भाई को हानि हो\r\nगई बड़े भाई को हानि हुई राहु केतु एक्स और मंग मंगल भी शनि को\r\nदृष्ट कर रहे हैं लग्नेश ठीक है जी तो एल्डर ब्रदर की को\r\nपरेशानी हो गई अब यह राजा\r\nबने ये इनका जन्म हुआ था दिसंबर\r\n18951 में राजा बन गए और 52\r\nतक 52 की उम्र तक यह राजा रहे यह राजा बने केतु की दशा\r\nमें दशमेश के साथ केतु हमने पिछले उसमें\r\nदेखा था नेलसन मंडेला केतु की दशा में जेल\r\nगए यह जेल नहीं यह राजगद्दी ली ठीक है जी और यह राजा रहे शुक्र में\r\nबुध तक शुक्र में बुध तक तो यहां पर भी बहुत\r\nचीजें दिख रही है कि शनि महाराज बुध को देख रहे\r\nहैं बुद्ध सटेश है और जन्म कुंडली अगर हम देखें याद है\r\nमेरे को तो भूल गई भाई जन्म कुंडली जन्म कुंडली लिरा की थी ठीक है तो\r\nइसको हम द्वादश लिब्रा के बुद्ध हो गए तो बुध हमें\r\nप्रॉब्लम दे रहे हैं शनि से दृष्ट है और चंद्रमा से दृष्ट है पर चंद्रमा तो अच्छे\r\nग्रह है पर यह जो बुध की दशा में इनको इनकी डेथ\r\nहुई और उसी तभी वह राजा से हटे नहीं तो वहां तक वो राजा\r\nरहे शुक्र में बु शुक्र से बवे में बुध भी है खैर दोस्तों मैं एक चीज कहूंगा कि यह\r\nआयु देखने का डी ए से मत करना\r\nभाई बहुत दफे गड़बड़ हो जाती है गड़बड़ कैसे हो जाती है अब मान लो इस\r\nकुंडली में मैं देखता हं अष्टमेश डी ए के\r\nमंगल ठीक है हम कहेंगे मंगल गवे भाव में बैठे\r\nहुए बृहस्पति से दृष्ट है तो आयु लंबी होनी\r\nचाहिए बृहस्पति कोई कहेगा भाई राहु केतु के राहु के डिस्पोजिटर है और नवमेश भी है\r\nपर द्वादश भी तो है तो द्वादश इनको देख रहे तोय माइनर\r\nपॉइंट कई दफ गड़बड़ा जाते हैं इनकी उपर 52 साल कितने 95\r\nमें 95 में बर्थ हुई 56 57 साल की उम्र\r\nमें इनकी डेथ हो गई जो एक राजा के लिए अी ठीक है अननेचुरल ही कहा जाएगा थोड़ा सा अर्ली\r\nडेथ तो हम इसे लॉन्ग लाइफ नहीं कह सकते कि इनको लंग लाइफ मिली क्योंकि मंगल गवे भाव\r\nमें पर वो और बृहस्पति से दृष्ट है तब भी लंबी ला लाइफ नहीं मिली है तो इस चीज को\r\nइस परे अप्लाई मत करना अगर आपके लंबी आयु आ रही है तो खुश\r\nहो लेना और क्योंकि अगर वो शॉर्ट लाइफ हो गई\r\nतो आपको पता भी नहीं चलेगा किसको कहोगे कि भाई मैंने तो यह\r\nदेखा था हो ही गया अब डेथ के बाद तो बोल ही नहीं पाओगे ना तो इसलिए उसको छोड़ के बाकी आप\r\nघटनाएं सुखद होंगी या नहीं होंगी देखिए घटना डीट में\r\nदोनों तरह की घटनाए जीवन में होती ही होती है तो अच्छी घटनाएं कब\r\nहोंगी उसको देखकर प्रसन्न हो लो और जो बुरी घटनाए हो रही है उस ग्रह की या किसी\r\nरिलेटिव की किसकी प्रॉब्लम आ रही है वह कम से कम देख सकते हो तो इसमें दशम भाव\r\nइंपॉर्टेंट है और उसके साथ साथ अगर दशमेश भी देख लिया\r\nजाए तो भी एक अच्छा क्लू मिल जाता है कि आप क्या कर रहे हैं आयु के लिए आपका रोल\r\nक्या हो रहा है ठीक है ना क्योंकि वो भी भगवान ने दे दिया परंतु\r\nआपने क्या किया खैर तो यह भैया आज का टॉपिक\r\nथा बताना और भी ऐसे स्पेशल वो लेते\r\nरहेंगे और आपसे वार्तालाप करते रहेंगे तो आज के लिए इतना ही बहुत-बहुत धन्यवाद\r\nनमस्कार"},{"topic":"Ch5_Double Khara Planet_Saral Jyotish Part 1","text":"नमस्कार मित्रों आज फिर आपको मैं सरल\r\nज्योतिष पर वेलकम करता हूं और आज\r\nफिर हम सरल ज्योतिष पार्ट वन\r\nका पांचवा अध्याय समझेंगे डिस्कस\r\nकरें अच्छा इंपॉर्टेंट टॉपिक है ये और\r\nइसका नाम सुनकर आपको लग रहा होगा\r\nइसका नाम हमने रखा है डबल खर\r\nप्लेनेट प तो खर\r\nसमझे\r\nखर का जिक्र आता है जब हम छिद्र ग्रह की\r\nबात करते\r\nहैं सात छिद्र ग्रह दिए हुए हैं उसमें दो\r\nछिद्र\r\nग्रह नवांश और द्रेश कान\r\nके क्लासिक ने लिखा\r\nहै कि चंद्रमा\r\nसे 64 वा\r\nनवांश खर नवांश होता\r\nहै और लिखा है के लगन\r\nसे बावा द्रेश कांड खर द्रेश कान होता है\r\nतो मतलब 64 वा नवांश चंद्रमा से और बावा\r\nद्रेश कान लगन\r\nसे ये हमें क्लासिक ने सिखाया\r\nहै\r\nअब अब जैसी आदत है रिसर्च करने की कुछ ना\r\nकुछ तड़का लग जाना\r\nचाहिए सब्जी टेस्टी हो\r\nजाएगी तो उस टेस्ट को करने के लिए हमने एक\r\nन नई तरीके से इस पर रिसर्च की अब उसको\r\nबताने से पहले जो क्लासिक का मीनिंग है वो\r\nमैं आपको बता रहा हूं कि कैसे यह क्लासिक\r\nसे भी डबल खर बन सकता है डबल खर किसको\r\nकहते\r\nहैं जब एक ही\r\nग्रह चंद्रमा से\r\nभी 64वें नवांश का स्वामी\r\nहो\r\nऔर वही ग्रह लगन से 22वें दृश कांड का भी\r\nस्वामी तब उसको हम डबल बोलते हैं भाई दोरा\r\nरोल हो गया उसका वो 64 वा नावाच भी है और\r\nबावा द्रेश कांड भी है इसलिए नाम डबल रखा\r\nगया है कहीं और कहीं यह डबल नाम नहीं\r\nमिलता है इसको आप कह सकते हैं कि दो जगह आ\r\nरहा है तो हमने इसका नाम डबल करके अब यहां\r\nआप देखो हम एक कुंडली लेते\r\nहैं इसको हम देखते हैं एक पहला मैं चार्ट\r\nले रहा\r\nहूं यह जाना माना चार्ट\r\nहै यह मैं किसलिए डेमोंस्ट्रेट कर रहा हूं\r\nकि नॉर्मली भी डब खर हो सकता है यह चार्ट\r\nहै इंदिरा गांधी\r\nका कैसे देखते हैं हम नवांश में देखिए सरल\r\nतरीका जो देखने का\r\nहै आप पहले 64 वा नवा\r\nसमझो किसी भी ग्रह\r\nके 60\r\nनवांश पांच राउंड में पूरे हो 12 प 60 12\r\nराशियों में घूम के वापस वही आ जाएगा 12\r\nपजे 60 हमको चाहिए 64 वा क्यों लि\r\nवो यह\r\nके 63 नवांश\r\nतक एक राशि में न नवांश\r\nहोते तो 63 नवांश तक सात राशियां पूरी\r\nई तो आठवी राशि\r\nजो चंद्रमा की उससे है वह आठवी राशि उसकी\r\nहो गई 6वी राशि\r\n6वा देखने का सरल तरीका क्या है अब\r\nचंद्रमा ने तो पांच राउंड पूरे कर लिए 60\r\nनवांश तक तो चंद्रमा से 64 वा नवांश\r\nपड़ेगा चंद्रमा से\r\nचौथा चंद्रमा वापस आ गया 60 नवांश पूरे कर\r\nलिए ठीक है 60 नवांश यहां पूरे कर लिए ये\r\n6वा हो\r\nगया अपनी पोजीशन प ये 62 हो गया ये 63 और\r\nये 64\r\nअब 64 में नवांश का\r\nस्वामी अब य जुपिटर महाराज बैठे हुए\r\nनवांश वह नहीं है\r\nखर उसका जो स्वामी है मतलब\r\nशुक्र शुक्र को हम खर मानेंगे\r\nठीक है जी इसी तरह से द्रेश कांड में क्या\r\nहोता\r\nहै तीन एक राशि में तीन दृश काण होते हैं\r\nतो सात राउंड पूरे हो गए 21 राशि में 21\r\nद्रेश कांड में तो बावा दृश कांड फिर आठवा\r\nलगन से यह देखिए अब दृश कांड में लगन\r\nसे आठवे भाव का स्वामी सिंपल इसको ऐसे देख\r\nये तरीका बताया मैंने देखने का तो यहां भी\r\nशुक्र जो है वो 22वें दृश कांड के स्वामी\r\nतो शुक्र इन्हें कष्ट\r\nदेगा अपने सिग्निफिकेंट\r\nदेगा मैरिज का है सेक्स लाइफ का है और\r\nअपनी दशा में भी कष्ट दे सकता है हमने\r\nइसको आगे और डिफाइन किया है कि किसकी दशा\r\nकिसकी अंत दशा उसमें वो कष्ट दे सकता है\r\nतो आप यह तो समझ गए कि भाई साहब हम क्या\r\nकहना चाह रहे हैं के डबल खर क्या होता है\r\nउसको पहले आप\r\nसमझ अब जो इसमें तड़का लगाया\r\nहमने वह तड़का\r\nहै के हम क्लासिक हमें कह रही है के\r\nचंद्रमा से आप 64 वा नवा\r\nदेखिए और लगन से बावा द्रेश\r\nका अब दिमाग में यह\r\nआया कि जब चंद्रमा भी कह रखा है और भी कह\r\nरखी है तो हम क्यों नहीं हर प्लेनेट से\r\nदेखें कि क्या किसी प्लेनेट की स्थिति\r\nसे उससे हम काउंट करेंगे चंद्रमा लगन की\r\nजगह उस प्लेनेट से काउंट\r\nकरेंगे तो उस ग्रह\r\nसे क्या 6वा नवांश और बावा दृश कांड एक ही\r\nग्रह हो सकता है या हो रहा है कुंडली\r\nमें\r\nतो उस ग्रह के लिए व खर हो\r\nगया ठीक है ना अब देखिए लगन से देखते हैं\r\nवह फिजिकल तकलीफ देता है बावा द्रेश\r\nकान 64 वा नवांश हम देखते हैं चंद्रमा से\r\nवह मानसिक तकलीफ देता\r\nहै तो क्यों ना जब हम एक ग्रह से देख रहे\r\nहैं तो वह\r\nग्रह को या जो खर बन गया दोनों का जब\r\nसंबंध आ जाएगा तो तकलीफ नहीं देगा\r\nक्या इसी थ्योरी को लेकर के हमने\r\nकहा के अब इस डबल खर का प्लेनेट के\r\nलिए देखने का एक बड़ा सरल तरीका\r\nहै जब\r\nमैं पर्सनली क्लास कंडक्ट करता\r\nथा तो इतना बता कर के छोड़ देता\r\nथा और वहां पूछता था\r\nकि भैया आप जो है वर्क आउट करो कि किस\r\nस्थिति\r\nमें एक ही ग्रह का र प्लेनेट एक निकलता\r\nहै तो यह मेंटल एक्सरसाइज हो जाती थी\r\nहमारे सारे सहपाठियों\r\nकी और मुझे बड़ी खुशी से कहना पड़ता है पढ\r\nरहा है कि रियली इतने अच्छे अच्छे\r\nस्टूडेंट मिलते हैं कि व खुद कैलकुलेट\r\nकरके और उसका प्रिंसिपल निकाल करके अगले\r\nदिन आके हमें बता देते थे खैर आपको नहीं\r\nवो एक्सरसाइज दे रहा हूं मैं ही बता देता\r\nहूं यह कब होता\r\nहै अब पहले कुंडली में देखिए आप कुंडली\r\nमें कोई भी\r\nग्रह द्वि स्वभाव राशि में होना चाहिए\r\nपहली कंडीशन\r\nदूसरी\r\nकंडीशन उस द्वि स्वभाव राशि में वह\r\nग्रह पहले या पांचवे या नवम नवांश में\r\nबैठा हुआ होना\r\nचाहिए मतलब डिग्री उसकी इस तरह से हो पहला\r\nनवांश होता है जीरो डिग्री से न डिग्री 20\r\nमिनट तक उसमें अगर कोई ग्रह\r\nहै पांचवा नवांश होता है 1 डिग्री 20 मिनट\r\nसे 16 डिग्री 40\r\nतक और नवम नवांश होता है 26 डिग्री 40 से\r\n30 डिग्री तक तो इन तीन नवांश में जो ग्रह\r\nबैठा\r\nहोगा वह उसके खर ग्रह एक ही होंगे दोनों\r\nखर कैलकुलेशन गिनती करने का अगर आप चेक\r\nकरना चाहे\r\nकि भाई कौन सा प्लेनेट खर बना अब ये\r\nडिसाइड करना है उसके\r\nबाद तो उसके लिए मैं आपको फिर से\r\nडिस्ट्रेट कर देता हूं दूसरी कुंडली\r\nमें अब उसके लिए हमने स्टीव जॉब्स की\r\nकुंडली\r\nली मैं स्टेप बाय स्टेप चलूंगा आप समझिए\r\nइसको पहला स्टेप था द्वि स्वभाव राशि\r\nमें कौन-कौन ग्रह बैठे हैं राहु केतु भी\r\nलेंगे उनके भी\r\nकर यहां पर बृहस्पति है केतु है राहु है\r\nवीनस है शुक्र और चंद्रमा\r\nहै यह पांच ग्रह द्वि स्वभाव राशि में\r\nबैठे इनमें से कौन सा पहले नवांश में है\r\nकोई भी ग्रह पहले नवांश में नहीं है\r\nदूसरे नवांश\r\nमें कौन है सॉरी पांचवे नवांश में आपको\r\nसिर्फ चंद्रमा\r\nदिख 132 से 1640 के अंदर तो यह 14 डिग्री\r\n30 मिनट पर च चंद्रमा जी बैठे हुए तो यह र\r\nये उसके लिए क्वालीफाई कर रहे अब हम देखें\r\nइनके र कौन और एक बैठे हैं\r\nवीनस 27 56 26 4 से 30 के बीच में नवम\r\nनवांश में ये\r\nबैठे इसके बाद बृहस्पति बैठे 27 डिग्री\r\nएकन यह भी नवम नवाच में तो तीन ग्रह हमारे\r\nइसमें\r\nनिकले अब इसको कैसे चेक करेंगे अब याद कर\r\nलीजिए चंद्रमा है\r\nशुक्र है और\r\nबृहस्पति तीन तीन के इनके कौन ककन खर हुए\r\nयह कागज पर नोट कर लेना जब ज्यादा आ जाते\r\nहैं बहुत सी कुलियो में एक भी खर नहीं\r\nमिलेगा पहले हमने ना माच से चेक किया\r\nभैया\r\nचंद्रमा चंद्रमा से\r\nचौथा शनि आ\r\nगए कुंभ की राशि पड़ गई तो शनि आ गए तो\r\nचंद्रमा के खर\r\nशनि उसके बाद थे\r\nबृहस्पति बृहस्पति से\r\nचौथे यह आ गए\r\nबुद्ध तो बृहस्पति का खर आ गया\r\nबुद्ध और शुक्र का खर आ गया शुक्र से चौथा\r\nमतलब\r\nबृहस्पति बृहस्पति के र\r\nबुध चंद्रमा के र\r\nशनि और शुक्र के र\r\nबृहस्पति अब इनकी म्यूचुअल दशा भी हमें\r\nवाच करनी पड़ेंगी दशा देखनी पड़ेगी यही\r\nमैं वेरीफाई करता हूं दश काल में भैया है\r\nक्या सेम ही है\r\nना पहले तो चंद्रमा देख\r\nलो कर्क में बैठे\r\nहुए हम लगन से आठवा देखते थे हम अब ग्रह\r\nसे\r\nआठवा चंद्रमा से आठवे का\r\nस्वामी फिर शनि हो गए और नवांश में भी शनि\r\nआ रहे थे चंद्रमा से\r\nचौथा उसके बाद हमने बृहस्पति से देखा\r\nबृहस्पति यहां गवे भाव में बैठे हुए\r\nयहां से\r\nआठवा बुध आ\r\nगए बृहस्पति से आ और नवाज में भी बुध आ\r\nरहे थे अब द्रेश कान में देखो बुध खर\r\nहै और वह उच्च की राशि में बैठा हुआ\r\nहै अब शुक्र से देख लो शुक्र की पोजीशन से\r\nआठवा\r\nद्रेश कांड में फिर जुपिटर आ\r\nबृहस्पति तो ये हमारा प्रिंसिपल क्या बन\r\nगया कि\r\nहम एक ग्रह जो अगर द्वि स्वभाव राशि में\r\nबैठा है जिस तरह से बैठा\r\nहै वहां\r\nसे उसी को हम चंद्रमा की जगह लगन भी मांग\r\nलेंगे चंद्रमा भी को भी उसको ग्रह को ले\r\nलेंगे और वहां से नॉर्मल तरीके से हम अपने\r\nखर डिसाइड\r\nकर अब क्या इसके नियम पहले हम जरा से नियम\r\nदेख लेते हैं उसके बाद हम आगे चलेंगे ठीक\r\nहै\r\nजी\r\nमैं इसको स्क्रीन\r\nको बंद कर चलो स्टॉप शेयरिंग कराऊ मैं अब\r\nआपको नियम\r\nबताऊंगा तो हमने खर तो निकालने सीख\r\nलिए अब इसका जो सबसे मोटा प्रिंसिपल\r\nहै कि\r\nयदि जो भी उसमें से प्लेनेट प्लेनेट या\r\nखर अगर सूर्य के होरा में\r\nहै ध्यान से सुन लो य अगर सूर्य के होरा\r\nमें है तो वह अधिक कष्ट\r\nदेगा चंद्रमा होरा में है क्योंकि वह मृदु\r\nहो रहा है उसमें वह कम कष्ट\r\nदेगा तो यह एक बड़ा प्रिंसिपल हो\r\nगया ठीक है और कहां का कष्ट देगा अपने\r\nसिग्निफिकेंट\r\nहै अपनी लॉर्डशिप का दे सकता\r\nहै जहां पर वह बैठा हुआ है जिसको एस्पेक्ट\r\nकर रहा है अगर वह खर से एस्पेक्टेड है\r\nप्लेनेट या वो खर खर्च से अगर वो ग्रह\r\nअपने खर्च से एस्पेक्टेड है या उसके साथ\r\nहै तो ज्यादा कष्ट देगा और सूर्य के रा\r\nमें तो यह जो है यह अति हो\r\nजाएगी अब स्टीव जॉब्स का हमने\r\nदेखा इनकी क्या प्रॉब्लम\r\nथी एक तो ड्रग्स प थे ये\r\nकाफी ड्रग का सेवन करते थे और बाद में खैर\r\nछोड़ दिया\r\nतो यह लेते थे\r\nड्रग्स यह मरकरी सेटन\r\nमें हालांकि रिलेटेड नहीं है आपस में पर\r\nसैटन बृहस्पति के साथ है\r\nमैं दोबारा स्क्रीन शेयर करूं आपके\r\nसाथ अब ये कुंडली में देख लीजिए\r\nआप\r\nये यह स्टीव जॉब्स की आ गई कुंडली अ ये\r\nजुपिटर और\r\nशुक्र जुपिटर के खर\r\nथे बुध\r\nठीक है तो वहां पर ये और जुपिटर के साथ\r\nशनि है नवांश\r\nमें तो इसके में और बुध हमने देखा था बावा\r\nदृश कांड होकर के वो उच्च का\r\nथा तो इन्होंने जो ड्रग्स की इनको हैबिट\r\nथी वो जुपिटर\r\nये सेटन मरकरी सेटन एलेस ली\r\nइनकी जो मृत्यु\r\nहुई मृत्यु हुई थी\r\nएक 5 अक्टूबर 2011 को मून जुपिटर\r\nमून जुपिटर\r\nअब ये भी आप देखो मून के खर है शनि और शनि\r\nबैठे जुपिटर के साथ मारग भाव में नवांश\r\nमें और यहां पर\r\nजो है जुपिटर\r\nमून में जुपिटर वो आठवे में बैठे मून से\r\nआठवे में बैठे शनि डबल डबल खरता चंद्रमा\r\nका तो यह जो है काफी तकलीफ दे सकते अब मैं\r\nआपको जो अगला चार्ट दिखा रहा\r\nहूं यह बड़ा इंटरेस्टिंग चार्ट\r\nहै यह हमारे एस्ट्रोलॉजी के कोलीग है साथ\r\nमें पढ़े स्टूडेंट भी रहे य मेरे इनको\r\nकाफी कई दफे हमारे जो इकट्ठी क्लासेस करते\r\nथे चार्ट भी डिस्कस किया कई दफे और तब तक\r\nमैं यह नहीं जान पाया कि इनकी जो मैंने इस\r\nपर लिखा है जुपिटर मून में जनवरी 15 से मई\r\nतक यह जॉब से बाहर हो गए 14 तक य फॉरेन कं\r\nमें थे बड़ा अच्छा जॉब चल रहा था\r\nकंसल्टेंट का बड़ी अच्छी रेपुटेशन पर\r\nमिनिस्ट्री के साथ ग कंट्रीज में और हम\r\nदेखते यार यह देखो जन्म कुंडली में\r\nबृहस्पति दशमेश\r\nहै चंद्रमा पंचमेश\r\nहै पांचवे और दसव भाव की केंद्र त्रिकोण\r\nकी युति बन रही है सॉरी चंद्रमा वहां पर\r\nबैठ गए हैं\r\nजाकर पंचमेश योग कारक हो गए\r\nहैं परंतु और जुपिटर बली है उच्च के शुक्र\r\nके साथ बैठे हैं तो कोई देख के बोल सकता\r\nहै भाई इसको नौकरी से हट जाएगा ये पूरे\r\nउसी पीरियड में जुपिटर मून में और जैसे ही\r\nमून खत्म\r\nहुआ ये फिर से अच्छी नौकरी मिल गई फिर\r\nविदेश चले\r\nगए तो भाई नहीं आता था समझ में ये क्लासेस\r\nकी मैं बात कर रहा हूं\r\n2000 18 19\r\nकी तब फिर हमने कहा इसका डबल खर\r\nदे डबल खर में पता चलेगा देखते क्या\r\nहै अब य द्वि स्वभाव में फिर से छ प्लेनेट\r\nचार पाच प्लेनेट\r\nब परंतु सिर्फ\r\nचंद्रमा उस डबल र के लिए क्वालीफाई है\r\nआखिरी नमाज है बाकी कोई एक पाचन में नहीं\r\nइन सारे\r\nग तो हम चंद्रमा का खर ढूंढते\r\nहैं चंद्रमा यहां\r\nपर धनु राशि में बैठे हुए नवांश में यहां\r\nसे चौथा का स्वामी\r\nबृहस्पति यह खरा है और द्रेश कांड\r\nमें चंद्रमा से चंद्रमा बैठे\r\nहुए द्वितीय भाव में यहां से आठवा फिर\r\nबृहस्पति आ\r\nग तो चंद्रमा के डबल खर\r\nबृहस्पति अब यह कौन-कौन\r\nथे यह बृहस्पति थे दशमेश और\r\nलग्नेश और चंद्रमा\r\nपंचमेश\r\nपरंतु फिर भी इनको डेढ़ एक साल सवा साल तक\r\nनौकरी के बगैर रखा कोई जीविका का साधन\r\nनहीं था व एस्ट्रोलॉजी पढ़ते थे फिर य उस\r\nसमय यह बाद में फिर समझ में आया अब इनकी\r\nमैं चार्ट क्लास में लगाया कि भाई क्यों\r\nनौकरी से\r\nबाहर इनके चार्ट को लेकर के और हमने फिर\r\nडबल कर\r\nतो यह बहुत\r\nज्यादा\r\nअच्छी कांसेप्ट है अच्छा तरीका है देखने\r\nका अब इसका क्या निदान हो अब हमारी मोटी\r\nबुद्धि में तो यह आता है के खर भूषण रावण\r\nके सेना में थे और ऐसे वीर\r\nथे कि जिसको रावण भी बोलता था इनको कोई\r\nहरा नहीं\r\nसकता तो श्री राम\r\nसे लड़ाई के लिए उनको रोकने के लिए खर\r\nदूषण को भेजा\r\nगया और श्री राम\r\nने उसको हराया ही नहीं उनको मार भी दिया र\r\nऔर दूषण को तो क्या पता ये वहां से नाम\r\nआया हो और अगर खर का हमें कष्ट हो रहा है\r\nतो उसे श्री राम ही मार सकते हैं मैं तो\r\nयह\r\nसोचता ये तो एक वैसी बात है को मैं उपाय\r\nवगर तो बताता नहीं हूं पर ऐसे ही दिमाग\r\nमें आया कि इसको खर कहा है ऋषियों ने और\r\nखर का वध किया था\r\nश्रीराम तो क्या हमारे खर का वध श्री राम\r\nही कर सकते\r\nहैं चलो शुभकामनाए पहले तो हम यह कहेंगे\r\nकि डबल खर्द नहीं होना\r\nचाहिए खर्द ग्रह तो होता ही है नॉर्मल\r\nहोरोस्कोप में भी डबल खर हो सकता है जैसा\r\nहमने इंदिरा गांधी के होरोस्कोप में\r\nदेखा परंतु अगर यह द्वि स्वभाव राशि की वो\r\nमिल जाती है तो वोह तो फिर पक्का है कि\r\nडबल खर होगा ही पर दो प्लेनेट तो खर बन ही\r\nसकते हैं ना हर और को तो हर एक की कुंडली\r\nमें कोई ना कोई खर होगा एक 64 में नमाज से\r\nहोगा एक बान से\r\nहोगा और वो कष्ट ही देगा छिद्र\r\nतो उसका कल्याण श्री राम करेंगे और उसी\r\nदिन आशा से सबके लिए श्री राम का आशीर्वाद\r\nकि वह सबके खर दूर करें उनका कष्ट दूर\r\nकरें जय श्री राम आज के लिए यहीं पर\r\nसमाप्त करता हूं थैंक यू वेरी मच\r\nधन्यवाद"},{"topic":"Even debilitated planets can give wealth","text":"नमस्कार\r\nमित्रों आज फिर राम नवमी के शुभ अवसर\r\nपर आपका एक बड़ा\r\nचहेता टॉपिक लेकर के फिर हाजिर हुआ\r\nहूं आप सबको राम नवमी की हार्दिक\r\nशुभकामनाएं भगवान श्री राम हम पर कृपा\r\nबनाए रखे हम सब\r\nपर तो आज जो टॉपिक है वो हमारे जीवन से\r\nबहुत ज्यादा जुड़ा हुआ\r\nहै मैं जीवन में समझता\r\nहूं प्रायोरिटी के हिसाब\r\nसे कि सबसे\r\nपहले हमारे परिवार का महत्व है अगर परिवार\r\nहमारा एक साथ\r\nहै एक साथ हम खड़े हुए\r\nहैं तो जीवन अपने आप बहुत ठीक हो जाता\r\nहै दूसरा मैं मानता हूं\r\nहेल्थ सेहत शरीर से आप ठीक रहे मानसिक ठीक\r\nरहे संतुलन रहे शारीरिक कष्ट ना हो तो आप\r\nसुखी\r\nरह और जो तीसरा इंपॉर्टेंट टॉपिक पॉइंट है\r\nवह है धन\r\nवेल्थ तो आज हम कुछ हट के नियम\r\nदेंगे कि जिससे\r\nजिससे भी आदमी को वेल्थ मिल सकती\r\nहै और यह हम नियम नीच राशि में बैठे हुए\r\nग्रह कब धन दे सकते\r\nहैं इस विषय\r\nमें हम\r\nएक नीच राशि\r\nका\r\nसूत्र पराशर जी का रेफर कर सकते हैं\r\nके कोई भी\r\nग्रह त्रिक भाव\r\nमें नीच राशि में बैठा हो विराजमान\r\nहो इनमें स्पेशली तीन छ\r\nआठ तो वोह\r\nग्रह उस भाव को बली कर देता है अगर वो\r\nसेकंड लॉर्ड या थ लर्ड जो हमारे धन के भाव\r\nहै उनका स्वामी नछ आ में नीच राशि में\r\nविराजमान हो तो वह एक धन योग है पराश के\r\nहिसाब\r\nसे\r\nदूसरा हमने\r\nइसको जमनी की अर्गला से देखा\r\nथा कि किसी भाव में अ धन की बात कर रहे\r\nहैं तो दो और\r\n11 अगर उसका स्वामी ही अर्गला कर रहा है\r\nऔर दृष्टि भी दे रहा है तो वह भाव बली हो\r\nजाते हैं अगर वो दूसरा भाव है तो धन का हो\r\nजाएगा गवा भाव है तो लाभ बहुत हो यह सूत्र\r\nहम बात कर चुके\r\nहैं अब हम आते हैं पराशर जी\r\nका जो सामान्य धन योग है उसको थोड़ा सा\r\nरिफ्रेश कर लेते\r\nहैं पराशर जी ने कहा है\r\nकि दूसरा भाव और\r\nगवा इनका\r\nसंबंध जब के भाव से हो जाता है तब वह धन\r\nयोग बनता\r\nहै सेकंड लॉर्ड और ट्रान\r\nलॉर्ड गवे का स्वामी थ लॉर्ड और ट्रान\r\nलॉर्ड यह धन योग बनते हैं और यह नॉर्मली\r\nहम देखते ढूंढते रहते हैं कि भाई धन है\r\nदेखिए कोई भी\r\nव्यक्ति निर्धन जब तक बिल्कुल ही भगवान की\r\nकृपा नहीं है तो भगवान रोटी तो सबको देता\r\nहै और धन की कितने पर व्यक्ति धनी होता है\r\nकहां उसकी संतुष्टि आती है वह व्यक्ति धनी\r\nहै मेरी समझ से परंतु हम यह आज देखने की\r\nकोशिश कर रहे हैं कि भाई धन कितना\r\nआ क्वांटिटी हम हिंदू लगन से भी देख सकते\r\nहैं और एकय सूत्र मैं आज आपको दे रहा\r\nहू और यह सूत्र ज्यादातर लोग कहते हैं कि\r\nभाई नीच का ग्रह हो गया नीच राशि में है\r\nतो यह तो कोई फल नहीं दे सकता बड़ा अच्छा\r\nफल दे देते\r\nहैं अब इसमें दो सूत्र\r\nहै पहला सूत्र तो है\r\nके जिस राशि\r\nमें ग्रह नीच का विराजमान है नीच राशि में\r\nविराजमान\r\nहै तो उसका\r\nडिस्पोजिटर उस राशि का\r\nस्वामी उस ग्रह को के साथ विराजमान\r\nया उसका डिस्प\r\nपटर उस नीच राशि के ग्रह को दृष्ट कर\r\nरहा अब यह कहीं भी हो सकते हैं कोई भी हो\r\nसकते हैं जरूरी नहीं कि वह दती हो या\r\nएकादश हो या त्रिकोण का स्वामी हो या\r\nकेंद्र कोई भी हो सकता है तो\r\nयह नीच राशि के ग्रह का एक बड़ा पावरफुल\r\nयोग\r\nहै या\r\nउसका एक और इसका वो है कि जो नीच राशि का\r\nग्रह\r\nहै यदि उसका\r\nडिस्पोजिटर उस नीच ग्रह से केंद्र में\r\nविराजमान\r\nअब शास्त्रों में क्या लिखा\r\nहै के केंद्र में कोई\r\nग्रह नीच राशि में\r\nहो और उसका डिस्पोजिटर भी केंद्र में\r\nतब वो व्यक्ति धनी होता है य मैं थोड़ी सी\r\nअमेंडमेंट कर रहा हूं हम हमेशा कोशिश करते\r\nहैं ना अच्छे अच्छे फल\r\nदेखें तो मैं इसमें यह अमेंडमेंट भी कर\r\nदेता हूं कि हो सकता है वो लगन से केंद्र\r\nमें ना\r\nहो परंतु जो नीच राशि का ग्रह है उससे\r\nकेंद्र\r\nमें तो ये दो तीन रूल हो गए हमारे\r\nमेरे ख्याल में इसको और व्याख्या करने की\r\nजरूरत नहीं है समझ में आ गया सिंपल रूल है\r\nके वह जो डिस्पोजिटर है नीच राशि में ग्रह\r\nका वह उससे केंद्र में हो लगन से केंद्र\r\nमें हो तो बहुत अच्छा है या उसका\r\nडिस्पोजिटर उसके साथ हो या उसको दृष्ट कर\r\nयह हमारे रूल\r\nहै तो अब हम करते हैं एक दो चार्ट पर इसको\r\nदेखने की कोशिश\r\nकरते अब यह जो पहला चार्ट मैं ले रहा\r\nहूं यह बिल गेट्स का चार्ट है सब मानते\r\nहैं बड़ा धनी आदमी था अब य\r\nनॉर्मल परारी नियम लगाओ\r\nदत सूर्य है और एकादशी शुक्र\r\nहै यह दोनों एक साथ विराजमान है युति में\r\nहै चौथे भाव\r\nमें परंतु त्र कोण के जो स्वामी है\r\nचंद्रमा मंगल और\r\nबृहस्पति इनसे कोई संबंध नहीं आ\r\nरहा तो हम उस रूल में कहेंगे कि भाई धन\r\nयोग नहीं बना भैया ये धनी नहीं\r\nहै क्योंकि दो और 11 का त्रिकोण से संबंध\r\nआना चाहिए पराशर जी के हिसाब से यहां तो\r\nइन दोनों का\r\nसंबंध शनि से आ रहा है जो इस लगन के लिए\r\nअच्छी अच्छे ग्रह नहीं\r\nहै सप्तम और अष्टम है और\r\nवो सप्तमेश मारक होकर के सप्तम भाव केंद्र\r\nके स्वामी है और उच्च राशि में विराजमान\r\nहै ठीक है तो इसको हम नीच भंग कह सकते हैं\r\nसूर्य का पर अब हम अपने सूत्र पर आते हैं\r\nजो अभी हम बात कर रहे\r\nथे के कोई भी नीच राशि का ग्रह केंद्र में\r\nनीच का\r\nहै सूर्य\r\nमहाराज नीच राश में विराजमान\r\nहै और जो इनके डिस्पोजिटर है\r\nशुक्र वह इनके साथ ही विराजमान\r\nहै युति में\r\nहै यह धन\r\nयोग नॉर्मल पराश नियम से हम धन योग नहीं\r\nलगा पा रहे\r\nथे पर अब हम हमारा लग गया\r\nअब यहां पर आप\r\nदेखोगे कि दूसरे 11 भाव\r\nमें केतु विराजमान\r\nहै और सेकंड हाउस में बृहस्पति है जो\r\nनाइंथ लड\r\nहै यह धन संचय दे\r\nदेंगे यह\r\nमानते परंतु नॉर्मल पराश्री धन योग हमको\r\nनहीं दिख रहा\r\nहै अब हम दूसरे चार्ट प\r\nयह हमने चार्ट लिया है\r\nपहले महान फुटबॉल\r\nखिलाड़ी काफी उथल पुथल की इनकी इनका जीवन\r\nरहा यहां ये किस लिए लिया है मैंने\r\nचार्ट यहां पर आप\r\nदेखिए के दो और 11 के स्वामी\r\nबुद्ध\r\nहै ठीक\r\nहै अब\r\nबुध बृहस्पति से दृष्ट है जो त्रिकोण के\r\nस्वा और लग्नेश के\r\nसाथ अ य\r\nलग्नेश\r\nसूर्य और\r\nशनि दो नीच राशि में\r\nहै अब मैं इसको सूर्य पर लगा के देखता हूं\r\nइस नियम\r\nको सूर्य के\r\nडिस्पोजिटर शुक्र\r\nहुए वह सूर्य से केंद्र में\r\nनहीं मैंने इसलिए इस रूल को मॉडिफाई किया\r\nय सूर्य भी केंद्र में नहीं है और इनके जो\r\nडिस्पोजिटर है व सूर्य से केंद्र\r\nमें अब मैं देखता हूं शनि\r\nशनि महाराज भी नीच राशि में विराजमान\r\nऔर इनके\r\nडिस्पोजिटर शनि से केंद्र में नहीं\r\nहै अब तीन पार्ट थे हमारे उस रूल\r\nका परंतु इसका डिस्पोजिटर\r\nमंगल शनि को दृष्ट कर रहे हैं अपनी आठवी\r\nदृष्टि से\r\nअब देखि जब भी डिस्पोजिटर उसको\r\nदेखेगा या साथ होगा तो उस नीच ग्रह के भाव\r\nका वह स्वामी हो\r\nगया ठीक है पहले बीमार तो रहे काफी और\r\nफुटबॉल में नाम भी बहुत कमाया और धन भी\r\nकमाया तो यह दूसरी बानगी थी किस तरह से\r\nइसको देखते हैं एक और चार्ट लेंगे\r\nयह\r\nब्रूसली अभय देखो मंगल से आ रहा है मंगल\r\nसे योग बन रहा है मैं इसको केवल धन योग ही\r\nनहीं मानता\r\nहूं मैं इसको स्टेटस भी\r\nमानता कि अच्छी किसी पोजीशन पर लाकर के दो\r\nनीच के ग्रह परस्पर दृष्टि रख जाए केंद्र\r\nमें हो जाए अब य देखो ब्रूस के\r\nउसम या फिर\r\nशनि अपनी नीच राशि मेष में विराजमान\r\nहै अब यहां से इनका जो डिस्पोजिटर\r\nहै वो इनसे केंद्र में है शनि\r\nसे और दृष्ट भी कर रहा\r\nअब यहां पर भी धन योग बन\r\nगया यहां इनके नॉर्मल पराश्री धन योग भी\r\nहै आप यह देखो गवे भाव का स्वामी बुध\r\nहै सेकंड हाउस का दूसरे भाव का स्वामी\r\nबृहस्पति है\r\nबृहस्पति केंद्र का भी स्वामी है त्रिकोण\r\nका भी स्वामी है और चंद्रमा भी त्रिकोण का\r\nस्वामी है और मंगल भी त्रिकोण का\r\nस्वामी ये सारे दो 11 और तीनों\r\nत्रिकोण एक दूसरे से दृष्टि संबंध बनाए\r\nहुए तो इसका तो बहुत ज्यादा हो\r\nगया अच्छा खासा अब इसने जब कैंसर हो गया\r\nथा तो क्या क्या पता नहीं डोनेट किया है\r\nलैंड किया है या ह मिलियन डॉलर दिए या ह\r\nएकर मुझे याद नहीं है पर हां इसने बहुत\r\nअच्छा कैंसर के लिए काम किया सारी अपनी\r\nपूंजी उसम\r\nलगा तो यह हमारा आज का नियम था ठीक\r\nहै बहुत आपके पास अब क कही नियम हो\r\nधन देखने के और हर एक के उसमें कहीं ना\r\nकहीं धन मिल जाता है अब आप यह\r\nदेखिए ज्यादातर हम\r\nलोग नीच ग्रह देख कर के घबरा जाते\r\nहैं कि मेरे तो ये ग्रह दो ग्रह नीच के हो\r\nगए या एक ग्रह नीच का हो\r\nगया तो कुंडली बेकार हो नहीं\r\nभैया 94\r\nपर तो ग्रह का निचव समाप्त हो जाता है\r\nकैंसिलेशन हो जाता\r\nहै मेरे पास ऐसे ऐसे उदाहरण\r\nहै के तीन तीन ग्रह उच्च राशि में\r\nविराजमान है बैठे हुए हैं कोई भी ग्रह नीच\r\nका नहीं है और कितनी तक तकलीफ में वो\r\nव्यक्ति अपना जीवन गुजार के\r\nगया यह भी है तो मेरा तो बड़ा मैसेज होता\r\nहै के नीच राशि का ग्रह देख कर के घबराना\r\nनहीं है हो सकता है यह ब्लेसिंग\r\nहो मेरी खुद की कुंडली में दो ग्रह नीच के\r\nहैं और दो उच्च के\r\nहैं ठीक है तो घबराना नहीं है और यह नीच\r\nग्रह का\r\nमैंने एक एक लगन के\r\nलिए एक एक ग्रह के लिए हर लगन के\r\nलिए आपको उनके रूल्स दिए है वह मेरी\r\nपुस्तक है सरल टू मैं एक्चुअली भैया\r\nप्रोपेट नहीं कर रहा हूं पढ़ ली होगी आप\r\nलोगों ने तो बहुतों ने पढ़ ली है वो\r\nक्योंकि काफी पॉपुलर हुई है तो उसमें\r\nमैंने सारे दिए हैं पर यह उससे हट के है\r\nयह\r\nरूल धन देने का वहा\r\nमैंने नीच के ग्रह को एनालाइज किया है कब\r\nअच्छा फल देगा कब खराब फल\r\nदेगा यह सूत्र धन योग का सूत्र है स्टेटस\r\nका सूत्र है आपको अच्छी पोजीशन दिला सकता\r\nहै जीवन में सफलता दिला सकता है यह जो आज\r\nका सूत्र हमने आपके साथ शेयर किया है तो\r\nआज बस इतना ही नमस्कार\r\nमित्रों आज के लिए अब बंद करते हैं"},{"topic":"How to check affairs before and after marriage","text":"नमस्कार\r\nमित्रों आज फिर एक बड़ा रोचक विषय लेकर\r\nके और जिसके बारे\r\nमें बहुत से लोगों\r\nने प्र सोचा कि इसको भी हम कवर करें\r\nक्योंकि पिछले वीडियो में हमने विवाह के\r\nकर्म पर बात की\r\nथी तो उसी से एक सवाल एक प्रश्न उठ रहा\r\nथा कि जी क्या प्रेम विवाह भी देखा जा\r\nसकता\r\nहै तो मैंने कहा चलो यही टॉपिक लेते\r\nहैं के विवाह से पहले या बाद में कभी भी\r\nप्रेम हो सकता है प्रेम की तो कोई संभाव\r\nरुकावट है ही नहीं\r\nपरंतु विवाह के बाद का प्रेम संबंध\r\nबहुत दफे कठिनाइयां पैदा कर देता\r\nहै\r\nऔर परिवार में रिश्ते टूट जाते\r\nहैं डाइवोर्स हो जाते हैं कोर्ट केस चलते\r\nहैं ठीक है वो भी होता रहता\r\nहै तो आज आज हम उसी पर थोड़ी सी चर्चा\r\nकरेंगे तो सबसे पहला\r\nबिंदु तो पंचम और सप्तम\r\nभाव हम जन्म कुंडली से ही शुरू\r\nकरें कि जन्म कुंडली के\r\nपंचमेश और सप्तमेश\r\nअगर इन दोनों में संबंध आ रहा है परस्पर\r\nसंबंध आ रहा\r\nहै तो प्रेम प्रसंग होने की संभावना हो\r\nजाती है और प्रेम विवाह की भी संभावना हो\r\nजाती\r\nयहां पर एक बात में जोड़ना चाहता\r\nहूं कि आजकल सब पढ़े लिखे\r\nहैं चाहे आपका परिवार ही विवाह की बात कर\r\nरहा\r\nहै परंतु आपकी सहमति के\r\nबगैर बहुत ज्यादा केसेस में वो पॉसिबल\r\nनहीं है तो उसको हम एगजैक्टली ये नहीं पर\r\nआपकी मर्जी से तो\r\nहुआ उसको आप ने पसंद नहीं किया बस इतना\r\nडिफरेंस तो हम जो यह बात कर रहे हैं उसमें\r\nआप एक दूसरे को पसंद करते हैं और फिर यह\r\nकरते विवाह करते हैं या नहीं करते प्रेम\r\nप्रसंग रह जाता है बहुत सी\r\nदफ तो उसका जो बेसिक फैक्टर है वह पंचमेश\r\nऔर सप्तमेश\r\nहै यह जन्म कुंडली\r\nमें एक दूसरे से संबंध बना रहे हो\r\nदूसरा नियम इसका क्या है कि जन्म कुंडली\r\nके पंचमेश और सप्तमेश\r\nनवांश में संबंध बना\r\nरहे तो नवांश का संबंध ज्यादा जरूरी\r\nहै ऐसे केस में क्या होता है कि अगर आपका\r\nनवांश में भी संबंध आ रहा है उन दोनों का\r\nजन्म कुंडली के पंचमेश और सप्तमेश का तब\r\nआप समझिए हां भाई यह परवान\r\nचढ़ेगा और अगर उसमें कोई पाप संबंध ज्यादा\r\nआ गया तो वह सिर्फ प्रेम प्रसंग रह\r\nजाएगा तो यह तो जन्म कुंडली के पंचमेश और\r\nसप्तमेश\r\nअब हम नवांश पर आते\r\nहैं तो नवांश के भी पंचमेश सप्तमेश\r\nका आपस में संबंध हो तो भी प्रेम विवाह\r\nपॉसिबल\r\nया अगर नवांश\r\nके पंचमेश और सप्तमेश\r\nइनका अच्छा संबंध आ रहा\r\nहै तो यह एक और बात की तरफ इशारा करता है\r\nयह कहता है कि विवाह के बाद प्रेम हो\r\nजाएगा प्रेम संबध तो है ना भाई नवमांश में\r\nतो विवाह के बाद प्रेम हो जाएगा और कुछ हम\r\nयह भी कह सकते हैं\r\nके जन्म के पंचमेश और सप्तमेश का नवांश\r\nमें संबंध नहीं आ रहा\r\nहै तो हो सकता है मैं यह नहीं कह रहा भाई\r\nबिल्कुल हो जाएगा\r\nपॉसिबिलिटी अगर और फैक्टर भी होते हैं\r\nपॉसिबिलिटी है कि जन्म में तो संबंध आ गया\r\nथा जन्म कुंडली में नवांश में नहीं था तो\r\nविवाह के बाद प्रेम कम हो\r\nजाएगा उ तरीका हो जाता\r\nहै अब आ य\r\nदेखिए के क्या क्या फैक्टर और जरूरी\r\nहै यह तो विवाह से पहले का प्रेम प्रसंग\r\nहुआ अब हम देखें बहुत सी दफे विवाह के बाद\r\nप्रेम प्रसंग हो जाता\r\nहै सीक्रेट अफेयर हो जाते\r\nहैं वो गलत है और उसको हम कैसे देखे बड़े\r\nबड़े लोगों के\r\nहुए तो उसमें सबसे पहली बात तो है के\r\nनवांश में करेज\r\nहोना ऐसा काम करने की जिसकी समाज इजाजत\r\nनहीं दे रहा है परंतु आपके अंदर उसका\r\nहौसला है अब जिसका हौसला नहीं है वह यह\r\nकाम नहीं कर\r\nसकता उसके लिए हम तीसरा भाव और तीसरे\r\nभावेश को\r\nदेखते इसके नियम आपको पता ही है करेज\r\nके कि अगर तीसरे भाव\r\nमें पाप ग्रह बैठा हो तो वह व्यक्ति को\r\nसाहसी बनाता\r\nहै और अगर वहा पाप ग्रह विराजमान है बैठा\r\nहुआ है और उसको शुभ ग्रह दष्ट कर रहा तो\r\nऔर ज्यादा बल मिल जाता\r\nइसका\r\nविपरीत अगर वह शुभ ग्रह विराजमान\r\nहै और अशुभ ग्रह देख रहे दृश कर रहे\r\nहैं तो क्या होता है कि पहले ही साहस नहीं\r\nथा और अशुभ ग्रह की दृष्टि ने और तोड़\r\nदी तो वह साहस नहीं देता अब इसके और\r\nपरम्यूटेशन कॉमिनेशन आप बना सकते\r\nहैं और जो तेश\r\nउसको भी बली होना\r\nपड़ेगा या तो तृतीय तृतीय भाव में बैठा हो\r\nतृतीय को देख रहा हो चाहे वह शुभ\r\nअशुभ तब तृतीय भाव के लिए तृतीय हमेशा\r\nउसको सपोर्ट करने वाला होता है फलदायक\r\nवाला तो पहला तो सबसे बड़ा पॉइंट यह\r\nहै दूसरा विवाह के बाद की बात कर रहे हैं\r\nसीक्रेट\r\nतो उसके\r\nलिए हमने जैसे पिछले वीडियो में बात की थी\r\nकि आप सुख कहां ढूंढते\r\nहैं तो चौथे भाव को या चतुर्थेश को अगर\r\nअष्टमेश\r\nप्रभावित कर रहा है दोनों में संबंध आ रहा\r\nहै तो वो\r\nसीक्रेट सुख की तरफ इशारा\r\nकरता बाकी और भी है अब उसके लिए एक पॉइंट\r\nऔर चाहिए कि भाई\r\nआप क्यों करोगे\r\nयह क्योंकि मेरी सेक्सुअल डिजायर बहुत\r\nहै मुझे वह तृप्ति चाहिए इसलिए जाऊंगा\r\nउसके क्या क्या पैरामीटर्स होते\r\nहैं यह सब हम डी ना में ंश में ही\r\nदेखें सबसे बड़ा स्ट्रांग\r\nफैक्टर होता\r\nहै मंगल और\r\nशुक्र का आपसी\r\nसंबंध नवांश में\r\nकेवल अगर जन्म कुंडली में यह मिल जाता है\r\nयह मत कहो कि भाई यह हो\r\nगया नवांश विवाह का चार्ट है वहां होना\r\nजरूरी\r\nहै जन्म कुंडली में मंगल और\r\nशुक्र एक साथ आ गए आप यह मत कहो यह कामक\r\nहै यह नवांश में चाहिए मैं ठोक ठोक के कह\r\nरहा हूं क्योंकि जन्म कुंडली में यह मिल\r\nजाता है घर में लड़ाई झगड़ा मत करना नवांश\r\nमें अगर नहीं\r\nहै और दूसरा क्या होता है कि यह इच्छा तो\r\nदेता\r\nहै पर अगर\r\nशनि शुक्र को दे रहा हो दृष्ट कर रहा हो\r\nया शुक्र के साथ हो तो इच्छाएं पूरी नहीं\r\nहोती अगर शनि बली\r\nहै अगर शनि बली नहीं\r\nहै ज्यादा स्ट्रंग नहीं है और उसका संबंध\r\nचार आठ से आ रहा\r\nहै तो वह इच्छा खुलेआम पूरी नहीं कर सकता\r\nसीक्रेट इच्छा पूरी होती\r\nपर शनि रुकावट देता\r\nहै ठीक\r\nहै दूसरा एक और योग है नवांश के लिए ही\r\nहै शुक्र के साथ केतु नवांश में\r\nहो कहीं पर भी\r\nबैठे इसी तरह मंगल शुक्र भी परस्पर संबंध\r\nकिसी भी भाव से कहीं से भी बना\r\nरहे रा एक और इंपोर्टेंट रूल\r\nहै ज्यादातर वो सिक्सथ हाउस सिक्सथ लड पर\r\nहोता है कि सिक्सथ लर्ड\r\nहमारा शुक्र\r\nको स सप्तम भाव या सप्तमेश को प्रभावित कर\r\nरहा यह नवांश में यह भी\r\nचाहिए ठीक है तो यह\r\nहमारे डिजायर के पैरामीटर्स हो गए अब\r\nदेखिए ज्यादातर तो अगर आपकी एक्सेस डिजायर\r\nनहीं है बहुत ज्यादा व नहीं है और तीसरा\r\nभाव आपका बली नहीं है तो भाई आप एक्स्ट्रा\r\nमार्शल विवाह के बाहर आप संबंध नहीं\r\nबनाएंगे यह भी विवाह के सेंसिटिव मैं नहीं\r\nलेता हूं ज्यादातर क्योंकि\r\nमेरा किसी\r\nकी जिंदगी ने का नहीं है सोच समझ के हमको\r\nलेना चाहिए और थोड़ी सी समाई रखनी\r\nचाहिए दूसरे को एक्सेप्टेंस की समाई रखनी\r\nचाहिए बहुत सी दफ जो देखा होता है या सुना\r\nहो कई दफ सुनी सुनाई बात प और जरा सा आपको\r\nमिल गया नवांश में तो भाई साब बंडर हो\r\nजाएगा तो थोड़ा समय रखिए शांति से उसको\r\nएनालाइज कर करिए बुद्धि अपनी भ्रष्ट मत\r\nकरिए जैसा मैंने पिछले वीडियो में कहा था\r\nबुद्धि भ्रष्ट होना बहुत जरूरी है तो\r\nबुद्धि भ्रष्ट मत करिए\r\nवैसा यहां पर आज मैं वो नहीं दे रहा हूं\r\nकि बुद्धि भ्रष्ट हुई पर आपको दिखेगा\r\nबुद्धि तो भ्रष्ट हुई है चलिए अब हम\r\nएग्जांपल लेते\r\nहैं ये पहला चार्ट हम लेंगे\r\nबहुत एक पुराने स्टाल वर्ड का है\r\n18828 में तो बिल क्लिंटन पैदा भी नहीं\r\nहुए थे ठीक है तो यहां हम एक तरह से देखना\r\nशुरू करते\r\nपंचमेश शनि\r\nहै और सप्तमेश\r\nबृहस्पति ठीक\r\nहै तो इनका\r\nसंबंध जन्म कुंडली में आ\r\nरहा तो यह अफेयर विवाह से पहले का हो सकता\r\nहै\r\nऔर इनका का संबंध शनि और बृहस्पति का\r\nनवांश में नहीं आ\r\nरहा तो मतलब विवाह के बाद हम जो पहले के\r\nप्रेम प्रसंग है उसको हम तवज्जो नहीं\r\nदे ठीक है अब हम\r\nआए थर्ड हाउस नवांश के तृतीय थर्ड\r\nहाउस थर्ड हाउस में कोई ग्रह नहीं\r\nपरंतु इसके स्वामी जो बृहस्पति\r\nहै वह उसको दृष्ट कर रहे शुभ दृष्टि आ गई\r\nअपने स्वामी की तो व्यक्ति में साहस आ गया\r\nबहुत साहस है विवाह के नवांश के मामले में\r\nसाहस है यह बहुत जरूरी है और क्या है अब\r\nदेखो कितने\r\nबड़ा योग मिल रहे हैं शुक्र और\r\nमंगल परस्पर संबंध बना\r\nरहे दोनों बली\r\nहै तो भैया डिजायर तो बहुत ज्यादा है\r\nमेरी और शुक्र स्व राशि के होकर के केतु\r\nके साथ विराजमान\r\nहै ठीक है तो यह क्या\r\nहुआ डिजायर फिर से बढ़ गई\r\nपरंतु शनि उसको दे विराज देख रहे\r\nहैं शुक्र को शनि देख रहे दृष्ट कर रहे\r\nहैं तो यह खुलेआम नहीं\r\nहै यह\r\nप्रसंग शुक्र के ऊपर शनि की दृष्टि कहता\r\nहै नहीं आप पूरी तरह से एंजॉय नहीं कर\r\nसकते पूरे तरह से यह जो एक्स्ट्रा प्रेम\r\nप्रसंग चलाओगे इसमें रिस्ट्रिक्शन होंगी\r\nतो यह रिस्ट्रिक्शन इनके ऊपर थी यह छुप\r\nछुप के ही काम होता\r\nथा और फिर खुले आम हो गया फिर पता भी\r\nचल ठीक है तो आप देख लेना किसकी है य\r\nकुंडली तो यहां पर हमने देख लिया थर्ड\r\nहाउस बहुत जरूरी था मंगल और\r\nशुक्र अब यहां जन्म कुंडली में देखोगे\r\nमंगल शुक्र को देख रहा है रिलेशन नहीं\r\nहै अगर जन्म कुंडली में म्यूचुअल रिलेशन\r\nभी होता तब भी हम डिजायर को ज्यादा नहीं\r\nभूलते अब दूसरा चार्ट\r\nलेते अब ये दूसरे चार्ट\r\nमें जन्म कुंडली में\r\nदेख यहां पर\r\nबृहस्पति और शनि\r\nफिर\r\nसे एक दूसरे ये पंचमेश और सप्तमेश हो\r\nग जन्म कुंडली\r\nमें बृहस्पति और शनि का संबंध नहीं आ\r\nरहा दोनों एक दो से दो में विराजमान\r\nहै अब यह जन्म कुंडली के जो पंचमेश्वर\r\nसप्तमेश थे इनका जाकर के नवांश में संबंध\r\nआ गया\r\nदोनों समसप्तक है एक दूसरे को देख रहे\r\nविराज ठीक है\r\nजी अब यहां क्या हुआ मतलब कि जो ये प्रेम\r\nप्रसंग विवाह से पहले शुरू हुआ था यह\r\nविवाह में बदल\r\nगया तो इस कन्या का प्रेम\r\nप्रसंग सन 99999 में शुरू हुआ 99 में और\r\nउस\r\nसमय 199 में यह शुरू हुआ\r\nथा और उसके बाद इनका विवाह हो\r\nगया शुक्र शनि में प्रसंग शुरू हुआ और\r\nजुलाई 2006\r\nमें इनका विवाह हो\r\nगया अब यहां हम\r\nदेखें के किस इस तरह से डिजायर सीक्रेट आ\r\nरही है नहीं आ\r\nरही अब यहां\r\nदेखो अष्टमेश\r\nबृहस्पति\r\nहै यह चतुर्थेश सूर्य को दृष्ट कर रहे\r\nहैं अच्छा उससे पहले इसका हौसला देख\r\nले कि बाद में प्रेम प्रसंग का हौसला है\r\nया नहीं\r\nहै तीसरे भाव में कोई ग्रह\r\nनहीं पाप करतरी\r\nमें परंतु बहुत ज्यादा इफेक्टिव वाली पाप\r\nकरतरी नहीं है क्योंकि मंगल उससे दूर जा\r\nरहे है राहु भी दूर जा रहे हैं पर इफेक्ट\r\nकौन सा स्ट्रांग आ रहा है बृहस्पति और\r\nशुक्र दो शुभ ग्रह देख रहे\r\nहैं बहुत बड़ा हौसला है\r\nऔर\r\nतृतीय अपनी उच्च राशि में विराजमान\r\nहै तो थर्ड हाउस बहुत स्ट्रांग हो गया\r\nथर्ड लॉर्ड कितना स्ट्रांग हो\r\nगया कुछ भी कर मटगा मैं बहुत हौसला\r\nहै और उसके बाद जो अष्टमेश है उन्होंने\r\nचतुर्थ को देख ली सीक्रेट अर\r\nअब यहां जो डिजायर का\r\nहै वह कोई डायरेक्ट बिल्कुल संबंध नहीं बन\r\nरहा जो हमने बोला था डिजायर\r\nका कि इसमें शुक्र केतु यह सिर्फ हम इसमें\r\nक्लासिक में नहीं लिखा हुआ\r\nहै परंतु केतु यदि आठवे भाव में होता\r\nहै तब भी वह थोड़ा सा\r\nसीक्रेट मतलब ज्यादा अर्ज दे देता\r\nहै और वो उस अर्ज को सोचता है यह मेरी\r\nनेचुरल स्पिरिचुअल अर्ज\r\nहै ठीक है तो इनका क्या हुआ इसके\r\nबाद विवाह हो गया 2006\r\nमें और 2010 में सूर्य की महादशा में फिर\r\nसे एक सीक्रेट अफेयर शुरू हो गया क्योंकि\r\nबृहस्पति सूर्य को दृष्ट कर रहे\r\nहैं प्रेम पहला प्रेम प्रसंग विवाह में\r\nबदल गया अब यहां दूसरा शुरू\r\nहुआ और 2013\r\nमें वो लाइम लाइट में आ\r\nगया अब जो सूर्य महाराज\r\nअब वो देखो एक बड़ा रोचक चीज आपको बता रहा\r\nहूं सूर्य की\r\nदशा पहले विवाह वगैरह जो हुआ वह शुक्र की\r\nदशा में हुआ अफेयर\r\nचला\r\nशुक्र चंद्रमा के होरा में\r\nहै नाइट का हो रहा\r\nहै ठीक है और जो सूर्य है\r\nवह सूर्य खुद स्वयं के होरा में है सूर्य\r\nदिन\r\nहै तो सूर्य की दशा में उजागर\r\nहुए शुक्र में नहीं हुआ और 2013 में इनका\r\nडाइवोर्स हो\r\nगया पता चल गया और संबंध इनका खत्म हो गया\r\nएक चार्ट और लेते हैं\r\nयह\r\nचार्ट मैंने पिछली कुंडली में भी पिछले\r\nवीडियो में भी लिया था वहां सिर्फ नवांश\r\nमैंने देखा था अब यहां देखो लगन से शुरू\r\nकरता हूं जन्म लगन से बृहस्पति और\r\nशुक्र यह हमें प्रेम प्रसन्न दे सकते\r\nहैं तो बृहस्पति और\r\nसूर्य बृहस्पति और शुक्र इनका जन्म कुंडली\r\nमें कोई संबंध नहीं है तो प्रेम प्रसंग\r\nनहीं है क्या यह नवांश में\r\nहै जुपिटर और शुक्र नवांश में भी इनका\r\nसंबंध नहीं आ\r\nरहा क्या नवांश\r\nमें पंचमेश सप्तमेश का संबंध\r\nहै मंगल और बुध ये एक साइडेड संबंध है\r\nमंगल बुध को देख दृष्ट\r\nकर तो यहां भी बोथ साइडेड नहीं\r\nहै और इस बुध\r\nको हमारे शनि महाराज भी देख रहे थ अब इनका\r\nविवाह हो\r\nगया इनको सुख मैंने जैसे बताया था विवाहित\r\nजीवन में सुखी नहीं\r\nतो अब यहां देखिए अब हम देखते हैं इनका\r\nथर्ड\r\nहाउस थर्ड हाउस में शनि महाराज स्वय राशि\r\nमें विराजमान\r\nहै और करतरी में है केतु भी जा रहे हैं\r\nउधर\r\nको और शुक्र और चंद्रमा भी उधर को थर्ड को\r\nआ रहे\r\nहैं तो करेज तो हो गया शनि को बहुत बल मिल\r\nरहा है परंतु छुप छुप के\r\nक्योंकि करतरी है करतरी बंधन\r\nहै विवाहित जीवन चलता\r\nरहा अब क्यों हुई यह बात करज तो था अब\r\nयहां देखिए शुक्र और\r\nमंगल दोनों एक साथ विराजमान\r\nहै एक साथ\r\nहै मंगल उच्च राशि में विराजमान है\r\nतो डिजायर बहुत स्ट्रांग\r\nहै मैनली डिजायर है इस\r\nकन्या ठीक है और कोई देखो कोई संबंध आपको\r\nदिख रहा हो अब यहां देखिए हर चार्ट में आप\r\nदेखोगे मैंने कहा था कि\r\nशुक्र छठे भाव से प्रभावित हो या सप्तमेश\r\nछठे से\r\nप्रभा इसमें मैंने ऑब्जर्व किया\r\nहै कि अगर शुक्र और सप्तम\r\nभाव\r\nविपरीत लॉर्ड से प्रभावित हो जाए तो कुछ\r\nविपरीत करने की इच्छा हो जाती अ विपरीत है\r\nतीन 6 आ\r\n12 तो\r\nमंगल जो द्वादश है शुक्र के साथ है और सपत\r\nको भी दृष्ट कर\r\nरहे यह भी एक बहुत बड़ा\r\nकारण तो वो जो रूल था छठे का क्लासिक में\r\nछ का\r\nरूल\r\nटे अगर शुक्र को सप्तम भाव सप्तमेश को\r\nप्रभावित\r\nकरें तब\r\nयह एक्सेस डिजायर देता है विपरीत डिजायर\r\nदेता है नॉर्मल समाज के नॉर्मल रूल से\r\nइलावा\r\nतो यह हमारा आज का विश्लेषण\r\nथा और दूसरे चार्ट आप देखिए\r\nपरंतु समझ बूझ\r\nके कोई इसमें आप यह ना करें कि कोई\r\nपरेशानी हो\r\nआपको तो बहुत ही शांति से उसको\r\nलगाइए और मेरे हिसाब से कोई भी विवाह को\r\nकोई भी\r\nप्रसंग अगर बुद्धिमता से किया\r\nजाए बुद्धि भ्रष्ट ना हो तो वह सॉल्व किया\r\nजा सकता\r\nहै और उसमें ज्योतिष की अगर आप सहायता\r\nलेते हैं तो बहुत अच्छा\r\nहै तो आज के लिए बड़ा इंपॉर्टेंट टॉपिक\r\nहमने किया है अब मैं आगे प्लान कर रहा हूं\r\nके कुछ टॉपिक पर जो जनरल आप लेते हैं\r\nसोचूंगा उस परे उस परे फिर से सीरीज जैसे\r\nसरल वन की की थी उस तरह से आपके जो विचार\r\nआ रहे\r\nहैं उसके ऊपर फिर हम कुछ वीडियोस\r\nबनाएंगे तो आपका बहुत-बहुत धन्यवाद\r\nनमस्कार नमस्कार"},{"topic":"How to check happiness in marriage","text":"नमस्कार\r\nमित्रों आज आप लोगों\r\nकी एक\r\nट्रिक\r\nआपके द्वारा दी गई सलाह के\r\nअनुसार मैं आप मैरिज\r\nपे स्टेप बाय स्टेप आज का एक सारे स्टेप\r\nनहीं आएंगे आज के वीडियो में\r\nपरंतु एक सरल तरीके\r\nसे जो पराशर\r\nनहीं जमिनी पद्धति\r\nसे क्योंकि जमिनी से बहुत जल्दी रिजल्ट\r\nसमझ में आ जाते\r\nहैं उस पद्धति से हम आज विवाहित जीवन\r\nमें सुख की बात\r\nकरें कि विवाहित जीवन सुखी होगा लंबा\r\nचलेगा प्रसन्न\r\nरहेंगे तो उस पर हम बात करेंगे आज काफी\r\nअच्छा टॉपिक है आपकी सबकी बहुत की डिमांड\r\nभी बहुत रही\r\nइसमें तो इसलिए मैं इसको बना\r\nरहा आज हम सिर्फ दो कारक की बात\r\nकरें एक\r\nएमके और एक\r\nपीके जिस पर\r\nहमारी विवाह की खुशी\r\nहैप्पीनेस अच्छा विवाहित जीवन चलता है इन\r\nदो कारक को मैं पहले ले रहा आप प्रश्न\r\nकरेंगे धारा काक को क्यों नहीं ले रहा रा\r\nकाक को भी लेंगे व उसका मीनिंग कुछ और\r\nहै आप कहेंगे वो विवाह का कारक तो धारा\r\nकारक ही है पर भाई पहले तो सोचो\r\nएमके एमके क्या है फोर्थ हाउस का\r\nरिप्रेजेंटेटिव है सुख का रिप्रेजेंटेटिव\r\nहै तो नवांश में\r\nएमके आपके विवाह के सुख को दिखाता है घर\r\nको दिखाता\r\nहै अगर वह पीड़ित हो जाता\r\nहै तो वह घर तोड़ सकता है कौन सा घर विवाह\r\nका\r\nघर मतलब\r\nमैरिज\r\nकई दफा क्या होता है\r\nके उस पर पाप संबंध आ रहा है परंतु वह योग\r\nमें\r\nहै अब जो यह रूल बता रहा हूं यही पीके पर\r\nभी लगेंगे पीके क्या है पीके हमारी बुद्धि\r\nहै इंटेलिजेंस है और नवांश में वह विवाह\r\nके जीवन\r\nमें हमारी इंटेलिजेंस किस तरह से काम करती\r\nहै अगर बुद्धि भ्रष्ट हो\r\nगई तो जीवन में विवाहित जीवन में सुख नहीं\r\nरहेगा चाहे आपका एमके कितना भी अच्छा हो\r\nयह दोनों इंपॉर्टेंस हो गई अब कहां से हम\r\nइसको देखते हैं दो तीन रूल जो आपके\r\nक्वेश्चन आते हैं उसी को भी लेते हुए मैं\r\nकर रहा\r\nहूं कि कारक यदि नीच राशि में है तो क्या\r\nहोगा यह सवाल आ रहा है उच्च राशि में हो\r\nतो क्या\r\nहोगा दोनों का जवाब देता हूं अगर नीच राशि\r\nमें कारक होता\r\nहै तो उस कारक को अहंकार नहीं\r\nहोता जब तक वह पीड़ित ना\r\nहो और अगर उच्च राशि में होता है तो वह\r\nअपने आप\r\nको अच्छा समझता है अपने ऊपर विश्वास होता\r\nहै मैं अहंकारी वर्ड नहीं यूज कर रहा हूं\r\nइसमें परंतु अपने आप पर विश्वास होता है\r\nसामर्थ होता है कि मैं कैपेबल\r\nहूं अब इसके और वो देखो अगर उस परे इन\r\nदोनों में से किसी पर भी जीके की दृष्टि आ\r\nजाए ज्ञाती कारक की दृष्टि आ\r\nजाए तो वह तकलीफ दे हो जाता है उस कारक के\r\nलिए और साथ ही\r\nसाथ अगर उसके उस पर राहु केतु की दृष्टि आ\r\nजाए तो और ज्यादा खराब हो जाता तब यह डबल\r\nइफेक्ट आ है पाप संबंध का डबल इफेक्ट\r\nहै इसी तरह पी के पर इसी तरह एम के पर\r\nयदि यह कारक राज योग में\r\nहो एम के राज योग में है\r\nऔर कोई अशुभ दृष्टि जीके की या राहु केतु\r\nकी नहीं है तो बहुत सुखी रहेगा जीवन बहुत\r\nमजे में\r\nरहेगी और अगर राजयोग में है और फिर भी\r\nइनका संबंध आ गया एक का आ\r\nगया मान लीजिए राहु का ही आ गया सिर्फ\r\nसंबंध तो कलेश रहेगा थोड़ा सा घर में कलेश\r\nरहेगा परंतु घर टूटेगा\r\nएमके के ऊपर अगर है इसी तरह पीके प अगर एक\r\nखराब दृष्टि है और राज योग है साथ में वो\r\nयोग में इवॉल्वड\r\nहै तो भी कशमकश चलती\r\nरहेगी परंतु बुद्धि भ्रष्ट नहीं होगी पूरी\r\nतरह\r\nसे तो यह थोड़े से भेद है इसके अब बहुत सा\r\nक्वेश्चन आता है कि जी 6 आ 12 में बैठे\r\nहोय हो अब जर्मनी में 6 आठ 12 की परवाह मत\r\nकरो ये हम बाद में आएंगे उस\r\nपरे अभी मैं आपको सिर्फ कारक दिखाने बता\r\nरहा हूं और हाउस लॉर्ड पर भाव स्वामी पर\r\nहम नेक्स्ट स्टेप में\r\nआएंगे भाव स्वामी भी इंपॉर्टेंट होते हैं\r\nपर उनका ज्यादातर\r\nरोल टाइमिंग में आता है जब हम यह वार्ता\r\nकरेंगे\r\nतब हम उनको भी ले सकते हैं तो आज के लिए\r\nहम सिर्फ एमके और पी के अब दो का अंतर\r\nमैंने आपको बता दिया कि क्यों सिर्फ एमके\r\nदेखने से विवाहित जीवन का\r\nसुख पूरी तरह से नहीं देखा जा सकता एमके\r\nबहुत अच्छी पोजीशन में है बहुत अच्छे शुभ\r\nसंबंध में है परंतु पीके खराब है पीके प\r\nअशुभ संबंध है तो आप\r\nकरते रहोगे दिमाग में कोई नाना कोई टेंशन\r\nउस तरह की चलती रहेगी ये ये एक फर्क है\r\nइसीलिए मैंने पीके को भी लिया है अब देखिए\r\nआप जल्दी से कुंडली देख लेते\r\nहैं यह हमारी पहली कुंडली\r\nहै 25 अप्रैल\r\n1954 528\r\nदिल्ली यह मैंने जो कुंडली ली है य\r\nसामान्य जो मेरे पास आए कंसल्टेशन वगैरह\r\nके लिए उनकी कुंडलिया ली प्रैक्टिकल\r\nएग्जांपल है तो अब आप यहां देखिए मैं र्थ\r\nचार्ट पर नहीं जा रहा हूं सीधा नवांश पर\r\nआ नवांश में सबसे पहला काम हमारा होगा कि\r\nहम उसको देख ले कि भाई जीके कौन\r\nहै तो यह मैंने नोट किया हुआ है ज्ञाती\r\nकारक इस कुंडली में\r\nशुक्र शुक्र ज्ञाती\r\nकारक अब हमारे एम के कौन है एम के सूर्य\r\nहै और पी के मंगल है सूर्य और मंगल एक साथ\r\nबैठे हुए पी के एम के एक साथ और\r\nइनके साथ में कौन सी दृष्टि आ रही है राहु\r\nकेतु की दृष्टि आ रही है जमनी दृष्टि की\r\nबात कर रहा हूं और चंद्रमा की दृष्टि आ\r\nरही तो चंद्रमा एक के है यह आप कारक अपने\r\nआप देख सकते हैं क्योंकि आपको इसको स्टडी\r\nकरना है बाद में तो एक की दृष्टि आई एम के\r\nऔर पी के के\r\nऊपर तो यह राजयोग बन गया परंतु राहु और\r\nकेतु की भी दृष्टि\r\nहै यह भी दुखी कर\r\nरहे अब एमके जो है चंद्रमा जो है जो के\r\nआपके एक\r\nहै यह नीच राशि में विराजमान बैठे हुए\r\nहैं तो एके मतलब मैं नवांश में मैं एक\r\nलाइक\r\nलग\r\nमैं विवाह में मेरे अंदर कोई अहंकार नहीं\r\nहै एक स्त्री की कुंडली है कि विवाह में\r\nमेरे को अहंकार नहीं है मैं अपने आराम से\r\nसबकी बात करता\r\nहूं परंतु इसके ऊपर शुक्र की दृष्टि है एक\r\nके\r\nऊपर एमके और पीके पर नहीं है एक पर है लगन\r\nल और राहु के साथ\r\nहै चाहे मेरे को कितनी पीड़ा है मेरे को\r\nअहंकार नहीं है और जीके से तकलीफ भी है\r\nपरंतु मैं विवाह मेरा चलता रहेगा एमके भी\r\nठीक है मेरी सोच विवाह के लिए ठीक है मैं\r\nकष्ट में होते हुए\r\nभी मैं अपनी विवाहित सोच को खराब नहीं\r\nकरता\r\nहूं समझे भाई तो यह कुंडली है अब इसी साल\r\nइनके विवाह को 50 साल पूरे हो\r\nजाएंगे और बहुत आराम से मतलब ठीक ठाक\r\nजिंदगी चली\r\nहै अच्छी तरह से मैं इनको बहुत अच्छी तरह\r\nसे जानता\r\nहूं अब दूसरा चार्ट\r\nदेखिए यह दूसरा चार्ट\r\nहै यह है वाइफ का कन्या का चार्ट है\r\nचेन्नई की और इसके बाद में लूंगा इनके\r\nहस्बैंड का\r\nचार्ट यह लव मैरिज है इन दोनों\r\nकी तो यह लव मैरिज के बाद यह कपल का मैंने\r\nचार्ट लिया है तो वाइफ का चार्ट इसमें हम\r\nवही चीज मार्क करते हैं फिर\r\nसे सूर्य जी के है सबसे पहले तो वो मार्क\r\nकर रहा\r\nहूं ठीक है सूर्य जी के है\r\nइसके बाद एम के है\r\nचंद्रमा और पी के है\r\nशनि सूर्य को अब देखें किसकिस को देख\r\nरहा\r\nसूर्य चंद्रमा को भी दृष्ट कर रहे\r\nहैं और पीके शनि को भी दृष्ट कर रहे\r\nहैं तो यहां पर इन्होंने\r\nदोनों को कलेश पहुंचाया\r\nहुआ अब अगर एक और चीज में देखूं एक इनके\r\nएक के इनके शुक्र\r\nहै स्वराशि के है घमंड\r\nहै और सूर्य फिर देख गए इसको सूर्य ने फर\r\nदृष्ट कर\r\nलि तो मेरा जो विचार था विवाह के\r\nलिए वो दूषित हो गया मेरी बुद्धि भ्रष्ट\r\nहो\r\nगई मेरा घर बर्बाद हो\r\nगया एमके पीड़ित हो\r\nगया मेरा घर बर्बाद हो\r\nगया और मैं ठीक हूं मैं बहुत अच्छा हूं\r\nपरंतु मेरे ऊपर जीके की दृष्टि\r\nहै मैं भी कष्ट में\r\nहूं अब यहां डिफरेंस देखो\r\nपिछली कुंडली में भी एके\r\nपर दोदो पाप प्रभाव\r\nथे परंतु एमके और पीके वह पीड़ित नहीं है\r\nवह राज योग में\r\nहै बहुत अच्छा योग बना रहे हैं तो वह\r\nविवाहा चल\r\nगया यहां पर इनका चार पाच साल से डाइवोर्स\r\nकेस चल रहा है अब सुप्रीम कोर्ट तक तक ये\r\nपहुंच चुके हैं अब इनके मैं हस्बैंड की\r\nगुमली लगाता\r\nहूं दोनों में डिफरेंस\r\nदेखना कि सोच में क्या डिफरेंस है\r\nकिसके यह हस्बैंड का है ये गुड़गांव के ही\r\nहै अब यहां आप देखिए इनके भी मैं कारक\r\nआपको बता देता\r\nहूं इनके भी जी के सूर्य\r\nहै अब यहां देखो\r\nकितना भयंकर दिमाग\r\nखराब सूर्य और राहु एक साथ बैठे हुए जीके\r\nऔर राहु करेला नीम\r\nचढ़ा इन दोनों का एस्पेक्ट जाएगा तो\r\nइकट्ठे जाएगा\r\nभाई दोनों को दुखी करेगा अब यहां पर एमके\r\nहै\r\nबृहस्पति एम के\r\nबृहस्पति बृहस्पति पर कोई दृष्टि नहीं\r\nहै तो जो मेरा सुख है मेरा घर है वो तो\r\nमेरा इंटैक्ट\r\nहै तो यह तो अपने आराम से रह\r\nरहे जो लड़की का था होरोस्कोप उसके घर पर\r\nभी जोर से इन्फ्लुएंस आ रहा था खराब\r\nइन्फ्लुएंस आ रहा था उसका घर टूट गया व घर\r\nछोड़ के\r\nचली इसका घर नहीं टूटा तो टूटा क्या भाई\r\nक्या तकलीफ हुई अभी जो पीके है यह बुद्ध\r\nहै अब यहां तमाशा\r\nदेखलो पीके बुध\r\nपर राहु सूर्य जी के और केतु उसकी भी\r\nदृष्टि है और\r\nचंद्रमा जो एमके है उनकी भी दृष्टि\r\nहै सॉरी एमके तो जुपिटर\r\nएमके जुपिटर से चंद्रमा एक\r\nहै एक पर एक पर दृष्टि नहीं है ए के इसको\r\nएस्पेक्ट कर रहे\r\nहैं और जी के एस्पेक्ट कर रहे योग तो नहीं\r\nबना क्योंकि डबल चाहिए मरकरी हमारे पीके\r\nहै पीके के मिला कर के हम योग भी कह सकते\r\nहैं परंतु डबल डबल यह आ रहा\r\nहै इनकी बुद्धि भ्रष्ट\r\nहुई किस वजह से रोज के एमके से नहीं हुई\r\nएमके नहीं खराब हुआ घर रहा परंतु सोच सोच\r\nकरके जब दिमाग खराब हो गया इस तरह का इस\r\nव्यक्ति ने पूरी कोशिश की कि मेरा घर ना\r\nटूटे मेरी बुद्धि ना खराब हो परंतु जब\r\nउसने केस ही डाल दिया विवाह के एक साल के\r\nबाद\r\nतो कब वह सुधारने का मौका भी नहीं\r\nमिला तो यह हमारे आज का जो चप था कि\r\nभाई कि किस तरह से हम पहले विवाह का सुख\r\nअब यहां से हमारे को आया कि सुख के\r\nलिए अपनी\r\nसोच अपनी इंटेलिजेंस अपनी बुद्धि यह\r\nजरूरी\r\nहै\r\nबजाय और एमके के खराब होने से पीके अगर\r\nखराब हो गया डबल एस्पेक्ट आ\r\nगया तो वह किसी ना किसी कारण से बुद्धि\r\nभ्रष्ट हो जाती देखिए भगवान कुछ और नहीं\r\nकरते आपको उसको कुछ जो करना होता है या तो\r\nसद्बुद्धि दे देता है या को बुद्धि दे\r\nदेता है बस उसी से आप अपना एक्शन करते चले\r\nजाते तो विवाह में भी यही है कि भाई मैं\r\nसद्बुद्धि से काम कर रहा हूं या मेरी\r\nबुद्धि भ्रष्ट कुबुद्धि हो\r\nगई तो जब कुबुद्धि हो जाएगी तो विवाह का\r\nसुख हैप्पीनेस सब\r\nखत्म ठीक है\r\nचलिए कुछ लोगों ने यह कहा कि जमिनी\r\nएस्पेक्ट वगैरा भैया ज्यादा मुश्किल नहीं\r\nहै किसी से भी आप अपने दोस्त से पूछ सकते\r\nहैं और वो आसान है और कारक कैसे निकलते\r\nहैं यह दो चीज है सिर्फ अभी तो आगे हम डीप\r\nजेमिनी पर जा ही नहीं रहे हम तो सिर्फ\r\nकारक की बात कर रहे हैं और जेमिनी दृष्टि\r\nकी बात कर रहे हैं तो मैं उनसे रिक्वेस्ट\r\nकरूंगा भाई उसको सीख लो क्योंकि मैं आपके\r\nलिए जो क्विक सलूशन लेकर के आता हूं उस\r\nउसमें जयमिनी बहुत बड़ा रोल प्ले करती है\r\nऔर आगे में इसको और बढ़ाना चाह रहा\r\nहूं वर्गों में जेमिनी का\r\nका कार्य कैसे होता\r\nहै बहुत ही बड़ी रिसर्च ये होगी जो आज तक\r\nनहीं हुई है लगा हुआ आप लोगों का सहयोग\r\nमिलता रहेगा तो उसमें भी कामयाब हो जाएंगे\r\nचलिए फिर से धन्यवाद फिर मिलेंगे\r\nनमस्कार"},{"topic":"How to check your Karma in married life","text":"नमस्कार\r\nमित्रों आज\r\nफिर आपके\r\nसाथ एक बहुत ही\r\nरोचक\r\nऔर जिसको सब सुनना चाहते हैं देखना चाहते\r\nहैं उस विषय पर बात\r\nकरेंगे और आज का\r\nविषय जो चुना गया है\r\nवह\r\nहै आपके विवाहित जीवन\r\nमें आप के कर्म कैसे रहते\r\nहैं अब यह सबको मालूम है कि भाई कर्म तो थ\r\nहाउस से देखे जाते\r\nहैं तो जिस किसी भी चार्ट के कर्म\r\nदेखने तो उसके लिए हम दशम भाव ले लेते हैं\r\nसबसे पहले तो हम देखते भाई हमारा\r\nजो चार्ट जो डिविजनल चार्ट है वो कितना\r\nबली\r\nहै उस हिसाब से हमारे कर्मों का बल भी\r\nआएगा दूसरा पॉइंट होता\r\nहै के किसी भी अपने रिश्ते में अपने किसी\r\nभी कर्म क्षेत्र में\r\nहम अपने दायित्व अपनी रिस्पांसिबिलिटी को\r\nसमझे अगर हम अपनी रिस्पांसिबिलिटी जानते\r\nहैं अपने कर्तव्य जानते\r\nहैं तभी तो हम अपने कर्म उस हिसाब से\r\nकरेंगे या जानते हुए भी गलत\r\nकरेंगे तो यहां य दो पॉइंट आपस\r\nमें एक दूसरे से रिलेटेड है\r\nतो इसके\r\nलिए हम दशम और नवम भाव को और विवाह का\r\nचार्ट हमारा मेनली नवांश को देखते हैं\r\nनवांश के और भी बहुत से यूज है पर आज हम\r\nविवाह के बारे में बात कर रहे हैं तो\r\nविवाह का नवांश\r\nदेखें अब यहां\r\nदेखिए पहले नवम भाव\r\nनवम भाव सब जगह बोला है भाई धर्म का\r\nभाव धर्म जैसे हम पहले भी बात कर चुके\r\nहैं कि धर्म वह होता\r\nहै जो आपको मिलता है परिवार से समाज से\r\nजिसमें आप रहते\r\nहैं तो नवांश का जो नवम भाव है वो नवांश\r\nमतलब विवाह के धर्म का\r\nभा मैं इसको धर्म की बजाय\r\nकर्तव्य धर्म इस कर्तव्य वही तो होता\r\nहै तो नवम भाव को मैं कर्तव्य भाव भी\r\nबोलता हूं और दशम भाव तो कर्म भाव\r\nहै तो\r\nइसीलिए किसी भी वर्ग में जन्म कुंडली कहीं\r\nपर भी नवम और दशम के संबंध\r\nको बहुत अच्छा राज योग माना गया\r\nहै कर्म धर्माधिकारी\r\nसबसे पहले नवम भाव को\r\nदेखें कि क्या मैं अपने कर्तव्य को समझता\r\nहूं क्या मुझे अपने कर्तव्यों की जानकारी\r\nहै उसके लिए नवम\r\nभाव पीड़ित नहीं होना\r\nचाहिए शुभ संबंध हो तो हम अपने कर्तव्यों\r\nको समझते हैं\r\nबहुत से दफ क्या होता है\r\nके शुभ संबंध नहीं\r\nहोता और कोई अशुभ संबंध आप कह\r\nलो तो वह है कि भाई वह कर्तव्य को नहीं\r\nसमझता या अब इसका एक और विश्लेषण हो सकता\r\nहै या वो कर्तव्यों\r\nको भली बाती देख नहीं पाता कर नहीं पाता\r\nऔर कहीं उसके कर्तव्य ज्यादा\r\nहै उसके लिए हमें कर्म टे को चेक करना\r\nपड़ेगा फिर ना को चेक करना पड़ उसके\r\nकर्तव्य बच्चों के प्रति ज्यादा है तो\r\nविवाह के प्रति कर्तव्य कम हो जाते हैं तो\r\nइस तरह से हम वो कर्तव्य कर्तव्य का देख\r\nकर के अगर शुभ संबंध आ जाता है तो तो वो\r\nबिल्कुल पहला सेट हो गया हमारा\r\nरू अगर शुभ संबंध नहीं भी आ रहा है तो\r\nउसको हम नकार नहीं\r\nसकते उसके लिए हमें दशम भाव में जाना\r\nपड़ेगा दशम भाव हमारे कर्म\r\nका अब मान लीजिए मुझे कर्तव्य का नहीं पता\r\nहै कि मेरे विवाह में क्या अपेक्षाएं हैं\r\nमेरे से मेरा धर्म विवाह का क्या कह रहा\r\nहै\r\nपरंतु मेरे कर्म ठीक\r\nहै कर्म में कमी नहीं\r\nछोड़ चाहे मैं कर्तव्य जानता हूं या नहीं\r\nजानता पर मैं कर्म अच्छे करर हूं तो भी\r\nविवा ठीक\r\nरहे तो ज्यादातर क्या होता है जब\r\nहमारे कर्तव्य और\r\nकर्म यह दोनों बिगड़ जाते हैं ना तो मुझ\r\nकर्तव्य की समझ है और ना मैं कर्म ठीक कर\r\nरहा तब वह विवाह नहीं टिकता\r\nहै अब लोग पूछते हैं मेरे से कई मैसेज आते\r\nहैं विवाह प आप बनाइए\r\nवीडियो तो उसके लिए मैं थोड़ा सा पहला\r\nअटेंप्ट कर रहा हूं कि यह दोनों भाव जो है\r\nबहुत ज्यादा इंपोर्टेंट\r\nहै इससे पहले हम एक वीडियो बना\r\nचुके विवाह के सुख के नाम से तो यह इसमें\r\nमैं आपको जेमिनी नहीं ले\r\nरहा केवल पराशर से समझाएंगे समझेंगे बात\r\nकरेंगे क्योंकि बहुतों का यह आया है कि जी\r\nजमिनी हमें\r\nसिखाइए वह भी होगा कभी देखते\r\nहैं तो यह हमारा रूल है अब इसमें\r\nदशम\r\nभाव कर्म का भाव\r\nहै अब\r\nव्यक्ति कर्म बिल्कुल अच्छी तरह से अपने\r\nको अहंकार ना लेकर के और करे व बहुत अच्छा\r\nहोता\r\nहै इसके लिए नवांश का अगर\r\nदशमेश अपनी नीच राशि में\r\nहो बहुत अच्छा है\r\nअहंकार नहीं है उसको कर्म में कुछ भी कर\r\nलेगा घर में बर्तन भी\r\nबांधले और\r\nयदि वहां पर उच्च राशि का ग्रह विराजमान\r\nहै तो उसको अपने ऊपर अहंकार होता है कि\r\nमैं बहुत अच्छे कर्म कर रहा हूं मैं अच्छी\r\nअच्छे कर्म कर रहा अब शुभ संबंध होगा तो\r\nकहेगा मैं बहुत शुभ\r\nकाम कर रहा\r\nहूं अशुभ संबंध होगा तो हो सकता है उसके\r\nकर्मों में कहीं ना कहीं कमी है और वह\r\nघमंड भी ले रहा\r\nहै उन बुरे कर्मों का भी घमंड ले रहा\r\nहै बहुत सी दफ क्या होता है\r\nके हम\r\nकर्म मजबूरी में उल्टे कर\r\nजा मूरी\r\nक्यों जब कर्म का भाव पीड़ित है मैं कर्म\r\nअपना कर नहीं पा रहा\r\nहूं तो फिर कहां से आता है फिर वह विवाह\r\nका सुख ढूंढता\r\nहै जब उसको विवाह के कर्म में पार्टिसिपेट\r\nनहीं किया जाता है वो नहीं कर पा रहा है\r\nतब वो सुख ढूंढता है तोय बहुत सारी\r\nसिचुएशन इसमें हो सकती है हम तो सिर्फ\r\nअप्रोच आपको बता रहे कि भाई देखना कैसे\r\nहै आहिस्ता आहिस्ता करके हम सारे नवाज के\r\nहर भाव का विश्लेषण भी कर सकते हैं चौथे\r\nभाव का भी हम कर सकते हैं पराश्री से जैसे\r\nचौथा भाव है वह विवाह के सुख का भाव है और\r\nचतुर्थेश जहां जाता\r\nहै वोह वहां पर अपना सुख ढूंढता है\r\nकरता है ना फोथ हाउस का\r\nलड तो व विवाह का सुख व ढूंढता है जहां\r\nचला जाता है विवाह का व कौन सा भाव है\r\nजहां चला गया वहां पर व सुख ढूंढना शुरू\r\nकर\r\nदेता तो यह सब छोटे छोटे बिंदु है नवांश\r\nको नॉर्मल जो आपको\r\nहर भाव की परिभाषा लिखी गई है\r\nसिग्निफिकेंट\r\nके संदर्भ में\r\nसोचो तो आपको आंसर मिल जाएगा बहुत बड़ा\r\nसेंटेंस है य आप उसके संदर्भ में\r\nस तो आप उसको अच्छी तरह विश्लेषण कर सकते\r\nहैं तो यह रूल हमने समझ लिए कि भाई नाथ और\r\nथ\r\nहाउस हम इसमें\r\nदेखेंगे और नाइंथ देखेंगे और ज्यादा\r\nइंपॉर्टेंट हमारा थ\r\nतो अब मैं आपसे स्क्रीन शेयर करता\r\nहूं यह मैं पहले एक अच्छी\r\nकुंडली लेकर के शुरुआत\r\nकरूंगा आपको बता ही देता\r\nहूं आजकल जरा अच्छे विवाह कुछ कम देखने को\r\nमिलते हैं तो मैं ने कहा कि लाल बहादुर\r\nशास्त्री जी की\r\nकुंडली देख लेते\r\nहैं कि यहां पर क्या\r\nहै अब यहां\r\nदेखिए नवम भाव\r\nमें मंगल की दृष्टि\r\nहै मंगल के साथ एक अच्छा पॉइंट हो\r\nगया अदर वाइज मिथुन के लिए हम सिर्फ नमाज\r\nकी बात कर रहे हैं\r\nभाई जन्म लगन नहीं लगाई है क्योंकि हमारी\r\nडिस्कशन नवांश प बट डाटा दिया हुआ है आप\r\nउसको लगन बना कर के भी देख\r\nसकते नवम भाव की हम बात कर रहे हैं यह\r\nमंगल से दृष्ट\r\nहै अब मंगल के साथ एक अच्छा यहां पर हो\r\nगया इसको बहुत ज्यादा स्ट्रेंथ या पाप\r\nनहीं मिला है\r\nक्योंकि मंगल दो य का स्वामी\r\nहै छठे और गवे\r\nभाव और वह नीच राशि\r\nमें\r\nअगर अगर\r\nयह अगर यह मंगल उच्च का राशि का होता तब\r\nज्यादा खराब कर सकता था त्रि शाय का\r\nस्वामी उच्च का हो\r\nजाए तो यहां पर कोई दृष्टि नहीं\r\nहै तो यह कर्तव्य अब इससे देख के लगता\r\nकर्तव्य समझते\r\nनहीं ठीक है अब मैं आता हूं दशम\r\nभाव दशम भाव में बुध लग्नेश बुध\r\nहै अब लग्नेश य नीच राशि में है\r\nतो विवाह के संस्कार में मुझे अहंकार नहीं\r\nहै मैं विवाह में अपना अहंकार नहीं\r\nदिखाऊ लगन लड नीच का हो गया नीच राशि का\r\nहो गया अगर सप्तमेश नीच राशि का हो जाता\r\nतो इनकी जो धर्म पत्नी या पति जो भी\r\nस्पाउस आता उसमें अहंकार\r\nनहीं अब यहां पर शुक्र उच्च राशि में\r\nविराजमान है\r\nलग्नेश के साथ\r\nहै कोई पाप दृष्टि नहीं\r\nहै तो विवाह के कर्म मैंने भली भाति\r\nनिभाए उसमें मेरे को कोई तकलीफ\r\nनहीं ठीक है और विवाह का सुख मुझे कर्म से\r\nही मिल रहा है\r\nचौथा ठीक है अब नेक्स्ट चार्ट\r\nयह दूसरा चार्ट\r\nहै यहां पर आप देखिए पहले हम नवम भाव को\r\nदेखते\r\nहैं नवम भाव में कोई ग्रह नहीं\r\nहै और ना कोई दृष्टि\r\nहै तो यहां भी वही सिचुएशन है कि मुझे\r\nकर्तव्य का भान नहीं है मैं समझता नहीं\r\nहूं ना मैं सोचता हूं कि मेरे विवाह का\r\nधर्म क्या\r\nहै अब मैं कर्म पर जाता\r\nहूं कर्म में दो दिग बली ग्रह बैठे हुए\r\nहैं सूर्य और\r\nमंगल और\r\nदोनों अपने डिस्पोजिटर बृहस्पति से\r\nदृष्ट\r\nहै कोई पाप दृष्टि नहीं\r\nहै परंतु सूर्य और मंगल महाबली\r\nहै तो मैं जो अपने कर्तव्य विवाह में करता\r\nहूं मैं पूरी अथॉरिटी से कर रहा हूं और\r\nजुपिटर ने मुझे और बल दे\r\nदिया तो मैं समझता हूं मैं ही कर रहा हूं\r\nठीक बाकी कोई ठीक नहीं कर रहा है\r\nठीक\r\nहै अपने आप को सोचा मैं कर्तव्य बिल्कुल\r\nठीक ठीक कर रहा\r\nहूं परंतु सुख कहां मिल रहा\r\nहै अब सुख का भाव जो है वहां बृहस्पति\r\nबैठे हुए हैं सूर्य और मंगल से दृष्ट\r\nहै और जो चतुर्थेश है वो छठे भाव में राहु\r\nऔर शनि के साथ विराजमान हो\r\nगए तो सुख जो मिलता है मुझे विवाह का व\r\nलड़ाई झगड़े से मिलता\r\nहै सप्तम लॉर्ड भी बुद्ध है वह भी चला गया\r\nतो विवाह में लड़ाई\r\nझगड़ा होता है और मैं अपने आप\r\nको स्ट्रांग कहता हूं मैं ही\r\nहूं मैं ही ठीक कर्म कर रहा हूं विवाह के\r\nचाहे वह गलत कर्म\r\nहै दो पाप ग्रह बैठे हैं और उनके ऊपर\r\nबृहस्पति की दृष्टि आ गई है कर्म मेरे ठीक\r\nनहीं है परंतु मैं सोचता हूं मैं ठीक कर\r\nर अब इसके बाद हम लगे तीसरा एक और\r\nचार्ट यह बड़ा रोचक चार्ट\r\nहै अब य नवम भाव देखो\r\nनवम भाव\r\nपर मंगल की दृष्टि\r\nहै और नवम\r\nभाव पाप करतरी में\r\nहै मैं\r\nअपने कर्तव्यों को रिस्पांसिबिलिटी को\r\nविवाह की रिस्पांसिबिलिटी को जरा भी\r\nतवज्जो नहीं देता मुझे मुझे कोई मतलब\r\nनहीं ना समझता ना मैं\r\nकरता मैं सिर्फ अपना अपना ही देखता हूं\r\nविवाह के कर्तव्य नहीं पता\r\nमेरे अब मैं देखता हूं दशम\r\nभाव दशम भाव\r\nमें सूर्य महाराज बैठे हुए हैं दिग बली\r\nफिर वही आ गया अथॉरिटी मेरे कर्म\r\nइंपॉर्टेंट है विवाह में मेरे कर्म\r\nइंपॉर्टेंट\r\nहै दूसरा मेरे कर्म करता\r\nरहे यह शनि और मंगल दोनों से दृष्ट\r\nहै इनका विवाह\r\nहुआ लव मैरिज\r\nहुई और विवाह के आ द महीने साल भर के अंदर\r\nअंदर\r\nये अलग-अलग रहने लग गए और कोर्ट केस\r\nइन्होंने शुरू कर दिए इन्होंने डाले हैं\r\nकोर्ट\r\nकेस तो ये कहां सुख ढूंढ रहे\r\nहैं चतुर्थेश\r\nपंचम भाव में विराजमान\r\nहै और शनि से दृष्ट\r\nहै और शेश के साथ तीन और छह\r\nके स्वामी बुद्ध के\r\nसाथ तो यहां गड़बड़ हो\r\nगई मैं कहां पर ले रहा हूं मजा कहां ले\r\nरहा हूं कहां से सुख ले रहा हूं\r\nलिटिगेशन एनीमिटी\r\nकरके\r\nशनि शनि की\r\nदृष्टि और छठे भाव बुध जो तीसरा भाव भी\r\nस्वामी है कोई और शुभ संबंध नहीं\r\nहै तो यह विवाह डाइवोर्स में या यहां पर\r\nकोई कर्तव्य पालन नहीं\r\nहो एक और चार्ट हम ले लेते\r\nहैं अब\r\nये एक स्त्री का चार्ट है\r\nअब हम देखते हैं नवम भाव\r\nकर्तव्य नवम भाव में शनि की और मंगल की\r\nदृष्टि और बृहस्पति की भी दृष्टि\r\nहै यह थोड़ा\r\nसा सेफ्टी दे रहा\r\nहै के कर्तव्य मुझे पता है\r\nपर कर्म कैसे है यह कर्तव्य को समझते\r\nहैं चाहे शनि और मंगल इसको भटकने के लिए\r\nभी बोल रहे हैं अब दशम भाव को देख\r\nलो दशम भाव\r\nमें राहु बैठे हुए हैं विराजमान\r\nऔर कोई शुभ दृष्टि नहीं है\r\nतो कर्तव्य तो मेरे मटेरियल\r\nहै जो सॉरी जो कर्म है वह सिर्फ मटेरियल\r\nके पीछे भागने के विवाह\r\nमें अब सुख कहां ढूंढता\r\nहूं चौथे भाव में तो केतु बैठे\r\nभा और जो चतुर्थेश\r\nहै उनका देख लो क्या बुरा हाल हो गया है\r\nवही है ना कि\r\nमैं कुछ अच्छा करने लगा और लुटा के आ\r\nगया चतुर्थेश\r\nबृहस्पति शनि और\r\nमंगल दोनों यह बहुत बली\r\nहैं\r\nमंगल उच्च राशि में बैठे हुए हैं शनि स्वय\r\nराशि में है और दोनों ये बृहस्पति को जो\r\nलग्नेश भी है नवांश के\r\nउनको पीड़ित कर रहे\r\nहैं जो बृहस्पति है वो सप्तमेश और\r\nदशमेश मेरा कर्म कहां है यहां चला गया\r\nमेरे सुख के\r\nपास मेरा जो सुख है बृहस्पति जहां मैं\r\nढूंढ रहा हूं अपना सुख\r\nवो दशम मेरे कर्म में चला कर्म के स्वामी\r\nके साथ\r\nहै एक्चुअली क्या है ये कन्या की कुंडली\r\nहै विवाह हो गया घर में सब विवाह में कोई\r\nचिंता\r\nनहीं शो ऑफ नहीं है परंतु इनका ऑफिस में\r\nएक कोलीग के\r\nसाथ टूरिंग जॉब है तो उस कुलीग के साथ वो\r\nटूर पर भी काफी जाते आते हैं और दोनों का\r\nअपना प्रेम प्रसंग चलता रहता\r\nहै\r\nऔर बहुत समय तक यह प्रेम\r\nप्रसंग दुनिया के सामने भी नहीं\r\nआया\r\nपरंतु यह जब मेरे को कुंडली दिखाने आई थी\r\nबहुत पहले जब मैं देखता\r\nथा तब ये अपने साथ जो जिसको लेकर आई थी\r\nउनको बाहर भेज दिया था\r\nऔर मैंने जब बताया कि भाई साहब ऑफिस का ही\r\nआपका कोई कोलीग\r\nहै विवाह आपका टूटेगा\r\nनहीं विवाह नहीं टूट रहा है और अभी उजागर\r\nभी नहीं होगा परंतु इस दशा में उजागर हो\r\nजाएगा इस दशा में पता चल जाएगा\r\nसबको तो वह काफी हौसले से फिर गई वहां से\r\nकि हां अभी तो मैं एक दो साल और मौज म\r\nकर\r\nसकती तो यह\r\nहमारा\r\nकर्तव्य\r\nऔर कर्म विवाह के कैसे देखा जाए उसके साथ\r\nसाथ हमने एक दो रेफरेंस और ले लिए हैं\r\nचतुर्थ भाव का भी ऑटोमेटिक आ गया कि भाई\r\nकर्तव्य या कर्म को सुख के सुख कहां\r\nढूंढते हैं उससे कैसे\r\nरिलेट तो नमाज का विवाह का सुख है\r\nचौथा तो वहां से हम इसको रिलेट कर सकते\r\nहैं ठीक है जी तो यह आज के लिए होप करता\r\nहूं उम्मीद है कि आप\r\nइसको ध्यान से समझ करके\r\nलगाइए क्योंकि यह इतना सेंसेटिव इशू\r\nहै कहीं आप अपने स्पाउस का या अपनी कुंडली\r\nदेखे और उसके गलत कंक्लूजन निकाल\r\nदे तो अच्छा खासा आपका जो विवाहित जीवन चल\r\nरहा है उसको आप हार्म पहुंचा सकते\r\nहैं जब तक आपको यह नियम पूरी तरह समझ में\r\nना आए आप इसको ग्रहण ना करें इसकी गहराई\r\nना\r\nसमझे तब तक आप किसी उदार रिस्क ना\r\nपहुंचे यह मेरी आपसे हाथ जोड़ के\r\nप्रार्थना है और इसीलिए मैं\r\nज्यादातर ऐसे विषयों\r\nपर वीडियो नहीं\r\nबनाता क्योंकि जो अभी सीख ही रहे\r\nहैं वह इसको गलत अपलाई कर जाएंगे और कहां\r\nसे प्रोटेक्शन मिल रही है उसको वो भूल जाए\r\nतो इसी आशा से उम्मीद से मेरा धेय किसी को\r\nकष्ट पहुंचाने का नहीं है किसी की बुद्धि\r\nखराब करने का नहीं है मैं सिर्फ जो\r\nज्योतिष के नियम है सूत्र है भाव का जो\r\nविश्लेषण है वो सिर्फ करके बता\r\nरहा भगवान करे आपके कोई ये भाव पीड़ित ना\r\nहो ना नवम भाव ना दशम\r\nभाव और चतुर्थेश अच्छे संबंध\r\nमें तो आप इधर उधर भागोगे नहीं ठीक है आज\r\nके लिए इतना ही बहुत-बहुत नमस्कार"},{"topic":"How to check your status in society with AmK","text":"नमस्कार\r\nमित्रों जैसा हमने फिर अब शुरू किया\r\nहै अगली सीरीज तो इसके बाद\r\nकरूंगा अभी हमने कहा था कि छोटे-छोटे\r\nटिप्स आपको\r\nसूत्र देते रहे तो आज एक सूत्र में दे रहा\r\nहूं एक बहुत जल्दी से तुरंत देखना कि भाई\r\nमेरा स्टेटस क्या होगा मेरा व्यवसाय कैसा\r\nहोगा उस सबको देखने के लिए अब इसके लिए\r\nजेमिनी बड़ी सरल होती है मैं अब आहिस्ता\r\nआहिस्ता आपको थोड़ा सा जेमिनी पर भी ला\r\nरहा\r\nहूं तो जेमिनी में इसका कारक होता\r\nहै प्रोफेशन का कारक एएम\r\nके ये सब जमनी जानने वाले इसको जानते\r\nहैं करना क्या है कि एएम के को\r\nबर्थ चार्ट में और जो प्रोफेशन का चार्ट\r\nहै डी\r\n10 उसमें उसको एग्जामिन कर ले कि भाई इसकी\r\nहालत क्या है अच्छा है या बुरा है इसमें\r\nजो बुराई आती\r\nहै वह आती है जब जीके अगर उसको संबंध बना\r\nजाए यह सारी दृष्टि जमनी के लिए नहीं है\r\nऔर अगर वो योग में हो उच्च की राशि में\r\nहो राज योग एक्सचेंज से किसी से भी बना\r\nरहा हो तो उसका पद और ऊपर हो जाता है अब\r\nपहले मैंने सोचा था कि कुछ दो चार हम\r\nजैसों की साधारण कुंडलिया लेकर के उसको\r\nमैं बताऊं\r\nपरंतु उसका\r\nअसरदार इफेक्ट देखने के लिए मैंने जिनके\r\nप्रोफेशन व्यवसाय या स्टेटस प\r\nअच्छी रही\r\nहै उनके दो चार्ट\r\nलिए इसका हम आगे अगर करते हैं आप इसको कोश\r\nकरिए कोशिश करिए तो आप अपने चार्ट पर भी\r\nइसको आराम से देख सकते हैं तो अभी मैं\r\nआपके साथ दो चार्ट शेयर करूंगा और उस पर\r\nइसको लगा करके इस पद्धति को दिखाएंगे एमके\r\nको हम एग्जामिन करेंगे मैं सारे कारक नहीं\r\nदेगा आप बनाइए और कारक\r\nलगाइ यह देखिए पहली कुंडली मैंने ली है\r\nमार्गरेट थैचर\r\nकी इनके एएम के बृहस्पति\r\nहै अब यहां एक दो सवाल मेरे पास आ रहे\r\nहैं कि जी टाइम डिफरेंस आपके किताब में और\r\nउसमें महात्मा गांधी का जैसे है अलग-अलग\r\nहोता है और भाई मैं जो चार्ट ले रहा हूं\r\nअगर वो उस टाइम पर चेंज नहीं हो रहा है\r\nदोनों के डिफरेंस में तो मुझे फर्क नहीं\r\nपड़ता मेरी प्रेडिक्शन वही रहे अगर दशमांश\r\nनहीं बदल रहा है तो वो ठीक\r\nहै तो उस तरह से आप उसको देखिए चलिए यहां\r\nये एएम के बृहस्पति है जन्म लगन में\r\nबृहस्पति\r\nआपके स्वराशि में विराजमान\r\nहै अगर इस पर दृष्टि की बात करें तो सूर्य\r\nए के\r\nहैं और वोह उसको दृष्ट कर रहे हैं और मंगल\r\nएमके है तो राजयोग में हो\r\nगए तो यहां हमें कंफर्म हो गया भा ये\r\nस्टेटस बहुत अच्छा होना चाहिए\r\nइसके बाद में दशमांश में आता हूं अब यहां\r\nदशमांश में आते ही देखिए\r\nबृहस्पति उच्च राशि में विराजमान हो\r\nगए अब य एक गलत जो कहेंगे आप वो क्या है\r\nकि इस पर राहु और केतु की दृष्टि\r\nहै यह क्या बता रहा है कि यह जो स्टेटस है\r\nयह संघर्ष में\r\nहै जूझना पड़े\r\nऔर राहु केतु कैसा करते हैं अपने राशी के\r\nहिसाब से वह काम करते हैं उसको मैं कारक\r\nनहीं बना रहा\r\nहूं उसको कारक मत बनाइए जैसे राहु शुक्र\r\nकी तरह काम कर लग्नेश की तरह काम कर रहा\r\nहै शुक्र ऑफ\r\nलगन तो वह एस्पेक्ट अच्छा है केतु जो है व\r\nअष्टमेश की तरह काम कर रहा है अष्टमेश\r\nमंगल सॉरी वृश्चिक के मंगल की तरह कार्य\r\nकर रहा ना के बवे के\r\nमंगल तो केतु का ये सप्तम भाव का फल दे\r\nरहा है तो उस तरह से उसको देखे तो परंतु\r\nहमारा टॉपिक था एमके को आप देख लीजिए और\r\nआपको मोटा मोटी एकदम जैसे तुरत पुत में\r\nबताना होता है तो यह हम देख के इस्तेमाल\r\nकर सकते हैं दूसरा चार्ट मैंने लिया है\r\nमोदी जी\r\nका अब मोदी इसमें के चार्ट में एम के\r\nशुक्र एम के शुक्र\r\nहै यह किससे दृश किसके साथ है शनि महाराज\r\nके साथ\r\nहै शनि एक है और कोई संबंध नहीं है जेमिनी\r\nवाला इनके ऊपर कोई जीके का उसका संबंध\r\nनहीं आ रहा है तो ये भी अच्छे हो गए अब\r\nनवांश में दशमांश में\r\nदेखिए दशमांश में\r\nशुक्र दशम भाव में ही विराजमान\r\nहै\r\nऔर\r\nतेश भी है और शनि के साथ राशि परिवर्तन\r\nमें है ये सबसे बड़ा योग हो गया शनि कौन\r\nथे आत्म\r\nकारक य ये राशि परिवर्तन ने फिर इनके लिए\r\nएक राजयोग बना दिया तो अमात्य कारक बहुत\r\nअच्छी स्थिति में\r\nहै तो यह\r\nहमारा आज\r\nका हमने इसको छोटे से समझा छोटा सा सूत्र\r\nहै और एम के देख कर के हम अपने व्यवसाय का\r\nप्रोफेशन का एक अच्छा अंदाजा लगा सकते हैं\r\nबाकी तो डिटेल एनालिसिस करना ही पड़ता है\r\nटे का परंतु एक असेसमेंट\r\nके वह क्या\r\nहै ज्यादा इंपॉर्टेंस हम डी 10 को\r\nदेंगे डी 10 में अगर वह इंप्रूव हो गया है\r\nऔर अच्छा हो गया है तो उसका स्टेटस पहले\r\nसे और बढ़ता च चला\r\nजाएगा तो यह हमारा आज जरा सा सा प्रोग्राम\r\nथा और आगे हम अपनी फिर सीरीज शुरू करेंगे\r\nऔर बीच-बीच\r\nमें इसी तरह के छोटे छोटे नियम हम आपके\r\nसाथ शेयर करते\r\nरहेंगे इस आप ध्यान दे रहे हैं इसका आपके\r\nलिए धन्यवाद नमस्कार मेरे लिए भी खुशी की\r\nबात है कि मैं आपके साथ यह शेयर कर पा रहा\r\nहूं धन वा\r\nAll\r\nFrom the series"},{"topic":"How to find your Successful Vimshottary Dasa","text":"नमस्कार\r\nमित्रों आज हम थोड़ा\r\nसा अलग हट के और एक बहुत ही इंटरेस्टिंग\r\nटॉपिक जो सबको बहुत अच्छा\r\nलगेगा उसके बारे में बात करने आए\r\nहैं आज का हमारा टॉपिक\r\nहै के कौन सी विमशोत्तरी दशा\r\nआपकी सक्सेस दे सकती है आपको सक्सेस दे\r\nसकती\r\nहै और वह सक्सेस मेहनत करने के बाद मिलती\r\nविमशोत्तरी दशा देखने के बहुत नियम है\r\nसूत्र\r\nहैं उसको कंफ्यूजन को थोड़ा सा दूर करने\r\nके लिए हम बहुत जल्दी से जैसे देख ले उसके\r\nलिए आज सिर्फ एक सूत्र पर हम बात करेंगे\r\nऔर यह बहुत कारगर सूत्र है इसको हम\r\nएग्जांपल पर भी\r\nदेखेंगे यह सूत्र है अब देखिए मेहनत का\r\nबात की है\r\nमैंने तो इसके लिए हम जन्म कुंडली का\r\nद्रेश कान चार्ट डी3\r\nलेंगे हम दशा को केवल डी3 में देखें है ना\r\nकितना अच्छा कि यह मेहनत का टाइम होगा आप\r\nमेहनत के के साथ सक्सेसफुल होंगे तो यह\r\nविमशोत्तरी दशा देखने का बहुत अच्छा नियम\r\nहै इसमें क्या होता है आप डी3 बना लीजिए\r\nड्रेस कान बना लिया जिस चार्ट का भी आपको\r\nदेखना है अब इसके थोड़े से नियम आप सुन\r\nले मेहनत के लिए आपको मंगल\r\nचाहिए लगे रहने के लिए हार्ड वर्क के लिए\r\nशनि चाहिए\r\nऔर मंगल के साथ-साथ बुध चाहिए बुध आपकी\r\nबुद्धि वर्ल्डली\r\nइंटेलिजेंस वह\r\nचाहिए तो सबसे प्रबल योग होता\r\nहै कि डी3 में दशम भाव में मंगल उच्च राशि\r\nमें विराजमान\r\nहो दूसरा होता है कि स्वराशि में हो\r\nतीसरा होता है कि मंगल दशम भाव को या लगन\r\nको दृष्ट कर रहे हो लगन में विराजमान हो\r\nलगन में उच्च के हो तो यह लगन और दशम\r\nभाव यही रूल हम बुध पर भी लगाएंगे\r\nमरकरी मरकरी उच्च राशि में हो दशम में हो\r\nलगन में\r\nहो और या मरकरी\r\nऔर मंगल का संबंध हो रहा हो कहीं भी हो\r\nरहा हो तो वो भी आपको मेहनत करके वह दशा\r\nउनकी बहुत अच्छी\r\nजाएगी और क्या होता है हम भाव कौन से लेते\r\nहैं भाव लेते हैं लगन पहला\r\nभाव तीसरा\r\nभाव दशम भाव और एकादश भाव\r\nइन राशियो इन भावों\r\nमें जो ग्रह विराजमान\r\nहो वह आपको हार्ड वर्क देकर के जीवन में\r\nसक्सेस देते हैं सफलता प्रदान करते हैं कई\r\nदफे क्या होता है के नहीं सफल दे सफलता दे\r\nरहे हैं उसका कारण यह होता है कि वो पाप\r\nसंबंध में है तो भी देंगे सफलता परंतु\r\nअत्याधिक कष्ट के साथ ज्यादा मेहनत करने\r\nके बाद वह कष्ट\r\nे इसके बाद अब जनरल रूल के जो ग्रह शुभ\r\nसंबंध रख रहा\r\nहै वह\r\nआपको अच्छी सफलता दे सकता\r\nहै अगर वह पीड़ित है और एकती 10 11 में\r\nनहीं\r\nहै तब व ग्रह अपनी दशा अंतर दशा में आपको\r\nकष्ट दे सकता है तकलीफ देगा वहां आपको\r\nफेलर करा सक्सेस के बाद भी फेलर\r\nकर अगर\r\nयही एक तीन 10 11 में जो ग्रह\r\nहै वो पीड़ित\r\nहै तो वह सफलता देगा परंतु अत्याधिक मेहनत\r\nके साथ\r\nदेगा और जगह पर अगर ग्रह पीड़ित नहीं है\r\nतो\r\nवह सफलता चाहे ना दे पर उसमें रोड़ा नहीं\r\nहटकाए अगर\r\nमहादशा अच्छी चल रही है मंगल की मंगल स्व\r\nराशि के बैठे हुए हैं बुध के साथ\r\nहै तो वह अच्छी दशा चल रही है परंतु उसमें\r\nअगर रोड़ा अटका वाला कोई आ गया पापी ग्रह\r\nकी अंतर दशा आ गई उसमें आपको कष्ट झेलने\r\nपड़ेंगे पर महादशा कह रही है नहीं मैं\r\nआपको अच्छे फल दे रहा हूं तो वहां कष्ट\r\nबढ़ जाएंगे आपके ऊपर केस लग सकते हैं\r\nतकलीफ हो सकती है जो आप व्यवसाय\r\nमें तकलीफ कोई शिकायत हो सक सकती है आपके\r\nअग केस लग सकता है तो उस तरह से वो चीज\r\nहमें लगती है तो\r\nये हमारे बड़े आसान से सूत्र है ये कि\r\nहमको एक तीन 10 11 पर कंसंट्रेट करना है\r\nइनकी दशाएं इनके बैठे हुए ग्रह\r\nइसमें शुभ संबंध में है हमेशा अच्छी दशा\r\nजाएगी अशुभ संबंध में है वह आपको तकलीफ\r\nदेंगे तो अब हम मित्रों बहुत ज्यादा व ना\r\nकरके हम इसको प्रैक्टिकल एग्जांपल से\r\nदेखते\r\nहैं\r\nदेखिए यह पहला हम चार्ट ले रहे\r\nहैं मैं सिर्फ दृश कांड दिखा रहा\r\nहूं आपको जन्म कुंडली नहीं दिखा रहा\r\nयहां पर आप\r\nदेखिए मंगल स्वराशि में\r\nहै बुध भी उच्च के कह लो स्वराशि में कह\r\nलो परंतु यह सूर्य और केतु के साथ\r\nहै यह तकलीफ दे\r\nहै अब यहां पर आप अगर आगे देखें\r\nमंगल चंद्रमा के साथ है तो चंद चंद्रमा को\r\nभी मंगल ने अच्छा कर दिया चंद्रमा मंगल की\r\nराशि में\r\nहै अब इनकी दशा\r\nदेखिए जन्म हुआ शनि की दशा में बुध की दशा\r\n62 से 79 तक रही इन्होंने कोई सक्सेस उस\r\nतरह से नोटिसेबल कोई चीज इनकी नहीं दिखाई\r\nदी इसके बाद केतु की दशा 86 तक\r\nरही कोई नोटिसेबल चेंज ज्यादा नहीं दिखाई\r\nदिया केतु हालांकि बैठे हुए हैं आपके\r\nचतुर्थ भाव में दशम में नहीं\r\nहै परंतु मरकरी के साथ है तो यह ग्रूमिंग\r\nपीरियड है केतु का पीरियड 79 टू\r\n86 86 से 2006 शुक्र\r\nमहाराज अब य शुक्र को\r\nदेखो शुक्र सप्तम भाव में वि मान\r\nहै इनके ऊपर कोई पाप दृष्टि नहीं\r\nहै यह मैं बहुत बड़ा सक्सेसफुल पीरियड\r\nनहीं लूंगा परंतु सक्सेस मिली आगे और\r\nसक्सेस भी आने\r\nवाली यह शुक्र की दशा\r\nमें तकरीबन आखिर में जाकर के य गुजरात के\r\nचीफ मिनिस्टर बन\r\nगए और कंटिन्यू करा इसके बाद सूर की दशा\r\nआई अब सूर्य की दशा देखो\r\nसूर्य उच्च के राशि के बुध के साथ है और\r\nकेतु भी बुध की तरह बिहेव कर रहे\r\nहैं इनके ऊपर भी कोई अशुभ दृष्टि और नहीं\r\nहै पर क्योंकि बुध उच्च उच्च राशि में\r\nबैठे हुए हैं सूर्य को पीड़ा सूर्य को\r\nकेतु से पीड़ा भी हो रही है और कोई शुभ\r\nसंबंध नहीं है तो सूर्य की दशा\r\nमें अंतर दशा इनकी और रही होगी बृहस्पति\r\nकी रही\r\nहोगी राहु की इनमें इनको कष्ट हुआ इनके\r\nऊपर केसेस वगैरह काफी\r\nलगे अब 2012\r\nमें चंद्रमा की दशा आ गई और यह प्राइम\r\nमिनिस्टर बन गए 2014\r\nचंद्रमा मंगल के साथ\r\nहै अति\r\nसुंदर उसके बाद मंगल की खुद की दशा आ रही\r\nहै 2022 से 2029 तक यह बहुत सक्सेसफुल\r\nपीरियड दिख रहा है मंगल स्व राशि के बैठे\r\nहुए हैं स्व राशि के बैठे हुए हैं\r\nउन्होंने ही चंद्रमा को बल भी दे दिया\r\nथा\r\nतो यह बात हुई ठीक है जी इसमें अब देखिए\r\nशनि नीच राशि में\r\nहै और शनि की दशा में ही जन्म हुआ\r\nहै हालांकि 11वें भाव में विराजमान है\r\nइनको अच्छा फल देना चाहिए तो कोई\r\nसक्सेसफुल ही कहूंगा मैं बचपन में इनकी ये\r\n12 साल की उम्र तक कोई उस तरह की सक्सेस\r\nनहीं जो घर में काम था कर रहे थे सक्सेस\r\nफली अब अगला चार्ट देखते\r\nहैं यह धोनी जी का चार्ट\r\nहै अब यहां\r\nदेखो बुद्ध स्व राशि के\r\nहैं मंगल के साथ\r\nहैं पिछले केस की तरह ही\r\nमंगल लगन को दृष्ट कर रहे\r\nहैं\r\nएक और 10 से संबंध आना था या इन भाव से\r\nआना\r\nथा मंगल एकादश\r\nहै बढ़िया है सारा कुछ अब यहां पर शुक्र\r\nदेखो शुक्र उच्च राशि में\r\nहै अपने डिस्पोजिटर बृहस्पति से दृष्ट\r\nहैं शनि स्वराशि में\r\nहै लगन\r\nमें तो यह भी अच्छे हैं\r\nअब यह सूर्य और चंद्रमा जो है इन पर कोई\r\nऐसी बात नहीं आ रही है नाय एक तीन 10 11\r\nके स्वामी है तो इनकी दशा मैं कहूंगा कि\r\nपता नहीं कैसी जाएगी अच्छी नहीं\r\nजाएगी अब इनको जो राइज\r\nमिला वह राइज मिला जुपिटर की दशा\r\nमें जुपिटर\r\nउच्च राशि के\r\nशुक्र से दृष्ट\r\nहैं और सबसे बढ़िया बात मंगल से दृष्ट\r\nहै मंगल मेहनत वो\r\nहै एक्टिव बनाता है बहुत ज्यादा अब\r\nबृहस्पति की दशा के बाद सूर्य की दशा आई\r\nअति\r\nसुंदर इसमें बड़े झंडे गाड़े शनि की दशा\r\nमें\r\nऔर शनि के एंड में इन्होंने रिटायरमेंट ले\r\nली नहीं सॉरी बुध में ली रिटायर मेंट बुध\r\nकी दशा आई वह भी आप देखिए कितना सुंदर है\r\nमंगल के साथ है स्वय राशि का है तो पूरी\r\nबुध की दशा में इनको सक्सेसफुल सक्सेस\r\nमिलती ही\r\nरहेगी और यह बुध जो\r\nहै बुध जो है 35 तक चल\r\nतो आगे हमें देखने की जरूरत ही\r\nनहीं इतने तक तो य रिटायर होते\r\nनहीं ठीक है केतु की दशा से पहले अब यह एक\r\nजनरल\r\nकुंडली भारतवर्ष की इंडिपेंडेंस की कुंडली\r\nली\r\nहै यहां पर किसलिए ली\r\nहै के जुपिटर सॉरी मंगल और\r\nबुध दोनों ने स्थान परिवर्तन कर रखा\r\nहै यह इनका अच्छा रिलेशन है भारतवर्ष की\r\nकुंडली\r\nमें चंद्रमा तीसरे भाव में स्वराशि के\r\nविराजमान\r\nहै तो हमने कहा था लगन में तीसरे भाव में\r\nदशम भाव में जो ग्रह\r\nबैठे अब एकादश भाव में शुक्र उच्च राशि\r\nमें बैठे हुए\r\nशनि के\r\nसाथ अब हम भारतवर्ष की दशाएं देख ले अभी\r\nआपने नोट कर लिया कि मंगल बहुत बढ़िया है\r\nशुक्र उच्च राशि का है परंतु शनि से प और\r\nशनि योग कारक भी मान सकते हैं परम भाव को\r\nदशम भाव के स्वामी को हम लेंगे कि दशम भाव\r\nएकादश में बैठा अब यहां आप देखिए शनि में\r\nजन्म\r\nहुआ बुध 65 में ने बुद्ध पीड़ित है केतु\r\nके साथ\r\nहै बर्बाद नहीं किया परंतु अच्छा भी नहीं\r\nकिया तेश के साथ एक्सचेंज में एकती 10 11\r\nसे संबंध नहीं\r\nहै इनका पर ये दोनों मेन कारक है तो\r\nबर्बाद नहीं किया है सिर्फ 65 में वार दे\r\nदी मरकरी शुरू होते\r\nही उसके बाद केतु की दशा आई\r\nउसके बाद हमारी शुक्र की दशा वो अच्छी\r\nचली कोई तकलीफ\r\nनहीं 2009 से में सूर्य की दशा शुरू हुई\r\nसूर्य में भी अब आप देखिए सूर्य महाराज\r\nकहां\r\nबैठे सूर्य एकादश भाव में\r\nबैठे परंतु शनि के साथ है और शुक्र के साथ\r\nभी तो सूर्य य मिलाजुला टाइम\r\nरहा सक्सेसफुल पीरियड रहा कब से कब तक\r\n2009 से 2015 तक और बीच में सत्ता\r\nपरिवर्तन हो गया शुक्र में जब हमारा अच्छा\r\nपीरियड जब आया 15 से पहले शुक शुक्र में\r\nकेतु केतु से पहले बुध जब आया तो दशा\r\nपरिवर्तन हो अब 2015 के बाद चंद्रमा की द\r\nशुरू हो\r\nगई अब देखो कितना बड़ा चेंज आ गया कितना\r\nसक्सेसफुल इस नेशन के लिए हो गया चंद्रमा\r\nस्व राशि के\r\nहै तीसरे भाव में एक तीन 10\r\n11 स्वराशि के हैं उसके बाद\r\nमंगल मंगल का\r\nपीरियड 2025 से 2032 तक अभी तो चंद्रमा चल\r\nरहा है\r\nमंगल भी एक्सचेंज में है और\r\nमंगल पर कोई अशुभ दृष्टि नहीं\r\nहै बुध और मंगल में यह अंतर\r\nहै बुध के साथ केतु बैठे हैं और वह सप्तम\r\nभाव में\r\nहै और मंगल के साथ बृहस्पति का संबंध है\r\nशुभ ग्रह का संबंध है उसके बाद राहु आएंगे\r\nराहु दशम\r\nराहु सूर्य एक\r\nमिनट एक मिनट एक मिनट हां इंडिया राहु लगन\r\nमें विराजमान\r\nहै परंतु शनि से दृष्ट\r\nहै और बुध से दृष्ट है शनि दशमेश हो के\r\nक्वालीफाई कर रहे हैं तो राहु का पीरियड\r\nभी अच्छा जाएगा\r\nराहु हमारा 2032 में शुरू हो रहा है मंगल\r\nतो 32 तक बहुत बढ़िया\r\nहै सन 2032 तक यह पीरियड बहुत अच्छा है\r\nउसके बाद राहु भी अच्छा है उसके बाद\r\nजुपिटर\r\nभी आपका बहुत अच्छा पीरियड है क्योंकि वह\r\nमंगल के साथ\r\nहै पर मेहनत\r\nकराएगा मेहनत पूरी होगी एक चारट और ले\r\nलेते\r\nहैं यह हमने कांग्रेस आई का चारक लिया है\r\nकांग्रेस ये 1979 में बनी\r\nथी अब यहां\r\nबुध और मंगल को\r\nदेखिए एकती 10 11 से संबंध नहीं आ\r\nरहा अच्छी बात क्या है मंगल दशमेश होकर के\r\nसूर्य के साथ एक्सचेंज\r\nमें और एक तीन 10 11\r\nमें सिर्फ सूर्य शनि और राहु विराजमान है\r\nऔर कोई नहीं है थ हाउस ज्यादा स्ट्रांग है\r\nक्योंकि शुक्र उसको खुद को दृष्ट कर रहे\r\nहैं तो शुक्र शुड बी गुड और वह मंगल से भी\r\nदृष्ट है\r\nअब हम दशा देखते मंगल में कांग्रेस का\r\nजन्म\r\nहुआ 72 से 79 तक वंडरफुल पीरियड बहुत\r\nअच्छा पीरियड\r\nरहा 79 से 97\r\nतक मंगल में खैर ऊंच नीच भी ई इमरजेंसी भी\r\nलगी यह हुआ अब इसके बाद राहु पीरियड आया\r\nअब राहु जो है वह स्वयं दशम भाव में\r\nविराजमान है\r\nऔर मंगल की तरह बिहेव कर रहे हैं शनि की\r\nतरह बिहेव कर रहे हैं यह जो शनि डेबिट में\r\nआ गया सूर्य के साथ भी इसने परेशानी दी\r\nसूर्य को भी परेशान किया उसकी अंतर महादशा\r\nमें और राहु को भी यह परेशान कर सकता\r\nहै ठीक है जी अब शनि का\r\nपीरियड शुरू हुआ\r\n2013 बड़ा अच्छा पीरियड चलता रहा 2013 तक\r\nकांग्रेस के\r\nलिए 2013 में शनि है तो दशम भाव में परंतु\r\nपीड़ित है अब शनि को हम पीड़ित मानेंगे\r\nक्योंकि राहु के साथ\r\nहै सूर्य के साथ\r\nहै और इसके ऊपर कोई शुभ दृष्टि नहीं\r\nहै तो जैसा हमने इंडिया का भी देखा अब यह\r\nशनि का पीरियड 2032 तक\r\nचलेगा 2032 के बाद बुध का पीरियड शुरू\r\nहोगा बुध हमारे लगन में विराजमान है तृतीय\r\nहै यह दो क्वालिफिकेशन रख रहा है तो 2032\r\nमें जब मरकरी शुरू होता है तो यह शायद\r\nरिवाइव हो\r\nजाए क्योंकि 2032 तक शनि में तो रिवाइवल\r\nनहीं आ\r\nरहा ठीक है मित्रों तो आज का हमारा यही\r\nलेक्चर था यही हमने\r\nआज देखा\r\nसीखा ठीक है\r\nतो फिर मिलेंगे इसको आप देखिए क्योंकि दशा\r\nजानने की बहुत ज्यादा इच्छा सबको होती\r\nहै\r\nतो आप दशा इसको लगा करके देख और अपना\r\nफीडबैक\r\nदीजिए बहुत-बहुत धन्यवाद आपका\r\nनमस्कार"},{"topic":"How to see transit that gives outstanding results","text":"नमस्कार\r\nमित्रों आज आपके\r\nपास एक बहुत ही\r\nरोचक और जिसके पीछे हमारे बहुत से\r\nस्टूडेंट बहुत से मेरे\r\nसाथी बात करते रहते\r\nहैं जहां तक मैं कई दफा बोलता हूं कि मैं\r\nट्रांजिट नहीं\r\nकरता मेरा जोर फलित पर ही रहता है\r\nट्रांजिट भी फलित\r\nहै तो आज हम गोचर ट्रांजिट\r\nप एक वार्ता करने वाले\r\nहैं परंतु यह ध्यान\r\nरखिए कि गोचर कब आता है कब देखना\r\nचाहिए देखिए हम होरोस्कोप से शुरू करते\r\nहैं प्रॉमिस देखते हैं\r\nउनको डिविजनल चार्ट में एग्जामिन करते\r\nहैं उसके बाद दशा देखते\r\nहैं दशा में भी हम कम से कम दो लेवल तक\r\nएमडी एडी पीडी तक जाते\r\nहैं उसके बाद गोचर आता\r\nहै पर जो कोई कई सूत्र ऐसे\r\nहैं जिसमें आप गोचर देख के एक अ अंदाजा\r\nलगा सकते हैं तो ऐसा ही एक\r\nगोचर आज हम आपसे शेयर कर\r\nरहे हमने बहुत अच्छी तरह से पढ़ा हुआ है\r\n64 वा\r\nनवांश और बावा द्रेश\r\nकांड और इनको छिद्र ग्रह बोला जाता है\r\nछिद्र ये ऐसे ही नहीं है य काफी\r\nइंपॉर्टेंट पॉइंट होते\r\nहोरोस्कोप\r\nके और यह कुंडली को अच्छी तरह प्रभावित भी\r\nकरते\r\nहैं 64 नवाज को चंद्रमा से देखा जाता\r\nहै 64 वा नवांश\r\nमतलब\r\n64 तो 12 ब राशिया अगर गिनता हूं 60 निकल\r\nगई 12 प 60 पांच राशिया निकल जाती है\r\nतो जो चौथी आती है वह 64 वा नवांश हुआ 6वा\r\nनवांश और यह चंद्रमा से देखा जाता है तो\r\nइसका तरीका है सीधा-सीधा नवांश में\r\nजाइए और नवांश में जहां पर चंद्रमा महाराज\r\nबैठे हुए हैं वहां से चौथी राशि\r\nग वो हमारे 64 में नवांश की राशि होती है\r\nहम राश की बात कर रहे हैं इस वीडियो में\r\n64 नवांश के स्वामी की जिसको खर कहते हैं\r\nउसकी बात नहीं कर\r\nरहे हम उस साइन की बात कर रहे हैं राशि की\r\nबात कर रहे 64 नवांश की तो हमने य नवांश\r\nमें देख लिया कि 64\r\nराशि कौन सी\r\nहै अब ट्रांजिट देखेंगे हम जन्म कुंडली\r\nमें उस राशि को हम जन्म कुंडली में लेकर आ\r\nजाएंगे और वहां से ट्रांजिट\r\nदेखेंगे अब इसका आप नियम\r\nसमझो जब कभी\r\nभी दो बड़े\r\nग्रह बड़े ग्रहों\r\nमें जब दो बड़े ग्रह\r\n64वें नवांश को प्रभावित\r\nकरें चाहे तो उसमें राशि में ट्रांजिट कर\r\nरहे\r\nहैं या एस्पेक्ट से उसको प्रभावित कर रहे\r\nहैं तो आपके जीवन\r\nमें कोई बड़ी इवेंट घटना घटती\r\nहै जिसका असर काफी दिनों तक रहता है आप\r\nयाद रखते हैं\r\nउसको इसम अब एक डिफरेंस\r\nहै अगर यह 64 वा\r\nनवांश आपके जन्म कुंडली के आठवे भाव में\r\nपड़े और उस परे यह गोचर\r\nहो तो अनफॉर्चूनेटली\r\nपरेशान करने की सब तरह से वो इवेंट होती\r\nहै और अगर केंद्र कोण में हो तो सबसे\r\nअच्छा है बाकी आठवे के अलावा और भाव में\r\nआप टेस्ट करके देख सकते\r\nहैं तो वहां पर दो मेजर ग्रह का ट्रांजिट\r\nसंबंध आना चाहिए गोचर संबंध आना\r\nचाहिए अब इसमें हम राहु\r\nकेतु शनि बृहस्पति और\r\nमंगल ये तो पांच बड़े प्लेनेट हो\r\nऔर सूर्य क्योंकि वह मंथ को दिखाता है और\r\nउसको भी बड़ा ग्रह माना गया है राजा\r\nहै पर फोकस हम जब ज्यादा बड़ी इवेंट होगी\r\nतो शनि बृहस्पति मंगल राहु केतु यही\r\nआएंगे उसका\r\nस्टार्ट सूर्य भी कर सकता\r\nहै जो माइनर प्लेनेट है जैसे चंद्रमा है\r\nबुध है शुक्र है उनको हम ज्यादा खास ध्यान\r\nनहीं देते\r\nहैं चंद्रमा का एक बहुत बड़ा इंपॉर्टेंस\r\nरोल इंपॉर्टेंट रोल होता है वह टाइमिंग के\r\nलिए बिल्कुल सटीक होता\r\nहै जब आपको और व गोचर करना आ जाए तब\r\nचंद्रमा का गोचर आप लगा सकते\r\nहैं तो यह शुभ फल भी दे सकता\r\nहै और अशुभ फल भी भी दे सकता है यदि 64 वा\r\nनवांश अष्टम भाव में जन्म के अष्टम भाव\r\nमें विराजमान\r\nअब इसको हम हमेशा की तरह से एक दो कुंडली\r\nपर लगा के देखते एक अच्छी लंगे बुरी लंगे\r\nठीक है जी तो मैं अब आपके सामने शेयर करता\r\nहूं स्क्रीन अपनी\r\nयह पहला चार्ट है 4 अगस्त 1961 ओन\r\nललू पहले तो हम इसका 64 वा\r\nनवांश का निर्णय करते\r\nहैं सीधा नवांश में जाते\r\nहैं कैसे देखते हैं चंद्रमा की पोजीशन\r\nदेखिए\r\nऔर चंद्रमा से चौथी राशि\r\nदेखी तो चंद्रमा वेश में है चौथी राशि\r\nकर्क पड़ रही है तो हमारा 64 वां\r\nनवांश कर्क हो गया अब इस कर्क\r\nको जन्म कुंडली में ले आओ ये सप्तम भाव\r\nमें\r\nहै आठवें भाव में कर्क राशि नहीं\r\nहै ठीक है अब इससे क्या वो कर रहा हूं मैं\r\nये नहीं बोलू है अब हम यह कुंडली है बराक\r\nओबामा\r\nकी इन्होंने 20\r\nजनवरी 20\r\nजनवरी 2009 को प्रेसिडेंट की शपथ\r\nली अब हम 20 जनवरी का चार्ट देखते हैं\r\nहमने यहां से देख लिया कि भाई कर्क है 64\r\nवा\r\nनाम अब ये मैं उनका ट्रांजिट लगाता हूं\r\n20 जनवरी 2009 को अब य देखो कर्क को एगजाम\r\nकर लो\r\nभाई आउटस्टैंडिंग\r\nइवेंट कितने बड़े रिजल्ट दिए प्रेसिडेंट\r\nबन\r\nगए केतु विराजमान\r\nहै बृहस्पति दृष्ट कर रहे\r\nहैं मंगल दृष्ट कर रहे हैं दो मेजर\r\nप्लेनेट आ गए तीन केतु भी आ गए और यहां पर\r\nसूर्य भी आ\r\nगए यह मैंने ट्रांजिट\r\nलिया जो जन्म लगन है उसी को लगन बनाते हुए\r\nट्रांजिट ले लिया\r\nमैं तो यह आउटस्टैंडिंग इवेंट इनके जीवन\r\nमें हुई दो दफे यह प्रेसिडेंट\r\nरहे अब मैं दूसरे दूसरा केस एक लेता हूं\r\nयह है हमारे\r\nपास यह केस है अब इसमें हम देख है चंद्रमा\r\nधनु में नवांश\r\nमें धनु से चौथी\r\nराशि वो पड़ी\r\nमीन तो मीन हमारा 64 वा नवांश हो\r\nगया अब यह 64 वा नवांश आप देखिए जन्म\r\nकुंडली में यह अष्टम भाव में विराजमान\r\nहै तो ये इसका ट्रांजिट\r\nआपको अनफॉर्चूनेटली\r\nदेगा अनफॉर्चूनेटली\r\nदेगा अब हम एक ट्रांजिट देखते\r\nहैं 30 मार्च 2024\r\nका यहां पर मीन राशि में राहु विराजमान\r\nथे और\r\nसूर्य पर सूर्य को हम इतना स्ट्रांग मेजर\r\nप्लेनेट नहीं\r\nमानते और इस दिन\r\nये डिटेंशन में चले गए इनको अरेस्ट कर\r\nलिया\r\nगया अब आगे की कहानी देखो यह बड़ी\r\nइंटरेस्टिंग\r\nहोगी\r\nमंगल जो\r\nअभी धनु राशि में है 30 मार्च\r\nको यह 23 अप्रैल\r\nको मीन में आ\r\nजाएंगे और 23 अप्रैल तक की इनकी डिटेंशन\r\nबढ़ गई है तो 23 अप्रैल को राहु भी वहां\r\nपर होंगे पर सूर्य निकल\r\nजाएंगे तो मंगल और राहु बन में होंगे\r\nठीक है अब आगे की इवेंट देखो अब आगे की\r\nइवेंट क्या होगी के 31\r\nमार्च 2025\r\nको शनि महाराज मीन में आ\r\nजाएंगे और राहु भी निकलने वाले नहीं नहीं\r\nहै यह भी मीन में ही\r\nरहेंगे तो मीन की\r\nहालत\r\nआपके 2025 31 मार्च को 2025 में ये और\r\nगड़बड़ कर\r\nजाएंगे ठीक है और 2025 में\r\nही\r\nमंगल अप्रैल में कर्क में और उसके बाद\r\nसिंह में आ जाएंगे लियो\r\nमें अप्रैल मई में ये लियो में आ\r\nजाएंगे सिंह राशि से फिर यह मीन को देख\r\nजाए तो तीन ग्रह का इफेक्ट आ जाएगा 2025\r\nमें अब आगे क्या होगा यह आप खुद देखिए\r\nसोचिए इसको परंतु इसका हम इस गोचर का हम\r\nउपयोग कर सकते हैं 64वें नवांश\r\nका इस पर एक और मैं टिप्पणी कर देता\r\nहूं\r\nके अब जो प्लेनेट है उसमें 62 वा नवांश भी\r\nआता है 62 वा सॉरी 22 वा ग्रेश कांड भी\r\nआता\r\nहै अब यह माना जाता है\r\nकि 64 वां\r\nनवांश वो चंद्रमा से देखा जाता है तो वो\r\nमानसिक मेंटल परेशानियां देता है\r\nऔर अगर बावा द्रेश कांड देखें वह लगन से\r\nकैलकुलेट किया जाता\r\nहै तो वह आपको फिजिकल शारीरिक कष्ट दे\r\nसकता\r\nहै इस पर भी आपसे मैं रिक्वेस्ट करूंगा\r\nदेखिए 22 दृश कांड को भी देखिए कि किसी का\r\nएक्सीडेंट वगैरह\r\nहुआ तो\r\nएक्टिव हो जाता\r\nहै और इसका नियम है कम से कम दो बड़े ग्रह\r\nमेजर\r\nप्लेनेट वह उसको प्रभावित करना\r\nचाहिए दूसरी\r\nकंडीशन के बावा दृश कांड भी अगर आठवें भाव\r\nमें पड़ रहा\r\nहै तब वह कष्ट देगा\r\nएक और रिसर्च इसमें हो सकती\r\nहै हम आठवा ही क्यों ले रहे\r\nभाई हम छ आ 12 क्यों नहीं ले\r\nले 12 में भी तो तकलीफ दे सकता है छ में\r\nभी तकलीफ दे सकता\r\nहै परंतु आठवे को सबसे बली त्रिक माना गया\r\nहै तो इसमें सबसे ज्यादा परेशानी या सबसे\r\nअच्छी इवेंट मिलती\r\nहै गहरी\r\nस्ट्रांग अगर केंद्र त्रिकोण में\r\nहो मान लीजिए नवम\r\nभाव मैं आपका 64 वा नवांश या बावा द्रेश\r\nकान पढ रहा\r\nहै बावा दृश कांड खैर नवम भाव में तो पढ़\r\nही नहीं सकता\r\nतो वो चार आठ 12 में ही\r\nपड़ेगा तो बावा दशका ज्यादा इफेक्ट\r\nखराब हो जाता है जन्म कुंडली के चार आठ\r\nबार मेंही जा सकता है व बावा दश\r\nका तो उसको ट्राई करो तो द्रेश का में दो\r\nपोजीशन खराब हो गई जिसमें आठवी पोजीशन\r\nसबसे खराब\r\nहै आठवे भाव में बावा दृश कांड कब होता है\r\nजब लगन की डिग्री पहले दृश कांड में\r\nपड़ती जीरो से 10\r\nडिग्री तो जो आठवा\r\nवही बावा दृश कान बन जाता\r\nहै किसी भी लगन के लिए अगर जीरो से 10\r\nडिग्री की लगन है तो बावा दृश कान आठवे\r\nभाव में\r\nपड़ेगा और उसका\r\nट्रांजिट फिजिकल तकलीफ दे सकता\r\nहै उसका चार्ट मैंने कोई नहीं लिया आप लोग\r\nकरि ट्राई कर\r\nउसको तो यह ट्रांजिट काफी सफ फल देख होता\r\nहै देखने के लिए यह आपके जीवन की ऐसी\r\nघटनाएं दे देता है कि जहां बहुत बड़े\r\nपरिवर्तन आ सकते हैं तो आज के लिए इतना ही\r\nनमस्कार थैंक यू जी"},{"topic":"Lords of Trishadaya houses","text":"नमस्कार\r\nमित्रों आप सबका मेरी सरल ज्योतिष य पर\r\nफिर से स्वागत\r\nहै और आज\r\nहम एक बहुत ही सीरियस टॉपिक लेकर के आपके\r\nसामने आए हैं यह टॉपिक कोई आसान टॉपिक\r\nनहीं\r\nहै आज का हमारा टॉपिक है त्रि शाय के\r\nस्वामी\r\nत्रि\r\nहड के\r\nस्वामी त्रि हड किसे कहते\r\nहैं त्रि शड आय इनसे मिलके शब्द बना है\r\nत्रि का मतलब\r\nतीसरा षड का मतलब\r\nछठा और त्रि शड आय आय का मतलब लाभ गेन वो\r\n11वां\r\nभाव तो तीन 6\r\n11 अब यह लघु पाराशरी में बहुत ही अच्छी\r\nतरह से विवरण दिया\r\nहै और बहुत सी कंप्लिशन आती है इसके\r\nएप्लीकेशन में बहुत से रूट्स निकलते हैं\r\nजड़ बहुत दूर है\r\nइसकी\r\nतो लघु पराश्री ने एक तो यह लिखा है दूसरे\r\nही श्लोक में\r\nहै कि यह जो हम सिद्धांत यहां पर दे रहे\r\nहैं यह आपको बृहत पराशर से थोड़े अलग\r\nदिखाई\r\nदेंगे परंतु वह भी ठीक\r\nहै और हमारे सिद्धांत भी ठीक\r\nहै दूसरी बात उन्होंने कही\r\nहै कि लघु\r\nपराश्री यह विमशोत्तरी दशा पर काम करती\r\nहै यहां से हम मतलब निकालते हैं कि यह जो\r\nत्रि\r\nलघु पराश्री के नियम है जिससे हमय आज\r\nवार्ता कर रहे हैं जिसके ऊपर वह दशा में\r\nज्यादा फल देते हैं पर हमने अनुभव में\r\nदेखा है कि फलित में भी फल देते\r\nहैं अब हम आते हैं मेन पॉइंट\r\nपर लघु पराश्री ने लिखा\r\nहै कि त्रि सदाय के स्वामी\r\nहमेशा अशुभ होते\r\nहैं कोई फेक्ट बट नहीं\r\nलगाया त्रि शाय के\r\nस्वामी अशुभ होते हैं वो शुभ फल नहीं\r\nदेते और जब के केंद्र के त्रिकोण स्वामी\r\nसॉरी त्रिकोण के\r\nस्वामी हमेशा शुभ होते\r\nहैं और केंद्र के स्वामी केंद्र अधिपति\r\nदोष ये हम एक वीडियो पहले कर चुके कि कब\r\nवो अच्छा होता है कब खराब होता\r\nहै अब बहुत सी दफ क्या होगा कई\r\nदफ कि त्रि शाय का\r\nस्वामी त्रिकोण का भी स्वामी\r\nहै तो क्या\r\nकरेंगे यह एक पहली गुंडी\r\nहै इस पर भी वार्ता होगी\r\nलंबा सब्जेक्ट है ये इस पर भी वार्ता होगी\r\nतो यहां पर हमें दोनों के फल मिलेंगे अभी\r\nमैं इतना ही कहना चाहता\r\nहूं अगर त्रि शाय का स्वामी केंद्र का\r\nस्वामी भी हो गया\r\nहै तो वह पापी हो गया क्योंकि केंद्र का\r\nस्वामी\r\nन्यूट्रल अब यहां जो एक बहुत बड़ी बात\r\nहै कि डाय के स्वामी लिए गए\r\nहैं ना के जो\r\nग्रह त्रि शाय में विराजमान\r\nहो उन परे यह नियम लागू नहीं होता है लघु\r\nपराशि ने वह कहीं नहीं बोला है उन्होंने\r\nसीधा सधा कहा है त्रि डाय के स्वामी अशुभ\r\nहोते हैं\r\nभाई लाभ का घर है तो ग्रह अगर वहां पर\r\nबैठा तो लाभ ही देगा\r\nना तो एक तो यह बड़ी बात\r\nहै अब यह त्रि छड के\r\nस्वामी\r\nज्यादातर अच्छा फल नहीं\r\nदेते अगर कोई शुभता नहीं आ रही है तो वो\r\nफल नहीं\r\nदेते अब इसके ऊपर एक जो विश्लेषण करके आया\r\nइन्ही चीजों से कि\r\nयदि त्रि शाय के\r\nस्वामी उपचय भाव में विराजमान\r\nहो उपचय भाव में बैठे\r\nहो तो वह अपना बुरा फल नहीं देते हैं इसको\r\nमैं थोड़ा कम\r\nकरूंगा बुरा फल नहीं देते हैं\r\nपरंतु त्रि शाय के जो तीनों भाव\r\nहैं वोह आपसे मेहनत कराते हैं तीसरा भाव\r\nपुरुषार्थ पराक्रम का है छठा\r\nआपका साधना बोलता हूं मैं तो\r\nइसको कंपटीशन का है साधना कि मैंने साधना\r\nकर ली भाई इससे लडूंगा मैं गवा भाव लोभ का\r\nहै\r\nतो यह तीनों\r\nभाव यह लोभ में आदमी आता है तो भी वह\r\nज्यादा मेहनत करता है बुरी तरह से भागता\r\nरहता है नछ 11 के\r\nस्वामी अगर उपचय भाव में होते\r\nहैं तो वह सफलता दे देते\r\nहैं अपनी दशा में अब देखिए दशा है ये लघु\r\nपराशर में दशा बात की\r\nहै तो मेहनत करा कर के\r\nवो अपना फल देते हैं उसके लिए और कंडीशन\r\nहै\r\nआगे कि त्रि सटाए का\r\nस्वामी यदि उपचय भाव में है तो कोई ग्रह\r\nउसके साथ या कोई दृष्टि उसके ऊपर नहीं\r\nहोनी चाहिए\r\nवो तो बेस्ट है तब वह अपना अच्छा फल दे\r\nदेगा दूसरा इससे नेक्स्ट\r\nहै के उसका\r\nसंबंध केवल शुभ ग्रहों के\r\nसाथ नैसर्गिक शुभ\r\nग्रह अब नैसर्गिक में मान लो बृहस्पति आता\r\nहै और बृहस्पति भाई त्रि शाय का स्वामी बन\r\nगया\r\nतो शुक्र त्रि शाय का स्वामी बृहस्पति देख\r\nरहा है तो वो शुभ माना\r\nहै बृहस्पति ष डाय का है शुक्र देख रहा है\r\nबुध देख रहा है अच्छा चंद्रमा देख रहा है\r\nतो व\r\nशुभना यह तो हो गई दो कंडीशन तीसरा क्या\r\nहै अगर मिक्सचर है शुभ और अशुभ दोनों का\r\nतो वो मिक्सचर का ही फल देगा अच्छा भी\r\nदेगा बुरा भी दे दोनों फल\r\nदेगा और यदि केवल पाप संबंध\r\nहै तो वह फल अच्छा नहीं\r\nदेगा यह कंडीशन हो गई उसके संबंध\r\nकी अब अगर\r\nवह उपचय में नहीं विराजमान\r\nहै कहीं और विराजमान है उपचय भाव में नहीं\r\nहै तो उस भाव को खराब कर देगा\r\nउस भाव के एडवर्स रिजल्ट बुरे रिजल्ट\r\nदेगा इसके ऊपर भी राइडर\r\nहै\r\nयदि वह जो त्रि छय का स्वामी\r\nहै वह उच्च राशि में विराजमान है जो कि उप\r\nच की राशि नहीं है उपचय में है वो चल\r\nजाएगा वो तो चल रहा है व नियम देख चुके\r\nहैं और और किसी राशि में है उच के\r\nबगैर और व उच्च राशि में है तो भैया फिर\r\nतो उस भाव के लिए और\r\nज्यादा वह खराब अशुभ प्रभाव देगा प्रबल हो\r\nगया भा वैसे ही अशुभ माना है त्रिश के\r\nस्वामी को और अशुभ ग्रह को आपने और बल दे\r\nदिया तो वो बल कहा कहां इस्तेमाल करेगा\r\nअशु फल देने में इस्तेमाल\r\nअगर कोई शुभ संबंध आ जाता है थोड़ा सा कमी\r\nआ जाएगी अगर कोई शुभ संबंध नहीं है तो फिर\r\nतो मैं इतना तक कह सकता हूं कि वह बहुत\r\nज्यादा अब भयंकर तो बहुत ही कठोर शब्द है\r\nअच्छे फल नहीं खराब फल दे अच्छे फल नहीं\r\nदेगा यह हमने बात कर ली और दूसरे भाव की\r\nतो क्या है कि त्रि शाय अपनी दशा\r\nमें अगर शुभ संबंध है या कोई संबंध नहीं\r\nहै या उपचय में\r\nहै उपचय में होकर के अगर उच्च का है नीच\r\nका है कोई\r\nदिक्कत उपचय में हो और शुभ\r\nस तो मेहनत के बाद वोह फल\r\nदेगा अगर उपचय में\r\nहै और उच्च का\r\nहै कोई संबंध नहीं है मेहनत ज्यादा\r\nदेगा शुभ संबंध\r\nहै तो वह प्रभाव डाल रहा है किस तरफ मेहनत\r\nकराएगा वो शुभ ग्रह कहां को ले जा रहा है\r\nक्या करा रहा है उससे वो शुभ ग्रह उसको कह\r\nरहा है ना भाई ये कर\r\nतो इस तरह से इसके अलग-अलग वेरिएशन मैंने\r\nकहा कि यह बहुत बड़ा टॉपिक है लघु पराश्री\r\nपर आप हजार पन्ने लिख लो तो भी कम है कहीं\r\nना कहीं से लिंक इधर उधर मिलती\r\nहै और लोक भाग कितनी ज्यादा लघु पराश्री\r\nकी ट्रांसलेशन मिल रही\r\nहै सब अवेलेबल\r\nहै और 50 50 100 पन्ने की 48 47 श्लोक है\r\nएक एक पन्ने में एक श्लोक बात\r\nकरके बिकती है और सब सोचते हैं कि भैया\r\nलघु पराश पढ़ ली हम पढ़ ली लघु पराश्री को\r\nसमझना\r\nहै वह पूरी ज्योतिष समझने के बराबर\r\nहै खैर अब हम आपसे कुछ चार्ट में इन चीजों\r\nको देखेंगे\r\nले\r\nजी पहला\r\nचार्ट यह आपका पुराना वही जाना पहचाना\r\nइंदिरा गांधी जी का चार्ट है अच्छा है\r\nइसलिए लिया है\r\nमैंने अब यहां देखिए त्रि छटा के स्वामी\r\nकौन\r\nकन बुद्ध\r\nहै बृहस्पति\r\nहै और शुक्र\r\nअब य पहले शुक्र की और बृहस्पति की बात कर\r\nलेते\r\nहैं बृहस्पति भी उपचय भाव में बैठे\r\nहैं और शुक्र भी उपचय भाव में विराजमान है\r\nबैठे\r\nहुए एक और मजे की बात दोनों में राशी\r\nपरिवर्तन भी\r\nहै उपचय में ही अब हम एक एक को इन दोनों\r\nको और थोड़ा सा देखते हैं बृहस्पति के\r\nऊपर सूर्य की दृष्टि है और बुध की\r\nदृष्टि बुध तो इसके लिए अच्छा नहीं है पर\r\nशु ग्र\r\nहै तो बृहस्पति अछूता नहीं\r\nहै यह भी छठे भाव का स्वामी\r\nहै इधर अब शुक्र को देख लो\r\nतो शुक्र के साथ राहु बैठे हुए हैं और कोई\r\nदृष्टि\r\nनहीं तो इसको भी गड़बड़ कर\r\nदी तो शुक्र की दशा भी अच्छी नहीं\r\nजाएगी बृहस्पति की दशा भी अच्छी नहीं\r\nजाएगी मतलब सुंदर नहीं कह\r\nसकते अंतर दशाएं भी कष्ट देते रहेंगे\r\nमेहनत कराएंगे\r\nदिमाग में बल देंगे मतलब बल क्या\r\nपरेशानिया अब एक है बुध त्रय के स्वामी यह\r\nउपचय में नहीं\r\nहै बुद्ध जो है वह उपचय में नहीं बैठे\r\nहुए पर गनीमत यह\r\nथी कि बुध की दशा नहीं मिली क्योंकि इनका\r\nजन्म सूर्य की दशा में\r\nहुआ तो बुध की दशा\r\nबहुत बाद में आती तो उससे यह बचा हो गया\r\nयह कुंडली की शोभा\r\nहै ठीक है\r\nजी तो यहां\r\nपर यह उपचयन कोई बहुत\r\nज्यादा ज्यादा गलत प्रभाव नहीं दिया दो\r\nउपचय आपस में स्थान परिवर्तन कर\r\nरहे ठीक है अब दूसरी कुंडली लेते हैं\r\nयह दूसरी कुंडली भी अच्छे परिणाम की मैं\r\nदे रहा हूं यहां पर एक तो\r\nबृहस्पति त्रि छड के\r\nस्वामी तीसरे और छठे\r\nके कहां बैठे\r\nहैं दशम भाव में सबसे बली उच\r\nभाव और और वो\r\nभी उच्च राशि\r\nमें मेहनत पूरी कराएंगे\r\nमेहनत में कमी नहीं\r\nछोड़ेंगे बहुत मेहनत कराएंगे पुरुषार्थ\r\nकराएंगे\r\nअब इनका जन्म देख लो राहु की दशा में हुआ\r\nथोड़ी सी बाकी थी और बृहस्पति 16 17 18\r\nसाल तक की उम्र के इन्होंने कितना रगड़ा\r\nखाया होगा ज्योतिष सीखने में पढ़ने\r\nमें आंदोलनों में पिताजी के साथ काम करने\r\nमें सक्सेस वहीं से आई है सीखना वहीं से\r\nआया है बृहस्पति की दशा\r\nने बिल्कुल जिसको कहते हैं ना एड़िया घिस\r\nदेता है त्रि छड़ाए का स्वामी उच्च का है\r\nअब मजे की बात क्या है बृहस्पति पर किसी\r\nकी दृष्टि नहीं है\r\nयह इसकी सुंदरता\r\nहै अब जो दूसरे तीसरा जो ग्रह है जो उपक\r\nत्रि शड का स्वामी है वह है\r\nसूर्य सूर्य में भी है तो केतु के\r\nसाथ शनि दृष्ट कर रहे\r\nहैं शनि योग कारक है पर है पाप\r\nग्रह इस कुंडली इसके लिए हम कहेंगे शनि की\r\nदृष्टि शुभ की दृष्टि नहीं है अगर वो\r\nलग्नेश होते तो शुभ मांग\r\nलेता और बुध की जो उच्च राशि में बैठे\r\nहैं उन्होंने इनका साथ दिया हुआ है\r\nसूर्य पर यह उपचय में नहीं\r\nहै तो सूर्य की दशा में इनको कष्ट\r\nहोगा और हुआ सूर्य की दशा में इनको कष्ट\r\nहुआ अब आ जाओ आगे और कुंडलियों में जहां\r\nपर थोड़ा सा गलत रिजल्ट आते\r\nहैं अब यहां\r\nदेखिए\r\nसूर्य एक त्रि शाय के स्वामी है बाकी के\r\nमंगल दो त्रि शाय के स्वामी\r\nअब इस कुंडली की ब्यूटी क्या है कि यह\r\nमंगल और सूर्य\r\nदोनों उपचय भाव में बैठे\r\nहु यहां पर एक और में जो आगे अगर पढ़ेंगे\r\nत्रिक और त्रि शाय को मिलाएंगे जब जब और\r\nबबाल हो जाएगा तो जो शुक्र\r\nहै वो त्रिक के भाव है के नहीं\r\nहै अगर यह दोनों एक हो जाते हैं वो भी कभी\r\nकिसी दिन करेंगे वीडियो अब हम देखते पहले\r\nसूर्य\r\nतते\r\nपराक्रम इनके ऊपर बृहस्पति की दृष्टि है\r\nशुभ की\r\nदृष्टि और सूर्य उच्च राशि\r\nके सूर्य की\r\nशने इनको इतना भागदौड़ कराई\r\nहै के दिन में घर में बैठना ही मुश्किल\r\nथा बहुत भागदौड़\r\n1989 से\r\n1995 तक एक्सीडेंट भी भागदौड़ जगह दिन और\r\nरात काम कराया पर फल भी\r\nदिया 95 तक अपना फल दे\r\nदिया और जो मंगल\r\nहै यह भी दो त्रि शाय के स्वामी है अब\r\nयहां पर क्या अच्छी बात है वह सबसे बली\r\nउपचय भाव में बैठे\r\nहुए दो शुभ ग्रह के\r\nसाथ और शनि से\r\nदृष्ट यह एक अशुभ दृष्टि है\r\nपर मंगल और शनि आदमी को चैन से आराम से ह\r\nकाम ही कराता\r\nहै शनि और\r\nमंगल परस्पर संबंध बना ले व भाई साहब काम\r\nमें ही लगा रहता है खाली बै नहीं बैठ पाता\r\nतो यहां पर आपने देखा मंगल\r\nने अशुभ प्रभाव नहीं\r\nदिया सिर्फ ये\r\nकिया क्योंकि मंगल द्वादश के साथ भी\r\nहै सिर्फ मंगल ने यह किया कि इन्होंने कहा\r\nरिटायरमेंट टाइम आ गया अब मैं अपना काम\r\nअपना यह यह बंद करता हूं मंगल की दशा इनकी\r\n60 साल की उम्र में आई\r\nथी तो तब\r\nसे खाली नहीं\r\nबैठे काम कर रहे हैं परंतु प्रोफेशनल काम\r\nवो खत्म कर अब एक और कुंडली में लेता\r\nहूं अब यह आपको असली स्वरूप अब देखने को\r\nमिलेगा यहां पर देखिए शनि पहले उपचय के\r\nस्वामी त्रय\r\nके यह शनि उपचय में नहीं\r\nहै बवे भाव में बैठे हैं\r\nऔर वह भी उच्च राशि\r\nमें और उच्च के सूर्य से दृष्ट\r\nहै कोई शुभ दृष्टि नहीं\r\nहै बहुत बुरा हाल रहा है\r\nइनका जहां बैठते हैं हमने बताया त्रिश डाय\r\nके स्वामी जहां बैठते\r\nहैं वहां उस भाव को चौपट कर और जबक यह\r\nउच्च\r\nके इतने लॉसेस इन्होंने\r\nदिए यह ट्रांसपोर्टर\r\nथे पार्टनरशिप में मिलके बैंक लोन वगैरह\r\nकर कर आके इन्होंने पांच सात ट्रक भी\r\nइकट्ठे कर लिए थे और वो ट्रक ट्रांसपोर्ट\r\nमें चलते थे पार्टनर्स ने धोखा दिया\r\nबिल्कुल कंगाल हो गए जिसको कहते हैं\r\nबिल्कुल बस एक मकान बचा था जिसमें रह रहे\r\nबाकी सब इतनी बीमारियां इनको मिल गई आप\r\nअंदाजा नहीं लगा सकते दुनिया में आप\r\nबीमारी का नाम लो और वह इनके पास\r\nथी यह शुरू हुई थी शनि से शनि से पहले भी\r\nशुरू हो गई\r\nथी उसके बाद दूसरे जो त्रि शनाय के स्वामी\r\nहै वह\r\nमंगल अब मंगल\r\nभी उपचय में नहीं\r\nहै ये भाई साहब भी बुद्ध के साथ\r\nहै बुध को कहने को थोड़ा सा शुभ मान\r\nलो परंतु जब बुध किसी पाप ग्रह के साथ\r\nहोते हैं तब उनको अशुभ मानते हैं यहां मैं\r\nछूट क्यों दे रहा हूं इसको थोड़ा शुभ\r\nमानने की क्योंकि मंगल\r\nलग्नेश अब और बात क्या है इस मंगल के एक\r\nतरफ सूर्य है जो प्रभावित कर रहे हैं\r\nकरतरी से दूसरी तरफ केतु है वह भी\r\nप्रभावित कर रहे हैं और बुध अष्टमेश\r\nहै और केतु अष्टम भाव\r\nसे इनको प्रभावित कर रहे हैं तो यह मंगल\r\nने भी कोई त्रि\r\nकि स्वामी है चौपट ही\r\nकिया अब जन्म कब हुआ था यह देख लो भाई\r\nपहले चंद्रमा की दशा में जन्म\r\nहुआ तो मंगल बचपन में ही बीत\r\nगया दुनियादारी उस समय नहीं\r\nदेखी इसके बाद बुद्ध भी त्री शाय के\r\nस्वामी है इनकी हालत और ज्यादा खराब\r\nहै अब ये बुध जो है मंगल के साथ बैठे हैं\r\nपाप करतरी में बैठे हैं कोई शुभ संबंध\r\nनहीं\r\nहै तो शनि की दशा उसके बाद बुध की\r\nदशा ठीक है तो ये आगे जाने ही नहीं देगा\r\nभाई यहां पर द एंड है इतना कष्ट बहुत\r\nज्यादा ये परेशान रहे अपनी लाइफ\r\nतो त्रि शड के स्वामी इस तरह का भी काम कर\r\nदेते\r\nहैं ठीक\r\nहै चलिए तो यह हमने अच्छी कुंडली से शुरू\r\nकरके लास्ट की कुंडली पर हमने देखा कितना\r\nअशुभ प्रभाव त्रि छड़ाए के स्वामी डाल\r\nसकते\r\nहैं इसमें मुझे पता है आप लोगों के बहुत\r\nसवाल\r\nआएंगे मैंने फिर कहा\r\nहै के लघु पराश्री पर आप हजार पन्ने भी\r\nलिख दो जब आपके उनके रूल्स को मिलाना शुरू\r\nकरोगे जैसे मैंने कहा त्रि सड के साथ\r\nत्रिक त्रि सड के साथ केंद्र\r\nत्रिकोण त्रि सड के साथ\r\nन्यूट्रल फिर उनकी\r\nप्लेसमेंट फिर उनके ऊपर स्पेक्ट तो यह\r\nसब कमजोर दिल के लिए नहीं है इनको बहुत\r\nगहराई तक जाकर के देखना\r\nपड़ेगा खैर हो सकता\r\nहै के ऐसे सवाल भी आए जिनका मैं शायद जवाब\r\nना दे पाऊ कोशिश करता हूं परंतु बहुत से\r\nसवाल टॉपिक से अलग होते\r\nहैं\r\nऔर अब इस पर आए\r\nकमस्ट हो तो क्या होगा रेट्रोग्रेड होगा\r\nतो क्या\r\nहोगा ग्र युद्ध में होगा तो क्या होगा\r\nभैया यह सारी चीजें हैं बारी बारी से\r\nदेखेंगे ठीक है जी तो आज के लिए आज के लिए\r\nइतना ही भैया फिर मिलेंगे धन्यवाद थैंक यू"},{"topic":"puskar navmansa","text":"नमस्कार\r\nमित्रों आज फिर मैं आपके पास आया\r\nहूं और आज हम अपने सरल ज्योतिष पार्ट वन\r\nका अंतिम चैप्टर चैप्टर नंबर 14 लेकर के\r\nआए\r\nहैं जो\r\nहै पुष्कर\r\nनवांश काफी रिक्वेस्ट भी आ रही\r\nपुष्कर\r\nनवांश हमेशा माना गया है कि बहुत ही अच्छा\r\nहोता\r\nहै बहुत ज्यादा शुभ फल देता है एक ग्रह भी\r\nअगर आपके पुष्कर नवांश में है तो आप खुश\r\nहो गए भाई\r\nसाहब अब पहले\r\nतो यह हम बिल्कुल क्लियर कर ले\r\nकि पुष्कर नवांश में ग्रह होने का क्या\r\nमतलब\r\nहै कोई भी\r\nग्रह यदि पुष्कर नवांश में होता\r\nहै तो उसको रिजल्ट देने की फलित करने की\r\nअपने अपना इफेक्ट देने की जो शक्ति\r\nहै वो बढ़ जाती\r\nहै अब यह शक्ति\r\nअच्छी चीज देगी शुभ फल देगी या अशुभ फल\r\nदेगी ये दोनों दे सकते हैं तो यह भ्रांति\r\nमें ना रहे के अगर पुष्कर नवांश में ग्रह\r\nहै तो मैं हमेशा शुभ ही शुभ\r\nहूं वो प्लेनेट शुभ ही शुभ\r\nहै सिर्फ यह है अगर वह अच्छे भाव का\r\nस्वामी है\r\nअच्छे भाव में है तो उनके शुभ फल में\r\nबढ़ोतरी\r\nकरेगा और नहीं तो बढ़ोतरी नहीं करे र पहले\r\nहम यह जान ले कि कहां कहा ग्रह पुष्कर\r\nनवांश में होता है इसके लिए मैंने एक\r\nतालिका तैयार करी है टेबल बनाई है यहां पर\r\nआप इसको पॉज करके वो टेबल को देख सकते हैं\r\nयह वो टेबल\r\nहै य आप देखिए जितने फायरी साइन\r\nके साइन है एक पान उसमें सातवा और नौवा\r\nनवांश आपके पुष्कर नवांश होता है इसी तरह\r\nसे चारों सेट में आप यह देख सकते हैं मैं\r\nरिपीट नहीं करूंगा इसको टोटल मिला कर के\r\nअगर आप\r\nदेखेंगे तो हमारे\r\n24 नवांश पोजीशन ऐसी है\r\nकि जहां वह ग्रह बैठता है तो वह पुष्कर\r\nनवांश में होता\r\nहै काफी अच्छी परसेंटेज है 20 2 पर ग्रह\r\nजो है व पुष्कर नवांश में होते हैं अब\r\nइसको देखने का तरीका क्या है यहां एक चीज\r\nबिल्कुल क्लियर है इस टेबल को भी अगर आप\r\nदेखोगे तो छह राशियां ऐसी\r\nहै\r\nजिसमें\r\nअगर\r\nग्रह स्थित है नवांश में तो वह कभी भी\r\nपुष्कर नवांश में नहीं हो\r\nसकता वह राशियां है एक तीन पा आ 10\r\n11 यह तुरंत का तरीका बता रहा हूं कि भाई\r\nपुष्कर नवांश में कौन सा ग्रह है देखने का\r\nतो नवांश में अगर एक तीन पा 8 10 11\r\nराशियों में\r\nकोई ग्रह बैठा हुआ है नवांश में तो वह\r\nपुष्कर नवांश में हो ही नहीं सकता उनको\r\nछोड़ दो इनके अलावा जो राशियां है उनमें\r\nजो ग्रह बैठा हो उनको जाकर के फिर इस टेबल\r\nसे या अपने बर्थ चार्ट से कि उसकी राशि\r\nदेख कर के इस टेबल से उसको तय कर ले कि यह\r\nभाई पुष्कर नवांश में है या नहीं तो पहला\r\nतो ये शॉर्ट कट टेस्ट मैंने बता पहला\r\nतरीका\r\nदूसरा क्या करना\r\nहै यह बड़े ध्यान से सुनिए\r\nभाई इसी पर सारा दारो मदार है हमारे\r\nपुष्कर नवाज\r\nका हमें क्या करना\r\nहै कि पहले तो हमने डिसाइड कर लिया कि कौन\r\nसा ग्रह पुष्कर नवांश में\r\nहै अब उस पुष्कर नवांश की राशि को नोट\r\nकरो कि ग्रह नवांश में किस राशि में\r\nविराजमान है बैठा हुआ\r\nहै अब उस राशि\r\nको बर्थ चार्ट\r\nमें देखो कि वह कहीं विपरीत हाउस की तो\r\nराशि नहीं\r\nहै ज्यादातर तो शास्त्रों में छ आ 12 लिखा\r\nहै\r\nविपरीत िक त्रिक भाव मैं उसमें तीसरा भाव\r\nभी जोड़\r\nलेता अगर छ आठ या तीसरे भाव में वोह ग्रह\r\nबैठा हो विराजमान है नवांश की\r\nराशि तो वह उस भाव के भी फल\r\nदेगा छठे में है आपको बीमारी\r\nदेगा आठवे में है सडन इवेंट देगा मृत्यु\r\nभय\r\nदेगा बवे में है आपका खर्चा ज्यादा कराएगा\r\nआपके सीक्रेट शत्रु पैदा करेगा छुपे हुए\r\nशत्रु सामने नहीं आते\r\nऔर तीसरे भाव की राशि में है तो वह आपको\r\nसाहस या षड्यंत्र में\r\nफसा थर्ड हाउस को खल हाउस भी बोला गया है\r\nऔर वह काफी मेहनत करा करके फल देता है तो\r\nयह हमारे नियम हो\r\nगए पहले\r\nहम इन नियमों को देख ले उसके बाद में\r\nपुष्कर नवांश की अदर एप्लीकेशन या पहले\r\nएप्लीकेशन बता देता हूं कि और कहां कहा\r\nइसको इस्तेमाल किया जा सकता\r\nहै जन्म कुंडली की तो हम बात कर ही रहे\r\nहैं तो इसको हम प्रश्न कुंडली में\r\nभी पुष्कर नवांश की सहायता ले सकते हैं\r\nपरंतु अगर एक भी ग्रह प्रश्न कुंडली में\r\nपुष्कर नवांश में है उसमें ये चेक करना जो\r\nचेक मैंने अभी बताया है कि प्रश्न कुंडली\r\nके तीन छ आठ 12 भाव में उसको नवांश में\r\nनहीं होना\r\nचाहिए नहीं तो वह बैड इफेक्ट भी दे सकता\r\nहै तो होरी तो मैं कर नहीं रहा हूं तो यह\r\nआप वहा इस्तेमाल कर सकते\r\nहैं दूसरा इस्तेमाल इसका जो एप्लीकेशन है\r\nवो महूरत में है\r\nमोरत निकालते हैं तो आप नोटिस\r\nकरेंगे कि हर एक घंटे\r\nमें के बाद हर घंटे में एक समय में लगन जो\r\nहै वह पुष्कर नवांश की उदय होती\r\nहै तो अब शास्त्रों के हिसाब से तो भैया\r\nवो वाला पोर्शन ले लो जब पुष्कर नवांश लगन\r\nमें हो रहा है और हर घंटे होता\r\nहै पर उस परे भी हम दोबारा वही चेक करेंगे\r\nजो मैंने सबसे पहले बताया\r\nहै कि वो नवांश में किस राशि में गया\r\nहै अगर वो इन विपरीत राशियों में नहीं है\r\nतो वोह अच्छे फल\r\nदेगा वैसे भी देगा वैसे भी फल देगा परंतु\r\nउन भावों के भी फल\r\nदेगा जैसा मैंने बताया छटा है बीमारी दे\r\nमान लीजिए दशम लड है दशमेश\r\nहै पुष्कर नवांश में है तो स्टेटस तो दे\r\nदेगा परंतु यदि वह नवांश में छठे भाव की\r\nराशि में बैठा\r\nहै तो वो बीमारी भी देगा य नहीं रोग रोग\r\nदेगा ये नहीं कि आपको प्रोफेशन की बीमारी\r\nदेगा नहीं आपको रोक\r\nदे तो यह चीज हमें ध्यान में रखनी चाहिए\r\nतो अब हम कुछ एग्जांपल चार्ट ले लेते हैं\r\nऔर इसको जरा सा समझते\r\nहैं अब पहला\r\nचार्ट हमने रमन साहब का है\r\nयह रमन साहब के चार्ट\r\nमें\r\nसिर्फ एक जो मंगल महाराज\r\nहै ये आप चेक करते रहना मैं तो देख कर के\r\nसीधा-सीधा कह रहा हूं मंगल पुष्कर नवांश\r\nमें\r\nहै अब यह नवांश में कहां गए तो यह देख लो\r\nमंगल नवांश में तुला राशि में\r\nहै ठीक है तो तुला राशि बर्थ लगन की नवम\r\nभाव की राशि\r\nहै तो यह विपरीत भाव में नहीं आई तो यह\r\nशुभ फल देगा मंगल अब इनके जन्म भी जो हुआ\r\nमंगल की दशा में\r\nहुआ मंगल दशमेश\r\nहै दशम घव के बड़ी प्रसिद्धि दे\r\nदी मंगल तृतीय भाव का भी स्वामी\r\nहै संघर्ष साथ भी दे\r\nदिया और मंगल जो है वह वाद\r\nविवाद क्रिटिक जिसको कहते हैं वह देता है\r\nतो यह क्रिटिक\r\nमतलब यह अच्छी तरह से चीज को समझ करके\r\nलॉजिकली देख कर के मंगल लॉजिक का भी कारक\r\nहै तो हर चीज का लॉजिक देख कर के वह निकाल\r\nदेते थे तो यहां पुष्कर नवांश ने इनको\r\nबहुत अच्छी सपोर्ट दी और कोई ग्रह पुष्कर\r\nनवाच में नहीं अब हम दूसरी कुंडली पर आते\r\nहैं यह शरद पवार जी की कुंडली\r\nहै इस कुंडली में दो\r\nग्रह पुष्कर नवांश में व दो ग्रह है राहु\r\nऔर\r\nशुक्र राहु और\r\nशुक्र तो नवांश में मैंने राहु और शुक्र\r\nको देखा ये कौन से साइन में बैठे हुए हैं\r\nये टोरस में बैठे अब मैं इनकी जन्म कुंडली\r\nपर गया भाई टोरस कौन सा साइन\r\nहै टोरस है छटा भाव का साइन छटे में\r\nहै तो इनको बीमारी भी देगा यह बीमारी की\r\nभी संभावना प्रबल हो जाती है पुष्कर नवांश\r\nजो है उसकी कैपेसिटी बढ़ जाती है ताकत बढ़\r\nजाती है अब यह जो शुक्र है यह एकादश भी है\r\nशश भी है और एकादश\r\nभी तो लाभ भी देते\r\nहैं लाभ बहुत देते हैं\r\nइनको और बीमारी भी देते हो संघर्ष भी\r\nदेते दूसरा प्लेनेट इनका राहु\r\nहै पुष्कर नवांश में वो नवांश में कहां\r\nविराजमान\r\nहै वो भी टोरस में है वृषभ\r\nमें तो यह भी बीमारी देते हैं राहु भी\r\nबीमारी देते हैं पर राहु जन्म कुंडली में\r\nकहां बैठे हैं वह दशम भाव में बैठे\r\nहैं तो यह राहु इनको स्टेटस भी\r\nदेगा ठीक है तो ये हमने देखा इनका जन्म\r\nशुक्र की दशा में हुआ तो बचपन में ही निकल\r\nगई बाद में राहु आया जब स्टेटस\r\nमिला तो यह हमने देखा अब एक और कुंडली\r\nदेखते\r\nहैं तीसरी कुंडली ये देखते हैं हम महात्मा\r\nगांधी जी कितना बड़ा स्टेटस दिया है\r\nइनको राष्ट्र पिता बन\r\nगए और मजे की बात अब देखो\r\nगांधी जी के होरोस्कोप में चार\r\nग्रह पुष्कर नवांश\r\nहै वह ग्रह है\r\nबृहस्पति शुक्र केतु और\r\nमंगल अब इनको मैं नवांश में देखता\r\nहूं पहले\r\nबृहस्पति यह धनु में विराजमान है\r\nकेतु शुक्र और मंगल यह वृषभ\r\nमें कौन सी राशियां\r\nहै धनु तृतीय भाव में है संघर्ष देते हैं\r\nऔर टोरस वृषभ यह अष्टम भाव की\r\nराश ये\r\nअचानक चीजें\r\nदेंगे अभी आगे आएंगे क्या अचानक किया\r\nइसने अब एक एक ग्रह को हम जन्म कुंडली में\r\nदेख ले\r\nबृहस्पति पुष्कर नवांश में\r\nहै\r\nबृहस्पति तीसरे और छठ के स्वामी सप्तम में\r\nबैठे हु\r\nरेट्रोग्रेड पर इनके ऊपर और भी इफेक्ट है\r\nतो मेरिड\r\nलाइफ ठीक कह सकता हूं पर बृहस्पति का\r\nवक्री होना य पर वह अच्छा नहीं माना\r\nजाए अब शुक्र जो है वह\r\nलग्नेश और अष्टमेश\r\nहै और पुष्कर नवांश में स्वय राशि में\r\nबैठे हुए तो शरीर को ठीक ठाक कर\r\nदिया उसके बाद केतु अब केतु दशम भा चतुर्थ\r\nभाव\r\nमें\r\nहै इसके ऊपर मंगल की दृष्टि है मंगल भी\r\nआपके पुष्कर नवांश में है और चंद्रमा की\r\nदृष्टि चंद्रमा स्व राशि\r\nके तो केतु ने कोई सुख में कमी नहीं की\r\nइनके आप कहोगे मकान नहीं बनाया घर नहीं\r\nबनाया परंतु अगर ऐसा घर मुझे भी मिल जाए\r\nजहां पर इतने लोग देखभाल करने वाले\r\nतो बहुत बढ़िया\r\nभाई इसके बाद\r\nमंगल अब मंगल जो है दविश है और सप्तमेश है\r\nपुष्कर नवाज में लगन में\r\nबैठे तो कोई तकलीफ नहीं थी फैमिली की भी\r\nउसकी भी फैमिली संतान भी थी सब थी अच्छी\r\nफैमिली थी अब अगर मेजर बात आप देखे तीन\r\nतीन चार ग्रह पुष्कर नवांश में है और इनकी\r\n30 जनवरी को गोली मार के हत्या हो\r\nगई उस\r\nसमय बृहस्पति में शुक्र शुक्र में मंगल की\r\nदशा चल रही\r\nथी तीनों ग्रह पुष्कर नवांश में\r\nहै परंतु अष्टम भाव नवांश में अष्टम भाव\r\nकी राशि में होने के\r\nकारण अल्टी ली\r\nइनको उस दशा में मृत्यु\r\nमिली और सब दिया पुष्कर नवासी ने अच्छा\r\nकिया जहां बैठा है जिस भाव का स्वामी है\r\nउसको उसका फल देने का उसकी ताकत बढ़ जाती\r\nहै चाहे वह अच्छा फल हो चाहे वो बुरा फल\r\nहो और अल्टीमेटली जो नवांश की राश है वो\r\nनवांश शाश्वत वो शाश्वत है वाह का फल मिल\r\nजाता\r\nहै ठीक है तो ये\r\nहमारा आज का टॉपिक था सरल ज्योतिष वन\r\nहमारा आज खत्म हुआ और इसके बाद हम फिर\r\nमिलेंगे और नए कुछ टॉपिक्स लेकर के तब तक\r\nके लिए बहुत-बहुत धन्यवाद\r\nनमस्कार\r\nAll\r\nFrom the series"},{"topic":"Rules of prediction when Sun is debilitated","text":"नमस्कार मित्रों आज से हम एक नई सीरीज शुरू कर रहे\r\nहैं और उसका विषय आप लोगों की बहुत ज्यादा डिमांड के\r\nऊपर मैं कर रहा हूं और ये एक ऐसा सब्जेक्ट\r\nहै जो बहुत बहुत सबको ज्योतिष प्रेमियों\r\nको परेशान करता है परंतु य डरने वाली बात नहीं हम आज जो सीरीज शुरू कर रहे\r\nहैं वह नीच ग्रह डेलन में नीच राशि में\r\nअगर कोई ग्रह विराजमान है तो उसका फलित कैसे\r\nकरें तो इस सीरीज में हम केवल सात ग्रह लेंगे सूर्य से श करके शनि तक और हर लगन\r\nके लिए उसका हम विश्लेषण\r\nकरेंगे सबसे पहले तो नी कहां कहा ग्रह नीच राशि में\r\nहोते हैं वह तो एक जो भी ज्योतिष प्रेमी है सबको पता है सूर्य तुला में होता है\r\nचंद्रमा वृश्चिक में होता है मंगल कर्क में नीच राशि में होते हैं\r\nबुध मीन राशि में बु होते हैं\r\nबृहस्पति मकर राशि में नीच राशि उनकी मानी जाती है शुक्र\r\nकी कन्या राशि और शनि की मेष राशि और वह\r\nडिग्रियां भी आपने जानी ई तो आज हम पहले तो रूल रिपीट कर देते हैं\r\nकि नी भंग कैसे होता है अब इसको सब बोलते हैं नीच भंग राज\r\nयोग तो अब इसके तीन पार्ट है भाई यह हम बाकी के लिए रिपीट नहीं\r\nकरेंगे तो अब यह जो है नीच भंग राज\r\nयोग तो पहला तो है नीच के शास्त्रों के अनुसार ग्रह को\r\nअपनी नीच राशि में होना चाहिए चाहे जैसे सूर्य की 10 डिग्री डीप\r\nडेबिट परम नीच बोला गया है परंतु हम पूरी राशि को नीच मान लेते हैं और उसी से हम\r\nविश्लेषण करते हैं यही हमने सोचा हुआ है बहुत से कहते नहीं है पूरी तरह से नी\r\nपरंतु हम उसको मान लेते हैं और उसके नीच\r\nभंग के हम नियम देख पहला तो आप यह देखो जब भी कोई\r\nग्रह अच्छा सॉरी मैं आ रहा था नीच भंग राजी तो पहला पार्ट है नीच उसके बाद नीच\r\nभंग मतलब उसका कैंसिलेशन उसका निवारण हो जाना चाहिए कि भाई कब वह नीच माना नहीं\r\nजाएगा और तीसरा भाग है राज\r\nयोग केवल नीच भंग होने से राजयोग नहीं बन\r\nजाता है राजयोग के अपने नियम है तो हम इसको नीच\r\nभंग बोलेंगे परंतु वह नीच भंग हो गया है इसलिए उसको राजयोग बोलते हैं क्या वो\r\nप्लेनेट नीच राशि में नहीं रहा परंतु यदि वोह राजयोग में आएगा तभी\r\nउसको हम पूर्णत नीच भंग राजयोग बोल सकते हैं\r\nपहला तो यह पॉइंट है दूसरा मैं हमेशा कहता हूं कि कोई भी नीच ग्रह अगर आपकी कुंडली\r\nमें है बिल्कुल घबराना नहीं है वह भगवान की ब्लेसिंग\r\nहै जो हमें खुद अपने परिश्रम से करके जो हासिल होता है हम जो लेते हैं\r\nउसमें अत्यंत खुशी होती है तो यह जो नीच राशि का ग्रह होता है यह\r\nबेसिकली अहंकार नहीं देता स्क्रैच से जमीन से जुड़ा होता है वहां से शुरू कराता\r\nहै अब हम आते हैं नीच भंग राजयोग नीच भंग कैसे होता है राजयोग बा\r\nबना अब जब भी कोई ग्रह नीच राशि में होगा तो उस राशि को के स्वामी को हम चेश\r\nबोलेंगे उसकी नीच राशि का स्वामी इसके और भी व्या देते हैं लोग पर मैं इस व्याख्या\r\nको इस्तेमाल कर रहा हूं इसी इसम और उसकी जो उच्च राशि का स्वामी है जहां वो उच्च\r\nका होता है उसको मैं उष बोल एक रूल में सारा आ\r\nजाएगा नीच ग्रह का संबंध अपने\r\nउष या चेश से हो रहा हो तो नीच भंग हो जाता\r\nहै या उसका चेश या उच्चे लगन\r\nसे या चंद्रमा से केंद्र में हो तो भी वह नीच भंग हो\r\nजाता है अब यहां देखो मंगल के नीचे चंद्रमा\r\nहै और बृहस्पति के उच्चे चंद्रमा\r\nहै तो य इन दोनों ग्रह के लिए मंगल और बृहस्पति के लिए उनका उच्चे या निचे चंद्रमा ही है तो\r\nवह चंद्रमा से केंद्र मेंही होगा ना या उसको ना माने तो इससे क्या होगा कि क्या हम यह कह\r\nसकते हैं कि मंगल और बृहस्पति कभी नीच राशि नीच का फल नहीं देते उनका हमेशा नीचे\r\nकैंसिलेशन हो जाता है वैसे तो मैंने किया है 94\r\nपर अग यदि नीच के ग्रह होते हैं 94 पर में\r\nउनका नीच भंग हो जाता है अब एक और नीच भंग का हम नियम दे रहे\r\nहैं जो आप साधारण का नहीं पढ़ते हैं वह नियम क्या है ध्यान से सुन\r\nलीजिए सूर्य शुक्र की राशि में नीज कहलाता\r\nहै अब हम सूर्य को लेले उसके नीचे को लेे\r\nऔर जिसमें वो नीचे शुक्र जिस राशि में उच्च का होता\r\nहै तो वोह उसका उच्चे हो गया उस उच्चे का संबंध यदि इस नीच राशि के ग्रह से आ जाए उ\r\nदृष्ट कर दे इसके साथ बैठा हो तो भी नीच भंग हो जाता\r\nहै अब इसकी यह सूत्र आप समझे और लगाए मतलब सूर्य के साथ बृहस्पति का संबंध\r\nआ जाए नीच के सूर्य के साथ उसका नीच भंग हो जाएगा अब चंद्रमा का आप सुन लो एक और\r\nबता देता हूं चंद्रमा के नीचे होते\r\nमंगल मंगल के उच्चे होते हैं शनि तो नीच के चंद्रमा पर यदि शनि का\r\nसंबंध आ जाए तो चंद्रमा का नीच भंग हो जाता तो यह टेबल आप अपनी बना सकते हैं और\r\nनहीं तो यह मैं ले रहा हूं सरल पार्ट टू से उसमें यह टेबल दी\r\nगई अब हमारा मेथड क्या होगा करने का कुछ पहले हम नियम देख\r\nलेते एक तो सबसे बड़ा नियम आ जाएगा के नीच ग्रह\r\nनीच राशि का ग्रह यदि लगन को देख रहा है लगन को दृष्ट\r\nकर रहा है तो बड़ा अच्छा विपरीत योग बन जाता है और यह राज योग का फल देता\r\nहै यह जरूरी है ऐसा अगर हो जाए दो नीच राशि में स्थित\r\nग्रह एक दूसरे को दृष्ट कर रहे\r\nतो भी वह राजयोग कहलाता है तीसरा एक और नियम मैं इसमें यहां बता\r\nदेता हूं यदि नीच राशि के ग्रह का\r\nस्वामी मान लीजिए बृहस्पति मकर में नीच के\r\nहैं और शनि उसके साथ संबंध बना रहे हैं श उसको दृष्ट कर रहे\r\nहैं तो भी वह राजयोग होता है नीच भन तो है\r\nही राजयोग होता है फिर पराशर जी ने नीच राशि के ग्रहों के\r\nलिए योग दिए हैं जो मैं पहले एक वीडियो में कवर कर चुका हूं कि तीन छ आठ में नीच\r\nके ग्रह विराजमान हो तो वो राज योग देते\r\nतीन छ आठ 12 तीन छ 12 आठ है उनके स्वामी\r\nनीच राशि में हो तो राज योग है तो यह तीन चार नियम है जिनको आप हमेशा जब भी नीच\r\nग्रह का हम बात करेंगे यह तीन चार नियम\r\nआपको हमेशा याद रख मोटा मोटी फिर मैं बता देता हूं दो नीच ग्रह\r\nनीच ग्रह का डिस्पोजिटर केंद्र में हो और जो नीच का\r\nग्रह है वह भी केंद्र में हो बहुत ही बढ़िया राजयोग हो जाता है ठीक है मैंने यह देखा है लगन से चाहे\r\nकेंद्र में ना हो शास्त्रों का मतलब है लगन से केंद्र में वह तो अति उत्तम\r\nहै उसके बाद है दोनों आपस में दृष्ट कर रहे और अगर दोनों आपस केंद्र में भी है तो\r\nहम यह कहेंगे हां कुछ तो है लगन से है तो पूर्ण\r\nराज ठीक है जी तो इस तरह से हमारी य वार्ता अब आगे चलेगी बेसिक हमने आपसे बात\r\nकर ली है अब मैं एक एकक चार्ट लेकर के और वह आपके साथ मैं स्क्रीन शेयर करता तो\r\nपहले हम मेष लगन में जाएंगे और सूर्य का हम देख रहे हैं आज सिर्फ सूर्य पर चर्चा\r\nहोगी अगले वीडियो पर चंद्रमा में होगी इस तरह से सात ग्रह की चर्चा होगी तो मैं एक\r\nएक राशि लूंगा और आपके साथ उसका विश्लेषण करते जाएंगे ठीक है जी तो पहले य हमने मेष\r\nराशि का लिया अब यहां आप अब खुद देखिए एक एक को\r\nसमझिए जरा सा ज्यादा विश्लेषण पर मत जाइए इसके जीवन में क्या घटना हुई ये हुई वो\r\nहुई आप विचार देखो कि उसको कैसे\r\nदेखना देखि ज्यादातर नीच भंग मिलेगा य हमें देखना क्या है मेष राशि में\r\nसूर्य अगर मेष लगन के लिए सूर्य\r\nपंचम और वह केंद्र में सप्तम भाव में नीच में हो की राशि में हो\r\nगए तो सबसे पहले तो सरसरी निगाह से चेक कर लो हां भाई नीच भंग हो रहा है ी हो रहा\r\nहै मंगल उसको दृष्ट कर जो उसकी उच्च राशि के स् सबसे पहले तो य देख अब क्योंकि यह\r\nकेंद्र में है तो दूसरा देखो क्या कोई राजयोग बन रहा\r\nहै तभी तो राजयोग बने ना के ये त्रिकोण का स्वामी\r\nहै क्या किसी केंद्र के स्वामी से आ रहा\r\nहै चंद्रमा से सम सप्त यह संबंध आ रहा है तो यह राजयोग बन\r\nगया और इसने कोई ज्यादा बर्बादी नहीं की सूर्य ने\r\nइनकी इनको ज्यादा यह मेयर थे बड़ी अच्छी\r\nपोजीशन पर रहे और सूर्य की दशा में बहुत अच्छा इनको मिला\r\nशुक्र में मेयर बन गए और सूर्य में भी रहे और यह अपना लंबा\r\nचौड़ा जीवन इन्होने अच्छी तरह से किया तो आप यह देखिए इसको मेष लग्न के\r\nलिए सूर्य को हम पंचमेश मान कर के चलते अब\r\nपंचमेश नीच राशि ठीक है क्या यह बुद्धि खराब करेगा\r\nनहीं पंचमेश जब तक इसके ऊपर कोई पाप संबंध नहीं\r\nआता है तब तक वह बुद्धि को नहीं करेगा अब सूर्य जो है सिंगल राशि का स्वामी तो यहां\r\nपर हम इसको पंचमेश मान कर के चल रहे ठीक है त्रिकोण का स्वामी मानकर\r\nचल अब दूसरा चार्ट लेते हैं\r\nयह दूसरा चार्ट अब मेष लगन के लिए अब मेष सॉरी वृषभ लगन के लिए अब यहां वृषभ सोच कर\r\nके चलो आप पहले पहले ऐसे करना है वृषभ लगन के लिए\r\nसूर्य चतुर्थेश तो सबसे पहले तो ये समझ लो अच्छा पिछले\r\nचार्ट में भी पंचमेश आ गया आप अपनी बुद्धि पंचम भाव को शो ऑफ नहीं\r\nकरोगे बच्चे शो बच्चों को शो ऑफ नहीं करोगे आप यहां पर क्या है चतुर्थेश\r\nनीच राशि में तो यह क्या है चतुर्थेश अपने सुख को उजागर नहीं करता\r\nज्यादातर अपनी बैड नहीं मारता वहां से बॉटम से शुरू होता है सुख कहीं से भी छोटी\r\nपोजीशन से भी वो सुख ना शुरू\r\nकरे और वृषभ लगन के लिए यह जाकर के सूर्य\r\nछठे भाव में नीच राशि में हो जाते यह पराशर का\r\nराजयोग अब यह राजयोग है बहुत प्रॉपर्टी भी दिलाएगा सुख दिलाएगा धन दिलाएगा सब\r\nदिखाएगा य भूल जाओ कि ये इतने सारे ग्रह के साथ बैठा हुआ था इसलिए नहीं\r\nयहां पर अगर नीच भंग हो गया है वो हो गया बृहस्पति महाराज साथ\r\nमें शुक्र साथ में बैठे हुए हैं और यह पराशर का राजयोग बन गया तो यहां भी डरने\r\nकी जरूरत नहीं है वृषभ में अगर आपका यह नीच राशि में हो जाते अब इस कुंडली की बात\r\nले रहे हैं तो कह शनि देख योग कारक शनि की भी दृष्टि आ रही है\r\nइतने सारे ग्रह उनके साथ है बृहस्पति भी है सूर्य भी है बुध\r\nभी तो धन योग भी बन रहा है तो ये जो थे यह\r\nसर की उपाधि इहे मिली थी और रग्स टू रिचेस मतलब जमीन से बिल्कुल\r\nहटे हाल से लेकर के और यह अरबपति बने अरबपति बोल रहा हूं मैं ख करोड़पति नहीं\r\nबोल रहा हूं इवन टेलीग्राफ जो अखबार था\r\nउसके भी मालिक थे डेली टेलीग्राफ गुप होटल्स थे कई सर की\r\nउपाधि ब्रिटेन में इनको मिली लंदन का जन्म ठीक है जी तो यहां भी हमें कोई\r\nघबराने की बात नहीं है इसके बाद हम आएंगे मिथुन लगन पर अब\r\nउसमें यही देखते चलना है हमें कैसे देखना है अब मिथुन का चार्ट देखते हैं\r\nमिथुन में सूर्य\r\nतृत्य थर्ड के स्वामी करेज के स्वामी है और\r\nवह नीच राशि में जाएंगे पंचम\r\nभाव अब यहां पर थर्ड और\r\nपंचम इनका संबंध अगर यह एक्स चेंज होता तो भी नीच\r\nभंग होता शुक्र के साथ परंतु\r\nव्यक्ति खल योग में आ क्योंकि थर्ड हाउस हमारा थर्ड खल हाउस\r\nहै अपनी मेहनत का हाउस है जूते तोड़वा देता\r\nहै ठीक है यह चार्ट जो लिया है यह हिलरी क्लिंटन का\r\nहै अब य य नी में हो गया इसका मतलब यह नहीं कि भाई बहन नहीं\r\nहोंगे भाई बहन होंगे थर्ड हाउस करेजियस भी होगा सोच के करेज\r\nकरेगा तो इसको हमें ऐसे देखना कि तते अब\r\nइसके बाकी और संबंध देख तेश के साथ हा तृत्य भाव में कोई ग्रह\r\nनहीं अगर वो हो गया तो वो गड़बड़ कर जाएगा तो\r\nइनका जो सूर्य की दशा थी वो इनकी अच्छी\r\nरही भाई भी है सूर्य की दशा इनकी 2006\r\nमें उसने इनको प्रेसिडेंट नहीं बनने बस इतनी\r\nगड़बड़ मेहनत में कमी या कहो भाग्य में कमी रह\r\nगई कारण क्या था अब देखिए इंडिविजुअली हमको करना\r\nहै मैंने शुरू में बोला लगन का इफेक्ट देखना जरूरी होता है अब यहां पर जो लगन\r\nहै वह मिथुन ल और इसके लिए सबसे भयंकर जो\r\nप्लेनेट है वह मंगल है अब मजे की बात मंगल भी डेबिटेड है और\r\nसूर्य और मंगल एक दूसरे से केंद्र में है तो उतना राजयोग तो दे दिया एक दूसरे से\r\nकेंद्र में है लगन से केंद्र में नहीं यह गड़बड़\r\nहो अगर यह लगन से केंद्र में होते जो हाइपोथेटिकल है सिर्फ\r\nतो यह अच्छा राजयोग बनता यह हमें यहां पर दो ग्रह\r\nआपसी केंद्र में मिल गए हैं उतना राजयोग रहा परंतु लगन से केंद्र में नहीं है और\r\nदूसरा मंगल वैसे तो विपरीत राजयोग दे रहा है कि सिक्सथ लॉर्ड छटे का\r\nस्वामी नीच में\r\nऔर उसका भी नीच भंग हो रहा है शनि के साथ है ठीक है जी तो मेरा फिर से मैं य कहता\r\nहूं इंडिविजुअल हर चार्ट का यह टोटलिटी में\r\nदेखा जाता है ना कि एक ग्रह को पकड़ कर के हम उसको पूरी कहानी उसकी कह दे किस किस और\r\nसंबंध में आ ठीक है अब हम आते हैं\r\nकर्क लगन अब कर्क लगन में\r\nदेखो सूर्य द्वितीय श सेकंड लड और\r\nन्यूट्रल यहां पर यह चतुर्थ भाव में अपनी नीच राशि\r\nमें तो दत चतुर्थ भाव में जाकर के नीच के\r\nहु अब कहने को सूर्य राजा है और द्वितीय भाव\r\nपरिवार है जिसमें आप पैदा हुए वह नीच के\r\nवोह नीच राशि में चले गए परिवार का जो स्वामी है पर यह कौन\r\nहै किंग चार्ल्स की कुंडली\r\nहै क्या इनको राज परिवार में जन्म नहीं मिला\r\nअब यहां आप देखिए कि सूर्य के\r\nसाथ दो विपरीत भाव के स्वामी बुद्ध विराजमान\r\nहै क्या सूर्य का नीच भंग हो रहा है\r\nसूर्य के उच्चे मंगल है चेश शुक्र है आपस में कोई\r\nसंबंध नहीं आ रहा है ठीक है परंतु अब यह देखो इनके जो चेश है वह\r\nस्वयं नीच राशि में वि\r\nस्वयं नीच राशि में विराजमान है और इनके\r\nजो नहीं पता चला था भाई कैंसिलेशन कैसे हो रहा है इनके\r\nजो ये जहां पर उच्च के होते हैं वहां शनि\r\nनीच के होते मंगल से अगर संबंध आता तो हम बोलते\r\nडायरेक्ट यह कैंसिलेशन हो रहा है परंतु यहां डायरेक्ट कैंसिलेशन हमको\r\nनहीं दिख रहा है सिर्फ शनि का जो प्रभाव इनके ऊपर आ रहा है उसको हम कह सकते हैं कि\r\nयह कुछ नीच भंग का काम कर रहा\r\nहै क्योंकि शनि तुला में उच्च के होते हैं\r\nठीक है तो इससे इस पर फर्क पड़ गया है नीच\r\nभंग तो पूरी तरह हम नहीं मान रहे हैं परंतु इस पर फर्क उनका पड़ गया है शनि\r\nका क्योंकि वह तुला में उच्च के होते हैं वह अपनी उच्च राशि को देख रहे हैं नीच भंग\r\nनहीं है मैं फिर रिपीट कर रहा हूं और यह एक राजा की कुंडली\r\nहै अब यहां हम कैसे देखेंगे सेकंड\r\nलॉर्ड वह चतुर्थ में चला इस तरह से हम सिर्फ इसको देखेंगे और\r\nवो नीच का हो मतलब हम यह कह कि परिवार का\r\nया स्पीच का स्पीच में नम्रता है परिवार में नम्रता\r\nहै उसका रब नहीं झाड़ रहा हूं यह सिर्फ नीच का होगा स्क्रैच से मैं\r\nशुरू हो रहा हूं कितने दिन रगड़ा खाया राजा नहीं बने पर शांति से बैठे रहे ठीक\r\nहै जी अब आते हैं नेक्स्ट उस\r\nपरे ये लियो लगन अब यहां पर सिचुएशन थोड़ी सी गड़बड़ आ जाती है क्योंकि शनि सूर्य अब\r\nये लग्नेश है अगर यहां पर यह लग्नेश होकर\r\nके लगन को नहीं देख सकते तो वह रूल तो\r\nलगेगा अब लग्नेश नीच\r\nके तो मेरे अंदर कोई ज्यादा घमंड नहीं है लग्नेश नीच के हो\r\nजाते हैं परंतु अब यहां भी शनि के साथ है\r\nऔर नीच भंग जो मैंने योग बताया था बृहस्पति से दृष्ट\r\nहै यह कारण है ज्यादा नीच भंग का अगर आप नॉर्मल नीच भंग का करें तो वह नीच भंग\r\nयहां नहीं दिख रहा है पर बृहस्पति के एस्पेक्ट में नीच भंग किया है और दूसरा जो\r\nशनि उच्च के वहां पर विराजमान है उन्होंने भी हेल्प की\r\nहै अब यह जो कुंडली है यह एक प्लेयर की\r\nहै बास्केटबॉल प्लेयर की कुंडली है तो अब हम क्या कहेंगे स्टेमिना कम है\r\nक्या नहीं शो ऑफ नहीं\r\nहै बस लियो लगन की कुंडली में अगर शनि\r\nनीचे का ये सूर्य नीच के हो जाते हैं तो अपनी शो ऑफ नहीं है और अपने ऊपर पूरी तरह\r\nसे कॉन्फिडेंस नहीं आता है हमेशा सोचते कुछ ना कुछ यार गड़बड़ ना\r\nहो जाए ठीक है तो यहां पर जिनका चार्ट है यह\r\nबास्केटबॉल खेली एथलीट रहे ऑनर्स मिली\r\nकाफी उसके बाद मेडिकल एजेंट बन गए वो काम\r\nकर लिया प्रोफेशनल कैरियर मतलब खुद का कोई बढ़ोतरी नहीं होती\r\nहै इसके बाद हम आएंगे विर्गो अब वर्गो को हम देखते\r\nहैं यहां पर यह द्वादश है और यह जाकर के\r\nसेकंड हाउस में नीच राशि में थ लड एक्सपेंसेस का है और सेकंड को हम\r\nधन का वि भाव बोलते हैं यह धन का भाव भी हो गया अब कई\r\nपुस्तकों में यह लिखा हुआ है कि अगर थ लर्ड सेकंड हाउस में चला जाए तो वह आश्रम\r\nबनवा दान पुण्य करता है उस तरह के खर्चे करता\r\nहै अब यहां आप देखो कैंसिलेशन ना मंगल से\r\nकोई संबंध आ रहा है ना शुक्र से संबंध आ रहा है नीचे और उच्चे से बृहस्पति देख रहे\r\nहैं जो रूल मैंने स्पेशल रूल बताया है उसकी वजह से यह नीच भंग हो रहा\r\nहै यह किनकी कुंडली फ्रांस के राष्ट्रपति\r\nरहे फ्रांस के राष्ट्रपति रहे मेरे ख्याल\r\nमें दो दो दफे\r\nरहे वैसे तो सूर्य को भैया राष्ट्रपति बनाना नहीं चाहिए जब नीच का सूर्य\r\nहै यहां पर इनको एक और जो सहारा मिल रहा है वो मिल रहा है\r\nचंद्रमा चंद्रमा और सूर्य का संबंध एक कुछ मायनों में कहीं पर भी हो हम और किसी भी\r\nकुंडली में इसको हम अमावस्या बोलते\r\nहैं और शास्त्रों में लिखा है नो मून नो मैन पर\r\nनहीं मैं इसको अच्छा खासा राजयोग मानता हूं किस तरह का राजयोग\r\nकि उसको अपनी मेहनत करनी पड़ती है पोजीशन भी मिलेगी परंतु उसको मेहनत\r\nबहुत करनी पड़ती है अब 12थ लर्ड यहां पर आएगा इसमें एक\r\nनेगेटिव पॉइंट हो जाता है थ कन्फाइनमेंट का\r\nहाउस जेल का हाउस है बीमारी का हाउस है आ मतलब आप अलग थलग हो जाएंगे समाज से कट\r\nजाए और यदि वह सेकंड में आ जाए थ लड तो परिवार से दूर हो जाएंगे परिवार से कट\r\nजाए तो इसमें क्या होता है अगर कोई बंधन योग वगैरह होता है तो अरेस्ट हो जाता है\r\nबंदा सजा हो जाती है या बीमारी हो जाती\r\nहै तो यह इनको मिलता है यह इसका नेगेटिव पॉइंट है हालांकि य\r\nराष्ट्रपति रहे फ्रांस के परंतु वार में अरेस्ट भी हुए सेकंड वर्ल्ड वार में\r\nअरेस्ट भी हुए इसके बाद हम आते\r\nहैं तुला लग तुला लगन में सूर्य\r\nमहाराज लगन को देखेंगे मतलब सॉरी देखेंगे क्या बैठेंगे लगन में\r\nही विराजमान होंगे क्योंकि वहीं तो वह नीच नीच में की राशि में है और यह हमने बताया\r\nथा कि यदि नीच ग्रह लगन को दृष्ट\r\nकरें तो वह एक राजयोग होता\r\nहै यह भी एक बहुत बड़े एक्टर थे राजयोग बन गया और कित ग्रह साथ में लग्नेश भी साथ\r\nमें बैठे हुए हैं नवमेश भी साथ में बैठे हुए ठीक है तो यहां भी घबराने की बात नहीं\r\nहै अगर तुला लगन में सूर्य अकेला\r\nही लगन में विराजमान है वह अपने आप में लगन को बहुत ऊंचा\r\nउठ दूसरा पॉइंट अब तुला लगन में क्या आता है सूर्य ए अधिपति है एकही राशि के स्वामी\r\nहै और यहां पर वह राशि इनकी गवे भाव में पड़ती\r\nहै तो दूसरा बेनिफिट क्या हो गया लेथ हाउस जो स्ट्रांगेस्ट सबसे बली त्रिश दय का\r\nस्वामी है वह नीच का हो तो वह बुरे फल नहीं दे\r\nसकता त्रि शाय का स्वामी यदि उच्च राशि में आ जाए तब वो ड्रामा कर सकता है तब वोह\r\nपरेशान करेगा अच्छी तरह परेशान कर ठीक है तो इसलिए तुला लगन के लिए अगर\r\nयह आपके सूर्य नीच के राशि में लगन में बैठ जाते हैं तो यह दो हमारे\r\nदो काम करते हैं डाय का और लगन को नीच ग्रह जो नीच का ग्रह है वो लगन को\r\nदेख रहा है या लगने लग्नेश के भी साथ है तो वह योग बना देता\r\nहै ठीक है जी अब हम आए आठ\r\nप यहां पर थोड़ी सी गड़बड़ हो जाती\r\nहै क्योंकि यहां अब जो सूर्य है\r\nवह दशमेश और वह जाकर के थ हाउस में बैठ\r\nजाते तो दशमेश का 12थ में जाना वह फॉरेन कनेक्शन दिखा देता विदेश से कनेक्शन दिखा\r\nदेता है और अपने प्रोफेशन में उतार चढ़ाव\r\nज्यादा दे देता है उतार चढ़ाव बहुत देता\r\nहै और यह 12वां भाव विदेश का तो हमने बोल ही दिया मतलब\r\nप्रोफेशन के खर्चे प्रोफेशन से\r\nथर्ड प्रोफेशन से खुद थर्ड में आकर के वह स्वामी नीच के हो गए तो प्रोफेशन में\r\nएफर्ट ज्यादा कराएंगे ऐसा प्रोफेशन होगा जो भाष ण देने\r\nवाला बोलने का काम होगा क्योंकि तीसरा भाव है\r\nना बोलने का सुनने का तीसरा सुनने का भी है\r\nहियरिंग अच्छा अब यहां देखो क्या हो रहा है भाई यह चेक करके\r\nदेखना के क्या नीच भंग हो रहा\r\nहै ना मंगल देख रहे है ना बृहस्पति दे शुक्र देख रहे हैं ना बृहस्पति देख रहे\r\nहैं तो यह एक ऐसा केस मिला है यहां पर मुझे तो इसका नीच भंग दिख नहीं रहा\r\nहै ठीक है जी तो ये इनकी मेहनत ज्यादा रही यह सिंगर\r\nथी और काफी बीमारी भी इनको रही मतलब\r\nरुकावट आती है प्रोफेशन मेन मेन पॉइंट यह नोट करने\r\nका इसके बाद हम आएंगे धनु लगन धनु लगन में अब आप\r\nदेखिए नाइंथ लड नवमेश जाकर के नीच के हो\r\nगए शास्त्रों में तो इतना तक लिख दिया है के अगर नवमेश\r\nअपनी नीच राशि में हो और दूसरे भाव\r\nमें पाप ग्रह विराजमान हो तो उसका सब कुछ नष्ट हो जाता है वह\r\nअनलकी टोटल भाग्य बिल्कुल साथ नहीं देता ना धन होता ना कुछ होता मतलब लाइफ जो है\r\nबर्बाद कर देता है अब यहां जो है यह बृहस्पति बैठ\r\nपाप ग्रह नहीं विराजमान है तो इसने यह तो बचाव\r\nकरया और दूसरे सूर्य का नीच भंग भी हो रहा\r\nहै यह बहुत बड़ी बिजनेसमैन थी तो अब हमें यहां देखना कैसे है ब\r\nअलार्मिंग है कि नाइंथ लॉर्ड नीच\r\nराशि एकदम हमको सेकंड हाउस नाइंथ हाउस\r\nभाग्य का है सेकंड हमारे धन का है हमें सीधा सेकंड हाउस देखना है और\r\nनाइंथ हाउस को भी देखना है कि नाइंथ हाउस पर कोई शुभ दृष्टि आ जाए तो बहुत अच्छा है\r\nभाई बच जाएंगे यहां पर शनि की दृष्टि\r\nआ और शनि को हम इसमें कोई\r\nअच्छा ग्रह नहीं मानेंगे तो यह एवरेज लाइफ\r\nरहेगी परंतु निर्धन नहीं है भाग्यहीन नहीं\r\nहै दूसरा क्या है के मंगल महाराज स्वराशि के होकर\r\nके इनको दृष्ट कर रहे सूर्य को बड़ा स्ट्रांग नीच भंग हो रहा\r\nहै अब हम नाइन आ गया अब 10 प आते अब 10 का\r\nभी देखिए सबसे पहले हमको यही देखना भाई है\r\nकौन अब यहां पर जो सूर्य है वो अष्टमेश है\r\nअब अष्टमेश का नीच होना वह फिर से राजयोग हो\r\nजाएगा तो यहां मुझे कोई डर ही नहीं है होने दो कहां पर होंगे नी दशम भाव में होंगे तो\r\nसिर्फ क्या देंगे यह प्रोफेशन में सडन\r\nनेस मेरे व्यवसाय में उतार चढ़ाव आते\r\nयह एक बड़ी बात होती है पर यह जो हमने चार्ट लिया\r\nहै यह चार्ट एक रेसलर का है मुक्केबाज का\r\nहै तो अच्छी तरह से प्रसिद्धि बहुत\r\nमिली प्रसिद्धि इनको मिल गई\r\nएथ एथ लॉर्ड डेबिटेड विद एसॉल्टेड\r\nसैटन मैंने पहले भी और दो तीन चार्ट में आपको आपने देखा है कि सूर्य के साथ जब शनि\r\nआता है क्योंकि सूर्य जहां डेविट हो रहे हैं\r\nवहां शनि उच्च के तो वो एक बहुत इस तक हद तक इसको चेंज कर देता\r\nहै उसके डेबिट को कैंसिल कर देता है ऑलमोस्ट कैंसिल पूरा कैंसिल नहीं\r\nकरेंगे अब आए हम अब यहां भी आप देखिए\r\nदेखिए मेन बिंदु मेरा क्या है के कुंडली वाइज जो ग्रह हमारा नीच राशि में जा रहा\r\nहै वो कौन है सीधी बात है अब यहां पर इस ल\r\nएक्वेरियस लगन के लिए शनि पंच सूर्य पंचमेश\r\nहो अब यहां गड़बड़ हो जाएगी सप्तमेश\r\nहोंगे सप्तम सप्तमेश नीच\r\nराशि तो जो आपके पार्टनर्स है मैं य सिर्फ वाइफ या स्पाउस की बात नहीं कर रहा हूं जो\r\nपार्टनर्स है उनमें घमंड नहीं\r\nहोगा यहां भी आप देखोगे शनि का संबंध जो स्वयं अब नीच राशि में\r\nहै यह फिर कैंसिलेशन हो गया यह योग बन गया दोनों एक दूसरे से\r\nकेंद्र में है तो जब भी आपको नीच का ग्रह मिलेगा कहीं ना कहीं रेमेडी मिल जाएगी\r\nउसकी घबराने की बात नहीं है तो आपका स्पाउस हो गया पार्टनर हो गए\r\nवह कहां चले गए कहां जाक नीच के होंगे नाइंथ\r\nहाउस और घमंड नहीं तो आपके साथ जो पार्टनर्स है जिनके साथ आप काम करते हो वह\r\nआपके भाग्य को सहारा देंगे कितनी अच्छी बात\r\nहै कुंभ लगन के लिए आपको बहुत सहारा\r\nमिलेगा किनसे सारे जो आपके कांटेक्ट में लोग आएंगे पार्टनर्स जो होंगे उनसे बहुत अच्छा\r\nसहारा मिलेगा इस चार्ट में तो और बात है भाई शुक्र खुद बैठे हुए हैं सूर्य के साथ\r\nऔर बहुत 50 पर केस में तो शुक्र आ ही जाएंगे सूर्य के साथ क्योंकि ज्यादा दूर\r\nजा नहीं सकते तो वैसे ही नीच भंग करते रहे अब लास्ट चार्ट\r\nलेते अब यह मेन लगन का का है तो यहां पर सूर्य जो होंगे वो\r\nस अब ये छठ के स्वामी अष्टम में\r\nनीच राशि में आ गए तो यह सुपर स्ट्रांग विपरीत राजयोग बन\r\nगया और इनके लिए शनि और साथ में विराजमान हो\r\nगई तो भी अच्छा खासा योग बन गया य तो मीन लगन के\r\nलिए सूर्य आठवे भाव में नीच राशि में\r\nजाएंगे कोई घबराना नहीं है बहुत अच्छा फल यह देते\r\nहैं और क्योंकि यह सुपर स्ट्रांग राजयोग\r\nबनता है ठीक\r\nहै इनके और भी और ग्रह भी नीच के हैं शुक्र नीच का है परंतु शनि उच्च के सूर्य\r\nके साथ तो हमने यह देखा\r\nहमने देखा ज्यादातर इन फेमस कुंडलियों\r\nमें शनि का संबंध भी आ रहा था कुछ कुंडलियों में यह विपरीत राजयोग बना जाते\r\nहैं जैसे लास्ट मीन मेंही देखा और में भी था एथ लड जाकर के दशम में नीच का हो है\r\nसडन दे देगा तो इसलिए बाकी भी हम देखेंगे आप भी कोशिश करिए कोई जो आपके सूर्य नीच\r\nराशि में होगा तो किसी कोई ना कोई लगन तो होगी और उसके आप अच्छे बिंदु\r\nदेखिए और फिर उसके बाद सूर्य का संबंध देखिए वह आपको सारी कहानी बता कोई डरने की\r\nबात नहीं है और यह अच्छा एक\r\nनीच का होना अच्छी बात है कोई ऐसी बात नहीं क्योंकि सूर्य कहां नीच के होते हैं\r\nशुक्र की राशि शुक्र सौम्य राशि है और सूर्य आत्मा\r\nहै दिवाली जब आती है तो सूर्य नीच राशि में ही होते\r\nहैं और इतना बड़ा पर्व मनाया जाता है\r\nउस दिन चंद्रमा भी इनके साथ होते\r\nहैं तो जब हम इतना बड़ा पर्व सूर्य की नीच में होने पर मना सकते\r\nहैं तो क्या जिंदगी में यदि सूर्य नीच\r\nराशि में हो तो वो हम प नहीं मानते क्या तो हर राशि के लिए सूर्य नीच होना\r\nकोई गलत बात नहीं है यह अच्छा फल भी देते\r\nहैं और ज्यादातर फल अच्छा ही देते हैं तो आज के लिए इतना ही अगले वीडियो में हम फिर\r\nचंद्रमा पर बात करेंगे और इस कंटिन्यू करेंगे या आप बताइए भाई करें या ना करें\r\nअगर सबको आता ही है तो उसमें क्या फायदा है मैं तो सिर्फ यह किसलिए कर रहा हूं कि\r\nएक एक राशि को आप हर नीच ग्रह के लिए बैठ\r\nके मनन करें हमारे जो ज्योतिष है मनन का विषय है बहुत बड़ा तो आप मनन करिए थोड़ा सा आगे फिर\r\nमिलेंगे नमस्कार"},{"topic":"एक से अधिक विवाह देखने का गुप्त रहस्य","text":"नमस्कार\r\nमित्रों आज हम आपके बहुत ज्यादा डिमांड के\r\nऊपर एक वीडियो लेकर के आए\r\nहैं और इस वीडियो\r\nमें एक बहुत ही गुप्त\r\nरहस्य विवाह के बारे में मैं आपको बता रहा\r\nहूं इसको ध्यान से लगाना भाई मैं आगे\r\nनवांश देखने का तरीका फिर कभी\r\nबताऊंगा मेरे को डिमांड आ रही थी कि दूसरा\r\nविवाह तीसरा विवाह कैसे\r\nदेखा तो मैंने\r\nसोचा के आठ विवाह तक भी दिखावा देता\r\nहूं आठ विवाह तक कैसे कैसे देखते हैं\r\nक्योंकि मेरे\r\nको एलिजाबेथ टेलर की कुंडली मिली\r\nजिन्होंने आठ विवाह किए\r\nथे एक विवाह तो उसी व्यक्ति से किया था\r\nदोबारा तो सात हस्बैंड\r\nथे तो आज जो हम तरीका बता रहे\r\nहैं पहले तो थोड़ा सा हम यह ज्ञान ले ले\r\nकि भाई बहु विवाह या बहुत सारे विवाह एक\r\nसे ज्यादा\r\nविवाह कैसे हो सकते हैं\r\nयहां\r\nपर कोई अफेयर चल रहा\r\nहो विवाह नहीं\r\nहुआ आजक उसको हम विवाह नहीं मानेंगे\r\nपरंतु यहां भी एक समस्या आती\r\nहै कि आजकल वह लिवन रिलेशन भी शुरू हो\r\nगया तो क्या उसको विवाह मानू या ना\r\nमान मेरा विचार है मानना तो\r\nचाहिए परंतु जो कैजुअल दोस्ती हो जाती\r\nहै उसको हम विवाह नहीं मान रहे\r\nहैं तो यहां एक यह डिफरेंस हमें करना\r\nपड़ेगा विवाह की\r\nडेफिनेशन विवाह क्या होता\r\nहै कब होता\r\nहै किसको भी मानते\r\nहैं वह एक बड़ा जटिल प्रश्न है और वो अभी\r\nतक हमें कोई उसकी राह नहीं मिली है कि भाई\r\nजब आपस में दोनों को पसंद कर लिया एक\r\nदूसरे ने शादी की बात पक्की हो\r\nगई क्या उसको विवाह की डेट मानेंगे\r\nउसके बाद सगाई रसम हो गई एक फंक्शन हो गया\r\nअंगूठियां एक्सचेंज हो गई क्या उसको विवाह\r\nमानेंगे\r\nफिर लास्ट\r\nमें जब फेरे होते हैं हिंदू तरीको में\r\nअपने अलग-अलग समाज में अलग-अलग तरीके से\r\nमैरिज को संपन्न किया जाता है क्या उसको\r\nमैरिज की डेट मानेंगे\r\nया उसके आगे जब दोनों पति पत्नी मिलते हैं\r\nक्या उसको विवाह की मानेंगे तो भैया इस पर\r\nतो मैं\r\nकंफ्यूज मैं इसका कोई सटीक प्रश्न नहीं\r\nआंसर नहीं दे सकता परंतु हां जब जिस धर्म\r\nका जैसा रीति रिवाज है समाज के\r\nसामने जब वह दोनों पति पत्नी बनते\r\nहैं उसको ही विवाह लेना ठीक होता है यह\r\nमेरा विचार है आगे और कोई कुछ कह सकता है\r\nतो उसको हम विवाह मान के चले कैजुअल\r\nरिलेशन को हम विवाह\r\nनहीं अब हमारा जो तरीका\r\nहै पहले तो देखे भाई के बहु विवाह हो सकता\r\nहै या नहीं हो\r\nसकता\r\nइसमें कई ओपिनियन है पर जो मुझे ठीक लगा\r\nहै वो है कि नवांश का सप्तमेश\r\nनवांश में उपचय भाव में होना चाहिए हम\r\nनवांश बात कर\r\nरहे उपचय भाव में होना\r\nचाहिए दूसरा बहुत से शास्त्रों\r\nमें शुक्र को\r\nभी लिया है कि शुक्र नवांश में उपचय भाव\r\nमें दो रूल य हो गए परंतु सप्तमेश जरूरी\r\nहै\r\nदूसरा एक नियम बहुत शास्त्रों में मिलता\r\nहै वह बृहस्पति पर आधारित\r\nहै कि बृहस्पति नवांश में किस राशि में\r\nहै नीच का है या उच्च राशि का है तो बहुत\r\nविवाह होंगे मित्र की राशि में है दो\r\nविवाह होंगे इस तरह से परंतु वह बिल्कुल\r\nसटीक नहीं आते हैं इसलिए मैं उसको रिपीट\r\nनहीं कर रहा ह नोट मैंने किए हुए हैं\r\nपरंतु उसको मैं रिपीट नहीं\r\nकर मेरा तरीका तो सीधा-सीधा है कि हर\r\nविवाह को\r\nमें नवांश की लगन बदल\r\nजाएगी जो आपका नवांश बनता\r\nहै वह आपके पहले विवाह की कुंडली\r\nहै अब उसमें आप नवांश को एनालाइज करो जैसे\r\nहम पहले कर चुके हैं नवांश में सुख मिलेगा\r\nदुख मिलेगा इस तरह का हमने देखा है किया\r\nहै वीडियो इसके साथ हम देख सकते हैं कि\r\nभाई अब नवांश बना हुआ है उस नवांश के\r\nहिसाब\r\nसे क्या मेरी मैरिज डाइवोर्स हो\r\nजाएगी टूट\r\nजाएगी या मेरी मृत्यु हो जाएगी पति की\r\nमृत्यु हो जाएगी पत्नी की मृत्यु हो\r\nजाएगी तो विवा विच्छेद हो गया उसके बाद हम\r\nदोबारा शादी करते\r\nहैं बहुत से नहीं भी करते तो पहले तो हम\r\nसप्तमेश को\r\nदेख अब जो गुप्त रहस्य बता रहा\r\nहूं पहला नवांश जो हमारा\r\nबना वह पहले विवाह का\r\nहै दूसरे विवाह\r\nकी नवांश की लगन\r\nनवांश का छटा भाव\r\nहोगा तो नवांश कुंडली को घुमा\r\nलो छठे भाव को लगन बना लो अब वो नवांश जो\r\nहै वह आपके दूसरे विवाह का\r\nहै अब उसको एनालाइज कर लो कि भाई विवाह\r\nकितने सुख दिन चलेगा सुख होगा दुख होगा\r\nक्या होगा सब उसी से सब पता चलता चला\r\nजाए अब इसी तरह से इसको रिपीट करते\r\nजा दूसरा विवाह छठे भाव से आ\r\nगया तीसरा विवाह गवे भाव से आ गया नवांश\r\nतो आप समझ ही गए होंगे मैं आगे और ज्यादा\r\nइसमें और बात नहीं कर रहा हूं तो इसके लिए\r\nमैंने आज जो सेलेक्ट की है कुंडली वो\r\nएलिजाबेथ टेलर\r\nकी उनके आठ बार विवाह\r\nहोए तो मैं एलिजाबेथ टेलर की नवांश से\r\nशुरू\r\nकरूंगा मैं उनके जन्म कुंडली से कोई\r\nसरोकार नहीं रख रहा सीधा नवांश प आऊंगा और\r\nआपके साथ वो एक एक नवांश में शेयर करता\r\nचला\r\nजा ये\r\nलीजिए ये\r\nइनका जो कुंडली का नवांश\r\nहै उसमें धनु राशि उदय हो रही है\r\nअब यहां\r\nदेखें इनका सप्तमेश\r\nबुध\r\nबुध तीसरे भाव में विराजमान\r\nहै उपचय हाउस में\r\nहै और शुक्र जो है वह भी उपचय भाव\r\nमें तो यहां से हमें इंडिकेशन मिलता है कि\r\nएक से ज्यादा विवाह\r\nहोगा और बृहस्पति भी अपनी नीच राशि में\r\nहै और बकरी\r\nहै और बृहस्पति का शनि से राशि परिवर्तन\r\nभी\r\nहै तो यहां से हमें ट मिलता है कि भाई\r\nसाहब मैरिज में कई मैरिज हो सकती है अब\r\nमैं एक एक मैरिज की मुझे बताना भाई मेरे\r\nको सारे याद तो रहेंगे नहीं मैंने लिख रखे\r\nहैं अब इनकी पहली मैरिज 6 मई 50\r\nको और जनवरी 51 में\r\nडाई छ सात महीने मैरिज\r\nचली अब यहां पर आप देखोगे मैरिज क्यों\r\nटूटी इसका मेन कारण\r\nहै के अष्टम भाव\r\nमें मंगल की दृष्टि है सप्तम भाव में मंगल\r\nकी दृष्टि\r\nसप्तम भाव में और कोई ग्रह की दृष्टि\r\nनहीं तो इनका विवाह जब य 18 साल की थी तो\r\nकोनार्ड हिल्टन के साथ इनका विवाह हो\r\nगया 6 मई 1950\r\nको और शुरू से ही वह अबूसिव थे बहुत\r\nज्यादा और मतलब अच्छे\r\nइनके रिलेशन नहीं रहे\r\nऔर इनका जनवरी 51 में डाइवोर्स हो\r\nगया ठीक है और इनकी जो हिलरी हिल्टन भी थे\r\nउनकी भी मृत्यु 1969 में हार्ट अटैक से हो\r\nगई अब हम दूसरी शादी अब देखिए लगन नोट कर\r\nली नगन है\r\nधनु यहां से छठा भाव पड़ा\r\nवृषभ तो दूसरी शादी हम वृषभ से देखेंगे अब\r\nमैंने वृषभ\r\nबना अब\r\nय अब इनकी दूसरी\r\nशादी एक यह भी फिल्म एक्टर थे मिशेल\r\nबिल्डिंग इवान हो के सेट पर इनकी मुलाकात\r\nहुई जब यह 20 साल की\r\nथी और जो\r\nथे यह इनसे 20 साल बड़े थे इनकी शादी 20\r\nसाल बड़े से\r\nहुई शादी हुई 21 फरवरी 1952 को और यह शादी\r\nपा साल चली दो संतान भी\r\nहुई और इनकी शादी हुई थी शनि में शुक्र\r\nमें\r\nशुक्र शुक्र लग्नेश है थ हाउस में बैठे\r\nहुए हैं शनि थ हाउस में है और नाइंथ और थ\r\nका एक्सचेंज\r\nहै और इनका डाइवोर्स\r\nशनि में मंगल में हो\r\nगया शनि अष्टमेश का भी फ फल दे रहे हैं\r\nजुपिटर का क्योंकि एक्सचेंज में है और\r\nमंगल वो अष्टम भाव में विराजमान\r\nतो सेवंथ लर्ड अष्टम में च\r\nअष्टम पीड़ित\r\nहै ठीक है तो इनका यह डाइवोर्स हो गया\r\nयहां पर डेथ नहीं\r\nई अब इसके बाद आते\r\nतीसरा तीसरे विवाह में अब आप देख लो पिछले\r\nमें टोरस थी यहां से हम छठे\r\nभाव तुला\r\nमें तो इनका तीसरा विवाह\r\nजो हुआ माइक टॉड से वह इनसे 25 साल बड़े\r\nथे यहां भी मंगल का रोल आ रहा है मंगल को\r\nयम माना गया है परंतु शनि से एक्सचेंज में\r\nहै मंगल के जो डिस्पोजिटर है और इनका जो\r\nविवाह हुआ था उससे इनको एक कन्या की का\r\nजन्म भी\r\nहुआ दूसरे विवाह से इनको दो\r\nबच्चों का मेल बच्चों का जन्म हुआ अब यहां\r\nदेखो आठवे भाव पर शनि की दृष्टि\r\nहै और अष्टमेश पीड़ित है तो विवाद लंबा\r\nनहीं रहना चाहिए बृहस्पति एक्सचेंज में यह\r\nबहुत बड़ी भयंकर चीज है इनके कुंडली\r\nमें और शनि इनका फल दे रहे हैं\r\nठीक है तो इन\r\nइनकी बहुत जल्दी माइक टॉड की एक साल शादी\r\nके बीच में ही 22 मार्च 58 को प्लेन क्रैश\r\nमें मृत्यु हो\r\nगई यह डाइवोर्स नहीं हुआ मृत्यु हुई\r\nहै आठवे भाव में में शनि की दृष्टि है और\r\nबृहस्पति की दृष्टि है\r\nनीचे तो इन्होंने यह विवाह बाय डेथ खत्म\r\nकराया अब इसके बाद चौथा विवाह अब चौथे\r\nविवाह के लिए पाइस लगन हो\r\nजाएगी अब लग्नेश जो है नीच के हो गए भाई\r\nसाहब अब यहां कहां शादी\r\nहुई इनके यह जो अब हस्बैंड\r\nबने यह एलिजाबेथ टेलर के जो गर्ल फ्रेंड\r\nथी एक\r\nडेबी उसके हस्बैंड\r\nऔर वहां उससे उसकी डेबी की शादी में\r\nएलिजाबेथ टेलर उसकी मेड बनी\r\nथी उसके शादी में पूरा सपोर्ट किया था और\r\nफिर उसके साथ ही शादी करली 12 मई 59 अपने\r\nफ्रेंड के उससे\r\nऔर यहां पर भी डाइवोर्स हो\r\nगया अष्टमेश उतना पीड़ित नहीं है वह बवे\r\nभाव में जाकर के पीड़ित\r\nहोआ यहां पर कोई बुरी दृष्टि नहीं आ\r\nरही सप्तम भाव के स्वामी जो है वो भी बवे\r\nभाव में विराजमान तो ये डाइवोर्स हो गया\r\nइनका उसके बाद पांचवी\r\nशादी जो इनकी बड़ी प्रिय शादी थी वह हुई\r\nरिचर्ड बर्टन\r\nसे जो क्लियोपेट्रा\r\nमें इनके साथ काम किया था और यह शादी काफी\r\nदिन\r\nचली फोर्थ मैरिज\r\nनहीं यह फोर्थ मैरिज डेब की\r\nथी एक मिनट यार मैं खुद तीसरी बता चुका\r\nहूं फोर्थ मैरिज बता दी अब पांचवे पर आते\r\nपांचवी\r\nमैरिज यह रिचर्ड बल्टन के साथ हुई\r\nथी पांचवी\r\nमैज अब यहां\r\nपर छठे और आठवे का एक्सचेंज है\r\nनवा तो यहां\r\nब यह विपरीत राजयोग है और मंगल भी दृष्ट\r\nकर रहा है शनि पीड़ित है तो यह विपरीत\r\nराजयोग है और इसको अब आप देखिए लव अफेर\r\nकहां से देखते हैं पंचम और सप्तम भाव के\r\nभावेश का\r\nसंबंध तो पंचमेश और सप्तमेश एक्सचेंज कर\r\nरहे यह लव अफेर से मैरिज ई क्लियोपेट्रा\r\nके सेट पर रिचर्ड बर्टन के साथ वहा एक\r\nलड़की इन्होने अडॉप्ट भी की और उसके साथ\r\nरिचर्ड बर्टन से डाइवोर्स भी हो गया 74\r\nमें 64 में शादी की 74 में डाइवोर्स हो\r\nगया इनकी शादी य लंबी चली\r\nथी उसके 11 महीने बाद ही इन्होंने रिचर्ड\r\nबर्टन से ही दोबारा शादी की तो इसको मैं\r\nछठी मैरिज\r\nमानूंगा अब प्यार नहीं था अब लव अफेयर\r\nनहीं था अब वो जो लड़की ली थी एक अडॉप्ट\r\nकी थी इन्होने उसके प्रेम की वजह से\r\nइन्होंने शादी\r\nकी अब यहां पर आप\r\nदेखो अष्टम भाव में सूर्य की दृष्टि आ रही\r\nहै तो ट डेथ से सेपरेशन नहीं हुई\r\nतो जो छठी शादी इनकी\r\nहुई अब आप दशा पीरियड देख\r\nलेना ठीक है और जो डाइवोर्स हुआ था वह\r\nमरकरी जुपिटर में हो गया था शादी हुई थी\r\nमरकरी राहु राहु आठवे भाव में वैसे भी\r\nनहीं चलना था ठीक है जी छठी मै अब इसके\r\nबाद हम आते सातवी मैरिज\r\nकी सातवी\r\nमैरिज यह मिले जॉन वेरियर से इनकी शादी\r\nहुई थी यह क्वीन एलिजाबेथ ने डिनर दी थी\r\nउसमें यह दोनों मिले\r\nथे ठीक है लव नहीं ऐसे ही मिले थे और ये\r\nडाइवोर्स हो हो गया था इसका तो इसने अब\r\nइनसे शादी करली सन 76 में इनकी छठी मैरिज\r\nसे डाइवोर्स हो गया था तो 76 में ही जॉन\r\nबरन से इन्होंने शादी कर अब यहां पर आप\r\nदेखिए जो नव सप्तमेश\r\nहै बृहस्पति वो आठवे भाव में विराजमान\r\nहै और जो अष्टमेश\r\nहै वो सप्तम भाव को देख रहे हैं तो अष्टम\r\nका रिलेशन दोनों से आ गया इसलिए इनका\r\nडाइवोर्स\r\nकेतु की दशा\r\nमें\r\nकेतु शुक्र में इनके डाइवोर्स हो\r\nगया ठीक है इसके बाद इनकी आठवी\r\nशादी मैं सिर्फ आपको मेथड बता रहा हूं भाई\r\nके कौन सी शादी किस भाव से देखनी होती है\r\nयह प्रश्न था ना\r\nसबका तो अब आठवी मैरिज हम वृश्चिक से देख\r\nऔर इसके बाद इन्होंने कहा भाई अब और शादी\r\nनहीं\r\nकरूंगी ये जो लास्ट इनके हस्बैंड थे\r\nलेरी यह फिल्म में नहीं\r\nथे आठवी\r\nमै ये इ ये\r\nएलिजाबेथ टेलर से 20 साल उम्र में छोटे\r\nथे शादी करे 92 में जब एलिजाबेथ 59 इयर्स\r\nकी हो\r\nगई तब यह शादी हुई\r\nहै और 6 अक्टूबर को शुक्र में\r\nसूर्य थ हाउस का बहुत बड़ा रोल होता है\r\nकर्म ऑफ एनी डिविजनल च किसी भी वर्ग में\r\nदशम भाव उसका कर्म होता है\r\nठीक है और डाइवोर्स हो गया था वीनस में\r\nराहु राहु भी दशम में\r\nबैठे वीनस सूर्य में विवाह हुआ और वीनस\r\nराहु में डाइवोर्स\r\nसूर्य में क्यों वो दशम भाव को बलि कर रहे\r\nहैं राहु को भी बलि कर रहे\r\nहैं अष्टम भी साथ में है तो यह इनकी आखिरी\r\nशादी थी और इन्होंने कहा कि अब इसके बाद\r\nमैं शादी नहीं करूंगी और इन्होंने इसके\r\nबाद शादी नहीं\r\nकी तो यह बड़ा आज इंटरेस्टिंग टॉपिक है\r\nमैंने बड़ी लंबी चौड़ी शादियों की कुंडली\r\nले ली है आप अगर सीमित रखना चाहते हैं\r\nदूसरी शादी\r\nतक जो डिमांड है बहुत लोग कह रहे भाई\r\nदूसरी शादी कैसे\r\nदेखे तो नवांश दोबारा बना\r\nलो छठे भा को नवांश के नवांश की लगन बना\r\nलो\r\nदूसरी दूसरी शादी के लिए दूसरे विवाह के\r\nलिए और वहां से आप पूरे दूसरे विवाह का\r\nस्वरूप वहां से\r\nदेख डाइवोर्स होगा डेथ होगी सुख मिलेगा\r\nविवाहित जीवन कैसा रहेगा सप्तम भाव\r\nसप्तमेश लगन लग्नेश यह सब यहां से\r\nदेख और भी बनाएंगे शादी पर कुछ वीडियो य\r\nबड़ा गरम गरम सब्जेक्ट था तो मैंने आपके\r\nसाथ यह शेयर कर लिया\r\nहै और फिर मिलेंगे मुझे उम्मीद है कि य यह\r\nवीडियो आपको पसंद आएगा\r\nगुड ज्योतिष का एक ये अनमोल मंत्र मैंने\r\nआपको दे दिया बहुत-बहुत धन्यवाद नमस्कार"},{"topic":"कब पंच महापुरुष योग कमजोर हो जाता है","text":"नमस्कार मित्रों आज फिर मैं आपके\r\nपास पंच महापुरुष योग लेकर के उपस्थित हुआ\r\nहूं पंच महापुरुष योग बहुत बड़ा नाम है बहुत बड़ा योग\r\nहै और बहुतों के मिलता है इसका अब कब बनता है पहले तो यह देखे\r\nमें जो लिखा है कि पांच ग्रह राहु केतु को छोड़ दीजिए सूर्य चंद्र\r\nको छोड़ दीजिए जो बाकी पांच ग्रह बचते हैं मंगल बुध बृहस्पति शुक्र और\r\nशनि इनसे यह योग बनता है इनके अलग-अलग नाम दिए हुए\r\nहैं जब भी यह\r\nग्रह स्वराशि में या उच्च राशि\r\nमें लगन से केंद्र में स्थित\r\nहो तब उसको पंच महापुरुष योग कहा जाता\r\nहै मंगल स्थिति में होता है तो उसको रूचक योग बोलते\r\nहैं बुध अगर इसी स्थिति में होता है तो उसे भद्र योग बोलते\r\nहैं और और बृहस्पति अगर इसी स्थिति में होता है\r\nतब उसे हंस योग बोलते हैं और जब शुक्र इस स्थिति में होता है तब\r\nउसको मालव योग बोलते हैं और जब शनि स्थिति में होता है तब उसको\r\nशशि योग बोलते हैं तो यह पांच पंच महापुरुष योग है इनका बहुत वजन है भाई\r\nबहुत सी अच्छी चीजें बोली गई है के अब इसका रियल सेंस क्या\r\nहै यह पांचों ग्रह किसी ना किसी तत्व\r\nके और अपने कारक स्पेसिफिक कारक नेचुरल कारक जो है\r\nउसके लिए को ज्यादा बल दे देते हैं ऐसा हम\r\nमानते हैं कि जब भी इनका कोई भी रूचक योग ब पंच महापुरुष योग बनता है जैसे मंगल\r\nसाहस देगा अच्छी पोजीशन\r\nदेगा परंतु एक चीज रूचक योग में अब मैं कुछ अपने टिप्स भी ऐड करता\r\nरहूंगा मंगल को सेनापति बोला\r\nगया अगर मंगल पूर्ण बली हो और पंच महापुरुष में\r\nहो तब वह आपको फौज की नौकरी देता है फौज\r\nके साथ काम कराता है अगर वह मध्यम बली\r\nहो तो वह पुलिस में नौकरी करा देगा पैरा मिलिट्री फोर्सेस में करा\r\nदेगा और अगर वो इस योग में बली नहीं है अब यह आज का हमारा टॉपिक\r\nहै कि कब उनका बल कम हो जाता है तो वह आपको आईएएस ऑफिसर\r\nबनाएगा कितनी विडंबना है अपना कारक किस तरह\r\nनिभाते इसी तरह से और के भी है बृहस्पति\r\nहै विद्वान बना वाइज बहुत\r\nगुण अगर वह कमजोर हो गया तो क्या कर देगा गुण को आपके दूसरी\r\nतरफ ले जाएगा व मालव योग है आपको लगजरी देगा सारी सुख सुविधाए देगा\r\nजीवन की अगर वह वीक हो गया कमजोर हो\r\nगया तो क्या करेगा सन्यासी बना\r\nदेगा किसी का बुरा नहीं चाहेगा मां आनंदमई मां के होरोस्कोप में\r\nदेख लो केंद्र में लगन में उच्च का शुक्र\r\nहै परंतु सन्यासी है क्योंकि वो शुक्र का जो योग\r\nहै वो क्षीण हो गया कम हो गया है\r\nअब बृहस्पति का योग जैसे हमने बात की इसी तरह शनि\r\nका शनि मेहनत कराता है अगर शनि का शशि योग वीक हो गया तो वह\r\nमेहनत कहां की कहां कराएगा फिजिकल\r\nकराएगा अगर बली होगा तो वो थिंकिंग देगा बहुत हाई क्वालिटी की थिंकिंग देगा बहुत\r\nबड़ा विचारक बन जाएगा बुद्ध\r\nबुद्धि दुनिया की इंटेलिजेंस को बुद्ध गवर्न करता\r\nहै अगर वह ण हो गया तो वह बुद्धि गलत डायरेक्शन में भी जा\r\nसकती है पहला पॉइंट दूसरा पॉइंट यह है कि अब मान लो शनि\r\nउच्च का हो मकर का हो कुंभ का हो ढाई ढाई साल रहता\r\nहै तो केंद्र में वह एक\r\nबती तीन स्थान एक ब च लगन में से 33 पर\r\nलगन 25 पर लगन में व केंद्र में आ जाएगा तो जब यह ढाई साल एक ही राशि में है\r\nतो साढ़े साल हो गए अपनी अपनी उसमें तो 25 पर लोगों में जब शनि इस\r\nस्थिति में होगा उनको शश योग मिलेगा सारे विद्वान बन\r\nजाएंगे बहुत मेहनती बन जाएंगे हार्ड वर्किंग बन जाएंगे डिप्लोमेट बन जाएंगे पर\r\nऐसा तो देखा नहीं भैया इसी तरह से बृहस्पति पूरे एक साल रहता है एक राशि\r\nमें कितने सारे योग बन जाएंगे तो इसी तरह से\r\nअब ये दो तरह से योग बनता है एक तो उच्च राशि में\r\nहो या स्वराशि में और केंद्र में अब इसमें\r\nएक स्वराशि के लिए एक खास पोजीशन आ जाती है सेवंथ हाउस\r\nकी सातव भाव को हम मारक भाव भी बोलते\r\nहैं और और कोई भी ग्रह स्वय राशि में उच्च का नहीं बोल रहा हूं स्वय राशि\r\nमें सातव भाव में बैठा हो हम उसको पंच महापुरुष योग\r\nबोलेंगे परंतु वो प्रबल मार्क हो जाता है यह ध्यान\r\nरखिए उसकी दशा अंतर दशा में आपको संसार से\r\nविदा लेनी पड़ सकती है केयरफुल रहना पड़ेगा उसमें\r\nयह सिर्फ स्वय राशि के उनका है तो अब यह मोटी मोटी बात हमारी हो\r\nगई अब इसमें हमने जो आज का टॉपिक चुना है\r\nवह है कि यह योग क्यों पूरा फल नहीं देता है कब यह कमजोर हो जाता\r\nहै इसका मेरे को मिला जो\r\nसूत्र मिला वह मिला देव केरलम\r\nमें देव केरलम में यह सूत्र मिला और वहां\r\nसे हमने कोशिश करके इसको हर पांचों ग्रह पर\r\nलगाने की कोशिश की देव केरलम का सूत्र\r\nसिर्फ शुक्र के लिए है वो क्या बोलता है के मालव योग\r\nयदि शुक्र के उच्च राशि में होने से बनता\r\nहै और यदि\r\nशनि बृहस्पति को दृष्ट कर रहा हो या उसके\r\nसाथ युति में हो तो मालव योग उसने तो लिखा\r\nकैंसिल हो जाता है इफेक्टिव नहीं रहता परंतु हम इसको यूज\r\nकर रहे हैं के ये कमजोर हो जाता\r\nहै ये डिस्कशन मैंने देख कर के अपनी सरल चार में भी लिखी है अब इसको हमने आगे\r\nएक्सटेंड किया और ग्रहो पे हमने ये देखा\r\nकि भाई शुक्र जो है देव केरलम का बोल रहा हूं मैं अभी शुक्र जो है वो किसकी राशि\r\nमें उच्च राशि का होता है बृहस्पति की राशि में वह उच्च राशि का\r\nहोता है तो बृहस्पति पकड़ा हमने और अब देखा कि\r\nबृहस्पति बृहस्पति\r\nकी उच्च का हो सॉरी उच्च का होता है बृहस्पति और\r\nशनि मकर राशि में जब होगा उसका डेबल लॉर्ड बृहस्पति का\r\nवह मकर है मकर का स्वामी है शनि तो हम शुक्र की बात कर रहे हैं शुक्र\r\nका उच्चे उच्च का स्वामी बृहस्पति है और\r\nबृहस्पति का नीचे जो उच्चे है उसका नीचे\r\nवो शनि है तो जब भी शनि उस ब को दृष्ट करेगा तो\r\nअसर आएगा शुक्र यह देव केरलम कहना चाह रहा\r\nहै यह हमने बाकी और ग्रहों पर भी इसको एक्सटेंड किया जैसे हम रचक योग से चलते\r\nहैं रुच की योग उच्च का यह जो कैंसिलेशन कमजोरी है यह\r\nसिर्फ उच्च के ग्रह का है स्वराशि के ग्रह का नहीं है यह भी\r\nरखना तो रचक मंगल मकर राशि\r\nमें उच्च राशि का होता है और उसके स्वामी है\r\nशनि अब शनि कहां नीच का होता है वह होता है मेश\r\nमें उसके स्वामी हो गए मंगल अगर मंगल शनि को दृष्ट करे या उसके\r\nसाथ हो तो रोचक योग का फल कम हो जाता\r\nहै फिलॉसफी आ गई समझ में क्या किस लिए देव केरलम ने लिखा था अब बुध है बुध वर्गों\r\nमें कन्या में उच्च राशि में होता\r\nहै और वह नीच राशि में कहां होता है\r\nबुध मीन में उसके स्वामी है बृहस्पति तो अगर\r\nबृहस्पति बुध को दृष्ट करें या बुध के साथ हो तो भद्र योग कमजोर हो\r\nजाएगा जुपिटर हंस योग जुपिटर कहां उच्च के\r\nहोते हैं क कर्क में चंद्रमा अब चंद्रमा नीच के\r\nकहां होते हैं वृश्चिक में मंगल आ गए तो\r\nमंगल यदि चंद्रमा को साथ हो चंद्रमा के साथ हो या दृष्ट कर रहा हो कौन दृष्ट\r\nकरेगा मंगल दृष्टि करेगा चंद्रमा को खैर वो चंद्रमा की तो सातवी दृष्टि होती है पर\r\nफिलोसोफी की बात उसकी बात कर रहा हूं कि मंगल यदि चंद्रमा को दृष्ट करे या उसके\r\nसाथ हो तो आपका हंस योग कमजोर हो जाता\r\nहै उसका पूर्ण फल नहीं मिलता मालव योग हम बात कर चुके हैं देव केरलम का\r\nही है इसके बाद शश योग पर आते हैं शश\r\nयोग उच्च का कब होता है जब व तुला में होते हैं\r\nशनि अब तुला के स्वामी है शुक्र शुक्र कहां पर नीच के होते हैं\r\nकन्या में जिसके स्वामी बुध है तो\r\nब और श्र यदि एक साथ हो तो शश योग का फल कम हो जाता\r\nहै अभ य मैं एस्पेक्ट नहीं बोल रहा बुध का एस्पेक्ट शुक्र पे क्योंकि दोनों बहुत\r\nपासपास रहते हैं तो बुध एस्पेक्ट नहीं कर सकता शुक्र को तो साथ साथ रहते हैं ठीक है\r\nजी तो यह हमारा हुआ तब यह योग कमजोर हो जाता है आप ये\r\nदेखो शुक्र और बुध ज्यादातर एक साथ ही रहेंगे आगे पीछे\r\nरहते हैं नहीं तो एक साथ कंजंक्शन में ही आ जाते हैं डिग्री डिफरेंस बहुत ज्यादा\r\nनहीं रहता है और शश योग हमने बताया साढ़े सा साल 30 साल में साढ़े सा साल 1 ब च\r\nकुंडलियों में मिलेगा परंतु भगवान ने क्या किया है कि वो शुक्र और\r\nबुध ज्यादातर एक साथ रहते हैं तो शश योग कमजोर हो जाता है नहीं तो सारे बड़े-बड़े\r\nडिप्लोमेट बन जाए ठीक है सब चाणक्य नीति करें तो यह हमारा उच्च\r\nके पंच महापुरुष योग का कमजोर पड़ना कैसे होता है अब दूसरा होता\r\nहै के स्वराशि\r\nका पंच महायोग बन रहा\r\nउसमें शास्त्रों में लिखा है मैंने बहुत ज्यादा इस पर देखा नहीं\r\nहै परंतु वो कहते हैं कि यदि\r\nकेतु पंच महापुरुष योग जो स्वय राशि से बन रहा हो उसके साथ केतु बैठ\r\nजाए केतु का कंजंक्शन आ जाए तो वो योग कम हो जाता है\r\nअब यहां में थोड़ा सा दुविधा में हूं पढ़ लिया पर आगे सोचा कि भाई केतु जब\r\nउस ग्रह के साथ उसी की राशि में बैठा होगा और राहु और केतु हमेशा जिस ग्रह की\r\nराशि में बैठे होते हैं उसका फल देते हैं और जिस ग्रह के साथ कंजंक्शन में होते हैं\r\nयुति में होते हैं उनका फल देते हैं तो क्याय केतु उसी ग्रह का फल नहीं देगा उसे\r\nकमजोर क्यों करेगा सिर्फ एक पॉइंट आता है कि भाई केतु\r\nजो है वह भौतिक चीजों से दूर करता\r\nहै अलौकिक चीजों की तरफ जाता है तो वह जो रचक योग है हम किसको मानते है कि दुनिया\r\nमें बहुत तूने कमाया बहुत नाम कमाया वो भौतिक है\r\nतो वह केतु जो है इसको भौतिक से निकाल कर\r\nके और दिव्य मार्ग पर जिसको कहते हैं भगवान\r\nके मार्ग पर ले जा सकता है जैसे मंगल मंगल सेनापति\r\nहै वह केतु के साथ बैठ गया केंद्र में तो रूचक योग तो बन गया पर केतु\r\nक्योंकि साथ में आ गया है तो वो मंगल की\r\nजो शुभ या दिव्य शक्ति है उनको बल देगा ना\r\nकि वह सेनापति बनाएगा लड़ाई झगड़ा नहीं करेगा व शायद लड़ाई झगड़ा\r\nसुलझाए उस तरह से उसको माना गया है तो यह हमारे इसकी थोड़ी सी हमने वार्ता\r\nकी अब जो उच्च ग्रहो उच्च राश के\r\nकैंसिलेशन का है उसमें अब जो\r\nग्रह उसको कमजोर कर रहा है पंच महापुरुष योग को कमजोर कर रहा है\r\nयदि वह जन्म कुंडली का लग्नेश\r\nहै तो उसका प्रभाव कम होगा कमजोरी कम होगी\r\nक्योंकि लग्नेश उस कुंडली के लिए हमेशा शुभ होता है तो यह\r\nहमारे एक दो राइडर थे अब हम दो चार कुंडली देखते हैं और उनको एनालाइज करते\r\nहैं ठीक है भाई पहला हमने लिया रूचक\r\nयोग यहां पर चंद्रमा मंगल चतुर्थ भाव में अपनी उच्च राशि में\r\nविराजमान है अच्छा पावरफुल योग बन रहा\r\nहै ठीक है अब यहां देखिए कैंसिलेशन कैसे हुआ रूचक का\r\nके मंगल शनि के साथ हो\r\nया शनि को दृष्ट कर रहा हो तो रचक योग\r\nकैंसिल हो जाएगा कमजोर हो जाएगा मैं फिर से कैंसिल बोल रहा हूं क्योंकि वो सब जगह\r\nअंग्रेजी में कैंसिलेशन ही बोलते हैं ना वह कमजोर हो जाएगा अब यहां पर मंगल जो है\r\nशनि को दृष्ट कर रहे तो इनका रचक योग पूर्ण बली नहीं\r\nरहा यह अब उसका बल कम हो गया इस रचक योग का यह कुंडली है चार्ल्स ला गाल की जो\r\nफ्रांस के प्रेसिडेंट रहे दो दफे फौज में भी काम किया थोड़े\r\nदिन परंतु फिर इन्ह एडमिनिस्ट्रेटर बना दिया रचक योग ने फौज का काम नहीं दिया\r\nइनको फौज के कमांडर जरूर बन गए पर वो एज पॉलिटिशियन\r\nएडमिनिस्ट्रेटर तो यह इसका यहां पर हमने वो देखा रोचक योग अब नेक्स्ट लेते\r\nहैं अब भद्र योग यह भद्र योग\r\nहमारा बनता है बुध से इसमें बुध जो\r\nहै वह स्वराशि कह\r\nलो उच्च के कह लो तो उस तरह से यह योग बन\r\nरहा है अब इसका कैंसिल कैसे हुआ भद्र योग का\r\nबृहस्पति यदि बुध को देख रहा हो या बुध के साथ युति में\r\nहो तो वह कमजोर कर देता है अब यहां मजे की\r\nबात देखो इस कुंडली में शुक्र बुध भी अपनी राशि का है\r\nबृहस्पति भी अपनी राशि का है बृहस्पति भी योग बना रहा है\r\nऔर बृहस्पति का योग कब कैंसिल होता है जब\r\nमंगल चंद्रमा को दृष्ट कर रहा जो यहां नहीं है तो इस कुंडली में आपका हंस योग\r\nज्यादा प्रबल है हंस योग कैंसिल कमजोर नहीं हुआ है भद्र योग कमजोर हुआ\r\nतो परंतु यह फिर भी क्योंकि दशमेश होकर के में बैठे हैं तो\r\nकाम में प्रोफेशन में तो तरक्की दे दी परंतु नंबर वन नहीं\r\nकिया इंटेलिजेंस में नंबर वन नहीं किया ये\r\nएक एक्टर थे बहुत सारी पिक्चरों में काम\r\nकिया और कब शुरू हुआ मरकरी की दशा इनको कब मिल गई यह देखिए पैदा ही मरकरी की दशा में\r\nहुए छ सात साल की मिली तो वो योग इन्होने एक्सपीरियंस नहीं\r\nकिया वो दशा में थोड़ी सी तकलीफ दे सकते थे अब बुद्ध में जब हुए बृहस्पति की दशा\r\nभी नहीं आई राइज कहां हुआ जो इन पावरफुल ग्रहों के साथ शुक्र जैसे\r\nबैठे शुक्र बुध और सूर्य के साथ है जो\r\nनवमेश दशमेश के का संबंध बना कर के बहुत\r\nबलि राज योग बना रहे ठीक है तो उस तरह से इनको उसका फल\r\nमिला अब हम एक और कुंडली देखते हैं य हंस योग की कुंडली\r\nहै हंस योग बृहस्पति उच्च राशि में विराजमान\r\nहै बुद्धि केंद्र में है दशम भाव में अब यह\r\nकैंसल या कब होता है जब मंगल चंद्रमा\r\nको अभी पीछे ही देखा था चंद्रमा के साथ हो या उसको दृष्ट\r\nकर अब यह यहां पर रोचक योग हंस योग कमजोर हो गया तो\r\nबुद्धि को थोड़ा सा गलत डायरेक्शन में भी यह डाइवर्ट कर सकता है टोटल स्पिरिचुअल\r\nनहीं दे यह एक कमजोरी आ\r\nगई कहने को तो बहुत बढ़िया योग है भाई जुपिटर केंद्र में बैठा है ठीक है परंतु\r\nयह खेल खराब कर दिया मंगल और चंद्रमा यह देव केरलम कह रहा है भैया मैं\r\nनहीं कह रहा हूं ठीक है जी यह कुंडली से आप सब वाकिफ\r\nहै इसके बाद एक और कुंडली लेते हैं भाई\r\nयहां पर मालव योग बन रहा है केंद्र में फिर से और मालव योग कहां खत्म होता है जब शनि\r\nबृहस्पति को देख रहे य देख\r\nरहे तो टोटली तो मालव योग खराब नहीं हुआ कमजोर हो\r\nगया इस शुक्र की दशा आरंभ होते\r\nही यह क्लास वन ऑफिसर बन गए पर शुक्र ने पीछा नहीं छोड़ा भाई साहब\r\n20 साल की दशा में नियर फेटल एक्सीडेंट भी दे दिए उस\r\nक्लास वन से इस्तीफा भी दिलवा दिया नौकरी छोड़ दी जानबूझ के नहीं करना\r\nमुझे ठीक है और कार्य क्षेत्र\r\nमें आगे बढ़ते रहे पर प्रसिद्धि उस तरह की नहीं मिली\r\nक्योंकि नौकरी में छोड़ गए फिर अपना बिजनेस किया ठीक है तो यह एग्जांपल है और शुक्र\r\nने अगर पूर्ण मालव योग देता तो ना तो एक्सीडेंट होते ना नौकरी\r\nछूटती ठीक है जी अब नेक्स्ट एक और ले लेते हैं शश\r\n योग अब यह शश योग यहां पर भी शनि महाराज\r\nलगन में उच्च राशि में\r\nबैठे अब इसका कमजोर कहां होता है यह कमजोर होता है के शुक्र और बुध एक साथ युति में\r\nहो वह यहां पर है युति में है पर यहां जो बढ़िया बात हो\r\nगई के जो कैंसिल कर रहा है\r\nवह तो कैंसिल जो कर रहा है वह बुध\r\nहै जिसको कैंसिल कर रहा है वह शुक्र है और शुक्र यहां पर लग्नेश\r\nहै वह बली है वह कहेगा भैया मैं कैंसिल नहीं हो\r\nरहा क्योंकि शुक्र और शनि में परिवर्तन\r\nयोग भी है ये एक अच्छी बात हो गई है तो यह भी एक\r\nअच्छी पोजीशन पर थे और आर्मी में भी काम किया अब यहां देखो\r\nमंगल दशम भाव को देख रहे दशम को जब भी मंगल प्रभावित कर देगा\r\nभैया और खाना भी अच्छा बनाएगा खाना एंजॉय भी करेगा और फौज के साथ भी काम\r\nकरेगा ठीक है और मरकरी ने सिर्फ क्या किया इसको जो\r\nइफेक्ट दिया के बुध की दशा में इनका देहांत हो\r\nगया मंगल ने देहांत नहीं दिया मंगल की अंतर दशा से पहले के आसपास\r\nइनका देहांत हो गया ठीक है भैया तो यह हमारी\r\nपेशकश\r\nथी तो यह हमने चार्ट भी डिस्कस किए\r\nऔर थोड़ा सा यह भी देखा कि पंच महापुरुष योग देख कर के सब लोग बड़े प्रसन्न होते\r\nहैं और मिलता है फल मिलता है यह मैं नहीं कह रहा टोटल फल नहीं मिलता फल मिलता है यह\r\nअपने में एक बहुत बड़ा योग है परंतु उसके\r\nपूर्ण फल कब नहीं मिलते हैं वह हमने आज\r\nदेखा देखिए मेरा कोई धे ज्योतिष के विपरीत जाने का नहीं है\r\nपरंतु उसके जो बारीक पॉइंट है जो लिखे हुए हैं उसको आख मीच के नहीं ले लेना है उस\r\nपरे हमें आगे सोचना है और उसकी\r\nगुणवत्ता कितनी है वह जांचना है अभी मैं\r\nआपसे एक और शेयर कर सकता हूं व करेंगे बाद में करेंगे कि पंच महापुरुष योग कब बली हो\r\nजाता है यहां तो हमने कहा कमजोर हो जाता है व बली भी हो जाता\r\nहै बली भी हो जाता है वह इसका विपरीत होगा यह भी देव केरलम से\r\nही निकाल कर के हमने कहा भाई अगर कमजोर हो रहा है तो बलि क्यों कब होगा तो बलि के\r\nलिए भी हम उसको देख सकते हैं सिर्फ रिवर्स\r\nकर मैं थोड़ा सा हिंट दे कर के छोड़ देता हूं जैसे रूचक योग है वह उच्च राशि उसके\r\nउच्च राशि के स्वामी शनि है अब शनि के उच्च राशि के\r\nस्वामी कौन है वहा हमने नीच राशि लिया था यहां उच्च राशि ले लो शनि के उच्च राशि के\r\nस्वामी हैं शुक्र तो शुक्र और\r\nशनि ये इकट्ठे हो जाए तो रूचक योग और बली\r\nहो जाएगा तो मैं ये एक्सरसाइज आपके लिए छोड़ता\r\nहूं सिर्फ जो कष्ट आएगा व भद्र योग में आएगा क्योंकि\r\nबुध वर्गो में ही उच्च का होता है और बुध फिर गगो में उच्च का होता है तो बुध तो\r\nअपने आप में ही है बुध शुभ होगा तो भद्र योग की पूरी कंडीशन मिल जाएंगी हंस योग\r\nकर्क में होता है चंद्रमा अब चंद्रमा कहां उच्च के होते हैं वृश्चिक में वृषभ में\r\nतो शुक्र आ गए तो शुक्र और चंद्रमा यह दोनों एक साथ\r\nहो तो हंस योग बहुत बली हो जाएगा अब जैसे हमने उस कुंडली में देखा था कमजोर भी है\r\nहंस योग और बली भी है क्योंकि शुक्र भी चंद्रमा के साथ बैठे हुए मंगल के साथ भी\r\nबैठे हुए हैं तो वहां वो बली हो रहे हैं तो यह बारीकियां देखनी पड़ेगी भाई मालव\r\nयोग शुक्र बृहस्पति बृहस्पति कहा उच्च का होता है चंद्रमा में तो चंद्रमा और\r\nबृहस्पति बहुत बढ़िया योग माना गया है इसी तरह से चंद्रमा और शुक्र यह जेमिनी\r\nमें बहुत बड़ा योग माना गया है इसी तरह से शश योग ले लो\r\nशनि शनि शुक्र में बली होते हैं शुक्र की राशि में उच्च के होते हैं और शुक्र\r\nबृहस्पति की में उच्च का होता है तो बृहस्पति और\r\nशुक्र ये एक साथ हो तो शस योग का फल अत्यंत बड़ा हो जाएगा और वैसे\r\nभी शुक्र और बृहस्पति एक साथ हो तो बहुत अच्छा धन योग बन जाता है ठीक है भैया तो\r\nयह लगे हाथ हमने कब बली हो जाता है इस पर आप लोग नन कीजिए मैं इसको डिटेल में और\r\nकुंडलिया लेकर के नहीं दे रहा हूं उन्हीं कुंडलियों में मैंने आपको यह बता दिया है\r\nतो आज के लिए हमारा इतना ही बहुत-बहुत धन्यवाद नमस्कार"},{"topic":"कर्तरी योग उदाहरण","text":"नमस्कार\r\nमित्रों आज हम फिर से कर्तरी योग\r\nका दूसरा वीडियो लेकर के प्रस्तुत हुए\r\nहैं हमने पहले वीडियो\r\nमें\r\nआपको किसकिस प्रकार से करतरी योग हो सकता\r\nहै वह हमने बात की\r\nथी उसमें जो सब इंपोर्टेंट पॉइंट\r\nथा वो था कि दोनों तरफ से प्रभाव आ रहा हो\r\nकिसी भी भाव पर या ग्रह पर दूसरा\r\nइंपॉर्टेंट पॉइंट जो बहुत से हमारे मित्र\r\nपूछ रहे\r\nहैं वह है कि यह शुभ करतरी है या पाप\r\nकरतरी है या क्या है भाई यह डिपेंड करता\r\nहै कौन ग्रह\r\nकरतरी दे रहे\r\nहैं वह\r\nअपने नैसर्गिक कार कत्व के हिसाब से\r\nज्यादा फल देते\r\nहैं यहां पर मैं एक चीज क्लेरिफाई करना\r\nचाहता\r\nहूं हम देख सकते हैं\r\nकि किस ग्रह पर करतरी आ रही है वो ग्रह\r\nकौन\r\nहै तो एक तो उसके नेचुरल कार कत्व जो है\r\nपराशर जी ने जो बोले हैं हम उस पर ध्यान\r\nदेते\r\nहैं दूसरा ध्यान जाता\r\nहै कि वह किस भाव के स्वामी है वह कौन\r\nहै अब यहां थोड़ी सी दुविधा हो\r\nजा क्योंकि सूर्य और चंद्रमा को छोड़ कर\r\nके बाकी सभी\r\nग्रह दो दो भाव के\r\nस्वामी है तो किस भाव के स्वामी पर करतरी\r\nहो\r\nरही अब उसमें एक छोटा सा हम यही कह सकते\r\nहैं कि भाई कौन सा भाव मली\r\nहै या कौन सा भाव ज्यादा इंपॉर्टेंट\r\nहै पर मैं ज्यादातर क्या करता\r\nहूं जब तक\r\nभावेश किसी केंद्र त्र वगैरा का ना\r\nहो क्योंकि केंद्र त्रिकोण है दूसरा उसका\r\nदूसरा भाव कहीं और भी हो सकता है 12 में\r\nहो सकता\r\nहै तो वो दोनों चीज देगा बीमारी भी देगा\r\nऔर केंद्र का भी उसका फल देगा पर\r\nस्टार्टिंग में आप उसके कारक को लेकर के\r\nचले और भाव भी लेंगे वो भी मैं आपको\r\nबताऊंगा तो इन दोनों से हम देख कर के बात\r\nकरते\r\nहैं एक और पॉइंट जो सबसे बली अर्गला है\r\nकर्तरी\r\nहै उस पर हम पहले ध्यान\r\nदेंगे बाकी एस्पेक्ट करतरी वगैरह है एक एक\r\nही हाउस\r\nमें अगर बली करतरी बन रही है वो भी हम\r\nइग्नोर नहीं करेंगे उसको ध्यान देना\r\nपड़ेगा तो ये आज करतरी का मैं आपके सामने\r\nप्रैक्टिकल\r\nएग्जांपल\r\nदूंगा और उससे कोशिश करूंगा कि आप उसको\r\nठीक से समझ पाए कि भाई कैसे देखना है\r\nकरतरी करतरी एक अच्छा\r\nइंपॉर्टेंट मेथड है देखने का और अपना फल\r\nदेता है हमेशा\r\nमिलेगा तो अभी हम आपसे पहले\r\nहम स्क्रीन शेयर कर लेते हैं और फिर बात\r\nकरते\r\nहैं यह पहला\r\nचार्ट हम वही ले रहे हैं जो हमने\r\nकल करतरी किसकिस प्रकार के होते हैं वो\r\nदेखने के लिए किया\r\nथा तो यहां पर हमने देखा था लगन कोई\r\nज्यादा जोरदार करतरी नहीं है बृहस्पति\r\nदूसरी तरफ जा रहा है मंगल भी दूसरी तरफ जा\r\nरहा है यहां पर चौथे भाव पर आप देखिए तो\r\nशुक्र डायरेक्ट भी\r\nआ सीधा है चतुर्थ भाव को प्रभावित कर रहा\r\nहै\r\nऔर दूसरी तरफ से सूर्य सबसे बली है निकटतम\r\nचतुर्थ भाव के तो हम इसको मानेंगे कि\r\nशुक्र की और सूर्य की\r\nकरतरी चतुर्थ भाव पर आ र पर सूर्य चतुर्थ\r\nभाव की तरफ नहीं जा\r\nरहा तो चतुर्थ भाव पर किसका प्रभाव ज्यादा\r\nआ रहा है व शुक्र\r\nका शुक्र का नेचुरल कार कत्व\r\nजो है वह स्पाउस\r\nहै पति है स्त्री का चार्ट है जुपिटर भी\r\nहै\r\nपरंतु\r\nशुक्र पति का भी कारक हो सक होता है\r\nक्योंकि वह एंजॉयमेंट का सुख का कारक है\r\nऔर वह चौथे भाव\r\nको प्रभाव दे रहा है तो इसका मतलब यह है\r\nकि\r\nशुक्र जो हमारा स्पाउस भी हो सकता है वो\r\nहमारे सुख घर सुविधा सब में प्रभाव डालता\r\nहै उसके ऊपर बहुत चीज डिपेंड करती\r\nहै ठीक है तो इस तरह से हम देखते हैं अभी\r\nकुछ मित्रों\r\nने यह बताया कि इसमें\r\nतीसरे और पांचवे भाव का परिवर्तन योग है\r\nउसका क्या फल होता\r\nहै अ भाइयों एक परिवर्तन योग का एक मीनिंग\r\nतो हो सकता\r\nहै\r\nऔर मैं इस\r\nपर आगे भी लिखने की कोशिश कर रहा हूं\r\nप्रत्येक भाव\r\nका भावे\r\nदूसरे भावेश से परिवर्तन क्या फल होता है\r\nतो यह मैं कोशिश कर रहा हूं लिखने की\r\nइकट्ठा कर रहा हूं कुछ कुछ जो अपने पास\r\nथोड़ा बहुत पढ़ लिख के जो ज्ञान आया है तो\r\nवह भी मैं आपसे साथ शेयर कर र आज का टॉपिक\r\nहमारा करतरी था तो इस पर मैंने कतरी बताया\r\nऔर जो लयो जो तीसरे भाव से किसी का भी\r\nग्रह किसी भी भावेश का एक्सचेंज योग होता\r\nहै उसको ल योग बोलते\r\nपरिवर्तन तो\r\nपंचमेश के साथ तृत का खल\r\nयोग और\r\nतृतीय नीच राशि के होकर के पंचम भाव में\r\nबैठ गए हैं और ज्यादा खराब कर तो इसका\r\nमतलब यह है\r\nके पांचवा भाव किसका\r\nकारक ज्यादातर हम लेते हैं भाई य बच्चों\r\nका संतान का कारक है तो इसने संतान में\r\nतकलीफ इनको दे\r\nदी उसमें खाली योग\r\nदे इन्होंने दो संतान अडॉप्ट की हुई है\r\nइनका कोई खुद की संतान नहीं\r\nहै ठीक है ये आएंगे इसको भी करेंगे हम कभी\r\nटॉपिक अब दूसरा चार्ट में लेता\r\nहूं यह हमारा वही जाना पहचाना मोदी जी का\r\nचार्ट\r\nहै अब यहां स्ट्रांग आप देखिए कहां कहा\r\nकर्तरी बन रहा है अभी गवे बवे भाव\r\nमें मुझे पांच ग्रह दिख रहे हैं केतु\r\nसमय तो एक तो भाई बुध के ऊपर करतरी बन है\r\nबुध वक्री है\r\nऔर केतु भी बकरी है तो बुध के\r\nऊपर बुध कौन\r\nहै मित्र गण है दोस्त है और यहां पर स्वय\r\nराशि के द्वादश भाव में बै तो जो द्वादश\r\nभाव है वह\r\nआपका\r\nसीक्रेट छुपे\r\nहुए शत्रुओं का होता\r\nहै अ कहेंगे वो तो आठवा भाव है जी नहीं\r\nआठवा भाव वो होता है जो शत्रु आप\r\nजानते 12वां भाव वो होता है एक और भी बहुत\r\nचीज है बवे भाव की के जो छुपे हुए शत्रु\r\nहोते हैं जो आपके सामने लाइन लाइट में\r\nनहीं आ रहे पीछे से काम कर रहे\r\nहैं उनका\r\nभाव तो बुध\r\nउसमें फसा हुआ\r\nहै यह गुप्त शत्रुओं\r\nका स्वामी भी है बुद्धि का स्वामी भी\r\nहै उस पर सूर्य और केतु की अच्छी करतरी आ\r\nरही\r\nहै तो\r\nइनको\r\nबुध छुपे हुए शत्रु देने की काबिलियत रखता\r\nहै\r\nदूसरी एक स्ट्रंग\r\nअर्गली\r\nकरतरी सूर्य के\r\nऊपर सूर्य के पीछे शनि\r\nहै जो सीधी मोशन में है डायरेक्ट मोशन में\r\nऔर आखिरी डिग्री पर बैठे हुए और सूर्य\r\nपहली डिग्री पर बैठे हुए ज्यादा दूर\r\nनहीं तो एक तरफ से तो शनि धक्का मार रहा\r\nहै सूर्य को और दूसरी तरफ से मरकरी\r\nजो छिपे हुए शत्रु हैं वो कर्तरी मार रहे\r\nहैं तो सूर्य के ऊपर पूर्ण करतरी आ गई भाई\r\nबड़ी बली करतरी\r\nआई अब आप देखो सूर्य की दशा में क्या हुआ\r\nये गुजरात के चीफ मिनिस्टर थे इनके ऊपर\r\nकेसेस\r\nलगे पाच छ साल तक जब तक सूर्य की दशा\r\nरही यह उन केसों में ही उलझे\r\nरहे और भगवान की कृपा या जो भी है इनका\r\nभाग्य था के बरी हो गए\r\nउस पर इस करतरी ने इतना\r\nस टेंशन वाला समय इनको दिखाया कितनी क्लोज\r\nकरते रही तो हम मेरा यही है क्लोज करते\r\nबाकी जो है आप देखते रहो इग्नोर कर दो या\r\nमत करो अब जैसे लगन के\r\nऊपर एक तरफ मंगल है वही नियरेस्ट है लगन\r\nके दूसरी तरफ कौन है नियरेस्ट सूर्य है\r\nसिर्फ सूर्य दे रहा है लगन\r\nको कर्तरी और सूर्य फसा पड़ा\r\nहै तो शरीर को मन को हमको वो तकलीफ दे रहा\r\nहै ठीक है जी तो ये हमने इस कुंडली में\r\nदेखा अब एक कुंडली और लेता\r\nहूं यहां भी मैंने इसलिए सेलेक्ट की है कि\r\nइसमें खास खास करतरी मिल रही\r\nहै ठीक है जी अब यहां देखिए लगन पे भी\r\nराहु वापस आ रहा\r\nहै लगन को देख रहा है बृहस्पति भी लगन की\r\nतरफ जा रहा\r\nहै तो लगन के ऊपर\r\nराहु और बृहस्पति की कर्तरी लगन में कोई\r\nग्रह नहीं है शरीर\r\nहै तो राहु का इफेक्ट तो आ गया वहां पर\r\nयहां पर मैं शनि को नहीं\r\nमानूंगा कि शनि प्रभाव क्योंकि शनि और लगन\r\nके बीच में बृहस्पति\r\nआया ठीक है जी 11वें भाव पर नहीं ले रहा\r\nहूं मैं कर्तव्य क्योंकि बृहस्पति सबसे\r\nपास है वो आगे जा रहे हैं 11वें भाव को\r\nनहीं देख रहे और सबसे पास बुध है जो वक्री\r\nहै वो उससे पीछे जा र तो गवे पाव पर\r\nप्रबल नहीं है अब देखिए हमारे पास मंगल\r\nमहाराज\r\nहै मंगल के पीछे सूर्य है जो\r\nडायरेक्ट मंगल की तरफ जा रहे\r\nहैं और दूसरी तरफ बुद्ध है जो वक्री होकर\r\nके\r\nमंगल की तरफ जा अब मंगल कौन\r\nहै मंगल अष्टमेश है तेश है अभी हमने\r\nबोला त्रिश और अष्टमेश पाप ग्रह है मंगल\r\nइस समय य\r\nपर तो\r\nये तकलीफ दे कौन तकलीफ में आ रहे हैं मंगल\r\nतकलीफ में आ रहे\r\nहैं अब ये देखो इसको शुभ कहेंगे अशुभ\r\nकहेंगे मैं कहूंगा कि भाई एक तरफ लग्नेश\r\nहै दूसरी तरफ अज्ञात शत्रु है\r\nसूर्य उसने मंगल को पकड़ रखा\r\nहै तो जो ओपन शत्रु\r\nहै मंगल अष्टमेश है वो ओपन शत्रु\r\nहै उनको यह पकड़ के रखते अपना प्रभाव डाल\r\nकर के टर्न पूरी\r\nकी अब ये नरसिंहा राव की कुंडली है अब एक\r\nऔर आप\r\nदेखो अष्टम भाव\r\nमें शुक्र 27 डिग्री 40\r\nमिनट और केतु उनसे पीछे है और वक्री\r\nहै ठीक\r\nहै चंद्रमा\r\nसीधी चाल से हैं तो वो शुक्र की तरफ आ रहे\r\nहैं तो शुक्र को\r\nचंद्रमा की करतरी मिल रही\r\nहै बाकी और भी चीज है वो नहीं जा रहा हूं\r\nपरंतु यहां चंद्रमा कौन है अब मैं इसको\r\nशुभ करतरी बोलूंगा या पाप करतरी\r\nबोलूंगा अब यहां चंद्रमा देखो एकादश\r\nत्रि शड के स्वामी\r\nहै मन\r\nहै ठीक है और यह शुक्र को प्रभावित कर रहे\r\nहैं शुक्र पत्नी भी कह सकते\r\nहैं ठीक है तो उनका साथ इनको बहुत ज्यादा\r\nनहीं मिला चंद्रमा की वजह\r\nसे दूसरा शुक्र के ऊपर प्रभाव है शुक्र\r\nकेतु के साथ केतु हालाकि वापस जा रहा है\r\nअब लग्नेश को मैं फिर से देखता हूं\r\nदोबारा लग्नेश\r\nवक्री इनके ऊपर कोई अर्गला नहीं है\r\nपरंतु मंगल उनकी तरफ आ रहा है दूसरी तरफ\r\nसे अर्गला नहीं मिल र सॉरी करतरी रगला\r\nदिमाग में चढ़ा हुआ है करतरी नहीं मिल रही\r\nऔर मंगल\r\nलग्नेश तो इनकी\r\nमृत्यु मंगल की वजह से यह पीड़ित हुए और\r\nइन्हें\r\nकैंसर डायरेक्टली नहीं आ रहा है करतरी से\r\nपर और चीज अगर मैं जोडा जब वहां लगाता हूं\r\nतब जाकर के यह पता चलता\r\nहै ठीक है जी क्योंकि यहां पर बुध स्व\r\nराशि में ही लग्नेश है और फिर से स्व राशि\r\nमें इस बुध ने इनको राइज भी\r\nदिया लग्नेश इंटें अपनी स्वय राशि\r\nमें परंतु यह पीड़ित हुए अष्टमेश\r\nसे\r\nऔर द्वादश\r\nसे तो करतरी का इस पर इतना ज्यादा असर\r\nनहीं दिख रहा है एक्सेप्ट\r\nमंगल तो मैंने यह आपको डिफरेंट प्रैक्टिकल\r\nएग्जांपल्स दी\r\nहै तो इससे मैं उम्मीद करता हूं आशा है कि\r\nप्रैक्टिकल आप देखना जहां कहीं\r\nभी आपको पूर्ण कर्तरी मिले किसी ग्रह पर\r\nकिसी भाव\r\nपर के आगे वाला ग्रह वक्री होकर उसकी तरफ\r\nआ रहा है और पीछे वाला ग्रह डायरेक्ट आ\r\nरहा\r\nहै तब उसका प्रभाव सबसे ज्यादा\r\nहोगा तो शुरू की उसमें अब बाकी करतरी को\r\nछोड़ सकते\r\nहैं सिर्फ इस प्रबल कतरी को आप ध्यान में\r\nरख\r\nके शास्त्रों में तो बहुत कुछ लिखा है\r\nहमने भी किताब में बहुत कुछ लिख दिया है\r\nहर तरह की करतरी लिख दी है\r\nव ज्ञान के लिए है नॉलेज के लिए है पर जब\r\nहम\r\nप्रैक्टिकल ज्योतिष करने बैठते\r\nहैं तो जो प्रत्यक्ष एकदम दिख रहा\r\nहै उसको ज्यादा ध्यान दो\r\nभाई ठीक है दूर के एस्पेक्ट करतरी वगैरा\r\nलगाते रहोगे तो उसमें हमें ज्यादा सफलता\r\nनहीं\r\nमिलेगी ठीक है तो आज के लिए मैं सोचता हूं\r\nकि अब करतरी का यह हमारा\r\nचैप्टर पूरा होगा और आप इससे कुछ भ्रम तो\r\nदूर होंगे करतर करतरी हम हमेशा रोज करते\r\nरहते हैं कितने जोगियों को क्लास में\r\nपढ़ाते टाइम वैसे करतरी जरूर बोल देते\r\nहैं तो इसलिए मैंने यह आपका आपके साथ यह\r\nवीडियो शेयर किया है बहुत-बहुत धन्यवाद\r\nहैप्पी न्यू ईयर हैप्पी गुड नाइट मजे करो\r\nथैंक यू"},{"topic":"कर्तरी योग","text":"नमस्कार आज से हम एक और नई\r\nसीरीज सरल ज्योतिष पार्ट टू की शुरू कर\r\nरहे\r\nहैं और इसके चैप्टर्स को हम लेकर के एक एक\r\nवीडियो बनाते रहेंगे जैसे भी टाइम\r\nमिलेगा काफी इंपॉर्टेंट टॉपिक्स है इसमें\r\nडेबिटेड प्लेनेट के है करतरी योग है जो आज\r\nहम ले रहे\r\nरेट्रोग्रेशन\r\nहै इत्यादि इत्यादि और भी है वो जैसे जैसे\r\nकरूंगा आपके सामने वो आते\r\nरहे तो आज हम चर्चा करेंगे कर्तरी\r\nयोग अब कर्तरी योग की बहुत ज्यादा\r\nभ्रांतियां है कैसे देखे शुभ है या अशुभ\r\nहै कैसे फल\r\nदेगा तो पहले तो हम इसकी उत्पत्ति कहां से\r\nकर्तरी उत्पन्न हुआ\r\nहोगा हमारे सब पुरानी टेक्स्ट में\r\nक्लासिक्स में शास्त्रों में सूर्य और\r\nचंद्र के योग दिए हुए हैं सूर्य से आगे\r\nकोई ग्रह हो पीछे कोई ग्रह हो उसके दोनों\r\nतरफ ग्रह हो इसी तरह चंद्रमा के भी\r\nहै तो दोनों तरफ के जो ग्रह हैं उनसे लेकर\r\nके ये कर्तरी शब्द का प्रयोग शुरू हुआ\r\nअब कर्तरी\r\nसे हम पहले समझे करतरी है\r\nक्या कोई हाउस है ग्रह\r\nहै चाहे हाउस के अंदर ही है तो आप यह समझो\r\nकि वो ग्रह या एक घर उस पर कोई भी चीज रखी\r\nहुई\r\nहै उसके आगे पीछे अब जैसे वीआईपी चलते हैं\r\nउनके बॉडीगार्ड होते\r\nहैं तो यह आप समझो\r\nबॉडीगार्ड एक आगे है एक पीछे है और उसकी\r\nदेखभाल कर रहे हैं देखभाल कर रहे हैं या\r\nनुकसान पहुंचा रहे हैं य यह भी बात है\r\nजैसे इंदिरा गांधी के बॉडीगार्ड नहीं इनको\r\nमार\r\nदिया अब यह\r\nबॉडीगार्ड आपके उसी कमरे में भी हो सकते\r\nहैं जिसमें आप बैठे हुए हैं दोनों तरफ\r\nबैठे हुए हैं\r\nके बाहर हो सकते हैं आजूबाजू के कमरों में\r\nबैठे हुए हैं बाहर बैठे हुए दूर से निगाह\r\nरख\r\nरहे दोनों तरफ से एस्पेक्ट दे रहे\r\nहैं इक्वल एक घर छोड़ के तीसरे घर में\r\nबैठे हुए हैं कि भाई आपका वो तो फिफा है\r\nतीसरा घर भी है पर इक्वल डिस्टेंस जिस तरह\r\nसे है तो यह सब आप देख लेना बहुत सारी\r\nवेरिएशन तो पहला तो यह है कि कतरी योग वो\r\nहै कि जब किसी भाव या किसी ग्रह के दोनों\r\nतरफ\r\nग्रह\r\nउपस्थित अब इसको एक तरह से हम कैची भी कह\r\nसकते हैं करतरी काटने\r\nवाली तो कैची जब काटती है जबक उसका तेज\r\nकाटने वाला\r\nजो सिरा है वह वस्तु की तरफ जाए कपड़े की\r\nतरफ\r\nजाए अगर मान लो कैची में एक सिरा एक डंडा\r\nउल्टा लग\r\nगया व कपड़े से दूसरी तरफ उसकी धार है तो\r\nवो तो नहीं काटेगा ना एक ही रह\r\nगया तो इसी तरह से हमारे ग्रहो में हम\r\nवक्री भी लेते हैं डायरेक्ट भी लेते हैं\r\nतो यह कंडीशन ज्यादा इंपॉर्टेंट है\r\nके कतरी देने वाले ग्रह अगर ग्रह की तरफ\r\nजा रहे\r\nहैं तब उनका प्रभाव ज्यादा होता\r\nहै यह एक मेन पॉइंट\r\nहै फिर क्या है कि अय शुभ प्रभाव होगा या\r\nअशुभ\r\nप्रभाव तो वो देखेंगे कुंडली के जो य कर\r\nदे\r\nरहे यह कौन\r\nहै क्या क्या रोल है इनके फिर दो रोल भी\r\nहो\r\nसकते पर अगर त्रिक का हो गया और करतर दे\r\nरहा है तो वह परेशानी भी तो दे रहा\r\nहै और भी होता है\r\nके किस भाव से करतरी दे रहे\r\nहैं अभी हम एग्जांपल में\r\nदेखेंगे कि सेकंड भाव से अगर करतरी है तो\r\nवो भी\r\nएक सेकंड भाव का भी वो इफेक्ट दे सकता है\r\nचाहे वो राहु केतु है दूसरे भाव में बैठे\r\nहुए या दूसरे का स्वामी है सेकंड हाउस का\r\nस्वामी है तो इस तरह से ये बहुत सारी\r\nवेरिएशंस हो जाती है और हम इसको उदाहरण दे\r\nदे कर के जिस तरह\r\nकहा कि आप यह देखिए कि कोई वीआईपी बैठा\r\nहुआ है और करतरी उसके\r\nबॉडीगार्ड और करतरी कैची की तरह काम करता\r\nहै उल्टी धार काम नहीं\r\nकरती तो मेरे ख्याल में बहुत तेजी से\r\nमैंने यह सारे नियम आपको बता\r\nदिए अब इसको हम देखते हैं प्रैक्टिकल लगा\r\nकर के कुछ चार्ट्स पे मैंने कुछ चार्ट लिए\r\nप्रॉमिनेंट चार्ट लिए है और ऐसे चार्ट लिए\r\nहैं कि जिसमें ज्यादा करतरी दिखाई\r\nदे अलग अलग ढंग की करतरी दिखाई दे ताकि हम\r\nउसको देख सके हर उसके पहलू को हम समझ\r\nसके तो अभी मैं आपसे स्क्रीन शेयर करता\r\nहूं और पहला\r\nचार्ट बताता\r\nयह पहला चार्ट हमने लिया\r\nहै यह चार्ट है पीवी नरसिंहा राव जी\r\nका जो भारत के प्रधानमंत्री रहे अब य देखो\r\nकहां कहा\r\nकरतरी पहले तो लगन पर देखो\r\nलगन के दूसरे भाव में राहु है राहु हमेशा\r\nवक्री होते हैं तो राहु लगन की तरफ आ रहे\r\nहैं शनि और\r\nबृहस्पति यह डायरेक्ट मोशन में\r\nहै वक्री नहीं है तो यह भी लगन की तरफ जा\r\nरहे हैं अब आप देखो शनि 26 डिग्री\r\nलगन के ज्यादा समीप है पास में बृहस्पति\r\nउसके\r\nपीछे सि में बृहस्पति पीछे तो इसकी\r\nइफेक्टिव कर्तरी जो है वह राहु और शनि की\r\nहै अब शनि महाराज कौन\r\nहै इस कुंडली में पंचमेश भी है और शश भी\r\nहै और भाई साहब छठे भाव को दृष्ट भी कर\r\nरहे हैं\r\nतो यह छठे भाव का भी इफेक्ट ज्यादा\r\nदेंगे य बाद की बात में पहले बोल रहा हूं\r\nइनकी\r\nमृत्यु राहु में शनि में\r\nहुई दोनों लगन लगन बॉडी आपका शरीर है उसको\r\nकरतरी दे\r\nरहे अगर मैं इसको एस्पेक्ट देखू कि भाई\r\nदूर बैठे हुए सामने फिर भी निगाह रखे हुए\r\nहैं तो यहां पर चंद्रमा को शनि बृहस्पति\r\nकी वो दृष्टि आ रही है और शुक्र और\r\nकेतु यह आठवे भाव में बैठे चंद्रमा से\r\nदूसरे भाव में\r\nबैठे तो सप्तम भाव पर भी आपकी करतरी आ रही\r\nहै अब इसमें जो सबसे बड़ी स्ट्रांग करतरी\r\nहै जो एक और बताया मैंने कि जहां वीआईपी\r\nबैठे हुए\r\nहैं उसी कमरे में भी दो गार्ड बैठे हुए\r\nहैं उसके आजूबाजू\r\nउनके बॉडीगार्ड है उनको रक्षा करने के लिए\r\nयही करतरी है तो आप दशम भाव में\r\nदेखो दशम भाव में मंगल के पीछे सूर्य है\r\nडायरेक्ट मोशन में मंगल की तरफ जा रहे हैं\r\nअब य दशम भाव पर करतरी नहीं है ये मंगल पर\r\nकरतरी है और जो बुध है वो दशमेश है स्वयं\r\nऔर लग्नेश है और वो भी मंगल की तरफ जा\r\nरहे तो मंगल को यह दोनों\r\nप्लेनेट प्रभाव डाल\r\nरहे तो मंगल को अच्छा बल मिल रहा है\r\nइनसे सूर्य से और बुध\r\nसे\r\nसूर्य द्वादश\r\nथोड़ा सा इनका रोल जो है लॉस का और चिंता\r\nका और शत्रुओं का हो जाता है तो वह मंगल\r\nको द्वादश दे रहे\r\nहैं अब अगर आप इसको देखोगे तो\r\nयह मंगल की दशा में प्राइम मिनिस्टर\r\nबने अब कहने को आप कह लो भाई साहब के बुध\r\nलगन है मंगल तो अष्टमेश है\r\nठीक है फिर भी यह मंगल में की दशा में\r\nशुरू में ही यह प्राइम मिनिस्टर बन गए और\r\nराहु की दशा में इनकी मृत्यु हो गई\r\nक्योंकि राहु दूसरे भाव में है दविश से\r\nदृष्ट\r\nहै शनि से दृष्ट\r\nहै ठीक है तो राहु जो है यह बिल्कुल मारक\r\nभाव का प्रभाव दे रहे हैं\r\nमैं बहुत दफा बताता हूं कि अगर सेकंड हाउस\r\nमें राहु केतु हो और त्रिकोण के स्वामियों\r\nसे संबंध हो जाए तो वह बहुत पावरफुल हो\r\nजाते\r\nहैं तो राहु शनि में इनकी मृत्यु\r\nहुई चलिए अब नेक्स्ट दूसरा\r\nचार्ट यह दूसरा चार्ट है\r\nअमिताभ\r\nबच्चन अब मैं इसमें यह जो कर्तरी है इसको\r\nआप वर्गों में भी लगा सकते हैं कोई दिक्कत\r\nनहीं अब यहां भी आप देखो लगन पर तो करतरी\r\nनहीं\r\nहै अष्टम भाव में देखो क्या हो रहा\r\nहै अष्टम भाव\r\nमें बुध वक्री\r\nहै सूर्य डायरेक्ट\r\nहै और शुक्र वो भी डायरेक्ट\r\nहै तो यहां भी वही सिचुएशन है देखो मंगल\r\nकी\r\nमंगल बुद्ध से अष्टम\r\nसे करतरी फुल प्रभाव आ रहा है और शुक्र से\r\nफुल\r\nप्रभाव अष्टमेश नवमेश\r\nऔर यह\r\nदोनों चतुर्थेश और पंचमेश भी है तो मंगल\r\nको चतुर्थेश और पंचमेश\r\nका पूरा प्रभाव आ रहा\r\nहै तो मंगल को योग मिल रहा है चतुर्थेश\r\nपंचमेश परंतु अष्टमेश का भी प्रभाव मिल\r\nरहा\r\nहै ठीक है तो मंगल इनको कैसा फल देगा आप\r\nदेखिए अब यहां दूसरा भाव देख पांचवा भाव\r\nदेखो यहां कोई ग्रह नहीं\r\nहै इसके दोनों तरफ एक तरफ शनि है जो बकरी\r\nहै और दूसरी तरफ बृहस्पति जन्म कुंडली\r\nमें तो बृहस्पति भी पांचवे भाव से दूर जा\r\nरहे हैं और शनि भी दूर जा रहे\r\nहैं तो इनका करतरी तो मानेंगे हम कि भाई\r\nबॉडीगार्ड खड़े हुए हैं परंतु दोनों का\r\nमुह दूसरी तरफ है उस भाव की तरफ नहीं\r\nदेख ठीक है सब तो यह एक और हमने आपको इसकी\r\nवेरिएशन बताई अब दशांश में\r\nदेखो यहां पर आपको लगन में बृहस्पति बैठ\r\nहु जो लग्नेश है बढ़िया हो गया कोई दिक्कत\r\nनहीं इस तरह से अब हम करतरी ढूंढते हैं\r\nइसमें चतुर्थ भाव पर देखो करतरी\r\nभाई केतु उल्टे जा रहे\r\nहैं वृषभ से मेष की तरफ जा रहे हैं और शनि\r\nजो है वोह मिथुन की तरफ आ तो चौथे भाव प\r\nशनि की करतरी ज्यादा\r\nहै शनि कौन है एकादशी है और द्वादशी है तो\r\nयह शनि सुख में कमी भी लाता\r\nहै इसी तरह से आप दशम भाव पर करतर\r\nदेखो दशम भाव पे आपको चंद्रमा\r\nसूर्य और राहु इनकी करतर आ रही है तो ये\r\nमंगल और बुध पर भी यह करतरी है परंतु अब\r\nदेखिए यहां इफेक्ट है या नहीं है इनका\r\nज्यादा सूर्य और चंद्रमा दोनों सीधे जा\r\nरहे हैं बवे भाव की तरफ और राहु उल्टे जा\r\nरहे हैं तो यह दशम भाव पर प्रभाव नहीं डाल\r\nर अब राहु पर देखो और नवम भाव पर\r\nदेखो यहां पर आप देख बुध जो\r\nहै\r\nवो राहु की तरफ नवम भाव की तरफ आ रहे\r\nहैं और जो शुक्र है वह भी नवम भाव की तरफ\r\nआ ग तो मैं इसको कहूंगा यह बली\r\nकरतरी और ये बृहस्पति से\r\nदृष्ट तो नवम भाव को बल मिल रहा है इस\r\nकरतरी\r\nसे आपको पिता का भी पता है और यह धार्मिक\r\nभी है पिता की सेवा भी की है ठीक है जी तो\r\nइस तरह से करतरी देखते हैं फलित आप खुद\r\nदेखते चलो पर मैं करतरी के नियम आपको बता\r\nअब तीसरा चार्ट एक और देख लेते\r\nहैं अब यहां\r\nदेखो लगन\r\nपे हम करतरी नहीं मानते नहीं है दशम भाव\r\nपर करतरी है परंतु स्ट्रांग\r\nनहीं बल नहीं मिल रहा दशम भाव को और\r\nकेतु पर हां शुक्र जो लग्नेश\r\nहै वह बहुत अच्छी स्थिति में विराजमान है\r\nनवम भाव में और लग्नेश है यह बल दे रहे\r\nहैं केतु को और दशम\r\nभाव तो बल दिया शुक्र ने केतु को केतु की\r\nदशा बढ़िया जाएगी\r\nचंद्रमा बल नहीं दे रहे हैं चंद्रमा सीधे\r\nजा\r\nरहे ठीक है अब यहां आप अष्टम भाव में देख\r\nलो कोई\r\nभी स्ट्रांग करतरी नहीं है क्योंकि सभी\r\nसीधे डायरेक्ट\r\nजा ठीक है अब मेन बात आती है दशम दशमांश\r\nदशमांश में केतु डायरेक्ट\r\nरेट्रोग्रेड लगन की तरफ और बृहस्पति की\r\nतरफ जा रहे\r\nहैं शुक्र स्वराशि के हैं वह भी लगन की\r\nतरफ जा रहे\r\nहैं दोनों का इफेक्ट आ रहा है\r\nइसमें केतु मारकेश का भी रोल\r\nकरेंगे और हमने कहा वहां से केतु की दशा\r\nअच्छी थी परंतु प्रोफेशन के लिए\r\nमार्केशिटी\r\nकरतरी नहीं है सूर्य और चंद्रमा दोनों\r\nडायरेक्ट जा रहे\r\nहैं मरकरी सिर्फ नवम भाव की तरफ जा रहे\r\nहैं जो\r\nलग्नेश जो दशमांश के लग्नेश मतलब मेरे\r\nप्रोफेशन में मरकरी मेरे को सहायता कर रहा\r\nहै मरकरी किसको बल दे रहा है\r\nपिता इन्होंने कोई रेगुलर प्रोफेशन नहीं\r\nहुआ इनका\r\nपरंतु पिता ने हमेशा मदद की सिर्फ इस\r\nबुद्ध की वजह से बुद्ध ने\r\nइसको बल दिया और बृहस्पति की दृष्टि ने बल\r\nदिया जो दशमांश\r\nइसके दशमांश के दशम लॉर्ड\r\nहै और पत्नी है दशमांश मतलब\r\nपार्टनर य पत्नी नहीं लगे व्यवसाय का\r\nपार्टनर\r\nउसने भी सपोर्ट कर\r\nदिया तो करतरी इस तरह से इसकी हमने देखी\r\nअब नेक्स्ट चार्ट एक और लेते\r\nहैं यह तो बहुत फैमिलियर चार्ट है इंदिरा\r\nगांधी\r\nका यहां पर भी देखो लगन में शनि विराजमान\r\nशनि के ऊपर आपके मंगल और केतु दोनों तरफ\r\nहै अब यहां देखो मंगल डायरेक्ट है और\r\nकेतु दूसरी डायरेक्शन में जा रहा है तो ये\r\nलगन के ऊपर\r\nबली नहीं बली करतरी नहीं\r\nकहेंगे ठीक है जी अब मैं दशमांश प देखता\r\nहूं अब आप ये देखो भाई\r\nसाब दशमांश\r\nमें केतु बैठे हुए हैं\r\nदशम भाव\r\nमें इनके ऊपर इक्विडिस्टेंट एक तो सूर्य\r\nकी शनि की\r\nचंद्रमा यह करतरी आ रय सूर्य की\r\nकरतरी सबसे इंपॉर्टेंट है क्योंकि वह दशम\r\nभाव की तरफ\r\nजा चंद्रमा और शनि वह दशम भाव से दूर जा\r\nइसी तरह से अब मैंने कहा कि घर के बाहर भी\r\nतो बैठ सकते पड़ोस में एक घर छोड़ कर के\r\nवहां पर बॉडीगार्ड बैठे हुए हैं तो यह बुध\r\nऔर\r\nशुक्र दोनों शुभ\r\nग्रह मैंने शायद एक वो किया था कंबन\r\nका\r\nवीडियो जिसमें हमने बताया था कि सूर्य से\r\nपरमानेंसी आती\r\nहै परंतु यहां वह केस नहीं लग रहा यहां\r\nसूर्य पर\r\nकेतु\r\nभी कर्तरी दे रहे और शुक्र भी कर्तरी\r\nदे तो सूर्य के ऊपर अच्छी कर्तरी आ रही है\r\nसूर्य स्वराशि के है बुध से शुक्र से\r\nसपोर्ट मिल रही है और केतु से मिल रही\r\nहै केतु दशमेश की तरह काम कर रहे\r\nहैं तो यह परमानेंट मतलब इनका\r\nअहदा रहेगा पोजीशन राज्य जो सूर्य के\r\nकारक अब हम इन्हीं का एक डी नान भी\r\nदेखते यह थोड़ा सा ट्रिकी\r\nहै अब यहां\r\nदेखो नवमांश की लगन\r\nपर\r\nबृहस्पति और शनि\r\nयह एक घर छोड़ के बैठे हुए पर बराबर इक्वल\r\nडिस्टेंस पर बैठे हुए\r\nनवा तो इसको हम लगन पर करतरी मान\r\nसकते\r\nबृहस्पति लगन की तरफ आ रहे हैं जो लग्नेश\r\nभी है तो बृहस्पति की जो है यह खराब भी है\r\nऔर अच्छी भी क्योंकि वक्री लग्नेश वक्री\r\nहो यह तकलीफ की बात है परंतु शनि भी आपके\r\nलगन की तरफ देख रहे हैं जा रहे हैं और\r\nस्वराशि\r\nठीक है जी शनि के ऊपर कोई बली करतरी नहीं\r\nहै केतु भी दूर जा रहे हैं और चंद्रमा भी\r\nदूर\r\nजा अब सप्तम भाव को ले\r\nलो सप्तम भाव में सूर्य और\r\nमंगल ये दोनों सप्तम भाव की तरफ जा रहे\r\nहैं परंतु सप्तमेश\r\nऔर अष्टमेश\r\nदोनों सप्तम भाव से दूर\r\nजा तो सप्तम भाव पर सूर्य और मंगल की ही\r\nकरतरी\r\nहै अब दूसरी और बात है कि भाई सप्तमेश जो\r\nथे वो आठवे में बैठ गए अष्टमेश के साथ बैठ\r\nगए मांगल्य को\r\nइन्होंने और शनि से दृष्ट हो\r\nगए ठीक है जो नवांश के त्रि छड़ा है के वि\r\nस्वामी है और द्वाद शेष भी है तो यह तकलीफ\r\nका मामला हो गया तो सप्तम भाव को बल नहीं\r\nदे\r\nपाए देखि जिस भी घर भाव का स्वामी अगर\r\nकरतरी दे दे तो वो भाव अच्छा बली हो\r\nजाता ठीक है जी तो ये हमारा आज का टॉपिक\r\nथा\r\nकरत अच्छा बड़ा टॉपिक है ये बहुत वेरिएशन\r\nहै अलग-अलग ग्रह को पहचानना देखना क्या कर\r\nरहा है कहां कहा का स्वामी है कैची किधर\r\nचल रही है बॉडीगार्ड बाहर भी बैठे हो सकते\r\nहैं ठीक है तो इस तरह से ये हमारा कतरी\r\nआगे भी और करेंगे इसी पुस्तक\r\nके हो सकता है मैं\r\nडेबिटेड प्लेनेट पर एक और कर दे ठीक है तो\r\nआज के लिए इतना ही नमस्कार धन्यवाद"},{"topic":"कारण और रोग बाहरी या आंतरिक है","text":"नमस्कार\r\nमित्रों आज फिर हम रोग के चैप्टर\r\nमें एक बहुत ही\r\nइंपॉर्टेंट टॉपिक लेकर\r\nके फिर आपके पास\r\nहै आज का हमारा जो टॉपिक\r\nहै वह है कि रोग मेनली कि रोग का\r\nकारण रोग तो में\r\nहोगा और रोग का\r\nकारण वो बाह्य है आउटसाइड सोर्स है बाहर\r\nसे आया है या शरीर के अंदर से\r\nआया यह जान कर के हम अपने ऊपर कंट्रोल कर\r\nसकते हैं अपने आपको को बीमारी से बचा सकते\r\nहैं यह एक बहुत बड़ा प्रिंसिपल है और यह\r\nप्रिंसिपल हमको ड्रेस कांड से मिलता\r\nहै अब वो बताता हूं यह द्रेश कान से कैसे\r\nदेते आपने सुना होगा रोग के लिए डी\r\nसि ंश का प्रयोग किया जाता\r\nहै एक\r\nंश पा डिग्री का होता है हर राशि को छ में\r\nभाग देते हैं तो एक ंश पा डिग्री का\r\nहोता और एक द्रेश कांड 10 डिग्री का होता\r\nहै तो इसका मतलब हुआ कि एक द्रेश कांड में\r\nदो षष्टि आंश होते\r\nहैं ंश को जमिनी पद्धति में कलक कहा कलक\r\nऔर बहुत से लोग रिकमेंड करते हैं कि डी स\r\nसे ही आपको रोग देखना चाहिए वो देख सकते\r\nहैं परंतु मैंने उसका जो प्रयोग किया है\r\nवह इस बात पर किया है के रोग का\r\nकारण बाहर से कि से आ रहा है या शरीर के\r\nअंदर से ही कुछ कमी\r\nहोग अब जो बाहर के कारण हो\r\nवो या तो एक्सीडेंट हो गया\r\nभाई शरीर में इसके अंदर से तो कारण नहीं\r\nआया एक्सीडेंट हो गया बीमार पड़ गया दूसरा\r\nजो सबसे बड़ा कारण है वह गलत खानपान का\r\nहै गलत चीज खा ली बाहर\r\nसे जंक फूड खा लिया गंदा पानी पी\r\nलिया बाहर की हवा की वजह से यह आ गया जो\r\nहम जो हमारी डेली नीड है भाई हवा और पानी\r\nयह तो हमें रोज चाहिए\r\nना तो उससे यह रोग आता है तो यह एक बहुत\r\nबड़ा नियम हम देख लेंगे\r\nके किस तरह से अगर वह बाहरी सोर्स है बाहर\r\nसे रोग आ रहा के कारण से रोग आ रहा\r\nहै तो मैं अपने उस कारण को बाहर से उसको\r\nरोकू ताकि मुझे रोग\r\nना यही उपाय है सबसे\r\nबड़ा ठीक है तो अब हम उसकी पद्धति\r\nसमझते एक दृश कांड में दो\r\nकलक हर कलक पा डिग्री का\r\nहै तो पहला कलक पहले दृश कांड में जीरो से\r\nपा\r\nडिग्री दूसरा लक पाच से 10 डिग्री पाच के\r\nऊपर निकल गया और 10 डिग्री\r\nतक इसी तरह से 10 से 15 डिग्री पहला\r\nकलक 15 से 20 डिग्री दूसरा\r\nकलक इसी तरह तीसरे द्रेश कांड में 20 से\r\n25 डिग्री तक पहला कलक और 25 डिग्री से 30\r\nडिग्री तक\r\nदूसरा अब इसका प्रिंसिपल क्या है कि पहला\r\nकलक\r\nया द्रेश कांड के पहले भाग में जो ग्रह\r\nहोता\r\nहै वह आंतरिक शरीर के अंदर से गड़बड़ होकर\r\nके तब बीमारी देता\r\nहै रोग देता\r\nहै और जो दूसरे कलक में होता\r\nहै उसका रोग का कारण बाहर की चीजें होती\r\nहै अंदर से जनरेट नहीं होती अंदर से पैदा\r\nनहीं\r\nहोती तो जो दूसरे कलक के ग्रह है उनको हम\r\nकंट्रोल कर सकते\r\nहैं अंदर के भी कर सकते हैं कि भाई यह है\r\nय इसमें मेरे को अंदर से बीमारी कुछ आ\r\nजाएगी तो यह हम समझते हैं प्रैक्टिकल\r\nकुंडलियों और आज मैंने जो कुंडली ली\r\nहै जो हमारे पिछले वीडियो में\r\nथी कि क्या रोग होगा किस राशि में रोग हो\r\nरहा है कौन सा ग्रह पीड़ित हो रहा है कौन\r\nसा ग्रह पीड़ा दे रहा है यह दो चार्ट हमने\r\nलिए थे वही चार्ट आज फिर लूंगा एक और\r\nचार्ट ले\r\nलूंगा तो अब इसमें यह समझिए कि जो ग्रह\r\nपीड़ा दे रहा\r\nहै वह\r\nकारण जैसे हमने पिछले उसम देखा था शनि प\r\nदे रहा है अब मैं उनकी कुंडली खोलता हूं\r\nऔर आपको यह पॉइंट इसमें समझाते\r\nहैं\r\nये यह हमने अब इसको हम जरा ध्यान से सारा\r\nदेखते\r\nजाएंगे अब यहां पहले हम डी 27\r\nआ हमने इस कुंडली में देखा था कि शनि\r\nने हमें रोक दिया रोग कारक है वो दे रहा\r\nहै टोरस को इसने पाप करतरी में रखा था हम\r\nकैसे देखेंगे अब शनि को\r\nदेखें कि रोग कहां से दे रहा\r\nहै यह जब जन्म कुंडली में\r\nदेखेंगे शनि 15 डिग्री 35 मिनट पर है\r\nदूसरे कलक में\r\nआ यह बाहर से रोग आया\r\nहै मैं अभी ऐसा करता हूं हर ग्रह का देख\r\nलेते हैं हम शुरू\r\nसे केतु बहुत इंपॉर्टेंट पॉइंट होता है\r\nकेतु 15 डिग्री 26 पर है यह रोग बाहर से\r\nदे बृहस्पति 13 डिग्री 15 मिनट पर है यह\r\nअंदर की बीमारी अंदर से ही बीमारी\r\nदेगा शनि बाहर का सोर्स\r\nहै चंद्रमा फिर बाहर का सोर्स है क्योंकि\r\nवह 25 डिग्री क्रॉस\r\nकर मंगल 21 डिग्री\r\nपा तो मंगल जो रोग देगा या कारण बनेगा या\r\nरोग दे मंगल का रोग जो होगा\r\nवो इंटरनल होगा आंतरिक होगा अंदर से ही\r\nउसका सोर्स\r\nहोगा शुक्र यह बाह्य है बाहर का सोर्स है\r\nबुध यह अंदर का सोर्स अंदर से तकलीफ\r\nदेगा और सूर्य फिर बा बाह्य रोग देता है\r\nतो इनको एक्सटर्नल सर्जरी हुई थी कैंसर से\r\nअब कैंसर कहां से\r\nआया शनि\r\nदूसरे कलक में है बाहर से यह रोग आया अंदर\r\nसे पैदा नहीं\r\nहुआ तो हमें यह देखना पड़ेगा कि भाई साहब\r\nआप बाहर की चीजों को अवॉइड\r\nकरिए और जो रोग\r\nहुआ राहु पर शनि की दृष्टि है शनि भी\r\nबाह्य है आउटसाइड का है तो ये शनि की वजह\r\nसे राहु को जो रोग हुआ कैंसर को वह शरीर\r\nमें बाहर दिखेगा\r\nअंदर बाहर\r\nदिखेगा अब जो शनि महाराज ने बृहस्पति और\r\nचंद्रमा को भी पकड़ रखा\r\nथा तो अब हम यहां से देखते हैं बृहस्पति\r\nपहले कलक\r\nमें रोग का सोर्स बाहर से है परंतु\r\nबृहस्पति का रोग शरीर के अंदर\r\nहोगा अब जब भी बृहस्पति या शुक्र पीड़ित\r\nहोते हैं दोनों ही पीड़ित है यह डायबिटीज\r\nजरूर दे देते\r\nहैं अब यहां बृहस्पति मेष राशि में है\r\nयहां पर परंतु यहां पास में\r\nहै अंदर का रोग पैरों में\r\nदेगा ठीक है\r\nमंगल अगर रोग\r\nदेगा वह सिर पर देगा एरिस में है डी स\r\nमें पनी से दृष्ट नहीं है इसलिए मैं इसको\r\nकाउंट नहीं कर रहा हूं परंतु मंगल पाप\r\nकरतरी करके टोरस को वृषभ को रोग दे रहा है\r\nतो मंगल का कारण आंतरिक है अंदर से इसने\r\nप्रॉब्लम दी है\r\nय बहुत ही इंपॉर्टेंट पॉइंट है मैं इसको\r\nऐसे नहीं छोड़ रहा हूं और भी मैं आपको\r\nदिखाता हूं ठीक है दूसरी कुंडली जो हमने\r\nबिल क्लिंटन की ली थी उस परे भी आप इस पर\r\nनिगाह\r\nमारिए अब आप देख सकते हैं मंगल पहले कलक\r\nमें है अंदर की बीमारी बृहस्पति पहले कलक\r\nमें है अंदर की बीमारी अंदर से आएगी\r\nअंदर की बीमारी\r\nहोगी शनि और बुध दोनों\r\nअंदर पहले कलक में है तो हमने देखा था\r\nइनको लंग्स का ऑपरेशन\r\nहुआ हार्ट का ऑपरेशन हुआ अंदर हुआ शरद\r\nपवार को बाहर हुआ फेस पर मुंह पर ऑपरेशन\r\nहुआ इनको इंटरनल हुआ एक्सटर्नल वाले कौन\r\nसे ग्रह है शुक्र\r\nकेतु है राहु है चंद्रमा\r\nहै बाकी सब ग्रह इंटरनल\r\nके तो हमने यहां से इनको देखा था कि भाई\r\nशनि महाराज\r\nने सूर्य को बीमारी\r\nदी शनि इंटरनल है न डिग्री पर है सॉरी\r\nएक्सटर्नल पर बाहर की चीजों से दी कहां दी\r\nसूर्य को दी चंद्रमा\r\nको\r\nसूर्य आंतरिक है अंदर दी बीमारी कारण बाहर\r\nका इसी तरह से मंगल को दी अब मंगल जो है\r\nयह भी 13 डिग्री प है यह भी आंतरिक\r\nहै अंदर के का रोग होगा कारण बाहर का है\r\nबाहर से आया\r\nहै चाहे वो कुछ भी हो खानपान हो\r\nअपनी डेली शेड्यूल हो कुछ हो भी जो भी हो\r\nउसकी वजह से ठीक\r\nहै अब एक और कुंडली मैंने ली\r\nहै इसका भी मैं विश्लेषण इसी तरह से करता\r\nहूं अब यहां\r\nदेखिए शनि से बीमारी आ रही\r\nहै शनि इंटरनल है\r\nशनि इंटरनल\r\nहै मंगल और शनि दोनों एक दूसरे को देख रहे\r\nहैं और राहु भी उसमें पार्टिसिपेट कर रहे\r\nहैं राहु एक्सटर्नल है मंगल इंटरनल है शनि\r\nइंटरनल है तो इन्होंने\r\nअंदर का रोग दिया हार्ट ऑपरेशन का जो\r\nमैंने बोला था आपको यह हार्ट ऑपरेशन की\r\nवजह से मंगल की वजह से हुआ\r\nइंटरनल क्योंकि यह अष्टमेश शुक्र से\r\nपीड़ित\r\nहै शुक्र 25 डिग्री पर है जीरो जीरो या वन\r\nकह लो 25 कंप्लीट हो चुके हैं मतलब सेकंड\r\nकलक में जा चुके तो यह जो कॉज दे रहा है\r\nयह एक्सटर्नल कॉज दे\r\nतो शुक्र का क्या हुआ शुक्र लस्ट वगैरह जो\r\nभी आपकी लग्जरीज के आइटम वगैरह है तो यह\r\nमुझे लगता है कि यह खानपान का और डेली\r\nरूटीन वगैरह जो था उस वजह से हार्ट प\r\nस्ट्रेस आई मंगल पर स्ट्रेस आई\r\nऔर मेरे को ऑपरेशन कराना पड़ अब इसी में\r\nआप\r\nदेखिए केतु मैं केतु पर बहुत जोर देता हूं\r\nयहां पर बताता हूं केतु कर्क राशि\r\nमें कर्क राशि में बैठा हुआ है तो कर्क\r\nराशि को ये पीड़ा दे और यह पीड़ा कहां से\r\nआई\r\nइंटरनल सॉरी एक्सटर्नल 15 डिग्री से ऊपर\r\nहै केतु 1745 पे है तो यह बाहर से आई अब\r\nमैं खैर सारी हिस्ट्री तो क्या बताऊंगा के\r\nबिजनेस के चक्कर में खानपान घूमना फिरना\r\nदोस्तों को एंटरटेन करना जब मैं बिजनेस\r\nमें था तो दिन और रात का कुछ पता नहीं था\r\nतो वह जब यह व्याधि यह रोग पकड़ा है ठीक\r\nहै जी तो यह हमने हमारी जो पुस्तक है\r\nलोकेट डिजीज की\r\nइसमें हमने इसको लिखा है इसको आप पढ़ लेना\r\nतो यह एक बहुत जरूरी पॉइंट है के रोग कहां\r\nसे रोग का कारण कहां से आएगा और रोग कहां\r\nहोगा सारे रोग होने शरीर में ही है पर कोई\r\nबाहर दिखेगा कोई आपको बाहर नहीं दिखेगा वह\r\nअंदर\r\nरहे ठीक है तो मेरे को उम्मीद है के इसको\r\nदेख कर के हम रोग निदान के\r\nलिए काफी कुछ इसमें हम पहले से प्रिकॉशन\r\nले सकते हैं पहले से\r\nही हम पहले से अपने आप को तैयार कर सकते\r\nहैं स्पेशली जो\r\nग्रह रोग दे रहा है रोग का कारण\r\nबन अगर वह दूसरे कलक में है एक्सटर्नल में\r\nहै\r\nतो मेरी सबको यह सलाह है मैं भुगत चुका\r\nहूं कि जब उसकी दशा\r\nहो तो अपने को कंट्रोल करके\r\nरखो बाहर की चीजों से कंट्रोल करके रखो अब\r\nजैसे सूर्य सूर्य मेरा सेकंड कलक में है\r\nऔर उसने हाट की बीमारी दी\r\nहै तो सूर्य के सेकंड कॉलम तो यह सिलसिला\r\nसूर्य की द में भी चलता रहा शुक्र की दशा\r\nमें शुरू हुआ और सूर्य की दशा में चलता\r\nरहा उसके बाद चंद्रमा की दशा आई वो भी\r\nसेकंड कलक में है 16 डिग्री\r\nप तो वहां भी एक्सटर्नल कंट्रोल नहीं हुआ\r\nबाह्य कंट्रोल नहीं हुआ उसके बाद जब राहु\r\nकी दशा आई वो इंटरनल दिखा रहा है अब बाहर\r\nका सोर्स नहीं है तो राहु की दशा में आपके\r\nबाहर के जो कारण\r\nहै वह आपके समाप्त हो\r\nजाएंगे और वही हुआ राहु की दशा के बाद\r\nबाहर के कारण मेरे\r\nसमाप्त तो उम्मीद है मेरे को भाइयों कि\r\nइसको आप समझेंगे और यह एक बहुत\r\nइंपॉर्टेंट आपको रोग निदान करने में मदद\r\nकर सकता है बाकी सारी ग्रह की और राशियों\r\nकी डिटेल वगैरह व पुस्तक में ही लिखी हुई\r\nहै ठीक है तो उसको पढ़ लेना नहीं तो जो\r\nमैं बता रहा हूं यह उसका निचोड़ ही बता\r\nरहा हूं नमस्कार"},{"topic":"केमद्रुम योग से डरना नहीं","text":"नमस्कार आज फिर हम आपके सामने एक नया\r\nटॉपिक लेकर के आए\r\nहैं इसकी डिमांड हो रही\r\nथी और यह टॉपिक है केमद्रुम\r\nयोग और मैंने इसका नाम दिया है कि\r\nकेमद्रुम योग से भयभीत नहीं होना है\r\nकुछ ऐसे टॉपिक हैं ज्योतिष\r\nमें जिनको बोल कर के हम लोग देख कर के कि\r\nमेरी कुंडली में यह है और हम डर जाते\r\nहैं जैसे साढ़े साती जिस पर हम बात कर\r\nचुके\r\nहैं नीच ग्रह नीच राशि में ग्रह हो यह भी\r\nमैंने सरल टू में दिया है केमद्रुम योग यह\r\nदेख कर के भी घबरा जाता\r\nतो यहां मैंने प्रूव किया है इसमें के नीच\r\nग्रह भी कहीं पर भी हो 94 पर\r\nउनका कैंसिलेशन हो जाता है और इसी तरह से\r\nअधिकांश केमद्रुम योग भी कैंसिलेशन हो\r\nजाता है और उनका कोई इफेक्ट नहीं ज्यादा\r\nविपरीत इफेक्ट नहीं दिखता है देखिए\r\nदुनिया में हर तरह के व्यक्ति हैं अच्छी\r\nपोजीशन पर है कोई गरीब भी है बीमार भी है\r\nअच्छी सेहत वाले भी है हर तरह का है तो यह\r\nसिर्फ एक ही चीज को लेकर के हम उस पर पूरा\r\nठीकरा नहीं फोड़ सकते कि भाई केमद्र योग\r\nहै तो ते बर्बाद हो\r\nगया आप देखोगे कितने बड़े\r\nबड़े साइंटिस्ट बड़े लोग पॉलिटिशियन\r\nएक्टर्स जिन्होंने अचीव किया है धनी लोग\r\nबहुतों के केम योग होता है और वह हम\r\nदेखेंगे\r\nआज उसका कैंसिलेशन भी होता है अब\r\nकैंसिलेशन ना भी हो तो और योग होते हैं तो\r\nव्यक्ति समाज में ऊंचा आता है जिंदगी में\r\nसुखी रहता है तो सबसे पहले तो हम समझे कि\r\nकेमद्रुम योग कैसे बनता है किसको कहते\r\nकई डेफिनेशन दी गई है अलग-अलग किताबों में\r\nये सब मैंने उसको लिस्ट किया है सबसे\r\nज्यादा जो\r\nहम\r\nहमारे सुनने में आता है या सब लोग जानते\r\nहैं वो यह होता है कि भाई चंद्रमा के\r\nआजूबाजू आगे पीछे अनफा\r\nसुनफ या दुर धुरा वो योग ना हो चंद्रमा\r\nअकेला है\r\nतो केमद्रुम योग होता है और भी कई तरह के\r\nयोग लिखे गए हैं जैसे कि शनि या शुक्र\r\nनवांश में शत्रु राशि में हो एक दूसरे को\r\nदेखते हो या दोनों साथ तो भी केंद्रम योग\r\nहोता है जेमनी एस्ट्रोलॉजी में एक और केदम\r\nयोग लिखा\r\nहै कि यदि लगन से दूसरे और आठ भाव\r\nमें बराबर नंबर वाले पाप ग्रह बैठे एक एक\r\nहो दो दो हो इतने सारे तीन तीन तीन तो\r\nनहीं हो सकते इतने तो ज्यादा नहीं होते तो\r\nएक या दो तक ही सीमित रहेगा ये तो भी\r\nकेमद्रुम योग होता\r\nहै और सबने लिखा है ज्यादातर किताबों में\r\nलिखा है के केमद्रुम योग निर्धन बनाता है\r\nजीवन में बहुत कष्ट देता है अब इस विषय\r\nमें आप सरल विचार सुन\r\nलीजिए कि हमारे\r\nविचार सबसे पहला तो होता है कि भाई केम\r\nद्रुप योग जो है वह जीवन की शुरुआत एक\r\nलोअर लेवल से कराता\r\nहै अब वो उसकी खुशी कुछ और ही\r\nहै जब आप एक नीचे स्तर से कम कम स्तर\r\nसे कष्ट वाले स्तर से ऊपर उठते\r\nहैं तो उसका आनंद उसकी संतोष भावना वो अलग\r\nहोती\r\nहै अब होता क्या है हमारे विचार से इस तरह\r\nसे नहीं पुस्तक में देखते अब मैं तो कुछ\r\nदूसरे तरीके से देख रहा हूं कि भाई\r\nचंद्रमा आपका मन है\r\nउसको आजूबाजू से इधर उधर से कोई सपोर्ट\r\nनहीं मिल\r\nरही तो इसका क्या मतलब है आपका मन\r\nइंडिपेंडेंट है एकांकी\r\nहै वो किसी के इधर उधर के प्रभाव में नहीं\r\nआता तो वह अपनी सोच से काम करेगा\r\nप्रभावशाली\r\nहोगा और मेरा विचार है अच्छे\r\nएडमिनिस्ट्रेटर बनते हैं\r\nअच्छा काम कर सकते हैं एकाग्रता होती\r\nहै ये सबसे बड़ा वो है तो दो पॉइंट मैंने\r\nदिए एक तो जीवन का\r\nआरंभ लोअर नीचे के स्तर से शुरू होता है\r\nदूसरा वह एकाग्रता से कोई उसको इधर उधर से\r\nबोलने वाला नहीं होता इन्फ्लुएंस करने\r\nवाला नहीं होता तो बहुत बहुत बड़े लोग\r\nइसमें आते\r\nहैं अब इसके कुछ कैंसिलेशन के रूल भी\r\nहै मैं दो चार बताऊंगा जो सबसे ज्यादा\r\nप्रोमिन है कि भाई बृहस्पति यदि चंद्रमा\r\nसे केंद्र में हो तो केमद्रुम का\r\nकैंसिलेशन हो जाता\r\nहै ज्यादातर किताबों में यही लिखा होता है\r\nऔर भी कैंसिलेशन है\r\nजैसे चंद्रमा को पाच चार पांच ग्रह दृष्ट\r\nकर\r\nरहे तो भी उसका कैंसिलेशन हो\r\nजाएगा और एक होता है वसुमति\r\nयोग अगर वसुमति यह पराशर जी ने भी लिखा है\r\nऔर कई पुस्तको में है कि वसुमति योग हो तो\r\nकेम ध्रु कैंसिल हो जाता है वसुमति योग\r\nक्या है आप खुद ढूंढेंगे मैं बताऊ चलिए\r\nबता ही देता हूं कहां\r\nढूंढोगे जब उपचय भाव\r\nमें प्रत्येक उपचय भाव में शुभ ग्रह\r\nबैठे तो वसुमति योग होता है अब\r\nएक्सपीरियंस से क्या है कि भाई शुभ ग्रह\r\nआपके पास चंद्रमा को मिलाकर के चार ही\r\nहै तो चार उपचय\r\nहै तो कहीं ना कहीं अगर दो शुभ भी एक साथ\r\nआ गए\r\nऔर उपचय आपको भरने हैं तो कहीं ना कहीं\r\nपाप ग्रह भी आ\r\nजाए शुभ ग्रह आएंगे तो हो सकता है एक में\r\nपाप ग्रह भी आ\r\nजाए तो भी कैंसिलेशन हम मान सकते हैं ऐसा\r\nमेरा\r\nविचार और यह\r\nकैंसिलेशन\r\nतकरीबन हर होरोस्कोप में मिल जाए 15 20 25\r\nहोरोस्कोप तो मैंने अपनी सरल टू में ही\r\nडिस्कस किए हैं बड़े-बड़े लोगों के तो वो\r\nवहां मिल जाएगा तो उसमें घबराने की बात\r\nनहीं है तो हम जो टॉपिक ले रहे हैं ये कि\r\nभाई जैसे साढ़े साती है घबरा\r\nगए नीच ग्रह है घबरा गए करतरी योग है घबरा\r\nगए पाप करतरी पड़ रहा है पर उस करतरी का\r\nक्या इफेक्ट होता है यह हमने अपने पिछले\r\nवीडियो में देखा तो इस तरह का टॉपिक\r\nहम देखने की कोशिश करते हैं तो अब मैं\r\nआपके साथ अपनी स्क्रीन शेयर करता\r\nहूं और उसको देखते हैं भाई कि क्या हो रहा\r\nहै तीन चार कुंडली\r\nलेंगे\r\nतो यह\r\nआपकी पहली\r\nकु अब यह देखो चंद्रमा एक तो नीच राशि में\r\nहै भाई\r\nसाहब और के मरम में है आगे पीछे कोई ग्रह\r\nनहीं है ना किसी ग्रह की दृष्टि\r\nहै पांच ग्रह की दृष्टि की बात कर रहे थे\r\nयहां तो एक भी नहीं है पर हां एक\r\nकैंसिलेशन है वो हम मान सकते हैं कि\r\nचंद्रमा के केंद्र में बृहस्पति विराजमान\r\nहै बहुत से शास्त्र इसमें लिखते हैं कि\r\nचंद्रमा केंद्र में हो तो भी कैंसिलेशन हो\r\nजाता\r\nहै बहुत से कहते हैं चंद्रमा केंद्र में\r\nहो और बृहस्पति भी केंद्र में हो तब\r\nकैंसिलेशन होता है तो अब यह\r\nदेखिए यह कुंडली है महान वैज्ञानिक\r\nआइंस्टीन इनकी\r\nशुरुआत प्रारंभिक जीवन इतना अच्छा नहीं\r\nरहा\r\nइवन कॉलेज में एडमिशन नहीं मिल रहा\r\nथा देश छोड़कर दूसरी जगह गए वहां पर\r\nएडमिशन मिले देखे क्या\r\nपढ़े परंतु एकाग्र चित अपने से ही यह\r\nमैथमेटिक्स और फिजिक्स में टॉप करते\r\nथे तो मैथमेटिक्स और फिजिक्स की वजह से\r\nइनको एडमिशन मिला और फिर कितनी बड़ी\r\nइन्होंने इन्वेंशन\r\nकी तो यहां देखो कोई डरने की बात नहीं है\r\nजैसे व्यक्ति के केव द्रुम योग\r\nथा अब हम नेक्स्ट कुंडली लेते\r\nहैं यह साइंटिस्ट की देख ली हमने अब हम\r\nनेक्स्ट देखते\r\nहैं कि भाई धनी आदमी की अब यहां देखो भैया\r\nचंद्रमा फिर विराजमान है आगे पीछे कोई\r\nग्रह\r\nनहीं ना बवे भाव में ना सेकंड हाउस ना\r\nजुपिटर के में\r\nहै यहां से पर चंद्रमा केंद्र\r\nमें तो क्या इसको कैंसिलेशन मानेंगे\r\nदो ग्रह से\r\nदृष्ट मंगल से और बुद्ध से दो ग से दृष्ट\r\nतो इनको तो जैसा शास्त्रों में ज्यादातर\r\nलिखा है के व्यक्ति केम ्र में पैदा हो तो\r\nगरीब होता\r\nहै धन होता\r\nहै अब यह कुंडली किसकी है भाई बिल गेट्स\r\nकी निर्धन बोलोगे\r\nउसको केंद्रम योग है इसे तो निर्धन होना\r\nचाहिए\r\nथा और आप\r\nदेखो सूर्य भी नीच राशि में है\r\nपरंतु शनि उच्च राशि\r\nमें बाकी और मैं डिस्कस नहीं कर रहा हूं\r\nये किस तरह से धन योग बन रहे\r\nहैं ठीक है डायरेक्ट धन योग तो दिख ही\r\nनहीं\r\nरहा कर्क और मेश दो और 11 को लेकर त्रिकोण\r\nसे जुड़ते हैं\r\nना कहीं त्रिकोण से नाता नहीं आ\r\nरहा पर यह दुनिया का बहुत बड़ा अमीर\r\nआदमी ठीक है जी तो यहां भी हमारा कद्र फेल\r\nहो गया अब नेक्स्ट चार्ट लेते हैं\r\nभाई अब यहां\r\nदेखो अब केंद्र में राहु केतु को नहीं\r\nलेते दो या 12 में राहु केतु होते हैं\r\nक्योंकि हर ने लिखा है भर शास्त्र में\r\nलिखा है चंद्रमा के आगे या\r\nपीछे को ग्रह नहीं\r\nहो राहु केतु को अब मैं उसका मीनिंग क्या\r\nसमझता हूं कि राहु केतु छाया ग्रह ग्रह\r\nनहीं है तो इसलिए उनको इंक्लूड नहीं कर तो\r\nयह कुंडली मैंने इसलिए ली यहां भी\r\nकैंसिलेशन तो हो रहा है अब देखो पांच ग्रह\r\nचंद्रमा को देख रहे\r\nहैं पांच ग्रह\r\nऔर इनका जीवन भी कोई बहुत ज्यादा हाई फाई\r\nफैमिली से शुरू नहीं\r\nहुआ यह\r\nकुंडली देवानंद इतने बड़े एक्टर की\r\nहै बिल्कुल नीचे से शुरू होकर स्ट्रगल\r\nकरके इतने बड़े एक्टर बने इतना बड़ा नाम\r\nकमाया आयु अब वो कहते आयु कम होती है नहीं\r\nबहुत से कहते दीर्घायु होता है पर निर्धन\r\nहोता है अब इस भाई की तो आयु भी बड़ी थी\r\nऔर निर्धन भी नहीं\r\nथा ज्यादातर आखरी दिनों में विदेश में\r\nरहे तो य कुछ नहीं दिख रहा इस तरह\r\nका कैंसिलेशन तो है मानता\r\nहूं अब इसके बाद एक कुंडली और लेंगे\r\nइस कुंडली में\r\nदेखो चंद्रमा के फिर दोबारा अकेले बैठे\r\nहुए केवल शुक्र से दृष्ट और शनि से\r\nदृष्ट यहां पर जमिनी का रूल का आपका केम\r\nध्रु योग बन\r\nरहा दूसरे भाव में राहु\r\nहै और अष्टम भाव में केतु एक एक पाप ग्रह\r\nहो गया य कोई शुभ ग्रह नहीं तो ये जेमिनी\r\nका केमद्रुम योग है और पराशर का भी\r\nकेमद्रुम योग है दोनों हो और यहां भी\r\nजुपिटर इसके केंद्र में\r\nनहीं अब यहां पर आप देखो भाई\r\nकैंसिलेशन कैंसिलेशन की यहां पर हम एक ही\r\nदेख सकते हैं कि भाई पांच ग्रह य चार ग्रह\r\nजुपिटर वगैरह लेकर के यह केंद्र में\r\nविराट जुपिटर केंद्र में है परंतु उससे\r\nकैंसिलेशन इतना स्पष्ट नहीं होता है दो दो\r\nके मम यग\r\nब और यह\r\nकुंडली फिर से फिल्म एक्टर धर्मेंद्र\r\nकी अब इनका भी देखो स्टार्ट हुआ जीवन में\r\nये लोअर लेवल मतलब इलेक्ट्रिशियन टाइप का\r\nघर घर जाकर के मैकेनिक की तरह व रिपेयर\r\nकिया करते\r\nथे मेरे ख्याल में इलेक्ट्रिशियन\r\nथे और वहां से कितने बड़े एक्टर बने कितने\r\nनाम कमाया हर कोई जानता है तो यहां भी\r\nडरने की बात नहीं है तो यह हमारा जो है\r\nहम जो इसीलिए टॉपिक यह लेते हैं कि डरना\r\nनहीं\r\nहै सिर्फ एक योग के कारण हम पूरी कुंडली\r\nको चौपट नहीं कर\r\nसकते एक और बात बताऊंगा भाइयों\r\nआपको मेरे पास बहुत सी क्वेरी यह आती\r\nहै कि भाई चंद्रमा इस नक्षत्र में बैठा है\r\nयहां पर बैठा हुआ है यह ग्रह यहां बैठा\r\nहुआ है मेरी दशा इसकी कैसी जाए\r\nभैया टुकड़े में नहीं देख\r\nसकते एक ग्रह को देख कर के आप उसकी पूरी\r\nदशा उस पर बाकी कुंडली को पूरा देखना होता\r\nहै हर काफी एंगल से उसको हमें देखना है तो\r\nइस तरह के जो टोटके या कहानि आपको मिलती\r\nहै कि सूर्य लगन में बैठा हुआ है ज्यादा\r\nसे ज्यादा क्या बोलेगा सूर्य लगन में अपनी\r\nराशि में बैठा हुआ है क्या फल\r\nहोगा भाई लगन के लिए तो बोल दिया हमने लगन\r\nलगने बली है दोनों है तेरी सेहत ठीक रहेगी\r\nऔर क्या क ठीक ठाक आदमी तो इस तरह के जो\r\nप्रश्न है जो एक ग्रह को लेकर के वह कृपा\r\nकरके आप खुद मनन\r\nकरें और उसका एकदम से बड़ा आसर आपको मिल\r\nजाएगा वो उसकी आप उम्मीद ना करें ये बड़ा\r\nमुश्किल होता है इस तरह से नहीं होता\r\nहै खैर आप देखते रहिए इस तरह से टॉपिक हम\r\nऔर भी कवर करते रहेंगे अब एक फरमाइश आ रही\r\nहै नीच ग्रह पर भी बनाइए कुछ अब सा सात\r\nग्रह हैं कहीं ना कहीं नीच होते हैं 12\r\nराशियां होती\r\nहै तो हर एक ग्रह का\r\nहर राशि के\r\nलिए क्या प्रभाव होगा वह भी कुंडली पर\r\nडिपेंड\r\nकरेगा और उसके क्या नियम है यह आपको खुद\r\nढूंढना पड़ेगा जो मैंने सरल टू में भी\r\nलिखा है पर मैं कोशिश करूंगा कि एकद ग्रह\r\nका आपको विश्लेषण कराया जाए तो इसके साथ\r\nही आपका बहुत-बहुत धन्यवाद\r\nनमस्कार m"},{"topic":"क्या मैं एक घर का मालिक बन सकता सक्ती हूँ","text":"नमस्कार आज फिर हम आपके पास एक नया टॉपिक\r\nलेकर के फिर उपस्थित हुए\r\nहैं और इस टॉपिक के\r\nलिए\r\nबहुत बहुत लोगों का आग्रह\r\nआया और यह टॉपिक आज का है\r\nहमारा कि क्या मैं अपने घर का मालिक बन\r\nसकता हूं मेरा अपना मकान होगा या नहीं\r\nहोगा उसमें आगे की डिटेल में नहीं जाऊंगा\r\nआज वो फिर किसी दिन के लिए\r\nरखेंगे अच्छा घर होगा यह भी तो यह तो आ\r\nजाएगा तो इसको देखने के\r\nलिए बर्थ चार्ट तो है परंतु पराशर जी के\r\nहिसाब से जो मेन चार्ट\r\nहै वो हमारा डी फोर है\r\nमतलब चतुर्थांश\r\nअब चतुर्थांश दो तरह से बनाया जाता है एक\r\nतो जो पराशर जी ने विधि दी\r\nहै उससे हम चतुर्थांश बनाते हैं दूसरा\r\nचतुर्थांश हम बोलते\r\nसाइक्लिकल\r\nक्रमिक चतुर्थांश तो आज हम पराशर\r\nचतुर्थांश की बात\r\nकरेंगे\r\nसाइक्लिकल की बात अभी नहीं बाद में फिर\r\nकिसी दिन वो भी\r\nकरेंगे तो चतुर्थांश बनाना तो आपको आता है\r\nआसान\r\nहै इसमें जो एक मेन चीज होती\r\nहै वो हम हमेशा हर वर्ग\r\nमें हम कोशिश करते हैं और शुरू करते हैं\r\nअपने लगन से लगन और लगन ल तो लगन जो है\r\nवह\r\nहमारी इच्छा को डिजायर को दर्शाता\r\nहै ठीक है और जो लगन लॉड है वह दर्शाता है\r\nकि हमारी इच्छा कैसे पूरी\r\nहोगी\r\nठीक तो यहां से हम देखते हैं कि अगर लगन\r\nपर शुभ प्रभाव\r\nहै तो इच्छा मकान की होने की होती है\r\nइसमें अगर\r\nलगन पाप ग्रह की भी है\r\nऔर वह उसको दृष्ट कर रहा है या विराजमान\r\nहै क्योंकि वह लग्नेश है इसलिए वह इच्छा\r\nदेगा नहीं तो हम नैसर्गिक शुभ ग्रहों को\r\nलेते\r\nहैं उसके बाद हम देखते हैं लग्नेश\r\nके\r\nलग्नेश अगर पीड़ित\r\nहै तो हमारी इच्छा पूरी नहीं\r\nहोती और अगर वह शुभ संबंध में है तो हमारी\r\nइच्छा जल्दी से पूरी हो जाएगी अगर दोनों\r\nशुभ और अशुभ दोनों प्रभाव है तो थोड़ा सा\r\nडिले हो जाता है पर इच्छा पूरी हो जाती है\r\nउसके बाद हमारा नेक्स्ट इंपॉर्टेंट भाव\r\nहोता है चौथा भाव क्योंकि वही प्रॉपर्टी\r\nका चौथा भाव होता है\r\nहमारा तो चौथे भाव के स्वामी को और चौथे\r\nभाव को उसी तरह से एग्जामिन\r\nकरेंगे चौथे भाव का स्वामी ज्यादा\r\nइंपॉर्टेंट है चौथे भाव में अगर त्रिक का\r\nसंबंध आ जाए\r\nत्रिक भाव का चतुर्थांश के त्रिक भाव का\r\nतो वह परेशानिया दे देता है प्रॉपर्टी के\r\nबारे में कुछ ना कुछ कष्ट दे देता\r\nहै\r\nअगर चतुर्थांश का चतुर्थेश या लग्नेश\r\nभी चतुर्थांश में उपचय भाव में विराजमान\r\nहो\r\nतो प्रॉपर्टी देता है कई प्रॉपर्टी भी दे\r\nसकता\r\nहै उच्च का हो तो अच्छी प्रॉपर्टी देता\r\nहै स्वराशि का हो तो भी एक बहुत अच्छी\r\nप्रॉपर्टी दे देगा किसी शुभ ग्रह से दृष्ट\r\nहो चतुर्थ भाव\r\nभी और वह ग्रह भी जो शुभ ग्रह है जितना\r\nबली होगा उतनी अच्छी प्रॉपर्टी देगा\r\nएक चीज और नोट करने की होती है\r\nइसमें वह होता है अष्टम भाव\r\nमें कोई ग्रह नहीं होना चाहिए चतुर्थांश\r\nक्योंकि वह ग्रह हताशा देता है जिसको\r\nइंग्लिश में डिस्पर बोते हताशा देता है कि\r\nउसके बारे में बहुत चिंता करते रहते हैं\r\nयह होगा नहीं होगा क्या\r\nहोगा अब उसको हम देख लेते हैं कि अगर\r\nसूर्य वहां पर\r\nहो तो वह चिंता कराता है अपने सेही अपने\r\nआप चिंता करता है या गवर्नमेंट वाले से\r\nचिंता हो जाती है प्रॉपर्टी के बारे में\r\nचंद्रमा हो तो प्रॉपर्टी अब ये चतुर्थांश\r\nजो है मां का भी चार्ट\r\nहै तो मां के बारे में हताशा होती है मां\r\nको कुछ तकलीफ होगी प्रॉब्लम होगी या मां\r\nसे दुखी हो रहते होंगे तो वह हताशा दे\r\nदेता है और अपनी मेंटल हैप्पीनेस नहीं\r\nरहती\r\nहै उसके बाद मंगल अब मंगल कारक है\r\nप्रॉपर्टी का अब देखिए प्रॉपर्टी के दो\r\nकारक होते\r\nहैं मंगल होता बिल्ट अप प्रॉपर्टी बने\r\nबनाए\r\nमकान\r\nऔर फार्म हाउस वगर जो ओपन फील्ड होते हैं\r\nएग्रीकल्चर प्रॉपर्टी होती है उसका कारक\r\nहोता है शनि\r\nतो यह प्र मंगल जो आठवे में आ जाए तो वह\r\nउसके लिए परेशानी देता है और बुध जो है वह\r\nतकलीफ देता है सुख कहां से नहीं मिलता\r\nइंटेलिजेंस से पढ़ाई से यह पढ़ाई का कारक\r\nबुद्धि का\r\nकारक उसके बाद\r\nबृहस्पति धन और अपने सुख के\r\nलिए हताशा होती\r\nहै कि मैं धन कैसे\r\nउसके बाद\r\nशुक्र शुक्र यह कहता है कि भाई यार सब कुछ\r\nहोते हुए भी मैं एजॉय नहीं कर पा रहा अपनी\r\nलगजरी को इस घर को एजॉय नहीं\r\nकर कुछ ना कुछ परेशानी लग जाती है और शनि\r\nका तो मैंने बताया शनि जो है आसपास की\r\nकॉमन मासे है फ्रेंड्स है ठीक है\r\nऔर स्थान परिवर्तन बार-बार वह स्थान\r\nपरिवर्तन करा देता है दोस्तों से सुख\r\nनहीं तो यह मोटा मोटी डी फोर का हमने देखा\r\nहै काफी इंपॉर्टेंट है और इसके बारे में\r\nबहुत सी रिक्वेस्ट भी आई थी तो अब मैं\r\nआपसे कुछ चार्ट लेकर के जैसा हमेशा करते\r\nहैं हम उसको देखेंगे एक और नियम मैं बता\r\nरहा हूं बहुत से लोगों का मकान नहीं होता\r\nअपना नहीं होता\r\nपरंतु वह गवर्नमेंट के मकान में\r\nरहते उसमें वो होता\r\nहै चतुर्थांश\r\nमें फोर्थ लॉड चतुर्थेश और सप्तमेश इनका\r\nसंबंध आ\r\nजाए\r\nया जन्म के चतुर्थेश और जन्म के सप्तमेश\r\nयह दोनों का संबंध चतुर्थांश में आ जाए अब\r\nभाई साहब बहुत से तो गवर्नमेंट ऑफिसर होते\r\nहैं गवर्नमेंट के मकान में रहते हैं और एक\r\nऔर गवर्नमेंट का मकान होता है\r\nभाई वह क्या होता है\r\nजेल तो वह मकान आपका जेल भी हो सकता है यह\r\nध्यान\r\nरखना चलिए अब हम देखते हैं एकद कुंडली हम\r\nएग्जामिन करते हैं\r\nयह पहली कुंडली है\r\nभाई अब यहां पर जन्म कुंडली जन्म डिटेल\r\nहमने सब दे द है हम अपना देखने का तरीका\r\nशुरू करते\r\nहैं चतुर्थांश\r\nमें टोरस वृषभ लगन उदय हो रही\r\nहै उस पर कोई संबंध\r\nनहीं मतलब न्यूट्रल हू मिल गई प्रॉपर्टी\r\nतो ठीक है नहीं मिली तो ठीक परंतु लग जो\r\nहै वह पाप करतरी में है अब यह आप देख लो\r\nभाई ठीक है वह पाप करतरी\r\nहै तो\r\nइसलिए तकलीफ तो\r\nहोगी मकान वगैरह जायदाद आने में संघर्ष\r\nकरना\r\nपड़ उसके बाद हम देखते\r\nहैं\r\nचतुर्थ च भाव के स्वामी चतुर्थ भाव में\r\nशुभ हम शुभ मानेंगे नैसर्गिक शुभ है बुध\r\nमहाराज बैठे\r\nहुए और चंद्रमा से\r\nदृष्ट ठीक है चतुर्थेश जो है वह अष्टम भाव\r\nमें अभी हमने बताया कि यह गवर्नमेंट से\r\nकष्ट देते हैं प्रॉपर्टी के बारे\r\nमें इसमें परेशानी आती रहती है तो\r\nगवर्नमेंट के झगड़े कभी टैक्स का कभी इसका\r\nकभी प्रॉपर्टी टैक्स का कभी अनऑथराइज्ड का\r\nउसका यह सब चक्कर होते\r\nरहते ठीक है अब\r\nयहां आठवे भाव का भी हमने देख लिया यहां\r\nपर अब एक और चीज आप देखो\r\nइसमें मंगल जो कारक है प्रॉपर्टी\r\nके वह स्वराशि में बैठे हुए 12\r\nपर स्वराशि\r\nके तो यह प्रॉपर्टी दिला देंगे\r\nअब यहां\r\nपर शनि और चंद्रमा जो दशम में बैठे अच्छा\r\nहै जुपिटर अब जो लग्नेश था हा लग्नेश की\r\nबात करना भूल गए थे लग्नेश शुक्र\r\nहै और वो उच्च राशि के बृहस्पति के साथ\r\nविराजमान\r\nहै और मंगल से\r\nदृष्ट मंगल कारक है परंतु दृष्टि फिर भी\r\nहम कहेंगे अच्छी नहीं\r\nहै मंगल से दृष्ट\r\nहै परंतु शुक्र\r\nका उच्च के बृहस्पति के होने के कारण\r\nइनको शुक्र की दशा में अच्छी प्रॉपर्टीज\r\nकी का लाभ मिला अच्छी खासी प्रॉपर्टी इनको\r\nमिली ठीक है\r\nजी अब यहां पर आप\r\nदेखो जुपिटर बहुत अच्छी पोजीशन में\r\nहै ठीक है अब नेक्स्ट चार्ट\r\nदेखते यह चार्ट है इनके पास भी प्रॉपर्टी\r\nहै देर से आई है\r\nलगन में राहु विराजमान\r\nलग्नेश की तरह काम कर\r\nरहे यहां अच्छी बात क्या\r\nहै कि यह अब पिछले चार्ट में पाप करतरी था\r\nलगन प यहां पर बृहस्पति लगन की तरफ जा रहे\r\nहैं शुभ करतरी दे रहे हैं और चंद्रमा भी\r\nलगन की\r\nतरफ चंद्रमा अपनी उच्च राशि\r\nको लग्नेश जो है\r\nवह उच्च राशि में है और उपचय भाव में अब\r\nस्ट्रिक्टली तो उपचय नहीं होगा क्योंकि\r\nदशम भाव\r\nखाली तो यह भी बहुत अच्छी पोजीशन में\r\nअच्छी प्रॉपर्टी दिलाने के मूड में है और\r\nकारक भी एस्पेक्ट कर\r\nरहे कारक जब भी भावेश के साथ संबंध बनाता\r\nहै तो भी वह अच्छा माना जाता है इनके\r\nअष्टम भाव में कोई नहीं\r\nहै ठीक है जी तो इनको भी अच्छी खासी\r\nप्रॉपर्टी की का लाभ हुआ और सबसे ज्यादा\r\nप्रॉपर्टी अब आप यह देखो राहु लगन में\r\nहै और लग्नेश उच्च के हैं सबसे ज्यादा\r\nप्रॉपर्टी राहु की दशा में आनी शुरू\r\nहुई सबसे ज्यादा अच्छी प्रॉपर्टी\r\nठीक है अब नेक्स्ट चार्ट देखते\r\nहैं अब यह चार्ट\r\nदेखिए यहां पर शनि महाराज लगन में बैठे\r\nहुए हैं और बृहस्पति देख\r\nरहे इसने डिजायर जो है वो दे दी है अब\r\nयहां पर भी देखिए चतुर्थेश चतुर्थ\r\nमें राहु है मरकरी है और बुध बुध है और\r\nशुक्र शुक्र का और बृहस्पति का एक्सचेंज\r\nहै नाइंथ हाउस में नाइंथ और फोर्थ\r\nका नाइंथ\r\nलॉर्ड चतुर्थ में है और चतुर्थ शेष नाइंथ\r\nमें ये बड़ा अच्छा योग बन गया है और\r\nचतुर्थ\r\nउच्च राशि के चंद्रमा के साथ\r\nहैं तो यह भी बढ़िया प्रॉपर्टी दिला रहे\r\nभाई शनि डिले कर देता है थोड़ा सा और\r\nअच्छी बात है के अष्टम भाव में कोई ग्रह\r\nनहीं\r\nहै अब यहां पर चतुर्थेश और सप्तमेश एक ही\r\nहै\r\nतो यह गवर्नमेंट के मकान में रहने का भी\r\nथोड़ा सा नियम थोड़ा सा रूल लग रहा है\r\nदोनों सेम\r\nहै तो जब भी\r\nबृहस्पति से कनेक्टेड दशा आएगी तो\r\nगवर्नमेंट के दशा उसम य रह\r\nलेंगे और थोड़े दिन जब तक 10 साल जब\r\nसरकारी नौकरी में रहे तो 10 साल के करीब य\r\nशुक्र की दशा में\r\nसरकारी गवर्नमेंट के आवास में\r\nरहे अब इसके बाद एक चार्ट और लेते हैं\r\nभाई यह उनका चार्ट है जो विदेश में रहते\r\nथे और विदेश छोड़ कर के यहां पर आकर के\r\nइन्होंने प्रॉपर्टी\r\nलेली अब\r\nये अब ये क्योंकि स्पेशल पॉइंट है उसको\r\nमैं पहले ले रहा\r\nहूं\r\nशनि अष्टम भाव\r\nमें हताशा अपने सुख की हताशा अपने दोस्तों\r\nसे मित्रों से साथ के संबंधियों से उनसे\r\nहोती\r\nहै तो आकर\r\nके इन्होंने अपने मित्रों के पास वहां पर\r\nमकान ले लिया वहां रहने लग गए परंतु कोई\r\nज्यादा बड़ी हेल्प उनसे\r\nनहीं मिल\r\nरही तो उसको यह लगता है यार हम\r\nक्यों अब लगन देख\r\nलो लगन में कोई दृष्टि नहीं\r\nहै तो न्यूट्रल है प्रॉपर्टी बाहर य जहां\r\nरहे फॉरेन में वहां प्रॉपर्टी थी\r\nइनकी परंतु रहने के लिए भाई चाहिए अगर 25\r\nसाल आप फॉरेन में रह रहे हैं तो\r\nलग्नेश सूर्य खुद जाकर के चतुर्थ भाव में\r\nविराजमान हो गए बल दे रहे चतुर्थ भाव को\r\nऔर कारक के साथ है कारक स्व राशि में है\r\nमजा आ गया ना अच्छी प्रॉपर्टी होई\r\nऔर चतुर्थेश\r\nस्वय राशि के शुक्र से इनका संबंध आ रहा\r\nहै दृष्ट कर\r\nरहे ब माइनस पॉइंट थाय शनि का\r\nतो इनकी भी प्रॉपर्टी\r\nरही चतुर्थ भाव चतुर्थेश\r\nउसको देखना जरूरी होता है अब एक चार्ट और\r\nलूंगा वह बड़ा इंटरेस्टिंग चार्ट मैंने\r\nढूंढ के निकाला है और आपको वह शेयर करता\r\nहूं एक फर्म\r\nके कुंडली है अब य देखो\r\nलगन पर बृहस्पति की\r\nदृष्टि इच्छा तो\r\nहै लग वो इच्छा पूरी होगी या नहीं\r\nहोगी अब वह जो लग्नेश है वह खुद जाकर के\r\nअष्टम भाव में\r\nबैठ फिर हताशा दिखा दी मकान के लिए हताशा\r\nमकान में सुख नहीं मिलेगा दोस्तों से सुख\r\nनहीं\r\nमिलेगा चतुर्थ भाव\r\nमें चंद्रमा\r\nहै और सप्तमेश चंद्रमा चतुर्थ में है और\r\nचतुर्थेश\r\nमंगल सप्तम में तो चौथे\r\nऔर सातवे का हमारा संबंध आ\r\nगया लगन के\r\nचतुर्थेश है शुक्र और दशमेश सप्तमेश है\r\nशनि शनि अष्टम भाव\r\nसे शुक्र को दृष्ट कर रहे हैं शुक्र बली\r\nहै स्वराशि का\r\nहै तो अब इसका मकान होगा भाई मतलब\r\nगवर्नमेंट के मकान में रहेगा\r\nय खुद की इच्छा तो\r\nहै परंतु शनि महाराज में चले गए और बुध का\r\nसंबंध है\r\nसिर्फ बुध जो है शश भी है अब यहां आप देखो\r\nके बुध का संबंध टश से टश भी है\r\nबुध तो ये लग्नेश को शश भी दृष्ट कर रहे\r\nहैं तो यह मकान के बारे में डिस्प्यूट\r\nतकलीफ देते हैं अब मैं राज खोल देता हूं\r\nयह एक क्रिमिनल की कुंडली है जिन्होंने\r\nबहुत सारे मर्डर किए और इनको जेल में\r\nसरकारी आवास में रहने का मौका मिला वो जेल\r\nमें रहे ठीक है है ना\r\nबढ़िया\r\nठीक तो ये आज का\r\nहमारा टॉपिक था इंटरेस्टिंग है ये\r\nटॉपिक तो चतुर्थ भाव सुख का भाव है और\r\nप्रॉपर्टी का भाव है मां का भाव है\r\nचतुर्थ चतुर्थ भाव को\r\nदेखकर तो इस पर आप देखिए क्या\r\nहै और आगे इस तरह से और मिलते रहेंगे\r\nनमस्कार थैंक यू वेरी मच"},{"topic":"जल्दी, समय पर और देर से विवाह की संभावना","text":"नमस्कार मित्रों आज फिर आपके सामने एक बहुत\r\nही सर्वप्रिय विषय लेकर के आया\r\nहूं और इस विषय के बारे में बहुत लोगों की\r\nक्वेरीज और सवाल आ रहे हैं हम नवांश प पहले भी वीडियो बना चुके\r\nहैं कि विवाहित जीवन सुखी रहेगा कैसा रहेगा मल्टी पर्पस कई विवाह वह भी हम बना\r\nचुके हैं आज हम एक बिल्कुल शुरुआती\r\nप्रश्न शादी के बारे में विवाह के बारे में उस पर चर्चा करने जा रहे\r\nहैं ज्यादातर यह सवाल पूछा जाता है कि भाई विवाह कब हो अब मैं आज एजेक्ट डेट तो नहीं\r\nबता रहा हूं परंतु हम तीन टॉपिक किई विवाह की संभावना को देखा कैसे\r\nजाए कि किस उम्र के स्पैन में टाइम में\r\nहमारा विवाह संभव है तो उसके लिए हम नवांश का प्रयोग करते\r\nहैं और यह जो आज मैं पद्धति बता रहा हूं यह बहुत जगह मैं शेयर कर चुका\r\nहूं कई वेबीनार में कर चुका हूं तो मैं यह सोचता था शायद आपको ज्ञान\r\nहोगा परंतु मैं फिर से आज शेयर कर देता हूं यह बहुत मेरी शुरुआती रिसर्च में से\r\nहै इसके लिए मैं थोड़ा सा बैकग्राउंड पर\r\nजाऊ पहला तो यह कि किसी भी वर्ग में वर्ग कुंडली\r\nमें जो लगन होती है वो हमारी उस वर्ग कुंडली के प्रति इच्छा\r\nको दर्शाती है यह तो भाव लग और जो भावेश होता\r\nहै वोह करता होता है वह कार्य कराने वाला होता\r\nहै और कारक सुंदरता होती है आज उस पर तो बात नहीं कर रहा तो यह\r\nनियम हर वर्ग कुंडली पर लगता है इसीलिए इसको मैंने सरल ज्योतिष\r\nबोला जब यह ज्ञान प्राप्त हुआ था थोड़ा सा तब से मैंने सरल इस्तेमाल करना शुरू किया\r\nथा सरल का प्रयोग कर अब इसको हम नवांश पर लगाते\r\nहैं नवांश को हम विवाह का चार्ट मान कर के\r\nचल रहे हैं कि यह विवाह को दिखाने वाली कुंडली है इसके और भी बहुत प्रयोग है परंतु हम आज\r\nइसको विवाह का चार्ट मान के चल रहे हैं तो जैसा हमने\r\nकहा के नवांश की लगन लग्नेश नहीं बोल रहा लगन पहले लगन\r\nएेंट राइजिंग साइन इन नवा वह आपकी विवाह के प्रति इच्छा दिखाता\r\nहै डिजायर दिखाता है य पर एक चीज मैं बता\r\nदूं कि नवांश का जब भी आपको न डिग्री 20 मिनट 6 40 10 डिग्री ऐसा नवांश के बिल्कुल\r\nसमीप आपको लगन की डिग्रीज मिले तो आप पहले पक्का कर ले कि आपका नवांश सही\r\nहै क्योंकि बहुत सी दफे नवांश आपका 330 आ रहा है 3 30 डिग्री आ रही है लगन में 0 पर\r\nनवास चेंज हुआ है तो भैया क्या समय में आपके एक मिनट भी अगर डिफरेंस था तो पुराने\r\nवाला नवा और बहुत से इसको अप्लाई करते हुए कहते हैं कि यह आपका प्रिंसिपल ठीक नहीं लग रहा\r\nहै मैं उनसे यही कहता हूं भैया आपकी उम हो गई है विवाह हो गया है या होने वाला है तो\r\nआप पहले नवां को शुद्ध कर पर यह जो प्रिंसिपल है यह पक्का लागू\r\nहोता है अब मैं प्रिंसिपल पर आता हूं नियम पर तो\r\nलगन हमारी इच्छा को दर्शाता है कि मैं विवाह करना चाहता\r\nहूं या नहीं या बहुत ज्यादा इच्छा नहीं हो जाए तो ठीक है नहीं हो तो ठीक है तो यहां\r\nसे तो हमने इच्छा अब ये इच्छा कैसे देखते हैं अगर नवांश की लगन\r\nपर केवल शुभ ग्रह की दृष्टि आ रही हो तो हम कहते हैं कि भाई विवाह की इच्छा\r\nहै और अगर केवल पाप ग्रह की अशुभ ग्रह की दृष्टि आ रही हो तो हम कहेंगे कि विवाह की\r\nइच्छा नहीं है अगर दोनों दृष्टि आ रही है\r\nशुभ भी है अशुभ भी है तो व शशो पंज में है कर लूंगा यार हो\r\nजाएगी तो हो जाएगी नहीं होती तो भी ठीक है मतलब शप इच्छा तो है पर वो दिखाता है नहीं\r\nभाई नहीं होगी तो कोई ऐसी बात तो यह तो हुई लगन की बात अब हम लेते\r\nहैं लग्नेश नवांश का लग्नेश जो करता है कार्य\r\nकराएगा वो मालिक है लग्नेश है वो ठीक से काम कराएगा या नहीं कराएगा\r\nअब ये आगे ध्यान से सुनना क्योंकि बहुत कॉमिनेशन परम्यूटेशन\r\nबनेंगे इस मैं पहले से शुरू करता हूं मान\r\nलीजिए लगन पर केवल शुभ प्रभाव\r\nहै मतलब व्यक्ति की विवाह की इच्छा है\r\nऔर लग्नेश का भी केवल शुभ से संबंध\r\nहै तो वह तुरंत इच्छा पूर्ति करा देगा मतलब उसका विवाह जल्दी करा\r\nदेगा अभी मैं लगन पर केवल शुभ ले रहा हूं और उसके\r\nपरटेन लगन पर शुभ संबंध है और लग्नेश पर केवल पाप संबंध\r\nहै क्या मीनिंग हुआ इच्छा तो है मेरी परंतु मेरा जो करता है कार्य करने\r\nवाला है वह कहता है नहीं मैं तो इच्छा तेरी पूरी नहीं होने देता है देर में\r\nकरूंगा मैं इच्छा नहीं पूरी होने दे रहा तेरी तो वह विवाह में देरी कराएगा जब तक\r\nदशा नहीं विवाह कब होगा जब लगने पर कोई एक शुभ\r\nसंबंध छोटा सा भी आ जाए तब संभावना बनती\r\nहै तीसरी पोजीशन होगी के लगन पर केवल शुभ\r\nसंबंध है परंतु लग्नेश पर मिला जुला संबंध शुभ\r\nभी है अशुभ भी अब कौन सा संबंध बली\r\nहै मान लीजिए शुभ ग्रह अपने उच्च राशि में स्वराशि में इसमें है तो वो ज्यादा बली है\r\nतो अशुभ प्रभाव थोड़ा कम होगा और शुभ प्रभाव ज्यादा आ जाएगा डिले तो\r\nहोगी पर बहुत ज्यादा लंबी चौड़ी डिले नहीं होगी केवल अशुभ प्रभाव\r\nहो स्ट्रांग अशुभ प्रभाव हो तो वो डिले लंबा\r\nहो तो ये हमने बात की जब लगन पर केवल शुभ संबंध है अब अगला सुनिए बड़ा\r\nध्यान से सुनना है यह नियम लगन पर केवल अशुभ संबंध\r\nहै तो व्यक्ति की विवाह की इच्छा नहीं\r\nहै परंतु लग्नेश शुभ संबंध में है\r\nतो वह क्या कह रहा है बेटे तेरी इच्छा में पूरी करा मैं तो करता हूं ना जो तेरी इच्छा\r\nपूरी कर दूंगा क्योंकि शुभ संबंध है मेरे साथ तो वह विवाह में बहुत डिले देगा या\r\nविवाह नहीं होने देगा आप देखो लगने शुभ\r\nसंबंध में है और लगन केवल पाप संबंध में\r\nहै बहुत लंबा डिले देगा या विवाह नहीं देगा\r\nविवाह तब देगा जब छोटा सा भी शुभ संबंध लग्नेश के साथ दूसरी\r\nपरिस्थिति लगन पर केवल अशुभ संबंध\r\nहै और लग्नेश पर भी केवल अशुभ संबंध\r\nहै दोनों पीड़ित है अब इच्छा क्या है मुझे शादी नहीं\r\nकरनी लग्नेश कहता है बेटा मैं तेरी इच्छा पूरी नहीं होने दूंगा\r\nक्योंकि मेरे साथ कोई शुभ संबंध नहीं है मैं तो इच्छा पूरी नहीं होने देता ऐसे में विवाह जल्दी हो जाएगा\r\nभैया लगन पर पाप संबंध है लग्नेश पर भी\r\nपाप संबंध है व जल्दी करा देगा शुभ संबंध आ ग थोड़ा डिले कर\r\nदे मुझे पता है इस पर आप बहुत क्वेश्चन पूछेंगे परंतु ध्यान से सुनकर जब अप्लाई\r\nकर तीसरी पोजीशन के लगन के साथ केवल अशुभ संबध\r\nहै और लग्नेश के साथ शुभ और अशुभ संबंध\r\nदोनों तो भी वह डिले देके मैरिज करा\r\nदेगा ठीक है जी अब तीसरा है मिक्स उसमें\r\nअब बुद्धि लगानी पड़ेगी थोड़ी सी आप लोगों को कि लगन पर शुभ भी है अशुभ भी\r\nहै और लग्नेश पर भी शुभ भी है अशुभ भी है\r\nअब य इसमें भी हो सकते हैं लगन पर शुभ और अशुभ दोनों प्रभाव\r\nहै पहला तो आपको ये डिसाइड करना पड़ेगा कौन सा प्रभाव बली\r\nहै अब लग्नेश के ऊपर के साथ यदि केवल शुभ संबंध\r\nहै तो वो इच्छा पूरी कर रहा है आपकी डिले की इच्छा है बहुत ज्यादा डिजायर नहीं है\r\nशादी करने की पर लग्नेश कहता है मैं तेरी इच्छा पूरी करूंगा अगर शुभ के साथ है अगर\r\nलग्नेश के साथ केवल पाप संबंध है तो वह कहता है मैं तेरी इच्छा पूरी नहीं\r\nकरूंगा तो यह सब जो मिक्सचर है इन दोनों को आपको एनालाइज करना आना\r\nचाहिए जितना अच्छे से आप एनालाइज कर लेंगे\r\nउतना अच्छा फल आप दे सकते दूसरा इसमें टाइमिंग के बारे में\r\nबहुत लोग पूछे अब स्पैन तो पता चल गया जल्दी होगी देरे में होगी समय पर हो जाएगी\r\nतो अब यह जो क्राइटेरिया है कि किसको जल्दी माना जाए किसको समय पर\r\nमाना जाए किसको देरी से तो यह देश काल पात्र के हिसाब से बदलता\r\nरहता है बहुत प लड़के की 18 साल की उम्र\r\nहुई 15 16 साल का लड़की हुई 21 का लड़का\r\nहुआ शादी हो जाती थी वह नॉर्मल ज मानी जाती थी तो हम शीघ्र को जल्दी को उसको\r\nमानेंगे जब इससे पहले शादी उसके बाद थोड़ा सा चेंज\r\nहुआ लड़कों की उम्र 25 साल के करीब मान ली गई कि भाई 25 साल प लड़के की शादी हो जानी\r\nचाहिए और लड़की की 18 साल 19 साल में शादी हो जानी उसके बाद य और बढ़ कर के लड़कियों के\r\nलिए भी 21 22 साल हो गई और लड़के भी 25 26 साल 28 साल 30 साल तक आजकल के जमाने में\r\nउसको सही आयु मानते हैं तो यह देश काल पात्र है तो जिस समय की कुंडली है आपको\r\nउससे देश काल पात्र देख करके चलना पड़ेगा\r\nसमाज भी देखना पड़ेगा और क्या उस समय की धारणा है समाज की और आप\r\nजिस समाज से बिलोंग करते हैं उसमें क्या ार यह देशकाल पात्र का रूल है दूसरा अब जो\r\nभी ग्रह विवाह दे रहा है इस एनालिसिस में शुभ आ रहा है वो इच्छा\r\nपूरी करा रहा है अगर विवाह की इच्छा पूरी करा रहा है क्योंकि इच्छा\r\nहै तो उस ग्रह से रिलेटेड ग्रहों की दशाओं में शादी हो\r\nजाएगी तो यही से आप अपना नियम लगा सकते हैं मैं जो आज चार्ट लूंगा उसमें भी आपको\r\nथोड़ा सा इसमें बता और अगले वीडियो में मैं\r\nआपको विवाह ना होने के योग द कि कैसे देखे विवाह नहीं होगा या बहुत\r\nजल्दी विवाह हो आयु से भी पहले तो वह योग हम अगले वीडियो में\r\nकरेंगे तो आज के इसी सस रूल्स के हिसाब से हम लेकर के आज चार्ट\r\nदेखते हैं रूल में फिर से सूत्र तुरंत बता देता हूं जल्दी से रिपीट कर देता हूं\r\nके नवांश की लगन आपकी इच्छा है नवांश का\r\nलग्नेश आपकी इच्छा को पूर्ति करने वाला करता है या कारक है आपकी इच्छा है शुभ\r\nग्रह के द्वारा इच्छा नहीं है वह अशुभ ग्रहों के\r\nद्वारा कर्ता आपकी इच्छा पूरी करेगा अगर वह शुख के साथ है\r\nइसका जो एक बहुत सीरियस पॉइंट जो बोला है मैंने के लगन पर अशुभ दृष्टि है केवल अशुभ\r\nदृष्टि है आप विवाह नहीं करना चाहते परंतु लग्नेश पर भी अशुभ संबंध है\r\nशुभ संबंध नहीं है आपका विवाह जल्दी हो जाएगा क्योंकि वह करता जो है कहता बेटे\r\nतेरी इच्छा में पूरी नहीं होने द ठीक है तो यह बड़ा इंटरेस्टिंग हो गया\r\nहै सब्जेक्ट अब हम जल्दी से कुंडलिया देख लेते हैं और समझते\r\nहैं यह लीजिए पहली कुंडली यह डॉक्टर राजेंद्र प्रसाद\r\nकी उन दिनों जल्दी की बैरिज सोचना चाहिए अभ य हम\r\nएनालाइज करते हैं अपने प्रिंसिपल लगन में शनि महाराज\r\nबैठे तो कहते हैं शनि महाराज कह रहे भैया मैं तो शद इच्छा नहीं है मेरी विवाह की\r\nनवाज की बात कर रहा हूं मेरी इच्छा नहीं\r\nहै अब देखो लग्नेश क्या कह रहे हैं लग्नेश बुद्ध\r\nहै वह मंगल के साथ विराजमान है\r\nलगन पर कोई शुभ दृष्टि नहीं है पूरत कहते मैं शादी नहीं\r\nकरनी और लग्नेश बुध पे भी कोई शुभ संबंध\r\nनहीं है तो लग्नेश मास्टर कहते हैं नहीं बेटे\r\nमैं तो तेरी इच्छा पूरी नहीं होने देता मैं तो तेरी शादी जल्दी\r\nकरा इनकी शादी हो गई जब यह 13 साल के थे\r\nमें टोरस में चंद्रमा है 23 20 पर\r\nअभी चंद्रमा की महादशा खत्म हुई है और मंगल की महादशा में यह पैदा हुए तो\r\nमंगल के सात साल और राहु की फिर 18 साल की दशा हो गई तो राहु की दशा में इनका विवाह\r\nहो गया अब यहां देख लो विवाह देने वाला कौन है सबसे ज्यादा बृहस्पति\r\nशुभ संबंध में है सप्तमेश है और राहु उनके साथ नवांश में विराजमान है दूसरे शुभ\r\nशुक्र से दृष्ट है तो राहु की दशा में इनका विवाह हो\r\nगया यह सिर्फ हिंट है बाकी एनालिसिस तो पूरी तरह से करना पड़ेगा अब यह चार्ट\r\nहै 1933 की बर्थ\r\nएक स्त्री का चार्ट है यहां पर भी हम देखते भाई क्या सिचुएशन\r\nआ रही है सेम क्योंकि वह रूल मेरे को बहुत\r\nट्रिकी है कि लगन पर केवल पाप ग्रह और उस पर पाप ग्रह लग्नेश पर\r\nभी इसके लिए मैंने यह चार्ट दो लिए हैं अब यहां देखो लगन पर केवल शनि फिर से बैठे\r\nहुए कोई शुभ संबंध नहीं है लग्नेश फिर बुध\r\nहै शनि से भी दृष्ट है मंगल से भी दृष्ट\r\nहै अब जो लग्नेश है वो कह रहे भैया मैं तो बिल्कुल तेरी इच्छा पूरी नहीं होने\r\nदूंगा यह स्त्री की कुंडली है इनका विवाह 48 या 49 में हो\r\nगया जब ये 16 साल की थी 15 कंप्लीट करके सवे साल में लगी थी इनका विवाह हो\r\nगया अब विवाह कब हुआ क्यों हुआ दशा देख लो अब यहां चंद्रमा जो\r\nहै 132 के करीब करब 1640 पर शनि खत्म हो\r\nजाएंगे तो शनि की चार पाच साल की जन्म की दशा मिल गई और उसके बाद इनकी बुध की\r\nदशा चालू हो गई ठीक है बुध की दशा में इनका विवाह हो\r\nगया क्योंकि वोह लग्नेश है वह कहते मैं नहीं पूरी होने दूंगा तेरी\r\nइच्छा जो है उससे विपरीत कर रहा हूं मैं तो बुध की दशा में इनकी इनका विवाह हो\r\nगया ठीक है अब नेक्स्ट चार्ट पर आते\r\nहैं यह चार्ट जो पिछली पिछला चार्ट था उनके पति पति का\r\nहै अब 48 में 4849 में शादी हुई तो 25 पार\r\nकर चुके थे 25 साल की उम्र इनकी हो गई थी और सन 23\r\nमें 25 साल को थोड़ा सा लेट माना जाता था टाइम से थोड़ा सा ज्यादा 21 22 में शादी\r\nहो जाती बंदे ने ग्रेजुएशन करा खत्म अब यहां देखो लगन को\r\nलगन पर शुक्र की दृष्टि आ रही\r\nहै और मंगल की भी दृष्टि आ रही\r\nहै शुक्र की दृष्टि सप्तम दृष्टि है और\r\nमंगल की दृष्टि अष्टम दृष्टि तो यह बीच का सा केस है भाई इच्छा\r\nभी है शुक्र दिखा रहा है और कोई ना हो तो\r\nभी ठीक है आईम कैरिंग न अब हम देखते हैं शनि\r\nमहाराज जो लग्नेश अब यहां इसने\r\nचमत्कार शनि सूर्य के साथ है सूर्य इनके\r\nडिस्पोजिटर अष्टम भाव में बैठे हुए हैं और वह लियो है सा तो उस साइन के लिए मैं सूर्य को बहुत\r\nज्यादा पापी नहीं मानूंगा पापी है मतलब र थोड़े से अब मजे की बात क्या बृहस्पति\r\nदेख वो कह रहे मैं तेरी इच्छा पूरी करा दूंगा सूर्य कहता थोड़ी सी ऑब्स्ट कल\r\nदूंगा तो इनका विवाह 25 साल की उम्र में दोनों दोनों इफेक्ट आ रहे हैं शुभ भी है\r\nअशुभ भी है अशुभ कम शुभ संबंध अच्छा है\r\nबृहस्पति ठीक है अब इनकी दशा चक कर लो जरा सा अब ये चंद चंद्रमा जो है ये 25 20 के है 26\r\n40 से शुक्र की दशा शुरू हो गई और केतु की जरासी मिल\r\nगई सॉरी वीनस की थोड़ी सी दशा मिल गई तो वीनस\r\nकी दशा के बाद इनको मिली सूर्य की दशा 6 साल की सूर्य के बाद चंद्रमा की दशा\r\n10 साल की 10 16 17 ठीक है सूर्य के बाद चंद्रमा मिल गए 16 17 साल\r\nकी उम्र हो गई चंद्रमा के बाद मंगल 22 2 साल की उम्र हो गई उसके बाद आई राहु की\r\nदशा और राहु में विवाह हो गया एक मिनट यार कोई गलती तो नहीं कर\r\nरहा चंद्रमा की दशा एक सेकंड केतु केतु\r\nशुक्र शुक्र का लास्ट इनको मिला थोड़ी सी दशा शुक्र की मिल गई उसके\r\nबाद सूर्य की मिली 6 साल की उसके बाद चंद्रमा की मिली 10 साल की 10 और छ 16 17\r\nसाल की उम्र हो गई चंद्रमा के बाद मंगल की तो मंगल की दशा में इनका विवाह हो जाना\r\nचाहिए ज्यादा से ज्यादा रा मैंने एजेक्ट कैलकुलेट नहीं किया है तो यहां पर देखिए\r\nमंगल को और राहु राहु यहां पर नवम भाव में बैठे हुए\r\nहैं मंगल से दृष्ट है चंद्रमा से संबंध नहीं\r\nबना तो यहां इसके लिए हमें और ज्यादा काम करना पड़ेगा दशा देखने के लिए परंतु इनसे\r\nरिलेटेड जो ग्रह बृहस्पति जो दशा दिखा रहे\r\nबृहस्पति तो बृहस्पति ज्यादा इंपॉर्टेंट हो जाते बृहस्पति मरकरी के साथ है शनि को\r\nदेख रहे हैं सूर्य को देख रहे हैं तो यह ज्यादा ग्रह इंपॉर्टेंट हो जाते हैं विवाह\r\nके अब इसके बाद एक लास्ट चार्ट हम लिखते\r\nहैं इस चार्ट को आप देखिए इच्छा\r\nथी केतु लग्नेश की तरह अब इसमें एक बात बता रहा हूं लगन में राहु या केतु होते हैं तो वह उसी\r\nके स्वामी की तरह का फल देते तो केतु यहां बुरा नहीं माना जाएगा\r\nक्योंकि शुक्र दृष्ट कर रहे हैं और कोई पाप संबंध\r\nनहीं तो विवाह की इच्छा बहुत है काफी प्रबल इच्छा है अब मैं लग्नेश को\r\nदेखता हूं लग्नेश है बृहस्पति बृहस्पति बली है\r\nऔर एक बली शनि के साथ है अष्टम भाव कोई और शुभ प्रभाव नहीं\r\nहै शुभ प्रभाव नहीं है तो शनि ने काफी लंबा डिले दे दिया\r\nक्योंकि इच्छा थी विवाह की यह ना विवाह होने की कुंडली क्यों नहीं\r\nबनी वह हम अगले लेक्चर में देखेंगे इनका\r\nविवाह 38 इयर्स की उम्र में 38 साल के बाद ठीक है तो अब य इनकी\r\nथोड़ी सी दशा का एनालिसिस कर लेते हैं चंद्रमा 20 डिग्री पर राहु खत्म हुआ उसके\r\nबाद बृहस्पति की दशा शुरू हुई बृहस्पति एक चरण तकरीबन निकल गया है\r\nतो 10 12 साल बृहस्पति की दशा रही उसके बाद 19 साल की इनकी शनि की दशा\r\nरही और शनि की दशा के बाद बुध की दशा आ उसमें विवाह हुआ अभी आप बुध को देखो\r\nसप्तमेश है बृहस्पति से दृष्ट है लग्नेश से सप्तमेश लग्नेश का संबंध आ गया है तो\r\nबुद्ध ने इनको विवाह\r\nदिया ठीक है अभी मैं सप्तमेश की करके बात नहीं कर रहा हूं व आगे फिर कभी लेंगे वो\r\nचैप्टर भी कि सप्तमेश को कैसे देखते हैं ठीक है तो यह\r\nहमारा चार कुंडलियों का हमने विश्लेषण किया और केवल नवांश से किया इससे हमको\r\nथोड़ा सा आयु का किस आयु में विवाह होगा\r\nउसका ज्ञान प्राप्त हो जाता है कि डिले है क्या बात है अगले वीडियो में हम इसको और\r\nएनालाइज करेंगे मैं फिर से रिपीट कर रहा हूं कि\r\nमेरे पास जब यह मैंने बहुत पहले रिसर्च की थी और इसको पढ़ाना शुरू किया था तो लाइव\r\nवेबीनार में लोग कुंडली लगाते थे और कहते थे सर ये अप्लाई नहीं हो\r\nरहा तब मैं उनसे कहता था आपका जन्म समय कितना ठीक है कम से कम नवांश तो करेक्ट कर\r\nलो यार तो उनके ज्यादातर मेरे को नवांश जहां\r\nचेंज होता है 3 20 6 40 10 डिग्री 13 डिग्री उसके आसपास लगन मिलती थी और जैसे\r\nही लवांस करेक्ट होता था उनकी वह कहानी बिल्कुल यह रूल लगते थे तो अगर कोई यह\r\nकहेगा कि य रूल नहीं लगता है मैं उसको स्वीकारने वाला नहीं\r\nहूं क्योंकि यह रूल कम से कम कम से कम 20 साल 15 20 साल 18 साल पुराना अप्लाइड है\r\nइसको मैं हर जगह अप्लाई कर चुका हूं और कहीं भी मेरे को फेलर नहीं\r\nमिला खैर प्रश्न उठाने वाले तो उठाते ही हैं\r\nपरंतु उसको ठीक से अप्लाई करो और सीखने के\r\nहिसाब से इसको लो यह बिल्कुल सटीक नियम लगेगा ठीक है इसी के साथ मैं आपसे आज विदा\r\nलेता हूं और फिर अगला वीडियो हम नो मैरिज पे या बहुत पहले मैरिज पे बनाएंगे उसके\r\nलिए हमें एक और वर्ग का सहारा लेना पड़ता है इसलिए मैंने वह आज नहीं लिया क्योंकि\r\nफिर मैं उस वर्ग को लेकर के चल नमस्कार"},{"topic":"त्रिक भावों के स्वामी","text":"नमस्कार\r\nमित्रों हमने पिछला\r\nवीडियो त्रि डाय भाव के स्वामियों पर\r\nबनाया\r\nथा रिक्वेस्ट आई लोगों ने आग्रह\r\nकिया के त्रिक भाव के भी स्वामियों पर\r\nहमें कुछ\r\nबताइए तो आज वह टॉपिक लेकर के मैं आपके\r\nसामने फिर उपस्थित हुआ\r\nत्रिक भाव के स्वामियों के बारे में हमेशा\r\nकहा जाता\r\nहै के जो त्रिक भाव का स्वामी\r\nहो व जहां भी जाता है उस भाव को खराब करता\r\nहै कोई भी भाव का स्वामी य त्रिक में आ\r\nजाए तो उस व खराब हो जाता है परंतु हम\r\nयहां भूल जाते\r\nहैं कि पराशर जी ने\r\nत्रिक भाव\r\nमें नीच ग्रह होने\r\nके\r\nया त्रिक भाव के स्वामी नीच में हो नीच\r\nराशि में\r\nहो तो उसको राजयोग बोला है और इसके ऊपर हम\r\nपहले चर्चा कर चुके हैं हमारे ही इन्हीं\r\nवीडियोस में हमने उस पर बात की\r\nहै बहुत से ये आते हैं भाई त्रिक का\r\nस्वामी कहां बैठ गया किस घर में बैठ\r\nगया कौन सा आ गया सूर्य से लेकर शनि राहु\r\nकेतु तक सबके फलित आपको किताबों में मिल\r\nजाएंगे कि यहां ये बैठ जाए यह सूर्य बैठ\r\nगया तो यह फल होगा चंद्रमा बैठ गया तो यह\r\nफल\r\nहोगा हम इससे थोड़ा सा हट के\r\nकुछ नया नजरिया\r\nऔर सरल तरीके से उसको करते\r\nहैं आज मैं एक बात और शेयर करता\r\nहूं कि यह नियम कैसे बनते\r\nहैं और जब एक नियम बनता\r\nहै तो उसमें इंप्रूवमेंट होती चलती\r\nहै जैसे जैसे आप और कुंडलियों पर उस नियम\r\nको लगाते\r\nहैं तब आपको और मनन करके और ज्यादा ज्ञान\r\nप्राप्त होता\r\nहै परंतु जो बेसिक पहला पॉइंट\r\nहै वह हमें शास्त्रों से ही मिलता\r\nहै अब शास्त्रों में जो लिख\r\nदिया अब उसको बिल्कुल ध्यान से पढ़ के\r\nसोचना पड़ता है कि यह क्यों लिखा\r\nहै जैसे हमने देव केरलम का लेकर के कि\r\nमहापुरुष योग कब कमजोर हो जाता है वह भी\r\nएक वीडियो बनाया था और देव केरलम के सूत्र\r\nसे हमने उसको निकाला था\r\nमालव और उस पर मनन\r\nकरके बाकी और ग्रहों पर भी उसको लगाया\r\nपांच के पांच ग्रह\r\nपर सातो ग्रह पर लगाया इसी तरह से जो आज\r\nका सूत्र\r\nहै यह मैंने\r\n2021 में पढ़ा\r\nथा और जैसा लिखा था उसी हिसाब से मैंने\r\nसरल फाइव में लिख भी\r\nदिया परंतु और आगे मनन करने\r\nपर हमें और ज्यादा उसका ज्ञान प्राप्त\r\nहुआ उस सूत्र में लिखा था कि जो हम भाव\r\nदेख रहे हैं जिसके इफेक्ट हम दिखाएंगे\r\nवहां ग्रह होना चाहिए परंतु जैसे जैसे हम\r\nकुंडलिया देखते\r\nगए तो वहां हमें हमने देखा कि चाहे ग्रह\r\nहो या ना हो पाप ग्रह हो शुभ ग्रह\r\nहो उस पुस्तक में सिर्फ शुभ ग्रह का लिखा\r\nथा परंतु उसको हमने अब एक्सटेंड कर दिया\r\nहै और यह थोड़ा सा सरल फाइव में\r\nमॉडिफिकेशन है यह मैंने सरल फाइव में दे\r\nरखा टॉपिक अब मैं इस पर त्रिक भाव के एक\r\nअलग विश्लेषण पर\r\nआता सरल फाइव में और भी विश्लेषण दिए गए\r\nहैं कि त्रिक भाव\r\nमें यदि कोई पाप ग्रह बैठा\r\nहो उसकी राशि देखो वहां भी पाप हो तो\r\nबर्बाद हो जाता\r\nहै आज हम बिल्कुल नया सूत्र दे रहे हैं और\r\nयह सूत्र कहां से मिला जो मैं 21 की 20 की\r\nबात कर रहा हूं मैंने पढ़ा\r\nथा कि यदि त्रिक का\r\nस्वामी नवम भाव में विराजमान हो नवम भाव\r\nमें बैठा\r\nहो\r\nऔर चतुर्थ भाव में कोई शुभ ग्रह\r\nहो तो चतुर्थ भाव में जो शुभ ग्रह है उसकी\r\nदशा में आपको चौथे भाव संबंधित हानि होती\r\nहै ओ भाई ऐसा कैसे हो गया\r\nयार क्या रिलेशन हुआ चौथे भाव का भाई\r\nत्रिक लड तो जाकर के नवम भाव में बैठा है\r\nचौथे भाव का फल में क्यों ले\r\nरहा यहां से सोच विचार शुरू\r\nहुआ कि त्रिक का स्वामी नवम भाव में\r\nबैठा और जो नवम भाव है वो भाव से त्रिक है\r\nफिर\r\nसे तो इसलिए चौथे भाव को भी उसका इफेक्ट\r\nआएगा तो हमारा रूल क्या हो गया हमने अब यह\r\nजो चौथे भाव में ग्रह बैठने की बात हुई थी\r\nवहा कही गई थी यह हमने देखा यह पूर्णत\r\nलगती नहीं है ग्रह बैठा हो या ना\r\nबैठा उसका फल तो मिलता है\r\nतो हमने यह रूल बनाया अब इसको ध्यान\r\nसे के त्रिक भाव के स्वामी नोट को नोट कर\r\nकि कौन\r\nहै एक एक तीन त्रिक भाव है एक एक को नोट\r\nकरलो\r\nऔर त्रिक भाव का एक त्रिक भाव का स्वामी\r\nजिस भी भाव में बैठा है\r\nकिसी और भाव में अपने भाव की नहीं में बात\r\nकर रहा उसके नियम अलग\r\nहै वहां बैठा है जिस भाव में वो विरा बैठे\r\nहुए\r\nहैं वो किस भाव से त्रिक\r\nभाव तो जिस भाव से वो त्रिक भाव है उस भाव\r\nसंबंधी हानि\r\nहोगी मैं उसको भी ले रहा हूं कि भाई ठीक\r\nहै वहा उस भाव में अगर शुभ ग्रह है तो वह\r\nहानि टेंपरेरी होगी और उसकी दशा खत्म होते\r\nहोते तक वह कष्ट दूर हो\r\nजाएगा तोब सवाल आता है कि ग्रह नहीं बैठा\r\nहुआ है तो और यदि पाप ग्रह बैठे हुए हैं\r\nतो क्या होगा तो फल तो मिलता है और उस भाव\r\nके संबंधित फल मिलता\r\nहै इसमें दूसरा दरा\r\nपॉइंट अष्टम भाव को सबसे बली ट्रिक माना\r\nगया है हालांकि उसको न्यूट्रल भी कहते\r\nहैं आ आठवे भाव को न्यूट्रल भी कहते हैं\r\nपर जब त्रिक की बात आती है तो अष्टम भाव\r\nके को सबसे बलित माना गया\r\nहै तो जो अष्टमेश है पहले उसको चेक\r\nकरो फिर छठे भाव के स्वामी को चेक करो फिर\r\nबवे भाव के स्वामी को चेक\r\nकरो तो अष्टम भाव का स्वामी जहां बैठ गया\r\nवह देखो वो किस भाव से अष्टम\r\nहै तो सबसे ज्यादा नुकसान वहां का\r\nहोगा फिर देखो किस भाव से छठे भाव में है\r\nकिस भाव से बवे भाव में है अब इनके अलग\r\nअलग मीनिंग है\r\nभाव से लॉस हानि होगी किसी भी चीज की उस\r\nभाव की हानि हो\r\nजाएगी छठे भाव से संघर्ष आता है छठे भाव\r\nको मैं साधना बोलता\r\nहूं साधना मतलब डिटरमिनेशन किसी चीज से\r\nलड़ने की साधना मेरे को यह करना\r\nहै यह\r\nविचार आप पूजा पाठ करते हो मुझे साधना\r\nकरता हूं मैं भगवान की कृपा के लिए उसके\r\nरहे\r\nहो अष्टम से वो थोड़े से\r\nपरमानेंट इफेक्ट आ जाते हैं परंतु जैसा\r\nशास्त्र में लिखा था कि यदि उस भाव में\r\nशुभ ग्रह बैठे हो तो वह दशा के साथ खत्म\r\nअब य दशा के ऊपर भी सोचा\r\nगया कि इसके फल कब\r\nमिलेंगे या तो वो त्रिक भाव की दशा में\r\nमिल जाएंगे\r\nज्यादातर वहां से मिल\r\nजाएंगे या चतुर्थ जैसे एग्जांपल में हमने\r\nदिया था चतुर्थेश में ग्रह या चतुर्थ भाव\r\nमें जो ग्रह बैठे उसमें मिल\r\nजाएंगे या वहां से जो और त्रिक भाव है\r\nउसमें कोई ग्रह वह भी वह फल दे\r\nदे खराब फल दे\r\nदेंगे और यह कई दफे काफी परमानेंट फल हो\r\nजाता है तो मेरे खल\r\nमें हम उदाहरण से ही\r\nसमझेंगे बात तो आपको पता चल गई कि मैं\r\nक्या कहना चाह रहा\r\nहूं किई त्रिक का स्वामी देख लो मैं एक से\r\nले\r\nचलो अष्ट बाकी त्रिक अपने आप जोड़\r\nलेना अष्टम भाव का स्वामी मतलब अष्टमेश\r\nकुंडली में\r\nकह भा जिसमें\r\nगया वो किस भाव से अष्टम\r\nहै तो वह त्र\r\nअष्टम जिस भाव से वह अष्टम भाव में बैठा\r\nहुआ है उसकी हानि\r\nकरेगा अब यह ज्यादातर त्रिक\r\nभाव ज्यादातर मटेरियल\r\nलॉस और आपके मान सम्मान मटेरियल लॉस मान\r\nसम्मान को ज्यादा दर्शाते\r\nहैं आपके जो रिलेट रिलेशन उसमें आते हैं\r\nउनका भी फल देते हैं पर ज्यादा फल\r\nआपको अपनी पोजीशन का मिलता\r\nहै ठीक है जी तो अब हम थोड़े से चार्ट देख\r\nलेते हैं और फिर आगे उस पर समझेंगे\r\nठीक है\r\nजी पहली कुंडली य हमने ली\r\nहै पहले तो इस पर देखते हैं हम कैसे देखे\r\nकैसे कर रहे\r\nहैं यहां\r\nदेखिए शनि महाराज छठे भाव के\r\nस्वामी ठीक\r\nहै और शनि महाराज नवम भाव में\r\nबैठे तो चतुर्थ भाव को हानि देंगे क्योंकि\r\nवो चतुर्थ\r\nसे छठा भाव है छ से\r\nछ बृहस्पति अष्टम भाव के स्वामी है और वोह\r\nलगन में\r\nबैठे अब यहां देखिए जो बृहस्पति\r\nहै वो छठे भाव से अष्टम में\r\nहै और अष्टम भाव से छठ में है\r\nतीसरे त्रिक का स्वामी है\r\nचंद्रमा वह शनि के साथ नवम भाव में\r\nबैठे तो चतुर्थ\r\nभाव से छठे भाव\r\nमें दो त्रिक के स्वामी बैठ\r\nगए नवम भाव में अब ये जो नवम भाव है यह\r\nआपके दूसरे भाव से\r\nअष्टम भी है दूसरा भाव आपका कुटुंब है\r\nफैमिली है सब है उसका फल देता है चतुर्थ\r\nभाव का फल देता\r\nहै अब यहां देखिए शनि की\r\nदशा 29 मार्च 2024 को शुरू\r\nहुई इसके आते ही इनको परिवार से दूर जाना\r\nप\r\nघर से दूर जाना\r\nपड़ा और यह सरकारी मेहमान बन कर के रहना\r\nशुरू कर\r\nदिया अब यह वैसे नहीं पता चलता है कि भा\r\nशनि की दशा क्या\r\nकरेगी अब यहां पर पराशर जी का भी नियम है\r\nकि अगर छठे भाव का स्वामी नीच राशि में हो\r\nवो योग कारक होता है योग भी दे रहा है\r\nचीफ मिनिस्टर भी बने\r\nहुए परंतु अब रिजाइन करना पड़ा अब घर से\r\nभी इनको निकलना\r\nपड़ा ठीक है अब एक और मैं यहां पर\r\nदशा शनि शनि केतु तक की लिखी है\r\nमैंने केतु\r\nसे यह दो त्रिक के\r\nस्वामी अष्टम भाव में है\r\nऔर केतु से तीसरे त्रिक के स्वामी बवे भाव\r\nमें तो केतु की प्रत्यंतर दशा काफी सीरियस\r\nहो सकती\r\nहै शनि शनि\r\nकेतु अब देखते हैं आगे क्या होता है\r\nक्योंकि टाइम है इसमें तो आने का तो शनि\r\nशनि केतु इसमें हम देखते हैं तो यहां पर\r\nये त्रिक का रू\r\nबिल्कुल परफेक्ट लग रहा इसके बाद हम दूसरे\r\nचार्ट\r\nप यह दूसरी कुंडली\r\nहमारी इंदिरा गांधी जी की\r\nहै यहां पर त्रिक के स्वामी बृहस्पति और\r\nशनि शनि महाराज लगन में बैठ गए जाकर\r\nके अब यह कहां से बृहस्पति और\r\nशनि कहां से और त्र में बैठे हुए मैं छठा\r\nभाव लेता\r\nहूं छठे भाव से\r\nशनि आठवे में है बृहस्पति छठे में छठे भाव\r\nमें बृहस्पति का और स शुक्र का राशि\r\nपरिवर्तन भी\r\nहै तो अब ये देखो\r\nभाई छठे भाव होता है शत्रुओं\r\nका रोग\r\nका काफी इसमें है एक छठे भाव की बहुत खास\r\nबात होती है उसको आप नवम और दशम से\r\nदेखो दशम का\r\nभाग्य और नवम के कर्म ये छठे ब में भी आते\r\nहैं तो इनको यह दशा 3 मई 1800 1987 को\r\nशुरू\r\nहुई और\r\nअक्टूबर 87 में इनकी हत्या कर दी\r\nगई क्यों अब यहां देखो कितने जबरदस्त\r\nकिहों फल दिया शनि और बृहस्पति मैं अंतर\r\nदशा नहीं लगा प्रत्यंतर नहीं लगा\r\nक्योंकि यह हो चुकी है\r\nघटना तो यह देखिए यहां से भी हमारे इनका\r\nत्रिक का कितना वैसे संबंध आ रहा है अब हम\r\nतीसरी कुंडली पर जाते\r\nहैं यहां पर बहुत ही अजीब सिचुएशन\r\nबनी मंगल और\r\nशनि और शुक्र\r\nमंगल और\r\nशनि मंगल और शुक्र यह दशम भाव में बैठे\r\nहैं शुक्र उच के भी है दो त्रिक वाले बैठ\r\nगए और तीसरे त्रिक से\r\nदृष्ट अब यहां से मैं सिर्फ आ\r\nआठवा कहां से पड़ता है य यह तीसरे भाव से\r\nआठवा में है और तीसरे भाव में बृहस्पति\r\nविराजमान है\r\nअब इनको बृहस्पति की दशा तो मिली नहीं अब\r\nतक परंतु बृहस्पति में जब जब अंतर दशा आई\r\nहै उसने इनको प्रोफेशन के बारे में काफी\r\nसेट बैक दिया है पीछे कर दिया है और चेंज\r\nकरना पड़ा है उसमें अच्छी तरक्की नहीं हुई\r\nहै राइज नहीं मिला\r\nतो यहां भी ये त्रिक का फार्मूला जब मैंने\r\nयह पढ़ा है तब समझ में आना शुरू हुआ कि\r\nभाई ये क्यों हो रहा है इतना बढ़िया देखो\r\nशुक्र उच्च के हैं पंचमेश है\r\nपंचमेश दशम भाव में उच्च के राज योग बना\r\nरहे हैं परंतु जब शुक्र में बृहस्पति का\r\nअत दशा आने की बात हो रही थी उससे दो\r\nमहीने पहले ही रिजाइन कर\r\nनौकरी छूट गई बहुत अच्छी खासी नौकरी छोड़\r\nदी फिर बृहस्पति का अंतर दशा चंद्रमा में\r\nआया एक बड़ी फैक्ट्री डालने की कोशिश की\r\nवह बर्बाद हो गई वह भी नहीं कर\r\nपाए तो इस तरह से यह बृहस्पति ने हमेशा\r\nतकलीफ दी\r\nहै अब हम एक कुंडली और ले लेते\r\nयह बहुत ही दुखियारी कुंडली\r\nहै अब यहां\r\nदेखिए\r\nमंगल और\r\nबुध यह दोनों त्रिक के\r\nस्वामी तीसरे त्रिक के शुक्र\r\nस्वामी अब यहां\r\nदेखिए मैं शनि से देखता हूं\r\nशनि\r\nसे दो त्रिक के स्वामी अष्टम में बैठे हैं\r\nऔर एक त्रिक का स्वामी छठे भाव में\r\nबैठ तो शनि के ऊपर पूरा पूरा त्रिक\r\nप्रभाव आ रहा है चनी से छ और आठ में तीनों\r\nत्रिक\r\nबैठे हमने सबसे ज्यादा जो पीड़ित है उसको\r\nदेख लिया\r\nशनि पीड़ित है बारवा भाव पीड़ित\r\nलॉसेस छुपे हुए\r\nशत्रु आठवा भाव होता है जो शत्रु जिनको आप\r\nदेखते हैं सामने बारवा भाव होता है जो\r\nछिपे हुए\r\nशत्रु जो उनको आप पहचानते नहीं है पर व\r\nशत्रु\r\nहो तो इनका\r\nकबाड़ा शत्रुओं ने कर दिया सारा बिजनेस\r\nइनका पार्टनर ने छीन लिया और दो 2004 में\r\nशनि की दशा शुरू\r\nहुई तो उसके दो चार साल बाद मतलब शनि में\r\nमेरे ख्याल\r\nमें शनि शनि में\r\nही या\r\nशनि बुध में इनकी\r\nमृत्यु बुध भी त्रि शाय के\r\nस्वामी मंगल के साथ है शट के साथ मेरे को\r\nएजेक्ट याद नहीं है परंतु हां शनि की दशा\r\nमें\r\nइनकी मृत्यु हो गई और यह दुखिया पर्सन को\r\nमुक्ति मिल\r\nगई तो यह हमारा त्रिक भाव का थोड़ा सा\r\nविश्लेषण था बाकी और सरल फाइव में त्रिक\r\nऔर त्रि का लिखा हुआ है पर यह जो त्रिक का\r\nमैंने विश्लेषण किया है इसमें थोड़ा सा\r\nचेंस सरल फाइव से बाद में जो 2021 में लि\r\nखा था लिखा था तो वोह अब जो है थोड़ा सा\r\nऔर रिफाइन गया है और मैं बार-बार चेंज\r\nनहीं करना चाह रहा था तो मैंने कहा वीडियो\r\nके माध्यम से आपके साथ वो मैं शेयर\r\nकरूंगा तो आज के लिए इतना ही फिर मिलेंगे\r\nअभी मैं आपको एक और क्वेरी आ रही है लोगों\r\nकी कि जो सरल सीरीज है इसमें क्या क्या\r\nटॉपिक्स आपने कवर किए हुए हैं बहुत से तो\r\nमैं बता चुका हूं इसी वीडियोस में और लिख\r\nभी देता हूं कि सरल से है यह तो मैं सोच\r\nरहा हूं एक छोटा सा\r\nवीडियो थोड़ा सा पाच सात मिनट का वह आपको\r\nमैं सरल सीरीज\r\nके हर भाग में क्या-क्या टॉपिक कवर्ड है\r\nऔर क्या टॉपिक मैं आगे लिखने जा रहा\r\nहूं उसका भी थोड़ा सा हम आपस में\r\nइंफॉर्मेशन शेयर करेंगे तो वो भी करेंगे\r\nकिसी दिन उस तब तक के लिए बहुत-बहुत\r\nधन्यवाद नमस्कार हैव ए गुड डे"},{"topic":"नवमांश से तलाक की ज्योतिषीय स्थितियाँ","text":"नमस्कार मित्रों आज फिर हम एक विवाह\r\nका दुखद पार्ट लेकर के आपके पास फिर से आए हैं और\r\nआज तलाक डाइवोर्स या सेपरेशन वगैरा विवाह\r\nके बाद सेपरेशन डाइवोर्स वगैरा वो ज्योतिष से कैसे देखे\r\nइसके लिए भी हम नवांश का ही प्रयोग करेंगे और पहले हम इस देखते हैं कि क्या क्या\r\nपरिस्थितियां हो सकती है एक तो होता है कि भाई विवाह के बाद डाइवोर्स हो गया सेपरेशन हो गई दोनों अलग\r\nअलग हो दूसरा केस क्या होता है कि एक ने\r\nडाइवोर्स की एप्लीकेशन डाल दी कोर्ट में केस चल रहा है और सालो साल तक वो केस\r\nखींचा रहता है दोनों की कहते भाई शादी दूसरी हो जाए\r\nवह भी नहीं हो पाता क्योंकि जब तक केस सेटल नहीं होगा और बहुत सी दफ डिमांड होती है पैसों\r\nकी प्रॉपर्टी की कुछ केसेस में ऐसा होता है कि विवाह\r\nनिभ नहीं रहा है परंतु उस अलग अ अलग रह रहे वो भी एक\r\nतरह से तलाक ही है परंतु ऑफिशियल तलाक\r\nनहीं होता कानूनी तलाक नहीं लेते कोई सा भी कोर्ट में नहीं\r\nजाता और ऐसे ही जिंदगी अपनी चलाते रहते हैं म्यूचुअल कांसेप्ट से रहते रहते\r\nहैं यह ज्यादातर होता है भाई कुछ साल हो जाते हैं विभाग\r\nको नहीं बनती है तो अलग अलग रहने लग जाते हैं तो यह कई चीज हो जाती है\r\nऔर इन सबको अलग अलग करके कैसे देखे हमारी ज्योतिष की समस्या यह आ जाती\r\nहै किई क्या क्लियर कट डाइवोर्स हो जाएगा क्या वह अलग रहेंगे क्या होगा कोर्ट\r\nकचहरी चलती रहेगी तो हमारे रूल वही जो हम बोलते भाई\r\nसरल है अब सरलता से आप उसको ले तो सरल\r\nहै नहीं तो सेपरेशन डाइवोर्स वगैरह के लिए आज तक हम जो पढ़ते आ रहे थे वो यही होते\r\nथे सेपरेट ग्रह विच्छेद ग्रह भाई राहु है सूर्य है शनि है जब इनका प्रभाव आता\r\nहै तो विच्छेद हो जाता है तलाक हो जाता है पर वो बहुत सी जगह\r\nनहीं लगता था था तो इसलिए हमने अपने सरल ज्योतिष से ही उसका फिर विश्लेषण किया हम\r\nआपसे बात कर चुके हैं कि नवांश की\r\nलगन विवाह की इच्छा को दर्शाती है और वहां से हमने देखा था कि विवाह जल्दी होगा देर\r\nसे होगा बहुत जल्दी हो जाएगा तब हमति शमशा\r\nलेकर के आए उसमें भी हमने देखा और उसको नवांश के साथ\r\nमिला कर के विवाह ना होने का हमने रूल\r\nबनाया हमने उसमें लेट मैरिज का भी दिया था कि विवाह में\r\nदेरी तो अब भैया जितना ज्यादा पाप संबंध होगा उतनी ज्यादा देरी\r\nहोगी ज्यादा पाप संबंध है जरा सा शुभ संबंध\r\nहै तो अब जैसे मैंने केस दिया था 38 39 यर्स 38 साल के उम्र के बाद वहा विवाह हुआ\r\nथा इसको और एक्सटेंड करो और ज्यादा पाप प्रभाव है 50 साल की उम्र में भी\r\nहोगा और या बिल्कुल नहीं होगा वह भी हम कवर कर चुके हैं तो यह बहुत से मेरे\r\nमित्रों ने प्रश्न पूछा है तो भाई वो इंटेंसिटी कितना प्रभाव प्रबल है किसका है\r\nशुभ का अशुभ का तो लगन और लग से हम यह देखते\r\nहैं अब संबंध डाइवोर्स के देखने के लिए अब इसमें\r\nफिर प्रश्न आएगा कि जी सेपरेशन एक पार्टनर की मृत्यु से भी तो हो\r\nसकता है बिल्कुल हो सकता है वह टॉपिक मैं आज कवर नहीं कर रहा हूं\r\nक्योंकि यह फिर नहीं तो और बड़ा हो जाएगा अभी हम सिर्फ\r\nतलाक की बात कर रहे हैं सेपरेशन की बात कर रहे हैं उनके अलग-अलग पहलुओं पर रंग पर\r\nबात करेंगे कैसे कैसे केस हो सकते हैं अब इसके लिए हमारे पास एक तो सप्तम\r\nभाव और सप्तम यश सप्तम भाव नवांश\r\nका हमारे विवाह का भाव है\r\nअगर उस पर सप्तम भाव पर केवल शुभ संबंध\r\nहो तो विवाहित जीवन कह सकते हैं भाई अच्छा है विवाहित पार्टनर अच्छा\r\nहै यहां पर एक मैं एक्सेप्शन करूंगा नवांश के सप्तम भाव में अगर शनि\r\nहोता है तो उस व्यक्ति को अपनी ससुराल से इज्जत\r\nमिलती है आपको अलग लगेगा पर फैक्ट यही\r\nहै और अगर सूर्य वहां पर होता है सप्तम भाव में तो इज्जत नहीं\r\nमिलती ठीक है जी तो यह तो सप्तम भाव पाप प्रभाव है वही विवाह में वाद विवाद चलता\r\nरहेगा और अब इसके बाद हम आते हैं सप्तमेश\r\nपर जो हमारा मेन करता है वह है असली\r\nपहलवान सप्तमेश अगर पीड़ित नहीं\r\nहै या केवल शुभ संबंध\r\nहै चाहे सप्तम भाव में पाप ग्रह बैठे\r\nहो डाइवोर्स नहीं  होगा सप्तमेश का अगर शुभ से संबंध है तो\r\nतलाक नहीं होगा चाहे सप्तम भाव कैसा ही\r\nहो दूसरा इसमें कड़ी आती है कि सप्तमेश के\r\nसाथ सप्तमेश का नवांश के त्रिक स्वामियों का संबंध आ जाए\r\n6 आ 12 के नवांश के स्वामियों का संबंध\r\nसप्तमेश से आ जाए तो भी वह एक लड़ाई झगड़े\r\nकी स्थिति बनती है अगर सप्तमेश पर पाप प्रभाव फिर भी आ गया या छ आठ 12 का प्रभाव\r\nहै तो वो सेपरेशन हो हो सकता है और अगर उस पर शुभ संबंध है\r\nकेव तो किसी हालत में डाइवोर्स नहीं होगा यह स्थिति ऐसी होगी के सप्तम भाव\r\nपीड़ित है सप्त में शुभ के साथ है तो आस पड़ोस के लोगों को बगैर सिनेमा\r\nकी टिकट लिए वहीं पर आपका ूब नाट ड्रामा\r\nसड़क पर दिख जाएगा पर डावर्स\r\nतो य दो रूल मैंने दे सप्तमेश का पाप\r\nसंबंध या त्रिक का संबंध अगर त्रिक का स्वामी भी पाप है और कोई शुभ संबंध नहीं\r\nहै तो तुरंत डाइवोर्स अब दूसरे फैक्टर पर\r\nआओ दूसरा फैक्टर होता है नाथ हाउस नवांश\r\nका नाइंथ हाउस हम यह देखते हैं कि क्या मैं विवाह का धर्म\r\n निभाऊंगा अगर नाइंथ\r\nहाउस नवम भाव पीड़ित है तो मैं विवाह का धर्म नहीं\r\nनिभाऊंगा अगर शुभ संबंध है चाहे कितना भी परेशानी\r\nहो मैं विवाह का धर्म निभाऊंगा अब ऐसे केस\r\nमें सप्तमेश पाप संबंध के साथ\r\nहै पर नवम भाव पीड़ित\r\nनहीं तो वो व्यक्ति अपना धर्म निभाने के लिए\r\nविवाह को चलाता रहेगा वो डाइवोर्स के फेवर में नहीं जाएगा चाहे उसका पार्टनर चला\r\nजाए ऐसी कुंडली में देख कर के आप कह सकते भाई इसकी इच्छा नहीं है या सप्तम शुभ के\r\nसाथ है तो कह सकते इस व्यक्ति की डाइवोर्स की इच्छा\r\nनहीं नवम भाव शुभ है वह कष्ट सहकर भी विवाह के को निभाने की\r\nपूरी कोशिश करे वो उसका धर्म है नवाज का धर्म है विवाह को\r\nनिवा तो यह हमने अब ये रूल तो बता दिए अब\r\nइसमें आपको खुद सोच करके अपने आप उसका विश्लेषण करना\r\nहै रूल यही है इन्हीं को अप्लाई करना है\r\nसप्तम भाव सप्तमेश त्रिक हाउसेस पाप ग्रह और नवम\r\nभाव ज्यादा से ज्यादा नवमेश जोड़ सकते हो नवम भाव तो अब हम एक एक परिस्थिति के\r\nकुछ चार्टों का विश्लेषण करते हैं देखते हैं हमेशा की तरह से जी\r\nअभी मैं आता हूं पहले\r\nचार्ट हां जी यह पहला चार्ट है दिल्ली का ही बर्थ\r\nहै 1974 कोई ज्यादा पुराना चार्ट नहीं है और जितने भी मैंने लिए है यह अपने रिकॉर्ड\r\nसे ही लिए हैं जो मेरे पास कंसल्टेशन के लिए आए अब\r\nयहां पर आप देखिए कंक्लूजन अ खुद निकालो कैसे कैसे\r\nहोता है हम सीधे नवांश पर\r\nजाएंगे नवांश में सप्तम भाव पर केतु\r\nविराजमान है और बृहस्पति की दृष्टि\r\nहै तो इस व्यक्ति का विवाह तो ठीक ठीक है केतु तो सप्तमेश हो गया ना फिर सीक्रेसी\r\nऔर ये कह लो अचानक तत्व और चंद्रमा भी देख रहे हैं बृहस्पति देख रहे हैं कोई\r\nप्रॉब्लम नहीं है इसको देख के आप कहेंगे भा ठीक ठाक चलना चाहिए बा अब हम देखते हैं\r\nसप्तम मेश को सप्तमेश है\r\nबुध और बुद्ध आठवें भाव में मंगल के साथ विराजमान है\r\nमंगल को हम पाप ग्रह ही लेंगे ना चाहे वो कोई भी है नवमेश\r\nलेंगे तो नेचुरल पाप पाप ग्रह अब क्या ये अपना कर्तव्य\r\nनिभाएंगे नवम भाव पर कोई पाप दृष्टि नहीं\r\nहै और नवमेश शुभ के साथ\r\nबुध को शुभ मानेंगे नेचुरल शुभ\r\nहै ठीक है इनका अब मैं पहले इनकी कहानी बता दूं थोड़ी\r\nसी इनका विवाह हुआ सितंबर 2010\r\nमें दशा वगैरह आप देखते रहे और नवंबर 201 में विवाह टूट गया दोनों\r\nअलग अलग हो गए थोड़े से दिन चला विवाह बस ठीक है मैं अब दशा वगैरह पर नहीं जा\r\nरहा हूं क्योंकि और लंबा हो जाएगा फिर हिसाब किताब ज्यादा ठीक है जी तो अब हम\r\nइनके जिसके साथ शादी हुई थी स्त्री की\r\nउनकी कुंडली लेते हैं\r\nइस लड़की से इनकी शादी हुई थी यह नरवाना हरियाणा की रहने वाली\r\nथी ठीक है जी अब इनका चार्ट\r\nदेखो सप्तम भाव पे सूर्य की दृष्टि है और फिर से बृहस्पति\r\nकी दृष्टि तो नॉर्मली तो हम कहेंगे भाई साहब\r\nकोई कोई बुराई नहीं है अब हम देखते हैं सप्तमेश को कहां से\r\nगड़बड़ पैदा हुई सप्तमेश है मंगल मंगल पर कोई शुभ दृष्टि नहीं\r\nहै और केवल शनि की दृष्टि\r\nहै अब यहां शनि को योग कारक भी बोलोगे मैं नेचुरल सिग्निफिकेंट\r\nकेतु एक्सस है राहु महाराज बैठे हुए हैं और चंद्रमा पीड़ित\r\nहै पूरी तरह पीड़ित है और मंगल नवम भाव को\r\nदृष्ट कर रहे हैं तो यह कर्तव्य नहीं निभाएगी\r\nहुआ यह था यही छोड़ कर के विवाह संबंध\r\nतोड़ करके और यह चली गई लड़का तो नहीं चाहता था\r\nयह छोड़ कर के जाए कुछ ऐसा दवे शब्दों में इसने मुझे\r\nबताया था के कुछ जो भी गोल्ड वगैरा जो चढ़ाया था लड़की\r\nको उसके लालच में वह उसको लेकर भाग गई घर\r\nसे ठीक है जी तो यह हमारा दूसरा केस था पहला केस हमने देख\r\nलिया इसके बाद अब नेक्स्ट चार्ट पर य आया तुरंत\r\nतुरंत का मामला हो गया ये यह वाला केस बिल्कुल तुरंत का मामला हो\r\nगया अब हम आते हैं नेक्स्ट चार्ट\r\nप यहां पर यह लड़के का चार्ट\r\nहै अब यहां देखिए सप्तम भाव में केतु विराजमान है फिर\r\nबृहस्पति देख रहे हैं\r\nऔर बृहस्पति देख रहे हैं परंतु यह कौन सा लगा दिया मैंने एक सेकंड\r\n2070 मेल ठीक है ठीक है कोचीन का है ना पायलट है य यह\r\nपायलट है इनके भी तकरीबन उसी तरह की समस्या कुंडली आ रही है इसलिए मैं चौक गया हूं\r\nमंग बुध फिर मंगल से पीड़ित अष्टम भाव पर कोई दृष्टि नहीं है\r\nअष्टमेश नवम भाव में बैठे हुए वो शुभ के\r\nसाथ तो यह कर्तव्य निभा रहे हैं इनका सेपरेशन हो गया है यह मेरे पड़ोस\r\nमें ही रहते थे और अभी तक डाइवोर्स नहीं हुआ\r\nअब इनकी पत्नी की कुंडली\r\nदेखो ये इनकी पत्नी की कुंडली है इनको मैं बहुत दिनों से बहुत बचपन से\r\nजानता हूं यहां देखिए सप्तम\r\nभाव पर शनि की दृष्टि तो विवाह तो पीड़ित हो गया थोड़ा\r\nसा छठे भाव का आ गया संबंध उस परे और मंगल की दृष्टि है मंगल\r\nअष्टम तो विवाह की क्वालिटी तो अच्छी नहीं\r\nरही अब जो सप्तमेश है वह बृहस्पति\r\nहै बृहस्पति का किसी भी पाप से कोई संबंध नहीं\r\nहै तो यह डाइवोर्स नहीं चाह रही है डाइव हुआ भी नहीं है अब\r\nतक ये कम से कम 10 12 साल से तो मुझे पता है के डाइवोर्स केस भी फाइल नहीं हुआ है\r\nअभी अब नवम भाव देखो नवम भाव में बृहस्पति\r\nबैठे कोई दिक्कत नहीं चौथे और नवम का एक्सचेंज\r\nहै नवमेश जो है शुक व चंद्रमा के साथ भी है षड के स्वामी है\r\nऔर मंगल के साथ एक्सचेंज है तो धर्म निभा\r\nनिभाना चाहता हूं पर मैं निभा नहीं पा रहा समस्या यह है यह कन्या जो है यह तो हर तरह\r\nसे कोऑपरेट करती है करना चाह रही है परंतु कर नहीं\r\nपाती तो ये अलग रंग दिख गया आपको ठीक है जी अब इसके बाद आएंगे\r\nपांच पांच नंबर\r\nकुंडली यह इस कुंडली का मेरे को सिर्फ इस\r\nलड़के की कुंडली मिली है इसकी किससे शादी हुई थी वह नहीं मिली\r\nथी यह तुरंत फुरत का केस है शादी का यहां\r\nपर क्या है सप्तम भाव में सूर्य विराजमान\r\nहै शनि से दृष्ट है मंगल से दृष्ट\r\nहै दोदो पाप ग्रह से दृष्ट है विवाह अच्छा नहीं\r\nहै और जो सप्तमेश है उस परे भी कोई दृष्टि\r\nकिसी का संबंध नहीं आ रहा कोई पाप दृष्टि नहीं है कोई शुभ\r\nदृष्टि नहीं है केवल क्या है कि कर्तरी योग में है बंधन\r\nमें और वो बंधन प्रबल जो है वो राहु का है क्योंकि राहु शुक्र की तरफ आ रहे\r\nहैं मरकरी शुक्र से दूर जा रहे हैं मंगल भी शुक्र से दूर दूर जा रहे हैं तो केवल\r\nराहु का प्रभाव प्रबल आ रहा है इनका क्या हुआ 20 अप्रैल\r\n2006 को इनकी शादी हुई और 27 अप्रैल को डाइवोर्स हो\r\nगया यह नहीं चाहते थे अब इनकी जो वाइफ हुई थी उस समय जिनसे डाइवोर्स हुआ वह चार्ट\r\nमेरे पास नहीं है नहीं तो उससे और ज्यादा अच्छा हो\r\nजाता यह नहीं चाहते थे सा चार दिन में सात दिन में एक हफ्ते में डाइवोर्स हो गया 20\r\nको शादी हुई 27 को डाइवोर्स हो अब इसके बाद हम आते\r\nहैं यह भी हमारे गुड़गांव के ही है इनका भी पाच छ साल से केस चल रहा है\r\nलंबा केस चल रहा है अब यहां भी देखते हैं सप्तम भाव में बुध विराजमान\r\nहै जो लग्नेश है तो विवाह की इच्छा तो बहुत अच्छी थी इनकी\r\nटेटी और लग्नेश पर कोई प्रभाव नहीं\r\nहै अब हम सप्तमेश की बात करेंगे मतलब विवाह तो इनकी तरफ से तो ठीक ठाक\r\nथा परंतु यह विवाह के को समझते थे कि बंधन\r\nहै मंगल और शनि का पाप करतरी मंगल का पाप\r\nकरतरी ज्यादा बली है शनि सप्तम भाव से दूर\r\nजा अब हम देखते हैं इनके स्वामी को सप्तमेश\r\nसप्तमेश बृहस्पति है इन पर\r\nशनि जो नीच राशि में माइंड\r\nइट जो नीच राशि में है वोह दृष्ट कर रहे हैं परंतु शुक्र भी\r\nदृष्ट कर यह विदेश में सेटल्ड\r\nहै तो इनका कोई चार पाच साल से केस चल रहा है पाच छ साल से और यह सुप्रीम कोर्ट तक\r\nपहुंच चु अब इनका नवम भाव देखो भाई निभाना चाहते हैं या\r\nनहीं नवम भाव में सूर्य विराजमान है और मंगल दृष्ट कर मंगल जो अष्टमेश\r\nसूर्य जो द्वादश है तो विवाह का\r\nकर्तव्य हो सकता है इन्होंने नहीं निभाया है ठीक से तभी यह सिचुएशन आई नहीं तो\r\nशुक्र जो है वो बृहस्पति को देख रहे थे तो विवाह में कष्ट नहीं आना चाहिए अब\r\nदेखिए यह फाइनल पॉइंट नाइंथ हाउस को कैसे देखना कर्तव्य नहीं निभाया तो भी शादी टूट\r\nजाएगी अब इसके बाद इनकी जिन कन्या से शादी हुई थी उसका चार्ट देखते\r\nहैं अब य देखो यह जो लड़का था गुड़गांव की बर्थ है\r\nऔर जो लड़की है वह तमिलनाडु चेन्नई की है दोनों का\r\nअफेयर हुआ मिल गए कहीं लव मैरिज हो गई और यह कोई साल से एक\r\nसाल से कम गुड़गांव में रही और फिर अपने वापस चली अब इसका देखिए सप्तम\r\nभाव सप्तम भाव पर कोई संबंध नहीं\r\nहै कहने को हम कह सकते भयंकर पाप करतरी तो यह\r\nलड़की अपने आप को बहुत बंधन में समझती थी परंतु आप देखिए केतु सप्तम भाव से दूर जा\r\nरहा है शनि भी दूर जा रहा है जहां तक मेरे को बात करके पता चला इसको फ्री\r\nइंडिपेंडेंस थी टोटल कोई भी इसके ऊपर बंधन\r\nनहीं था अपने काम के लिए इंडिपेंडेंटली जाती थी\r\nमेरे को गदर कर किया है मैंने तो इस तरह का बंधन नहीं था अब हम देखते हैं सप्तमेश\r\nसप्त में शुक्र है बड़े बली होकर के स्व राशि में बैठे\r\nहुए जो विवाह का मार्क स्थान भी है और शनि से\r\nदृष्ट ठीक है जी तो इनकी तरफ से डाइवोर्स\r\nदिया गया इसकी इच्छा थी डाइबोस की शुक्र पर कोई शुभ संबंध नहीं\r\nहै अब मैं देखता हूं भाई कर्तव्य निभाना अपना धर्म\r\nनिभाना नवमेश नवम पर मंगल की दृष्टि\r\nहै नवम भाव पर शनि और सूर्य की कतरी है\r\nनव मेश बृहस्पति राहु के साथ विराजमान\r\nहै बवे भाव तो यह कन्या ने कर्तव्य का निभा नहीं\r\nकिया अपने धर्म का निभा नहीं किया और यह डाइवोर्स की एप्लीकेशन फाइल हो चुकी है इन\r\nदोनों की और अब मामला सुप्रीम कोर्ट तक पहुंच चुका है अब एक चार्ट\r\nअब इस चार्ट को देख के अब यह प्रश्न है आपसे अभी इतना मैं बोल चुका हूं बता चुका\r\nहूं थोड़ा सा इस चार्ट को भी समझाता हूं 1953 की बर्थ है\r\nये ठीक है 70 साल के करीब के 71 साल के हो\r\nगए ठीक है अब यह देख के बताओ अब नॉर्मल आप\r\nदेखोगे तो सप्तम भाव को में राहु देख कर के हम कहेंगे भाई\r\nसाहब विवाह अच्छा नहीं है ठीक है नहीं\r\nपर डाइवोर्स होगा या नहीं होगा बुध देख रहे\r\nहैं नैसर्गिक शुभ ग्रह है परंतु है बवे और तीसरे के\r\nस्वामी अब असली पॉइंट आता है\r\nसप्तमेश सप्तमेश है शनि शनि\r\nमहाराज शनि को शुक्र और राहु कतरी दे रहे\r\nहैं शुक्र की कतरी भी बड़ी ठीक है शुभ ग्रह की है शनि के ऊपर और कोई पाप दृष्टि\r\nनहीं है अब नवम भाव को देख\r\nलो नवम भाव पर कोई संबंध नहीं\r\nहै यह अपने विवाह का धर्म निभा रहे चाहे विवाह की क्वालिटी अच्छी नहीं है राहु\r\nबैठे हुए हैं और जो नवमेश\r\nहै वो मंगल से दृष्ट है तो गुस्सा तो बहुत आता है करत धर्म\r\nनिभाने में झुंझलाहट भी होती है वायलेंस भी होती है पर धर्म\r\nनिभा क्योंकि नाइंथ हाउस पर कोई पाप संबंध\r\nनहीं है सप्तमेश पर कोई पाप संबंध नहीं\r\nहै तो अब देखिए ऐसे भी केस मिलते हैं भाई साहब ऐसे केस में यह मत कह देना कि तलाक\r\nहो जाएगा इनका तो नहीं हुआ 71 साल के हो गए अच्छी\r\nतरह से चल रहा है मामला विवाह चल रहा है ठीक है तो ये हमने आज\r\nकुंडलिया आपके साथ शेयर की और मैंने प्रयास किया है कोशिश की है कि डाइवोर्स\r\nके ये अलग-अलग रंग आपको दिखाने की कोशिश करूं जो आखिरी कुंडली थी\r\nनॉर्मली उसको देख कर के नवांश को देख कर के आप कहोगे सप्त में छटे में चला गया है\r\nविवाह खत्म कुछ नहीं रो रोग तो है पर डाइवोर्स होगा या नहीं होगा हम उस विषय पर\r\nचर्चा कर तो हमने दो पॉइंट पकड़े आज सप्तमेश\r\nका पाप संबंध त्रिक का संबंध दूसरा पॉइंट पकड़ा हमने\r\nनवम भाव तो इसी तरह से हम इसको देखते\r\nहैं फिर और मिलेंगे आगे अभी मैं एक विचार कर रहा था बहुत ज्यादा डिमांड आ रही थी के रोग पर\r\nआप कोई रोग पर भी बताइए तो एक बहुत सरल तरीका है उस पर\r\nमैंने पुस्तक भी लिखी है लोकेट डिजीज पर वो पुस्तक\r\nइंग्लिश में है पर उसको तरीका मैं बता दूंगा आप पढ़ के अप्लाई कर सकते हैं उस\r\nकिताब से आप आईडिया भी ले सकते हैं कहोगे तो मैं बता दूंगा भाई कहां मिलेगी ठीक है\r\nतो एक मैं आप कड़ी एक दो दिन में रोग स्थान पर भी\r\nबनाऊंगा तब तक के लिए आपसे मैं विदा लेता हूं धन्यवाद आपको ये अच्छा लगा होगा मैरिज का\r\nमेरे ख्याल में काफी टॉपिक हमने ले लिए और सजेस्ट देखते हैं और कोई टॉपिक\r\nनिकलता है ठीक है जी धन्यवाद फिर से"},{"topic":"नीच राशि के बुध से फलित","text":"नमस्कार\r\nमित्रों आज हम नीच ग्रह या डेबिटेड\r\nप्लेनेट\r\nकी सीरीज\r\nमें फिर आपके साथ\r\nहै और आज\r\nहम बुध के नीच राशि में होने पर वार्ता\r\nकरेंगे उसका क्या फलित होता\r\nहै बुध का नीच में होना नीच राशि में होना\r\nएक बहुत ही\r\nरोचक विषय\r\nहै और\r\nबुध हमारी बुद्धि का कारक\r\nहै और बुद्धि का कारक होने के साथ-साथ\r\nयह एक ऐसा ग्रह\r\nहै जो हमेशा जब भी नीच राशि में होगा तो\r\nअपनी उच्च राशि को देखेगा अपनी उच्च राशि\r\nको मतलब वो कन्या को हमेशा\r\nदेखेगा अब हम देखते हैं कि\r\nयह किन कुंडलियों में हमको मिलता\r\nहै देखिए\r\nबुध सूर्य से 23 24 डिग्री से ज्यादा दूर\r\nनहीं जा\r\nसकता तो जब\r\nबुध नीच राशि में\r\nहोगा तो वह सूर्य के आसपास ही\r\nहोगा तो\r\nसूर्य या तो कुंभ में हो सकता\r\nहै या मीन में हो सकता\r\nहै या मेष में हो सकता है तभी आपको बुध\r\nनीच राशि में मिल सकता\r\nहै तो यह जो जन्म\r\n15 मार्च के से 15 मई तक के बीच के होते\r\nहैं उसमें आपको बुध नीच राशि में मिल सकता\r\nहै तो पहला पॉइंट तो यह\r\nहै दूसरा पॉइंट है के शुक्र\r\nभी इनके आसपास ही रहते\r\nहैं और यदि\r\nशुक्र बुध के साथ मीन राशि में आ\r\nतब वह अपनी उच्च\r\nराशि तो दोनों का कैंसिलेशन भी हो\r\nजाएगा ठीक\r\nहै तीसरा\r\nपॉइंट कि यह सूर्य के भी आसपास रहते\r\nहैं अब या तो वह सूर्य से बवे भाव में\r\nहोंगे सूर्य के साथ होंगे या सूर्य से\r\nदूसरे भाव में\r\nहोंगे शुक्र तो और दूर भी जा सकते हैं\r\nपरंतु बुध तो यही घूमेगा इन्हीं के आसपास\r\nरहेगा तो यह जो सूर्य योग\r\nहै उनको भी जन्म दे सकते\r\nहैं के शुक्र या बुध में से एक सूर्य के\r\nपीछे है और एक सूर्य से आगे\r\nहै जो सूर्य से पीछे ग्रह है वो डायरेक्ट\r\nमोशन में है और जो आगे ग्रह है वह वक्री\r\nमोशन में है तो दोनों सूर्य पर प्रभाव डाल\r\nरहे\r\nहैं तो वह तीन योग अपने बनाते हैं सूर्य\r\nऔर यह दोनों ग्रह एक राशि में भी हो सकते\r\nहैं और यदि सूर्य इन दोनों के मध्य में\r\nहो तब भी यह योग बन जाता\r\nहै ठीक है ये एक दो पॉइंट हो\r\nगए एक पॉइंट और होता\r\nहै कि जब भी बुध मीन राशि में\r\nहोगा तो वह क्रूर दृश कांड में ही\r\nहोगा मीन राशि के पहले दो दृश काण आयुध\r\nदृश काण कहलाते हैं और और तीसरा द्रेश काण\r\nसर्प द्रेश काण कहलाता है तो सर्प दृश काण\r\nआपको बंधन भी दे सकता है आयुष में लड़ाई\r\nझगड़ा दे सकता है\r\nया ऐसी प्रवृति दे सकता है कि मैं आयुध\r\nउठा कर के काम\r\nकरू लडू किसी भी\r\nचीज ठीक है तो एक ये हो गया\r\nयह सारे फैक्टर में गिन रहा हूं कि बुध जब\r\nनीच राशि में इसमें जो सबसे इंपॉर्टेंट\r\nफैक्टर है वह यह है कि जब भी\r\nबुध मीन राशि में होगा तो वह अपनी कन्या\r\nराशि\r\nको दृष्ट करेगा हमेशा\r\nकरेगा अब यहां एक दो पॉइंट जरूरी है\r\nअगर कन्या राशि में कोई ग्रह नहीं है फिर\r\nदोबारा सुनिए अगर कन्या राशि में कोई ग्रह\r\nविराजमान नहीं\r\nहै तो बुध की वह\r\nदृष्टि जहां भी कन्या राशि पड़ रही है उस\r\nभाव\r\nको उस भाव\r\nसे सेपरेशन दे देती है अलगाव दे\r\nवहां से अगर वो अच्छी राशि है अच्छे भाव\r\nकी राशि है वहां से भी दे\r\nदेगी और जो बुरी है उससे भी दे\r\nदे तो यह अलगाव दे देती है अलगाव से मेरा\r\nमतलब है कि यदि मान लो चतुर्थ भाव\r\nमें कन्या राशि है वो घर से अपने जम जहां\r\nपैदा हुए हो उस स्थान से अलगाव दे देगी और\r\nबहुत जल्दी दे देती\r\nइसी में एक और है कि अगर कन्या राशि में\r\nकोई ग्रह नहीं\r\nहै तो बुध की दशा\r\nमें उस भाव\r\nका फल नहीं\r\nमिलेगा यह लघु पराश्री का बहुत बड़ा\r\nसिद्धांत\r\nहै कि अगर मान लीजिए चतुर्थ भाव में कन्या\r\nराशि\r\nहै तो बुध की दशा में आपके परिवार की\r\nदुर्दशा आपके मकान की दुर्दशा होगी आपका\r\nअपना मकान नहीं बन सकता आपको वो लाभ नहीं\r\nहो सकता तो यह बेसिक पॉइंट्स है और बहुत\r\nइंपॉर्टेंट पॉइंट्स है बहुत ही रोचक इसका\r\nनीच राशि में होना होता है तो अब हम कोशिश\r\nकरेंगे एक एक ग्रह को एक एक इसको एक एक\r\nराशि के लिए\r\nहम बात\r\nकरें और देखें ठीक है तो अब हम अपनी\r\nस्क्रीन शेयर करते हैं\r\nअब पहले हमने लिया मेष\r\nराशि यहां पर यह बवे भाव\r\nमें अपनी नीच राशि में\r\nहोंगे अब यहां एक अच्छी बात क्या हो रही\r\nहै के शुक्र साथ में जो द्वितीय वाणी के\r\nवो है तो यह जो कुंडली है यह एक डांसर की\r\nहै\r\nआर्ट और इस कुंडली में तीन और छह के\r\nस्वामी बुद्ध हो जाते हैं जो अपनी नीच\r\nराशि में है तो ये एक अच्छा पराशर\r\nप्रिंसिपल\r\nहै दूसरा एक एक और योग इस कुंडली में बन\r\nरहा है मैं इसलिए भी बता रहा हूं कि सिर्फ\r\nबुध प ही सारी चीज नहीं है कि अष्टमेश\r\nतृतीय भाव में है ये सुपर स्ट्रांग विपरीत\r\nराजयोग भी बना रहे\r\nहैं ठीक है\r\nशुक्र सेकंड लॉर्ड है व तो हमने देख ही\r\nलिया तो ये एक डांसर थी अब तकलीफ कहां\r\nआई के छठे भाव\r\nमें ऋण रिपु रोग दुश्मन वगैरा तो कोई नहीं\r\nथे पर यह अपनी ही खुद खुद की दुश्मन\r\nथी इनको ड्रग्स की एडिक्शन\r\nथी क्योंकि सेकंड लॉर्ड हमारे संस्कार का\r\nस्वामी है इसके लिए हमें नवांश में जाना\r\nपड़ेगा मैं उतनी डिस्कशन को आगे नहीं बढ़ा\r\nरहा हूं मैं यहीं से देख के सिर्फ यह कह\r\nरहा हूं कि\r\nसंस्कार को प्रभावित बुद्ध ने किया और वो\r\nबुध शनि से भी दृष्ट\r\nहै अब नेक्स्ट चार्ट\r\nदेखिए यह भी सिंगर का चार्ट\r\nहै यहां पर भी क्योंकि शुक्र जो है बुध के\r\nसाथ है\r\nअब\r\nयहां हम कन्या पर फिरते हैं कन्या हमारा\r\nमेन टॉपिक\r\nहै कन्या पांचवा भाव है इस कुंडली का यह\r\nभी सिंगर प पॉप म्यूजिक सिंगर थे परंतु\r\nपांचवे भाव ने क्या किया यह स्कूल में फेल\r\nहो\r\nगए और इन्होंने आगे पढ़ना छोड़\r\nदिया और अपना म्यूजिक ग्रुप बना लिया और\r\nआगे चलते रहे नेक्स्ट कुंडली हम लेते हैं\r\nयह आइंस्टीन की कुंडली\r\nहै जो मैंने पहले बोला है वह यहां से बहुत\r\nकंफर्म होता है कि कन्या राशि चतुर्थ भाव\r\nमें\r\nहै बहुत ही छोटी उम्र में इनको अपना देश\r\nछोड़ कर के भागना\r\nपड़ा यह देता ही देता है अर्ली देता है और\r\nबुध की दशा में कोई मकान जायदाद नहीं बना\r\nपाएंगे ठीक है जी अब नेक्स्ट चार्ट यहां\r\nपर तीसरा\r\nभाव जिसमें कन्या है वहां पर कोई ग्रह\r\nनहीं\r\nहै मेरे\r\nको एस्ट्रो डाटा बैंक से नहीं इसमें पता\r\nचला कि भाई छोटे भाई बहन होंगे या नहीं\r\nहोंगे\r\nपर मुझे लगता है कि छोटे भाई बहन\r\nनहीं यह टेनिस\r\nप्लेयर छटा भाव बहुत प्रबल है इसलिए य\r\nटेनिस प्लेयर\r\nबने और एक विपरीत राजयोग भी बन रहा है छठे\r\nभाव का\r\nस्वामी यह अष्टम भाव\r\nमें विपरीत राजयोग बोल रहा\r\nसुपर स्ट्रंग नहीं बोल रहा क्योंकि\r\nबृहस्पति के साथ है और चंद्रमा से चंद्रमा\r\nलग्नेश अब यहां पर आप\r\nदेखो के अष्टमेश और नवमेश य साथ में कुछ\r\nऔर मैं बताता जाता हूं अष्टमेश और नवमेश\r\nका परस्पर परिवर्तन योग\r\nहै तो यह परिवर्तन धर्म के विरुद्ध कर\r\nदेता\r\nठीक है य टेनिस प्लेर तो कोई बात\r\nनहीं अपने धर्म का पालन कर्तव्यों का पालन\r\nकम\r\nकरें इसके बाद हमारे\r\nलियो यह पॉलिटिशियन की कुंडली\r\nहै यहां पर यह अष्टम भाव में\r\nबुध नीच राशि यहां भी कन्या में कोई ग्रह\r\nनहीं है\r\nदत्य भाव होता है किस चीज को सेपरेट करेगा\r\nयही तो मैं कह रहा हूं यह रोचक है पता\r\nनहीं किस चीज से सेपरेशन कराते तो या\r\nफैमिली से सेपरेशन\r\nकर या तो हम यह कहे कि भाई जीव जीव से\r\nकराएगा मटेरियल से कराएगा तो जीव तत्व में\r\nज्यादा इफेक्ट आता है ऐसा मैं सोचता हूं\r\nकि फैमिली से दूर कराएगा जीव तत्व फैमिली\r\nका ये लियो में पॉलिटिशियन थे फैमिली\r\nसे दूर रहे और मिनिस्टर\r\nबने क्योंकि लग्नेश और\r\nदशमेश यह बहुत ही अच्छी स्थिति में\r\nहै ठीक\r\nहै नेक्स्ट\r\nविर्गो अब ये भी एक ऑथर थे राइटर थे\r\nअब यहां पर क्या है\r\nदेखिए बुध के साथ भी केतु\r\nहै कन्या में भी ग्रह\r\nहै अब यहां मैं चंद्रमा को अच्छा नहीं\r\nमानूंगा चंद्रमा वैसे ही शत्रु राशि में\r\nहै और त्रि शाय के स्वामी\r\nहै सबसे बली त्रि शाय तो इनकी कहानी क्या\r\nथी यह राइटर थे\r\nयह राइटर थे\r\nऔर इन्होंने अपनी जो पुस्तक में ऐसा\r\nलिखा कि बहुत बड़ा सेक्स कैंडल्स उजागर हो\r\nअब यहां भी देखिए और चीज भी बता रहा हूं\r\nइसमें के अष्टम और\r\nनवम अष्टम और नवम के स्वामी एक साथ है\r\nविराजमान\r\nतो कर्तव्य पालन में आपको कमी आ गई और ऊपर\r\nसे इंटेलिजेंस खराब हो गई इंटेलिजेंस आपकी\r\nबर्बाद\r\nहै इसके बाद हम आते हैं तुला\r\nपर तुला\r\nमें यहां पर फिर मरकरी केतु के साथ है और\r\nकन्या\r\nमें फिर से राहु विराजमान तो अब ये राहु\r\nका भी\r\nअब जो राहु का इफेक्ट\r\nहै वो मिस्टीरियस है फिर से मटेरियल है\r\nसीक्रेट एनिमी\r\nहै जिनको आप नहीं जानते बारवा भाव फिक्शन\r\nराइटर्स का भी होता\r\nहै तो\r\nयह जो थे ये स्पाइडरमैन में एक्टर थे\r\nसक्सेस क्यों मिल रही\r\nहै क्योंकि\r\nशुक्र लगन को देख रहे हैं खुद शुक्र के\r\nस्वामी है परंतु त्रि शड के जो स्वामी है\r\nसूर्य वह उच्च राशि में विराजमान है तो यह\r\nसेवंथ हाउस का कवाड़ा कर देते\r\nइसके बाद हम आते हैं वृश्चिक अब वृश्चिक\r\nमें कन्या राशि 11 भाव में पड़ती\r\nहै गवे भाव में कोई ग्रह नहीं\r\nहै तो य हम कह सकते हैं 11वां भाव होता है\r\nहमारे ट्रस्टेड अच्छे मित्रों का बड़े भाई\r\nबहनों का हमारे एडवाइजर्स का तो उनसे कोई\r\nसंबंध नहीं\r\nरहे ये मैं इस कुंडली को देख के बोल रहा\r\nहूं ठीक है यह भी एक राइटर\r\nथे इनको क्यों प्रसिद्धि मिल\r\nगई क्यों यह सक्सेसफुल हो गए यह\r\nमंगल लगन को देख रहे हैं जो\r\nलग्नेश खुद\r\nलगने तो इनको सक्सेस मिल मेरे से कई\r\nक्वेश्चन आते क्या एक ही प्लेनेट सारा कुछ\r\nबना सकता है भैया ऐसे नहीं है क्यों नौ\r\nग्रह रखे हुए हैं हर एक को देखना पड़ता है\r\nहर एक का अपना अपना रोल है इसके बाद हम\r\nधनु प आते हैं अब ये चौथे भाव\r\nमें नीच राशि में होंगे और दशम भाव को\r\nदृष्ट\r\nकरें दशम भाव आपके कार्य क्षेत्र का भाव\r\nकार्य जो करते हैं कर्म जो करते\r\nहैं तो यहां पर क्या हुआ कर्म तो अच्छे\r\nकरा दिए\r\nभाई दशा में अपनी नहीं\r\nकराए परंतु पोजीशन दे\r\nदी पोजीशन इनको मिल गई यह\r\nजर्मन के बड़े आर्मी के बहुत बड़े सीनियर\r\nऑफिसर\r\nथे और सेकंड वर्ल्ड वार में\r\nयह सोवियत कैंप में जर्मनी में\r\nचले सोवियत से लड़ाई थी रशिया से इनकी\r\nजर्मनी की पर व वहां पर व भी तो डेरा डाल\r\nके चल काम कर सकते हैं ना तो वहां चले गए\r\nऔर रशियंस ने इनको अरेस्ट कर लिया और वही\r\nइनके कैरियर की समाप्ति हो\r\nगई आगे नहीं बढ़ पाए इसके बाद मकर\r\nमकर लगन\r\nमें बुध तीसरे भाव\r\nमें नीच के होंगे और यहां रगो फिर खाली\r\nहै यह\r\nकुंडली एक बैंकर की है अब देखि नवम भाव\r\nखत्म हो गया\r\nभाग्य\r\nकर्तव्य धर्म जो भी काम अच्छा करना चाहिए\r\nवो सब य खत्म हो यह बैंकर थे इन्होंने\r\nबैंक में फ्रॉड किया कंस्पिरेशन की और\r\nटैक्स की चोरी की तो इनको\r\nजेल और जेल की सजा भुगतनी\r\nपड़ी इसके बाद\r\nएक्वेरियस अब यह एक्वेरियस में सेकंड हाउस\r\nमें नीच के हुए और अष्टम भाव को ये\r\nदेखेंगे तो अष्टम भाव की क्या चीजें खराब\r\nकरेंगे जो लॉन्ग टर्म बीमारी है क्रॉनिक\r\nबीमारिया है उसको यह समाप्त कर द क्यों\r\nसमाप्त कर देंगे ज्यादा बल कहां से मिला\r\nशनि तृतीय भा अष्टम भाव को दृष्ट कर रहे\r\nशनि कारक लंग आयु के लंबी उम्र\r\nके तो\r\nइनको लंबी उम्र मिली और यह भी म्यूजिशियन\r\nथे रॉक बैंड वगैरह चलाते\r\nथे फिर से शुक्र इनके साथ आ गया शुक्र योग\r\nकारक\r\nहै वह भी बुध के साथ आ गया है दशम दशमेश\r\nभी साथ में आ गया है ठीक है तो यह इनकी\r\nकहानी रही इसके बाद यह सबसे बुरी कुंगली\r\nमिल गई\r\nमेरे अब यहां देखो अब छठे में फिर बैठा\r\nदिया ग्रह\r\nलगन में शुक्र के\r\nसाथ बुध है और शुक्र इस कुंडली के लिए\r\nअच्छा ग्रह नहीं है और व उच्च\r\nका शनि से संबंध शनि कन्या में है शन शनि\r\nभी जो है वह भी एक अशुभ ग्रह इस कुंडली के\r\nइनका सबका संबंध\r\nठीक है तो यह एक सीरियल किलर की कुंडली\r\nहै यहां\r\nपर यह भी\r\nस्ट्रंग काम करना आयुध दृश कांड में है और\r\nके भी थे तो ज्यादा अग्रेसिव बंदा हो जाता\r\nहै जब भी नीच का हो जाए अगर वो लग्नेश हो\r\nबुध तब अग्रेशन थोड़ा कम हो जाता\r\nहै क्योंकि ईगो कम हो जाती है बाकी में\r\nअग्रेशन आ जाता\r\nहै मेंटल इंटेलिजेंट अग्रेशन हो जाता है\r\nतो यह हमारे इनके रूल थे तो यहां पर आप\r\nइनको देख के आप कर सकते हैं बहुत ही\r\nरोचक बुध का नीच राशि में होना बहुत ही एक\r\nअच्छा सब्जेक्ट है इसके ऊपर और काम किया\r\nजा सकता है यह योग भी बनाता है बड़ बुढ़े\r\nदृश कान में भी होता है बुद्धि का भी कारक\r\nहै यह सब लेकर के आदमी को की बुद्धि भी\r\nभ्रष्ट कर देता है ठीक है आगे फिर मिलेंगे\r\nऔर कोई रोचक विषय लेकर के ठीक है फिर\r\nमिलेंगे नमस्कार धन्यवाद"},{"topic":"नीच राशि के बृहस्पति से फलित","text":"नमस्कार\r\nमित्रों आज हम नीच ग्रह या डेबिटेड\r\nप्लेनेट\r\nकी सीरीज\r\nमें फिर आपके साथ\r\nहै और आज\r\nहम बुध के नीच राशि में होने पर वार्ता\r\nकरेंगे उसका क्या फलित होता\r\nहै बुध का नीच में होना नीच राशि में होना\r\nएक बहुत ही\r\nरोचक विषय\r\nहै और\r\nबुध हमारी बुद्धि का कारक\r\nहै और बुद्धि का कारक होने के साथ-साथ\r\nयह एक ऐसा ग्रह\r\nहै जो हमेशा जब भी नीच राशि में होगा तो\r\nअपनी उच्च राशि को देखेगा अपनी उच्च राशि\r\nको मतलब वो कन्या को हमेशा\r\nदेखेगा अब हम देखते हैं कि\r\nयह किन कुंडलियों में हमको मिलता\r\nहै देखिए\r\nबुध सूर्य से 23 24 डिग्री से ज्यादा दूर\r\nनहीं जा\r\nसकता तो जब\r\nबुध नीच राशि में\r\nहोगा तो वह सूर्य के आसपास ही\r\nहोगा तो\r\nसूर्य या तो कुंभ में हो सकता\r\nहै या मीन में हो सकता\r\nहै या मेष में हो सकता है तभी आपको बुध\r\nनीच राशि में मिल सकता\r\nहै तो यह जो जन्म\r\n15 मार्च के से 15 मई तक के बीच के होते\r\nहैं उसमें आपको बुध नीच राशि में मिल सकता\r\nहै तो पहला पॉइंट तो यह\r\nहै दूसरा पॉइंट है के शुक्र\r\nभी इनके आसपास ही रहते\r\nहैं और यदि\r\nशुक्र बुध के साथ मीन राशि में आ\r\nतब वह अपनी उच्च\r\nराशि तो दोनों का कैंसिलेशन भी हो\r\nजाएगा ठीक\r\nहै तीसरा\r\nपॉइंट कि यह सूर्य के भी आसपास रहते\r\nहैं अब या तो वह सूर्य से बवे भाव में\r\nहोंगे सूर्य के साथ होंगे या सूर्य से\r\nदूसरे भाव में\r\nहोंगे शुक्र तो और दूर भी जा सकते हैं\r\nपरंतु बुध तो यही घूमेगा इन्हीं के आसपास\r\nरहेगा तो यह जो सूर्य योग\r\nहै उनको भी जन्म दे सकते\r\nहैं के शुक्र या बुध में से एक सूर्य के\r\nपीछे है और एक सूर्य से आगे\r\nहै जो सूर्य से पीछे ग्रह है वो डायरेक्ट\r\nमोशन में है और जो आगे ग्रह है वह वक्री\r\nमोशन में है तो दोनों सूर्य पर प्रभाव डाल\r\nरहे\r\nहैं तो वह तीन योग अपने बनाते हैं सूर्य\r\nऔर यह दोनों ग्रह एक राशि में भी हो सकते\r\nहैं और यदि सूर्य इन दोनों के मध्य में\r\nहो तब भी यह योग बन जाता\r\nहै ठीक है ये एक दो पॉइंट हो\r\nगए एक पॉइंट और होता\r\nहै कि जब भी बुध मीन राशि में\r\nहोगा तो वह क्रूर दृश कांड में ही\r\nहोगा मीन राशि के पहले दो दृश काण आयुध\r\nदृश काण कहलाते हैं और और तीसरा द्रेश काण\r\nसर्प द्रेश काण कहलाता है तो सर्प दृश काण\r\nआपको बंधन भी दे सकता है आयुष में लड़ाई\r\nझगड़ा दे सकता है\r\nया ऐसी प्रवृति दे सकता है कि मैं आयुध\r\nउठा कर के काम\r\nकरू लडू किसी भी\r\nचीज ठीक है तो एक ये हो गया\r\nयह सारे फैक्टर में गिन रहा हूं कि बुध जब\r\nनीच राशि में इसमें जो सबसे इंपॉर्टेंट\r\nफैक्टर है वह यह है कि जब भी\r\nबुध मीन राशि में होगा तो वह अपनी कन्या\r\nराशि\r\nको दृष्ट करेगा हमेशा\r\nकरेगा अब यहां एक दो पॉइंट जरूरी है\r\nअगर कन्या राशि में कोई ग्रह नहीं है फिर\r\nदोबारा सुनिए अगर कन्या राशि में कोई ग्रह\r\nविराजमान नहीं\r\nहै तो बुध की वह\r\nदृष्टि जहां भी कन्या राशि पड़ रही है उस\r\nभाव\r\nको उस भाव\r\nसे सेपरेशन दे देती है अलगाव दे\r\nवहां से अगर वो अच्छी राशि है अच्छे भाव\r\nकी राशि है वहां से भी दे\r\nदेगी और जो बुरी है उससे भी दे\r\nदे तो यह अलगाव दे देती है अलगाव से मेरा\r\nमतलब है कि यदि मान लो चतुर्थ भाव\r\nमें कन्या राशि है वो घर से अपने जम जहां\r\nपैदा हुए हो उस स्थान से अलगाव दे देगी और\r\nबहुत जल्दी दे देती\r\nइसी में एक और है कि अगर कन्या राशि में\r\nकोई ग्रह नहीं\r\nहै तो बुध की दशा\r\nमें उस भाव\r\nका फल नहीं\r\nमिलेगा यह लघु पराश्री का बहुत बड़ा\r\nसिद्धांत\r\nहै कि अगर मान लीजिए चतुर्थ भाव में कन्या\r\nराशि\r\nहै तो बुध की दशा में आपके परिवार की\r\nदुर्दशा आपके मकान की दुर्दशा होगी आपका\r\nअपना मकान नहीं बन सकता आपको वो लाभ नहीं\r\nहो सकता तो यह बेसिक पॉइंट्स है और बहुत\r\nइंपॉर्टेंट पॉइंट्स है बहुत ही रोचक इसका\r\nनीच राशि में होना होता है तो अब हम कोशिश\r\nकरेंगे एक एक ग्रह को एक एक इसको एक एक\r\nराशि के लिए\r\nहम बात\r\nकरें और देखें ठीक है तो अब हम अपनी\r\nस्क्रीन शेयर करते हैं\r\nअब पहले हमने लिया मेष\r\nराशि यहां पर यह बवे भाव\r\nमें अपनी नीच राशि में\r\nहोंगे अब यहां एक अच्छी बात क्या हो रही\r\nहै के शुक्र साथ में जो द्वितीय वाणी के\r\nवो है तो यह जो कुंडली है यह एक डांसर की\r\nहै\r\nआर्ट और इस कुंडली में तीन और छह के\r\nस्वामी बुद्ध हो जाते हैं जो अपनी नीच\r\nराशि में है तो ये एक अच्छा पराशर\r\nप्रिंसिपल\r\nहै दूसरा एक एक और योग इस कुंडली में बन\r\nरहा है मैं इसलिए भी बता रहा हूं कि सिर्फ\r\nबुध प ही सारी चीज नहीं है कि अष्टमेश\r\nतृतीय भाव में है ये सुपर स्ट्रांग विपरीत\r\nराजयोग भी बना रहे\r\nहैं ठीक है\r\nशुक्र सेकंड लॉर्ड है व तो हमने देख ही\r\nलिया तो ये एक डांसर थी अब तकलीफ कहां\r\nआई के छठे भाव\r\nमें ऋण रिपु रोग दुश्मन वगैरा तो कोई नहीं\r\nथे पर यह अपनी ही खुद खुद की दुश्मन\r\nथी इनको ड्रग्स की एडिक्शन\r\nथी क्योंकि सेकंड लॉर्ड हमारे संस्कार का\r\nस्वामी है इसके लिए हमें नवांश में जाना\r\nपड़ेगा मैं उतनी डिस्कशन को आगे नहीं बढ़ा\r\nरहा हूं मैं यहीं से देख के सिर्फ यह कह\r\nरहा हूं कि\r\nसंस्कार को प्रभावित बुद्ध ने किया और वो\r\nबुध शनि से भी दृष्ट\r\nहै अब नेक्स्ट चार्ट\r\nदेखिए यह भी सिंगर का चार्ट\r\nहै यहां पर भी क्योंकि शुक्र जो है बुध के\r\nसाथ है\r\nअब\r\nयहां हम कन्या पर फिरते हैं कन्या हमारा\r\nमेन टॉपिक\r\nहै कन्या पांचवा भाव है इस कुंडली का यह\r\nभी सिंगर प पॉप म्यूजिक सिंगर थे परंतु\r\nपांचवे भाव ने क्या किया यह स्कूल में फेल\r\nहो\r\nगए और इन्होंने आगे पढ़ना छोड़\r\nदिया और अपना म्यूजिक ग्रुप बना लिया और\r\nआगे चलते रहे नेक्स्ट कुंडली हम लेते हैं\r\nयह आइंस्टीन की कुंडली\r\nहै जो मैंने पहले बोला है वह यहां से बहुत\r\nकंफर्म होता है कि कन्या राशि चतुर्थ भाव\r\nमें\r\nहै बहुत ही छोटी उम्र में इनको अपना देश\r\nछोड़ कर के भागना\r\nपड़ा यह देता ही देता है अर्ली देता है और\r\nबुध की दशा में कोई मकान जायदाद नहीं बना\r\nपाएंगे ठीक है जी अब नेक्स्ट चार्ट यहां\r\nपर तीसरा\r\nभाव जिसमें कन्या है वहां पर कोई ग्रह\r\nनहीं\r\nहै मेरे\r\nको एस्ट्रो डाटा बैंक से नहीं इसमें पता\r\nचला कि भाई छोटे भाई बहन होंगे या नहीं\r\nहोंगे\r\nपर मुझे लगता है कि छोटे भाई बहन\r\nनहीं यह टेनिस\r\nप्लेयर छटा भाव बहुत प्रबल है इसलिए य\r\nटेनिस प्लेयर\r\nबने और एक विपरीत राजयोग भी बन रहा है छठे\r\nभाव का\r\nस्वामी यह अष्टम भाव\r\nमें विपरीत राजयोग बोल रहा\r\nसुपर स्ट्रंग नहीं बोल रहा क्योंकि\r\nबृहस्पति के साथ है और चंद्रमा से चंद्रमा\r\nलग्नेश अब यहां पर आप\r\nदेखो के अष्टमेश और नवमेश य साथ में कुछ\r\nऔर मैं बताता जाता हूं अष्टमेश और नवमेश\r\nका परस्पर परिवर्तन योग\r\nहै तो यह परिवर्तन धर्म के विरुद्ध कर\r\nदेता\r\nठीक है य टेनिस प्लेर तो कोई बात\r\nनहीं अपने धर्म का पालन कर्तव्यों का पालन\r\nकम\r\nकरें इसके बाद हमारे\r\nलियो यह पॉलिटिशियन की कुंडली\r\nहै यहां पर यह अष्टम भाव में\r\nबुध नीच राशि यहां भी कन्या में कोई ग्रह\r\nनहीं है\r\nदत्य भाव होता है किस चीज को सेपरेट करेगा\r\nयही तो मैं कह रहा हूं यह रोचक है पता\r\nनहीं किस चीज से सेपरेशन कराते तो या\r\nफैमिली से सेपरेशन\r\nकर या तो हम यह कहे कि भाई जीव जीव से\r\nकराएगा मटेरियल से कराएगा तो जीव तत्व में\r\nज्यादा इफेक्ट आता है ऐसा मैं सोचता हूं\r\nकि फैमिली से दूर कराएगा जीव तत्व फैमिली\r\nका ये लियो में पॉलिटिशियन थे फैमिली\r\nसे दूर रहे और मिनिस्टर\r\nबने क्योंकि लग्नेश और\r\nदशमेश यह बहुत ही अच्छी स्थिति में\r\nहै ठीक\r\nहै नेक्स्ट\r\nविर्गो अब ये भी एक ऑथर थे राइटर थे\r\nअब यहां पर क्या है\r\nदेखिए बुध के साथ भी केतु\r\nहै कन्या में भी ग्रह\r\nहै अब यहां मैं चंद्रमा को अच्छा नहीं\r\nमानूंगा चंद्रमा वैसे ही शत्रु राशि में\r\nहै और त्रि शाय के स्वामी\r\nहै सबसे बली त्रि शाय तो इनकी कहानी क्या\r\nथी यह राइटर थे\r\nयह राइटर थे\r\nऔर इन्होंने अपनी जो पुस्तक में ऐसा\r\nलिखा कि बहुत बड़ा सेक्स कैंडल्स उजागर हो\r\nअब यहां भी देखिए और चीज भी बता रहा हूं\r\nइसमें के अष्टम और\r\nनवम अष्टम और नवम के स्वामी एक साथ है\r\nविराजमान\r\nतो कर्तव्य पालन में आपको कमी आ गई और ऊपर\r\nसे इंटेलिजेंस खराब हो गई इंटेलिजेंस आपकी\r\nबर्बाद\r\nहै इसके बाद हम आते हैं तुला\r\nपर तुला\r\nमें यहां पर फिर मरकरी केतु के साथ है और\r\nकन्या\r\nमें फिर से राहु विराजमान तो अब ये राहु\r\nका भी\r\nअब जो राहु का इफेक्ट\r\nहै वो मिस्टीरियस है फिर से मटेरियल है\r\nसीक्रेट एनिमी\r\nहै जिनको आप नहीं जानते बारवा भाव फिक्शन\r\nराइटर्स का भी होता\r\nहै तो\r\nयह जो थे ये स्पाइडरमैन में एक्टर थे\r\nसक्सेस क्यों मिल रही\r\nहै क्योंकि\r\nशुक्र लगन को देख रहे हैं खुद शुक्र के\r\nस्वामी है परंतु त्रि शड के जो स्वामी है\r\nसूर्य वह उच्च राशि में विराजमान है तो यह\r\nसेवंथ हाउस का कवाड़ा कर देते\r\nइसके बाद हम आते हैं वृश्चिक अब वृश्चिक\r\nमें कन्या राशि 11 भाव में पड़ती\r\nहै गवे भाव में कोई ग्रह नहीं\r\nहै तो य हम कह सकते हैं 11वां भाव होता है\r\nहमारे ट्रस्टेड अच्छे मित्रों का बड़े भाई\r\nबहनों का हमारे एडवाइजर्स का तो उनसे कोई\r\nसंबंध नहीं\r\nरहे ये मैं इस कुंडली को देख के बोल रहा\r\nहूं ठीक है यह भी एक राइटर\r\nथे इनको क्यों प्रसिद्धि मिल\r\nगई क्यों यह सक्सेसफुल हो गए यह\r\nमंगल लगन को देख रहे हैं जो\r\nलग्नेश खुद\r\nलगने तो इनको सक्सेस मिल मेरे से कई\r\nक्वेश्चन आते क्या एक ही प्लेनेट सारा कुछ\r\nबना सकता है भैया ऐसे नहीं है क्यों नौ\r\nग्रह रखे हुए हैं हर एक को देखना पड़ता है\r\nहर एक का अपना अपना रोल है इसके बाद हम\r\nधनु प आते हैं अब ये चौथे भाव\r\nमें नीच राशि में होंगे और दशम भाव को\r\nदृष्ट\r\nकरें दशम भाव आपके कार्य क्षेत्र का भाव\r\nकार्य जो करते हैं कर्म जो करते\r\nहैं तो यहां पर क्या हुआ कर्म तो अच्छे\r\nकरा दिए\r\nभाई दशा में अपनी नहीं\r\nकराए परंतु पोजीशन दे\r\nदी पोजीशन इनको मिल गई यह\r\nजर्मन के बड़े आर्मी के बहुत बड़े सीनियर\r\nऑफिसर\r\nथे और सेकंड वर्ल्ड वार में\r\nयह सोवियत कैंप में जर्मनी में\r\nचले सोवियत से लड़ाई थी रशिया से इनकी\r\nजर्मनी की पर व वहां पर व भी तो डेरा डाल\r\nके चल काम कर सकते हैं ना तो वहां चले गए\r\nऔर रशियंस ने इनको अरेस्ट कर लिया और वही\r\nइनके कैरियर की समाप्ति हो\r\nगई आगे नहीं बढ़ पाए इसके बाद मकर\r\nमकर लगन\r\nमें बुध तीसरे भाव\r\nमें नीच के होंगे और यहां रगो फिर खाली\r\nहै यह\r\nकुंडली एक बैंकर की है अब देखि नवम भाव\r\nखत्म हो गया\r\nभाग्य\r\nकर्तव्य धर्म जो भी काम अच्छा करना चाहिए\r\nवो सब य खत्म हो यह बैंकर थे इन्होंने\r\nबैंक में फ्रॉड किया कंस्पिरेशन की और\r\nटैक्स की चोरी की तो इनको\r\nजेल और जेल की सजा भुगतनी\r\nपड़ी इसके बाद\r\nएक्वेरियस अब यह एक्वेरियस में सेकंड हाउस\r\nमें नीच के हुए और अष्टम भाव को ये\r\nदेखेंगे तो अष्टम भाव की क्या चीजें खराब\r\nकरेंगे जो लॉन्ग टर्म बीमारी है क्रॉनिक\r\nबीमारिया है उसको यह समाप्त कर द क्यों\r\nसमाप्त कर देंगे ज्यादा बल कहां से मिला\r\nशनि तृतीय भा अष्टम भाव को दृष्ट कर रहे\r\nशनि कारक लंग आयु के लंबी उम्र\r\nके तो\r\nइनको लंबी उम्र मिली और यह भी म्यूजिशियन\r\nथे रॉक बैंड वगैरह चलाते\r\nथे फिर से शुक्र इनके साथ आ गया शुक्र योग\r\nकारक\r\nहै वह भी बुध के साथ आ गया है दशम दशमेश\r\nभी साथ में आ गया है ठीक है तो यह इनकी\r\nकहानी रही इसके बाद यह सबसे बुरी कुंगली\r\nमिल गई\r\nमेरे अब यहां देखो अब छठे में फिर बैठा\r\nदिया ग्रह\r\nलगन में शुक्र के\r\nसाथ बुध है और शुक्र इस कुंडली के लिए\r\nअच्छा ग्रह नहीं है और व उच्च\r\nका शनि से संबंध शनि कन्या में है शन शनि\r\nभी जो है वह भी एक अशुभ ग्रह इस कुंडली के\r\nइनका सबका संबंध\r\nठीक है तो यह एक सीरियल किलर की कुंडली\r\nहै यहां\r\nपर यह भी\r\nस्ट्रंग काम करना आयुध दृश कांड में है और\r\nके भी थे तो ज्यादा अग्रेसिव बंदा हो जाता\r\nहै जब भी नीच का हो जाए अगर वो लग्नेश हो\r\nबुध तब अग्रेशन थोड़ा कम हो जाता\r\nहै क्योंकि ईगो कम हो जाती है बाकी में\r\nअग्रेशन आ जाता\r\nहै मेंटल इंटेलिजेंट अग्रेशन हो जाता है\r\nतो यह हमारे इनके रूल थे तो यहां पर आप\r\nइनको देख के आप कर सकते हैं बहुत ही\r\nरोचक बुध का नीच राशि में होना बहुत ही एक\r\nअच्छा सब्जेक्ट है इसके ऊपर और काम किया\r\nजा सकता है यह योग भी बनाता है बड़ बुढ़े\r\nदृश कान में भी होता है बुद्धि का भी कारक\r\nहै यह सब लेकर के आदमी को की बुद्धि भी\r\nभ्रष्ट कर देता है ठीक है आगे फिर मिलेंगे\r\nऔर कोई रोचक विषय लेकर के ठीक है फिर\r\nमिलेंगे नमस्कार धन्यवाद"},{"topic":"नीच राशि के मंगल से फलित","text":"नमस्कार\r\nमित्रों आज हम फिर\r\nसे अपने नीज राशियों के ग्रहों के सीरीज\r\nमें आपका फिर स्वागत\r\nहै आज हम मंगल पर बात करने वाले\r\nहैं और आज से यह जो\r\nसीरीज मंगल से हम जब शुरू कर रहे हैं\r\nतो यह दो राशियों के स्वामियों की सीरीज\r\nअब शुरू हो गई है अब तक हमने केवल एक एक\r\nराशि के स्वामी सूर्य और चंद्रमा का हमने\r\nविश्लेषण\r\nकिया मंगल\r\nडेबिटेड अब यहां आप देखिए मंगल की दो\r\nराशिया मेष और\r\nवृश्चिक जब भी मंगल नीच राशि में होगा तो\r\nमेष से\r\nवो केंद्र में जाएगा और वृश्चिक से\r\nत्रिकोण हो जाए तो यह हमेशा केंद्र या\r\nत्रिकोण में अपनी राशियों से जाता है जो\r\nअच्छी पोजीशन है हम इसे खराब नहीं कह\r\nसकते दूसरा क्या मंगल का हमेशा नीच भंग हो\r\nसकता\r\nहै मुझे लगता है हां\r\nक्योंकि हमारा नियम है के ग्रह जिस राशि\r\nमें नीच राशि में होता है अगर उसका\r\nस्वामी चंद्रमा से या लगन से केंद्र में\r\nहो तो उसका नीच भंग हो जाता है अब चंद्रमा\r\nकर्क राशि में नीच के होते\r\nहैं और उनका जो स्वामी है कर्क का व\r\nचंद्रमा स्वयं\r\nतो मंगल के जो नीच राशि के स्वामी हैं वह\r\nहमेशा चंद्रमा ही है और जो चंद्रमा से\r\nकेंद्र में तो नीच भंग हो जाना\r\nचाहिए ठीक है तो इसलिए हम यह कह सकते हैं\r\nके यह हमेशा\r\nनीच दूसरा मंगल क्या है मंगल सेनापति\r\nहै क्या\r\nसेनापति हार मा सकता है कमजोर समझ सकता है\r\nअपने आपको को इसीलिए शायद यह नियम बना\r\nहै के मंगल हमेशा सेनापति है रक्षा करने\r\nके लिए है वह कभी कमजोर नहीं हो\r\nसकता इसकी सपोर्ट में एक और पॉइंट\r\nहै कि मंगल को विशेष दृष्टि प्रदान की गई\r\nहै पराशर\r\nमें वो चतुर्थ और अष्टम भाव को पूर्ण\r\nदृष्टि\r\nदेते अब यहां मैं मानता हूं कि जो चतुर्थ\r\nदृष्टि\r\nहै वह एक पुलिस की दृष्टि है चतुर्थ भाव\r\nसमाज का भाव है जनता का भाव है उसको\r\nप्रोटेक्ट करना है यहां पर मंगल का रोल\r\nपुलिस का हो जाता\r\nहै दूसरी उनकी स्पेशल दृष्टि दी गई है\r\nअष्टम भाव को अष्टम भाव का रोल यह आर्मी\r\nसीक्रेट अफेयर्स उनका होता\r\nहै तो यहां पर रोल मंगल का सेनापति का है\r\nकि शत्रु को हराना है उसको मारना है\r\nउसको हमको विजय प्राप्त करानी है और\r\nसुरक्षित रखना है तो दोनों सुरक्षा करने\r\nके यह इनके रोल है\r\nअब यहां पर एक चीज और हम याद रखें आगे और\r\nजो आएगा सारे ग्रहों के लिए कि पराशर जी\r\nने नीच ग्रहो के लिए कुछ विशेष सूत्र दिए\r\nहुए हैं एक्सेप्शन दी हुई\r\nहै उसमें पहली एक्सेप्शन है कि यदि तीन छ\r\nऔर आठवे भाव\r\nमें कोई ग्रह नीच राशि में विराजमान हो तो\r\nवह योग कारक हो\r\nजाता दूसरा नियम दिया है कि त्रिक भाव के\r\nस्वामी 6 आ 12 के स्वामी यदि नीच राशि में\r\nहो तो भी वह योग कारक होते हैं अब इसमें\r\nएक नियम में अपना ऐड कर देता\r\nहूं इसमें मैं ऐड कर रहा हूं देखिए तीन छ\r\nआ तो आ चुका 12 आ गया\r\nइनमें अब सब भली त्रि शाय भाव का स् त्रि\r\nशाय भाव होता है\r\nगवा और सबसे ज्यादा खराब फल देने वाला\r\nमाना गया है उसको अब देखिए पराशर ने तीन छ\r\nको तो निकाल दिया खड़ा में से कि वह अगर\r\nबैठे हो तीन में बैठे हो छ में बैठा हो या\r\nउसका लड नीच का हो तो योग हो गया अब गवे\r\nका\r\nस्वामी यदि नीच राशि\r\nमें तो भी मैं उसको कहूंगा वह त्रि शनाय\r\nका\r\nस्वामी खराब फल नहीं दे\r\nसकता और अगर कहीं वह उपचय में चला गया तो\r\nतो वह सुंदर फल दे\r\nदेगा तो यह\r\nहमारी इनकी बेसिक पॉइंट था इसको आप हमेशा\r\nअब याद रखना आगे के उसमें भी हमार वीडियोस\r\nमें तो अब हम मंगल को एक एक राशि में अब\r\nइससे तो लगता है कि किसी राशि में भी खराब\r\nनहीं होना चाहिए किसी भी लगन के लिए मंगल\r\nको खराब नहीं होना चाहिए परंतु हम देखेंगे\r\nकब खराब हो जाएगा और कब वह अच्छा फल हमेशा\r\nदेता रहे तो अब हम थोड़ी सी स्क्रीन शेयर\r\nकरने की बात करेंगे\r\nयहां से भैया हमने मेष राशि से शुरू\r\nकिया मेष राशि में अब देखिए चतुर्थ भाव\r\nमें मंगल नीच के हो गए अब यहां जो अच्छी\r\nसुंदर बात हुई है कि इनको शुक्र दृष्ट कर\r\nरहे जो है केंद्र के स्वामी भी है द्वितीय\r\nके भी है परंतु प्रबल मारक भी\r\nहै और मंगल को बल मिल अभय मंगल देखिए\r\nदूसरे तरीके से भी यह अष्टमेश\r\nहै अष्टमेश होक के यह नीच राशि में हो तो\r\nपराशर का राजयोग\r\nहै यह एथलीट\r\nथे काफी अच्छा इन्होंने प्रदर्शन किया और\r\nराजयोग का फल स्पोर्ट्स में इनको मिला अब\r\nदूसरी कुंडली पर आते हैं\r\nदूसरी\r\nकुंडली यह टोरस लगन की यहां आप देखिए\r\nतृतीय भाव में\r\nमंगल नीच राशि में है तो दोनों में पराशर\r\nका य लग\r\nगया तो मंगल तो योग काक हो\r\nग पहले उसमें भी कुछ नहीं हुआ इसमें भी\r\nकुछ नहीं हुआ ठीक है इनकी क्या कहानी\r\nहै अब इसमें दो दो योग बन रहे एक तो तीसरे\r\nभाव\r\nमें नीच के ग्रह बैठे हैं और थ लॉर्ड नीच\r\nका वह भी एक योग है दो बताए थे हमने थ\r\nलॉर्ड नीच का है यह भी धावक थे\r\nस्प्रिंटर और इन्होंने 200 मीटर रेस में\r\n68 ओलंपिक में 20 सेकंड से कम का समय\r\nनिकाला बहुत अच्छा इन्होंने प्रदर्शन किया\r\nतीसरे भाव में आकर के यह साहस अपना तो\r\nपक्का कर ही देते हैं साहस बहुत ब बढ़िया\r\nहो गया और जुपिटर उ के बैठे हुए बहुत\r\nबढ़िया साहस इनका है साहसी बना दिया तो\r\nयहां भी मंगल खराब नहीं हुए अब हम मिथुन\r\nपर देख लेते हैं\r\nभाई मिथुन लगन के लिए\r\nमंगल द्वितीय भाव\r\nमें नीच राशि में होंगे अब कौन है\r\nये सिक्सथ के स्वामी\r\nहै पराशर जी का\r\nराजयोग एकादश के स्वामी\r\nहैं सबसे बड़े त्रि शनाय का\r\nस्वामी तो ये तो बहुत ही बढ़िया हो गया\r\nत्रि शाय का स्वामी\r\nअब यहां फिर दत्य हाउस में बैठ गए तो धन\r\nभी\r\nदेंगे वाणी भी अच्छी\r\nदेंगे और राहु जो है वह भी दश का काम\r\nकरेगा यहां\r\nपर तो यह एक बहुत बड़े म्यूजिशियन\r\nथे इसके बाद हम कर्क पर आते हैं अब यहां\r\nये लगन में ही नीच के हो जाएंगे अब देखिए\r\nएक एक को देखते जाइए अभी तक बुरा नहीं\r\nमिला मेरे\r\nको मंगल बुरा नहीं कर रहा और कोई बुरा करे\r\nतो\r\nकरें अब यहां मंगल को हम योग कारक मा\r\nमानेंगे कर्क राशि के लिए मंगल योग कारक\r\nहोते हैं अब यह दशमेश है कोई कंडीशन नहीं\r\nलग रही और पंचमेश है वो भी कंडीशन नहीं लग\r\nरही\r\nअब यह गड़बड़ हो\r\nगई ठीक है\r\nना परंतु यह दशमेश\r\nहै मंगल ने खराब नहीं किया अब यह वाइस\r\nप्रेसिडेंट\r\nथे वाइस प्रेसिडेंट रहे 5 साल तक उसमें\r\nमंगल का कोई रोल नहीं था कि उन्होंने ना\r\nमना कर दिया हो कि भाई मत करो तुम\r\nपरंतु मंगल राज योग में नहीं\r\nहै मंगल राज योग में नहीं\r\nहै शनि के साथ होने से इनको बल\r\nमिला और भी चीज है शुक्र अपनी राशि के हैं\r\nबृहस्पति अपनी राशि के हैं लगन लॉर्ड और\r\nबृहस्पति एक साथ है नाइंथ लॉर्ड लगन लॉर्ड\r\nका संबंध है तो मंगल की वजह से इनको हानि\r\nनहीं\r\nहुई यहां पर हो सकता है अगर मंगल गड़बड़\r\nकर जाए और कोई योग ना हो तो जहां राज योग\r\nप्रदान करते हैं वहां गड़बड़ कर सकते हैं\r\nयह हम देखेंगे अभी लियो सिंह लगन की\r\nकुंडली तो हमें कहां अजीब दिख रहा है देख\r\nकर के जहां पर मंगल को हम राजयोग कारक\r\nबोलते हैं वहां पर अगर यह गड़बड़ कर जाते\r\nहैं तो अब\r\nयहां अब यहां क्या होगा फोर्थ लॉर्ड\r\nबवे ठीक है पराशर जी का नियम नहीं लग रहा\r\nहै बवे में नीच ग्रह बवे का लर्ड नीच का\r\nहोना चाहिए तब राजयोग होता है दूसरे यह\r\nनवम भाव के स्वामी\r\nहै और यह नीच रा में चले\r\nगए नौ और 12 का\r\nएक्सचेंज अब एक और य नियम बहुत ही\r\nस्ट्रांग लग रहा है\r\nजो के नवमेश अगर नीच राशि में\r\nहो और द्वितीय भाव में पाप ग्रह विराजमान\r\nहो तो वह व्यक्ति निर्धन होता है उसकी\r\nलाइफ बर्बाद हो अब यहां देखिए\r\nसूर्य लग्नेश है नॉर्मली हम कहेंगे नहीं\r\nइसको हम पापी नहीं मान सकते नहीं मान रहे\r\nहैं हम नहीं मान\r\nरहे परंतु यहां पर जो शुक्र है वो नीच\r\nराशि में विराजमान तो यह कुंडली हमारे को\r\nएक क्रिमिनल किलर\r\nकी अब य नाइंथ लॉर्ड हमारा डेबिटेड हो\r\nकर्क लगन के लिए थ लर्ड डेबिटेड हो\r\nजाए तो मंगल का कोई इन दोनों लगन में अगर\r\nमंगल नीच का हो जाता है जब हम सोचते हैं\r\nकि भाई\r\nमंगल खराब है कन्या के लिए खराब था ष\r\nमिथुन के लिए खराब था वहा तो अच्छा फल दे\r\nरहा था खराब ग्रह िक का अगर नीच में हो\r\nजाता है तो वह शुभ फल देता है योग कारक\r\nनीच का हो गया तब वो अच्छे फल नहीं\r\nदेता अब इसके बाद हम देखेंगे वर्गो में अब\r\nयहां पर यह योग कारक नहीं\r\nहै अब\r\nयहां वर्गो में आप देखिए यहां पर यह\r\nकौन-कौन है भाई\r\nतृत नीच के हो\r\nग पर यह योग कारक नहीं\r\nमाना अष्टमेश नीच के हो ग तो\r\nयोग ठीक\r\nहै तो यह हमारे को यह मंगल जो है अब योग\r\nदेने वाला बन गया और बहुत से कॉमिनेशन आ\r\nरहे हैं इसके यहां पर वीनस और बुध का भी\r\nकॉमिनेशन आ रहा है राजयोग बन रहा है ठीक\r\nहै मंगल ए सच इसके लिए अच्छे नहीं है\r\nऔर यह जो मंगल है अष्टमेश है सॉरी तृत है\r\nस्कॉर्पियो के और छठे भाव में केतु\r\nविराजमान\r\nहै यह आर्मी के बहुत बड़े जनरल\r\nथे बहुत साहस का काम इन्होंने हमेशा किया\r\nतृतीय\r\nलॉर्ड नीच का पराशर योग नहीं\r\nहै साहस देता\r\nहै अब यहां पर देखा जाएगा हम कहेंगे भाई\r\nये कैसे साहस दे दिया शनि महाराज रिस्ट कर\r\nरहे\r\nहैं पर मंगल योग में इवॉल्वड है अब हो\r\nसकता है भ आर्मी जनरल रहे हो साहसी ना हो\r\nबड़े डिसीजन ना लिए हो अब यह मैं नहीं कह\r\nसकता यह तो मैंने जो पढ़ा है इसमें उसको\r\nमैंने बता दिया\r\nअब इसके बाद हम लेते\r\nहैं तुला\r\nराशि तुला राशि में अब मंगल प्रबल मार्क\r\nहै प्रबल मार्क है\r\nये और नीच राशि में हो गए\r\nहैं अब यहां गड़बड़\r\nहै दूसरा सबसे बड़ी बात क्या हुई है य\r\nके बृहस्पति ने इस मंगल को दृष्ट किया\r\nहै तुला लगन के लिए बृहस्पति भी बहुत ही\r\nबेकार ग्रह\r\nहोते अभ बताऊंगा तो भाई साहब यह कुंडली\r\nमाता हारी की\r\nहै जिसको जो जर्मन के के\r\nअगेंस्ट इसने जासूसी की और कम उम्र में ही\r\nइसको फायरिंग स्क्वेयर से मार दिया गया\r\nथा डांसर थी सबसे बड़ी जासूस माना गया\r\nइसको माता हारी यह उसका चार्ट है उसके\r\nमंगल दशम भाव में नीच का था तो तुला लगन\r\nके\r\nलिए कितना भयंकर परिणाम इसने दे\r\nदिया इसके बाद हम आते हैं\r\nवृश्चिक वृश्चिक\r\nमें अब यह लग्नेश भी है और नवम भाव में\r\nनीच राशि में बैठ कोई दिक्कत नहीं है कोई\r\nदिक्कत\r\nनहीं और यह ष्ठ\r\nहै छटे का स्वामी नीच राशि\r\nमें फिर हो गया\r\nराजयोग अब मंगल एक्चुअली फोर्स और आर्मी\r\nऔर इसका बहुत बड़ा वो प्लेनेट है जहां भी\r\nयह कनेक्ट हो जाता है तो स्पोर्ट्स में और\r\nउसमें ले जाता है तो यहां पर भी यह\r\nबास्केटबॉल प्लेयर\r\nथे अब एक वृश्चिक के लिए एक खास बात\r\nहै वृश्चिक लगन के लिए या मेष लगन के लिए\r\nअगर मंगल नीच राशि में हो जाता है तो वह\r\nव्यक्ति हर एक से अच्छी तरह मिलता जुलता\r\nहै कोई ईगो\r\nनहीं ये सबसे बड़ा पॉइंट इसमें आ जाता है\r\nठीक है अब हम आते हैं धनु\r\nपर अब धनु के लिए मंगल अष्टम भाव में नीच\r\nराशि में होंगे योग बन गया पराशर जी का\r\nयोग बन\r\nगया और पंचमेश अब नीच राशि\r\nमें द्वाद शेष अब नीच राशि में दूसरा योग\r\nहो तो कोई तकलीफ नहीं है सिर्फ एक पंचमेश\r\nका नीच राशि में जाना यह थोड़ा सा गड़बड़\r\nकर जाता है थ लड भी आ गया ये आ गया अब\r\nयहां यह चार्ट है एक्ट्रेस का\r\nहॉलीवुड की एक्ट्रेस थी अच्छा नाम\r\nकमाया\r\nपरंतु विवाहित जीवन और वह सब इनका खराब हो\r\nगया\r\nबुद्धि बुद्धि की जहां तक बात हो जाती है\r\nउसको यह थोड़ा सा वृश्चिक में यह गड़बड़\r\nकर जाता है क्योंकि यह लग्नेश की उच्च\r\nराशि है अब कर्क जो है लग्नेश की उच्च\r\nराशि है और वहां पर ये जाकर\r\nनीच राशि में विराजमान हो\r\nजाते इसके बाद हम\r\nलेंगे\r\nमकर अब मकर में सप्तम भाव\r\nमें नीच\r\nराशि यह\r\nडेफिनेटली पाप संबंध आकर के यह विवाहित\r\nजीवन में काफी बुरा हाल कर सकता है\r\nअब यहां\r\nपर मंगल अब लगन को भी देख रहे हैं और इस\r\nकुंडली में यह चंद्रमा को भी देख रहे हैं\r\nजो इसका\r\nडिस्पोजिटर या यह कहे चंद्रमा इनको देख\r\nरहे तो मंगल को बल मिल गया दूसरा क्या है\r\nशुक्र अपने भाव को खुद देख रहे\r\nमंगल की वजह से यह पॉलिटिक्स में नहीं\r\nआए यह पॉलिटिशियन की कुंडली\r\nहै वहां क्या है किसलिए यह अब मेरा वाला\r\nइसमें त्रि शाय का योग लग जाता है के गवे\r\nका स्वामी नीच राशि में और वो भी पाप\r\nसंबंध में और अपने डिस्पोजिटर\r\nदृष्ट तो यहां य इन्होने बड़ा अच्छा\r\nपॉलिटिशियन पैदा कर दिया अब इसके बाद हम\r\nआते हैं एक्वेरियस\r\nप एक्वेरियस में अय छठे भाव में नीच राशि\r\nमें होंगे कोई दिक्कत\r\nनहीं छठे भाव का स्वामी हो या छठे भाव नीच\r\nराशि में हो योग कारक\r\nहै और यहां भी चंद्रमा फिर इनको देख\r\nनीच भंग भी हो रहा है वैसे भी ठीक है जी\r\nतो यहां पर यह भी आर्मी नेवी के ऑफिसर थे\r\nफ्लायर फ्लाई भी करते थे नेवल ऑफिसर काफी\r\nअच्छी पोजीशन पर थे\r\nऔर तो यह एक नेवल ऑफिसर और ये फ्लाई\r\nइन्होंने स्पेस में भी फ्लाई किया स्पेस\r\nमें भी गए वो भी एडवेंचर इन् ने किया तो\r\nयहां पर अब इनका तीसरा भाव भी और दशम भाव\r\nदोनों प्रॉस्पर कर\r\nरहे ठीक है अब लास्ट हमारी कुंडली रह गई\r\nअब पायस\r\nकी पायस में यह पंचम भाव में उच्च के हो\r\nजाए नीच के हो जाएंगे यहां पर भी नवमेश\r\nनीच का\r\nनवमेश नीच राशि में चले गए पर यहां अच्छी\r\nबात क्या हुई है सेकंड हाउस में कोई पाप\r\nग्रह नहीं है इसलिए कंगाल नहीं\r\nबनाया नहीं तो लाइफ बहुत बुरी हो\r\nजा सेकंड लॉर्ड नीच के है नीच राशि में है\r\nयहां पर इस शनि से\r\nवन साइडेड अब य मैं ये नहीं कह सकता कि\r\nबहुत ज्यादा धन है पर यह एक एक्ट्रेस\r\nकी कुंडली\r\nहै तो हमने अभी तक\r\nदेखा\r\nके कुछ राशियों को छोड़\r\nके ज्यादातर\r\nमंगल अगर नीच राशि में हो\r\nतो वह बहुत ज्यादा खराब रिजल्ट नहीं दे\r\nसकते योग कारक अगर वो कर्क में और सिम में\r\nहो रहे हैं वहां पर नीच होना अच्छा नहीं\r\nहै तुला लगन के लिए यह प्रबल मार्क\r\nहै\r\nतो इतना ज्यादा खराब नहीं है\r\nजितना लियो और कर्क के लिए\r\nतो यहां भी यह दो तीन राशियों में सिर्फ\r\nअच्छे फल नहीं देते हैं बाकी यह अच्छे फल\r\nही देते\r\nहैं और ज्यादातर इसका मंगल नीच का हो या\r\nउच्च का हो तो वह\r\nस्पोर्ट्स आर्मी\r\nडिफेंस इस तरह की एजेंसीज लॉ जिसमें वह\r\nलोगों को दंड दे सके\r\nदंडाधर में वो दंड सुनाते हैं उसमें भी\r\nमंगल आना जरूरी है इसीलिए मंगल को दशम भाव\r\nमें दिग बली माना गया है सूर्य और चंद्र\r\nमंगल यह दोनों ही दशम भाव में बली होते\r\nहैं और इन्हीं के पास अथॉरिटी है कि हम\r\nकिसी को दंड दे स दंड अधिकारी तो मेफिक\r\nअगर थ में आते हैं\r\nमंगल भी आते हैं तो वह दंड देने वाला\r\nव्यक्ति बन सकता है ठीक है जी नमस्कार\r\nबहुत बहुत धन्यवाद फिर मि"},{"topic":"नीच राशि के शनि से फलित","text":"नमस्कार\r\nमित्रों आज हम नीच ग्रहों की सीरीज\r\nमें आखिरी ग्रह शनि महाराज को लेकर के\r\nप्रस्तुत\r\nहुए शनि\r\nमहाराज काल के नियंत्रक\r\nहै उनकी मर्जी के बगैर कोई काम नहीं होता\r\nशनि मेष राशि में अपनी नीच राशि में होते\r\nहैं अब\r\nशनि शैने शैने मतलब स्लो स्लो चलने वाले\r\nहैं तो ये तकरीबन साढ़े 29 साल में अपने\r\nएक चक्कर एक साइकिल पूरी करते\r\nहैं तो नीच राशि में ये तकरीबन 29 साल के\r\nबाद आपको दिखाई देता\r\n1911 में ये नीच के थे उसके बाद ये 40 41\r\n1940 41 में नीच राशि में आए फिर 70 71\r\nमें\r\nआए तो ज्यादातर जो फेमस आदमियों की कुंडली\r\nहमें मिलेंगी वो 1911 1940 1970 के आसपास\r\nकी होंगी क्योंकि मैं डाटा एस्ट्रो डाटा\r\nबैंक से लेता\r\nहूं क्योंकि इस तरह से अगर मैं लोकल\r\nकुंडिया देखू बहुत मुश्किल है मिलना बहुत\r\nसे लोग बोलते हैं कि आप लोकल बाहर की\r\nफॉरेन की कुंडलिया क्यों लेते हैं भाई\r\nमेरे लिए आसान है मुझे तो नियम समझाना\r\nहोता है ना कहीं की भी\r\nहो अब जब\r\nशनि मेष राशि\r\nमेंे तो मेष राशि में सूर्य उच्च के होते\r\nहैं उच्च राशि में होते हैं\r\nतो सूर्य और शनि का संबंध सूर्य चाहे साथ\r\nहो या दृष्ट कर रहे हो वो उसका नीच भग तो\r\nकरेगा\r\nही और अच्छा फल उसको देने के लिए मजबूर भी\r\nकरेगा अब बहुत से इसको पिता पुत्र का\r\nसंबंध मानेंगे अगर दोनों य साथ में होते\r\nहैं तो अब वो किस परिस्थिति\r\nमें खराब करता है पिता पुत्र के संबंध को\r\nवो भी हम देखेंगे अभी बात करते हैं\r\nदूसरा यह शुक्र की राशि में उच्च के होते\r\nहैं तो शुक्र के साथ भी अच्छा संबंध आ\r\nजाएगा व तो भी नीच भंग हो\r\nजाएगा शुक्र बृहस्पति के राशि में उच्च\r\nराशि\r\nमें तो बृहस्पति\r\nसे अगर शनि का संबंध आता है दोनों एक साथ\r\nबैठ जाए या बृहस्पति देख रहे हो शनि को तो\r\nभी एक बहुत अच्छा योग राज योग बनता है\r\nजैसा हमने बृहस्पति के नीच राशि में होने\r\nपर यह कहा था कि अगर बृहस्पति नीच राशि\r\nमें शनि के साथ हो तो राजयोग बनता है जैसे\r\nकि हमने बराक ओबामा की कुंडली में देखा\r\nथा तो मंगल सूर्य और बृहस्पति और शुक्र टू\r\nसद एक्सटेंट ये हमारे स्पेशल ग्रह हो गए\r\nइसके\r\nलिए एक और पॉइंट\r\nके जब भी शनि नीच राशि में होंगे तो वो\r\nमकर को दृष्ट\r\nकरेंगे अब जैसा\r\nहमने बुध में देखा था कि बुध जब नी नीच\r\nराशि में होते हैं तो वह कन्या को दृष्ट\r\nकरेंगे अब इन दोनों में क्या डिफरेंस\r\nहै बुध को सौम्य शुभ ग्रह माना गया है\r\nतो व जीव तत्व को बढ़ाते हैं जहां पर भी\r\nअगर कन्या राशि पड़ी है जिस भाव में भी उस\r\nभाव के जीव तत्व को अच्छा कर देते\r\nहैं इसके विपरीत शनि मकर को हमेशा देखेंगे\r\nजब नीच में\r\nहोंगे तो वह मकर राशि जहां पड़ रही है\r\nउसके जीव तत्व को हानि कर देंगे परंतु\r\nभौतिक तत्व को बढ़ावा द जैसे मान लो मेष\r\nमें मेष लगन है तो दशम भाव को वो दृष्ट\r\nकर अब दशम भाव का जीव\r\nतत्व ऐसा मान सकते हैं कि वह आपके ऑफिस\r\nआपके कार्य क्षेत्र का\r\nबॉस तो बॉस को हानि\r\nकरते परंतु आपके व्यवसाय प्रोफेशन को\r\nपोजीशन को उसको अच्छा\r\nकरें तो यह बेसिक हमारे पॉइंट\r\nहै शनि\r\nकी नीच राशि में होने के इन्हीं को हम\r\nअप्लाई\r\nकर मकर में देखेंगे बाकी कोई राजयोग\r\nदेखेंगे दूसरा एक जब भी नीच ग्रह देखो\r\nपराशर जी के वह दो\r\nनियम किस किस भाव में नीच ग्रह\r\nका नीच ग्रह का बैठा हुआ\r\nराजयोग देता है किस भाव\r\nका लॉर्ड नीच राशि में हो तो राज योग देता\r\nहै यह दो हम कई दफर रिपीट कर चुके हैं तो\r\nउसको हम हमेशा याद र अब हम आते हैं अपनी\r\nकुंडलिया\r\nदेखने ठीक है\r\nजी पहली पहला चार्ट ये मेष राशि का हमने\r\nलिया यहां पर शनि लग में ही नीच राशि में\r\nहै और दशम भाव को देखें तो अभी हम जैसा\r\nबता के चुके कि दशम भाव के भौतिक तत्व को\r\nस्टेटस को ऊंचा\r\nकरें परंतु बॉस को\r\nहार ये ब्रिटेन के पॉलिटिशियन की कुंडली\r\nहै और यह एमपी रहे हाउस ऑफ कॉमनस जैसे\r\nहमारा लोकसभा होती है उसी तरह से हाउस ऑफ\r\nकॉमनस के यह मेंबर रहे चुने गए 1979 में\r\nऔर अपनी डेथ तक 97 तक यह मेंबर ऑफ\r\nपार्लियामेंट रहे अब क्या हुआ जब इनकी डेथ\r\nहुई तो जो प्राइम मिनिस्टर व इनके बॉस हुए\r\nउनकी गवर्नमेंट अल्पमत में आ गई और रिजाइन\r\nकरने तक की नौबत आ गई परंतु बच\r\nगए तो यहां पर यह इन्होंने शनि ने अब यहां\r\nएक और अच्छा पॉइंट है कि त्रि शाय का\r\nस्वामी नीच राशि\r\nमें त्रि शाय का स्वामी उच्च में हो तो\r\nगड़बड़ करते है तो आप य हमेशा देखो उच्च\r\nराशि के ग्रह को हमें बड़े सतर्कता से\r\nलेना होता है नीच राशि में ज्यादातर नीच\r\nभंग हो जाएगा और वह कहीं ना कहीं अगर प्री\r\nशड का स्वामी भी हुआ तो वो बुरे फल नहीं\r\nदेगा तो यह तो हुआ मेष का\r\nअब\r\nहम वृषभ लेते\r\nहैं यहां पर यह बवे भाव\r\nमें अब\r\nयह राजयोग कारक है टोरस के\r\nलिए और राजयोग कारक का नीच राशि में\r\nहोना अच्छा नहीं माना\r\nगया पर हमें और चीज इस कुंडली में क्योंकि\r\nफेमस लोगों की कुंडली है तो हमें अच्छा\r\nकोई और सग कोई हमें मिल जाता है अब यहां\r\nबृहस्पति शनि को दष्ट कर\r\nरहे एक\r\nराजयोग दूसरा\r\nतृत अष्टम भाव में चले गए दूसरा\r\nराजयोग\r\nटश फिर अष्टम भाव में चले गए वो राजयोग छ\r\nऔर का एक्सचेंज हो गया तो यहां भी बढ़िया\r\nहो गया तो यह बहुत अच्छा इनके\r\nलिए अब कहते हैं भाई नाइंथ लॉर्ड\r\nअगर डेबिटेड हो जाए तो भाग्य खत्म\r\nहो पर उसके लिए दूसरे और गवे भाव में कोई\r\nनीच ग्रह होना चाहिए यहां वो नहीं है अब\r\nयह शनि ने मकर को नवम भाव को दृष्ट\r\nकिया इनके फादर की डेथ होई जब यह बहुत\r\nछोटी सी उम्र की थी अकेली लड़की थी पिता\r\nकी बहुत छोटी उम्र में इनके फादर की डेथ\r\nहो\r\nगई अब इसके बाद हम आते हैं मिथुन पर अब यह\r\nजो है गवे भाव में\r\nनीच राशि में होंगे और अष्टमेश हो के नीच\r\nके हो गए अब य नवमेश होकर के भी नीच के तो\r\nयह भी क्या भाग्य खत्म\r\nकरेंगे\r\nनहीं अष्टमेश नीच राशि में होना राजयोग\r\nहै वह बन गया बढ़िया राजयोग बन\r\nगया मंगल और शनि में एक्सचेंज हो गया है\r\nमंगल और शनि तो अष्टम भाव भी प्रबल हो\r\nगया हुआ क्या इनकी डेथ जो है वो कैंसर से\r\nई इसलिए लिया है एल डेबिटेड वो तो ठीक है\r\nमंगल का जो एक्सचेंज\r\nहै उसने बली तो किया परंतु रोग को भी बली\r\nकर दिया थ हाउस को बली कर दिया\r\nएथ जीव तत्व\r\nमकर राशि है अष्टम भाव\r\nमें जीव को हानि पहुंचा उनके आयु के उसको\r\nहानि पहुंचा दी इनको कैंसर जैसा तक का रोग\r\nदे\r\nदिया अब इसके बाद आते हैं\r\nकर्क कर्क राशि में अब यह दशम भाव में ही\r\nनीच राशि में\r\nहोंगे अब यहां देखो\r\nकुरली बृहस्पति साथ में आ गए हमारा राजयोग\r\nबन\r\nगया परंतु शनि ने सप्तम भाव को\r\nदृष्टि मकर वहां पड़ रहा है सप्तम\r\nभाव तो इनके विवाह में तकलीफ देती जीव\r\nतत्व\r\nविवा पति और संबंधी जो भी आते हैं अब ये\r\nचार्ट है नैंसी सिनाट्रा का जो फ्रेंक\r\nसिनाट्रा की लड़की है और खुद ने भी\r\nम्यूजिक में बहुत ज्यादा काम नाम कमाया\r\nअष्टमेश नीच के राजयोग हो\r\nगया ठीक है तो यहां पर भी वह थ्योरी हमारी\r\nकाम करती\r\nहै अब यह लियो लगन के\r\nलिए अब यहां लियो लगन के लिए आप देखो भाई\r\nशनि नवम भाव में नीचे\r\nऔर मजे की बात नवमेश भी नीच के\r\nहैं नवम और द्वादश में परिवर्तन योग\r\nहै नवमेश नीच\r\nके दूसरे भाव में\r\nकेतु पर इनको कंगाल तो नहीं बनाया भाई अभी\r\nतक पता नहीं क्या होगा\r\nक्योंकि जब भी केतु एक मैंने नोटिस किया\r\nहै कि केतु अगर द्वितीय भाव में होते हैं\r\nतो उसको\r\nकंट्रोल वाणी पर दो दो योग मिल गए य पर\r\nअपनी वाणी पर कंट्रोल नहीं होता केतु\r\nद्वितीय में होता है उसे पता ही नहीं होता\r\nमैं क्या भल गया याद नहीं रहता दूसरा एक\r\nहोता है कि अगर\r\nबुध लगन में विराजमान हो और बृहस्पति से\r\nदृष्ट\r\nहो तो उसको अपनी वाणी पर कंट्रोल नहीं\r\nरहता ये दोनों यहां मिल रहे हैं एक और शनि\r\nकी\r\nदशा इनकी 29 मार्च 2024 को\r\nशुरू और उसी दिन इनको अरेस्ट कर लिया\r\nगया तो शनि का फल क्योंकि ऐसी सिचुएशन\r\nयहां बन रही है बहुत ही\r\nअजीब होने वाला है शनि की दशा शुरू हुई है\r\nसाल अब इसके बाद हम आते हैं कन्या\r\nलगन कन्या लगन में अब शनि जो है यह अष्टम\r\nमें आ\r\nगए अब यहां क्या हो रहा है मंगल जो इनके\r\nडिस्पोजिटर है खुद उच्च के एक्सचेंज है\r\nशनि में और मंगल में और बृहस्पति देख रहे\r\nहैं अब इनकी इनका\r\nजीवन फिल्मों में एज एक्स्ट्रा इन्होंने\r\nकाम शुरू किया और एक हफ्ते के सात डॉलर और\r\nलंच इनको मिलता था 1911 में ठीक है जीविका\r\nके लिए सा न डलर डे उनको मिल जाता था काम\r\nचल रहा परंतु भयंकर बात क्या हुई कि\r\nइनको सिर्फ 26 साल की आयु\r\nमिली 26 साल की आयु में इनकी डेथ हो कारण\r\nशुक्र\r\nहै शुक्र और बृहस्पति में एक्सचेंज है\r\nदोनों\r\nमारक तो वीनस की दशा में इनकी डेथ\r\nहो इस एक्सचेंज\r\nने और राहु केतु के एक्सेस ने\r\nइनको खराब कर दिया और जो वीनस का फल था वो\r\nवीनस जो है चंद्रमा के साथ है जो त्रि\r\nसडायरी है तो यहां इसने खराब कर दिया वही\r\nजो रूल है त्रि शडा और उसका तो अब हम आते\r\nतुला लगन\r\nप तुला लगन में ये सप्तम भाव में\r\nनीच राशि\r\nमें सप्तम भाव में नीच राशि में विराजमान\r\nहोंगे जैसे पहले कहा था अगर योग कारक\r\nकुंडली\r\nका नीच ग्रह राशि में चला जाए और यहां तो\r\nपीड़ित भी\r\nहै तो यह कुंडली है ईवा ब्राउन\r\nकी जो हिटलर की प्रेमिका थी और हिटलर ने\r\n30 अप्रैल\r\n1945 को सुसाइड किया अब मेरा जन्मदिन मत\r\nदेख लेना उस दिन का 30 अप्रैल\r\n1945 और विवाह से\r\nपहले विवाह किया और विवाह के बाद इन्होंने\r\nसुसाइड कर अब एक सुसाइड का अब बात आई है\r\nमेरे से रुका नहीं जाता है मैं बता देता\r\nहूं नियम जो सुसाइड के होते हैं सुसाइड का\r\nनियम एक सबसे स्ट्रंग\r\nके मारक भाव\r\nमारकेश तीसरे भाव को दृष्ट\r\nकरें अब यहां सिचुएशन बहुत\r\nभयंकर मार्के प्रबल\r\nमार्केशिटी रा भी मार्केशिटी\r\nछठा भाव कितना बली हो गया अच्छा मैंने अब\r\nय कर मकर अपने आप देख लेना भाई और और जगह\r\nयहां पर मकर से थर्ड हाउस\r\nको जीव तत्व को हानि दे रहा है हो सकता है\r\nछोटे भाई बहन मुझे लगता है यह ब्रूसली की\r\nकुंडली है शायद यह सबसे छोटे थे अपने\r\nपरिवार\r\nमें और साहस बहुत दे\r\nदिया ब्रूसली अपने पिक्चर में आते थे\r\nफिल्म वग में और बड़ा नाम था कि कौन सा\r\nवो गेम खेलते हैं उसमें बहुत ज्यादा इनका\r\nनाम\r\nथा अब यहां पर क्या हुआ जुपिटर भी साथ में\r\nतो नेम फेम दे दिया मंगल देख रहे हैं\r\nशुक्र देख रहे\r\nहैं ठीक है मंगल जो खुद डिस्पोजिटर है\r\nइनके उच्चे है सब देख रहे हैं अब यहां\r\nगलती गड़बड़ क्या हुई है के त्रिश बलि\r\nत्रि शाय बुध जो स्वामी है वह भी देख\r\nरहे तो ओवरडोज ऑफ मेडिसिन से इनकी डेथ\r\nहुई यह मरकरी ने खराब कर दिया नहीं तो\r\nसारे बड़े अच्छे अच्छे योग इनको मिल गए थे\r\nअब यहां आते हैं धनु लगन अब य पंचम भाव\r\nमें\r\nशनि आएंगे इस कुंडली में मंगल खुद शनि के\r\nसाथ\r\nहै बृहस्पति से दृष्ट\r\nहै और राहु भी उनके साथ है उसकी पीड़ा हम\r\nकह सकते\r\nहैं तो शनि को हम मानेंगे राहु जब साथ में\r\nआया कि वोह एफ्लिक्टेड है कुछ तो\r\nएफ्लिक्शन है\r\nयह जो कुंडली थी ये लूसी आई लव लूसी बहुत\r\nज्यादा इनके वो सीरियल चले\r\nथे\r\nइनका शनि द्वितीय भाव को देख\r\nरहा द्वितीय भाव से सेपरेशन दे दी फैमिली\r\nसे फैमिली के लोगों से सेपरेशन दे दी\r\nपरंतु भौतिक धन दिया धन में कमी नहीं\r\nकी तो यह नियम इनके भी लगता है\r\nअब इसके बाद हम आते हैं\r\nमकर मकर\r\nमें अब शनि महाराज इस कुंडली में\r\nभी\r\nयह बृहस्पति से दृष्ट\r\nहै तो यह फेम भी दे\r\nगया और जो अय शनि है यह भाई साहब लगन को\r\nदेख रहे\r\nहैं मकर लगन में है तो खुद से सेपरेशन दे\r\nदेंगे ये म्यूजिशियन\r\nथे परंतु खुद से सेपरेशन कैसे दे दी शनि\r\nमें चंद्रमा की दशा में इनकी\r\nमृत्यु चंद्रमा भी मारक है शनि भी मारक\r\nहै और शनि चंद्रमा को दृष्ट भी कर रहे\r\nहैं तो केंद्र में ये शनि\r\nमार्ग का भी काम कर रहा था ठीक है जी अब\r\nइसके बाद आते\r\nहैं कुंभ\r\nमें यहां पर ये तीसरे भाव में नीच राशि\r\nमें होंगे पराशर योग बन\r\nगया और बृहस्पति के साथ फिर योग बन\r\nगया ठीक है अब जो शनि है ये बवे भाव को\r\nदृष्ट कर रहे हैं\r\nबावा\r\nभाव जीव तत्व आपके गुप्त शत्रुओं का होता\r\nहै जिनका आपको नहीं पता\r\nहोता अष्टम भाव होता है शत्रुओं का जिनको\r\nआप जानते\r\nहैं प्रकट हो जाते हैं बवे भाव में व\r\nप्रकट नहीं होते बिहाइंड की सीन काम\r\nकरते तो ये अब ये\r\nलग्नेश तीसरे भाव\r\nमें नीच के हो\r\nगए मेहनत बहुत\r\nकरेंगे बहुत मेहनती है ल्थ लॉर्ड डेबिटेड\r\nफिर राजयोग हो\r\nगया तो यह भी अच्छी लाइफ इन्होंने रखी और\r\nशनि की दशा में जो 1960 में शुरू हुई तब\r\nसे 40 50 साल से यह अपने काम में मशगूल है\r\nकाम कर रहे हैं एफर्ट का है थर्ड\r\nहाउस ठीक है अब इसके बाद आते हैं हम मीन\r\nराशि मीन राशि में यह द्वितीय भाव में नीच\r\nराशि में\r\nहो अब यहां पर क्या\r\nहै किसी की दृष्टि नहीं आ रही है जुपिटर\r\nकी भी\r\nइनकी दशम\r\nभाव मकर गवे भाव में तो थ हाउस के जीव\r\nतत्व को तकलीफ दी परंतु आय बढ़ा दी आय\r\nबहुत होई बाकी और कॉमिनेशन है\r\nइनके जिससे यह न्यूट्रिशन वगैरह पर यह लेख\r\nलिखते हैं किताबें लिखते\r\nहैं अब यहां जो मेन चीज है इस कुंडली में\r\nक्या होगी कि बारवा का लॉर्ड थ लर्ड जो है\r\nवह दूसरे भाव में\r\nआ तो ऐसा व्यक्ति अब बवे भाव का स्वामी\r\nअगर दूसरे में आ जाए तो शास्त्रों में\r\nलिखा है वह दान पुण्य\r\nकर खाने पीने की फूड की बात\r\nकर उस तरह से तो यह अपने न्यूट्रिशन खाना\r\nपीना कैसा बनाना चाहिए क्या करना चाहिए तो\r\nबवे का स्वामी दूसरे में आ जाए तो या तो\r\nदान पुण्य\r\nकरेगा किताबें लिखेगा इसकी न्यूट्रिशन की\r\nबात करेगा खाने की बात करेगा पौष्टिकता की\r\nबात करेगा ठीक है जी तो यह हमारी 12\r\nराशियों के लिए नीच के शनि के गणना है कुछ\r\nटिप्स दिए हैं आप उनको नोट करिए परंतु जो\r\nलगाते हैं\r\nतो ध्यान से लगाने पड़ेंगे खास तौर से आयु\r\nके सुसाइड वगैरह के जो\r\nहै तो आज हमारी य नीच ग्रह की सीरीज\r\nसंपन्न हुई है आगे फिर कोई और टॉपिक लेकर\r\nके आपके साथ फिर रहेंगे और फिर कोई ना कोई\r\nऔर आगे बात करेंगे नमस्कार धन्यवाद one"},{"topic":"नीच राशि के शुक्र से फलित","text":"नमस्कार नीच ग्रहों की सीरीज\r\nमें आज हम शुक्र ग्रह को लेकर के प्रस्तुत\r\nहुए हैं और उसके बारे में कुछ बात\r\nकरेंगे\r\nशुक्र कन्या राशि में अपनी नीच राशि में\r\nहोते\r\nहैं और\r\nशुक्र सूर्य से 48 डिग्री से ज्यादा दूर\r\nनहीं जा\r\nसकते तो जब\r\nभी सूर्य कर्क से लेकर के और वृश्चिक लगन\r\nतक वृश्चिक\r\nमें गोचर रहते हैं तब तक ही पॉसिबिलिटी है\r\nकि शुक्र नीच राशि में\r\nहोंगे अन्यथा नहीं होते हैं\r\nअब दूसरी चीज\r\nइसमें जब भी\r\nशुक्र कन्या में\r\nहोंगे तो वह मीन राशि को दृष्ट\r\nकरेंगे हर कोई और जो मीन राशि है वो उनकी\r\nउ उच्च राशि है तो हर ग्रह जब भी नीच राशि\r\nमें होता है तो अपनी उच्च राशि को भी व\r\nदृष्ट करता है बहुत से जो मेजर ग्रह वो तो\r\nतीन तीन राशियों को भी दृष्ट कर लेते हैं\r\nयह तो एक ही दृष्टि है इनकी सप्तम दृष्टि\r\nतो व उसी को दृष्ट\r\nकरें तो यह अगर वहां मीन राशि में कोई\r\nग्रह नहीं है तो यह उसको बल\r\nद और अगर कोई और ग्रह\r\nहै तो वह उसके अनुसार चल\r\nदेंगे शुक्र का\r\nहमेशा नीच भंग यदि बुध के साथ है तो हो ही\r\nजाता है दूसरा नीच भंग इनका बृहस्पति से\r\nहोता है और भी नियम है वो केंद्र में आ\r\nजाए इस तरह\r\nसे दूसरा शुक्र को कला का ग्रह माना गया\r\nहै और दूसरा ग्रह कला का जो माना गया है\r\nवह है\r\nचंद्रमा तो प्राय हमेशा नहीं है भाई मैंने\r\nकुछ में नोटिस किया क्विक\r\nदेखने के लिए के\r\nचंद्रमा शुक्र से केंद्र में हो और या लगन\r\nसे केंद्र में हो तो वह अपने कार्य में\r\nनिपुण हो जाता है आर्ट में निपुण हो जाता\r\nहै यह मैंने नीच के शुक्र के साथ देखा है\r\nक्योंकि जब भी बहुत सारे जो चार्ट मेरे को\r\nमिले हैं एस्ट्रो डेटा बैक से क्योंकि वही\r\nमेरा सोर्स है ऑथेंटिक सोर्स है नहीं तो\r\nकोई कहेगा भाई कहां से कुंडली आप ले आते\r\nहो य किसकी ले ली है किसकी कुंडली है तो\r\nयह जो मैं डाटा शेयर करता हूं यह सिर्फ\r\nएस्ट्रो डटा बैंक से है आप डेट ऑफ बर्थ\r\nदेख करके एस्ट्रो डाटा बैंक से पूरा टाइम\r\nवगैरह सब वो निकाल सकते हैं और चेक कर\r\nसकते\r\nहैं ठीक है एक और नियम जो\r\nहर जब भी कोई ग्रह नीच राशि में होता है\r\nतब वो लगता\r\nहै वैसे सामान्य तौर पर देखे तो लग्नेश\r\nयदि लगन को दृष्ट कर रहा हो तो लगन बली हो\r\nजाती है कुंडली को बहुत बल मिल जाता\r\nहै इसके साथ ही वह नियम है कि अगर नीच\r\nराशि का ग्रह भी अगर लगन को देख रहा\r\nहो तो लगन को व बली कर देता है और अपने फल\r\nभी अच्छे देता\r\nहै अब य शुक्र के काम में क्या होगा जब वो\r\nकन्या राशि में है तो सिर्फ मीन लगन को वह\r\nदृष्ट कर सकते हैं तभी यह नियम\r\nलगेगा बाकी में यह नियम नहीं लगेगा\r\nअगर यह नीच राशि में शुक्र है ठीक है जी\r\nतो अब हम एक एक कुंडलियों पर देखते हैं और\r\nआगे उस पर वार्ता करते\r\nहैं यह लीजिए पहली\r\nकुंडली मेष लगन\r\nकी मेष लगन की कुंडली है इसमें छठे भाव\r\nमें शुक्र नीच राशि में\r\nहोंगे और पराशर जी का नियम वह पहले भी\r\nबताया था कि भाई नछ आ में नीच नीच राशि\r\nमें ग्रह हो तो राज योग होता है 6 आ 12 के\r\nस्वामी यदि नीच राशि में हो तो राज योग\r\nहोता\r\nहै सबसे बढ़िया हो गया तो यह अच्छा हो गया\r\nऔर यहां पास में मीन में चंद्रमा\r\nबैठे यह पास को बली दे रहे बल दे रहे हैं\r\nऔर चंद्रमा भी वहां विराजमान हो गए तो बल\r\nऔर मिल गया मीन को कर दिया इन्होने दृष्ट\r\nतो यह एक एक्टर राइटर थे बहुत ही स्किल्ड\r\nथे अपने आर्ट में\r\nइनकी जो शुक्र की दशा थी\r\nवोह सन 61 में शुरू हो\r\nगई 44 का जन्म है 17 साल की उम्र में इनकी\r\nशुक्र की दशा शुरू हो गई और शुक्र ने इनको\r\nबहुत इनकम भी दी सेकंड लॉर्ड है सेकंड\r\nलॉर्ड डेबिटेड मैं हमेशा बोलता हूं व कहीं\r\nना कहीं धन दे ही देते\r\nखास तौर से कर्क राशि में अगर चंद्रमा\r\nकर्क राशि के लिए चंद्रमा नीच में हो तो\r\nकर्क को बहुत बढ़ावा दे देता है ठीक है तो\r\nयह एक्टर की कुंडली है और इसमें एक और बात\r\nहै कि बृहस्पति त्रिकोण में यह मैंने\r\nबृहस्पति के वीडियो में बोला था कि\r\nबृहस्पति र त्रिकोण में आ जाते हैं तो वह\r\nकाफी अच्छा फल दे देते हैं\r\nअब हम टोरस पर आते हैं टोरस में अब शुक्र\r\nजो है पंचम भाव\r\nमें नीच राशि में होंगे और एकादश भाव को\r\nदृष्ट\r\nकरें ठीक है तो यहां पर आप देखिए एकादश\r\nभाव को बली किया चंद्रमा केंद्र\r\nमें और शुक्र\r\nलग्नेश\r\nहै तो लग्नेश नीच का होना वह अच्छी बात\r\nनहीं मानी गई\r\nहै\r\nपरंतु यह शेश होकर के नीच राशि में तो\r\nराजी\r\nब यह एक्टर बोल्ड एंड ब्यूटीफुल एक सीरीज\r\nआई\r\nथी उसके वेल्थी एक्टर थे बहुत अच्छा\r\nइन्होंने काम किया\r\nइसके बाद हम आते हैं मिथुन अब मिथुन राशि\r\nमें यह चतुर्थ भाव\r\nमें नीच राशी में होंगे और अब पास को\r\nदेखें पास को बली\r\nकरेंगे अब यहां पर\r\nयह बेस्ट सेलिंग सिंगर थी यह भी आर्ट में\r\nथी जुपिटर से केंद्र में फिर जुपिटर से\r\nकेंद्र में\r\nशुक्र से केंद्र में चंद्रमा नहीं\r\nहै ठीक है यह भी आर्टिस्ट\r\nथे यहां पर राइटिंग का भी इफेक्ट आ रहा है\r\nक्योंकि तृतीय और पंचमेश एक साथ\r\nबैठे चतुर्थ भाव\r\nमें तो यह बेस्ट सेलर थे राइटर भी थे गाने\r\nगाने में और इनको\r\nइनको यूके\r\nसे वो स्टेट ऑनर भी स्टेट ओनर जो भी वो\r\nदेते हैं वह लिखा हुआ है उसमें कि स्टेट\r\nऑनर भी मि बारवा भाव बली हो गया बारवा भाव\r\nबारवा भाव नहीं पायस बली हो ग उसने उसको\r\nदशम भाव ने इनको ऑनर दिला अब हम आते हैं\r\nकर्क अब कर्क में सिचुएशन अच्छी नहीं होती\r\nहै\r\nअब कर्ग में जो है ये एकादश\r\nहै त्रि शाय के स्वामी बन जाते हैं और\r\nचतुर्थेश\r\nहै केंद्राधिपति दोष है और दूसरी राशि\r\nत्रि शड में पड़ रही है तो यह अच्छे ग्रह\r\nनहीं\r\nरहते अब यहां शुक्र जो है यह पापी हो जाते\r\nहैं अब पापी शुक्र जो है अशुभ हो जाते हैं\r\nवह नवम भाव को देख रहे\r\nहैं अब यहां एक और बात हुई यह पादरी थे\r\nधर्म का बढ़ावा दे\r\nदिया परंतु शुक्र अच्छे नहीं\r\nहै शनि भी कोई अच्छे ग्रह नहीं\r\nहै सूर्य भी अच्छे ग्रह नहीं है केवल बुध\r\nइनका बचाव कर रहा\r\nतो यह एक पादरी\r\nथे जब 30 साल के थे तभी यह शुक्र की दशा\r\nशुरू हो गई चलते रहे और उसके बाद कोई बड़ा\r\nनाम इन्होंने नहीं कमाया क्योंकि शुक्र\r\nएफ्लिक्टेड\r\nहै तो इसके लिए यह अच्छा नहीं होता है\r\nअब लियो में आएंगे तो शुक्र यहां पर दूसरे\r\nभाव\r\nमें नीच राशि में\r\nहोंगे और शुक्र तृत\r\nहै तते भी अब नीच के हो गए ठीक ठाक हो गया\r\nकोई प्रॉब्लम\r\nनहीं और यहां पर सूर्य लगन में खुद बैठे\r\nहुए पिछली कुंडली में बताना भूल गया व\r\nकर्क में चंद्रमा खुद बैठे हुए थे तो उनकी\r\nलाइफ ठीक ठक चल गई इतने साल नहीं तो शुक्र\r\nऔर ज्यादा भयंकर परिणाम दे सकते\r\nथे तो यहां पर\r\nयह अवार्ड\r\nविनिंग एक्टर थे\r\nवल्दी काफी धन इनको प्राप्त हुआ क्योंकि\r\nधन के\r\nस्वामी बुध एकादश और द्विती होकर के\r\nलग्नेश के साथ लगन में विराजमान है\r\nऔर लग्नेश भी लगन में है तो इन्होंने\r\nकुंडली को उठा दिया और धन दिया अब इसके\r\nबाद हम आते हैं विर्गो प अब यहां यह लगन\r\nमें ही नीच राशि में हो जाते हैं तो हमारा\r\nवो रूल लग\r\nगया कि नीच राशि का ग्रह यदि लगन को देख\r\nरहा हो तो वह राजयोग दे देता\r\nहै तो यह यहां से देखते ही हमने कहा\r\nबढ़िया हो गया य तो यह भी एक्टर डायरेक्टर\r\nथे हॉल ऑफ फेम में इनको जगह\r\nमिली\r\nऔर हॉल ऑफ फेम में जगह मिली अब यहां पर आप\r\nऔर लगन को भा इतना ही बहुत है इसको बताना\r\nचंद्रमा यहां पर एकादश\r\nहै वह अपनी उच्च राशि में विराजमान\r\nतो चंद्रमा की दशा ठीक नहीं\r\nजाएगी ठीक है जी अब इसके बाद नेक्स्ट आते\r\nहैं हम तुला लगन\r\nपर तुला लगन में यह बवे भाव में नीच राशि\r\nमें हो और यहां पर इनका जो चंद्रमा है वह\r\nभी मीन में विराजमान\r\nहै अब यहां क्या हुआ है अष्टमेश नीच के\r\nहैं और लग्नेश नीच के हैं अब य एक सूत्र\r\nबता देता\r\nहूं\r\nलग्नेश यदि बवे भाव\r\nमें य तो पी नीच के हो गए बवे भाव में\r\nपीड़ित\r\nहो और बवे भाव के जो स्वामी हैं वोह भी\r\nपीड़ित हो तो वह एकांतवास अपनी एक्सक्लूजन\r\nमें जिंदगी बिताते\r\nहैं पर सेविंग फैक्टर क्या\r\nहै कि यह लग्नेश है बवे में चले गए\r\nऔर बुध सूर्य से पीड़ित\r\nहै ठीक है सूर्य\r\nएकादश आयु तो लंबी दे दी 90 साल की उम्र\r\nतक इन्होंने काम किया पर लाइफ सेक्ड किसी\r\nसे मिलना जुलना कमी होता\r\nथा इसके बाद वृश्चिक वृश्चिक में यह गवे\r\nभाव\r\nमें नीच राशि में\r\nहोंगे अब यहां जो है एक इस अब यह सेवंथ\r\nलॉर्ड है और थ लर्ड है ब सेवंथ लॉर्ड\r\nजब भी नीच राशि में\r\nहो तो कोई भी जो उनके संबंध समप में\r\nसंपर्क में आता\r\nहै तो उसको ईगो नहीं होती तो इनको हमेशा\r\nजेंटलमैन\r\nमिले शांति से अच्छे दोस्त मिलेंगे\r\nक्योंकि दविश एकादश में चले\r\nगए कोई ईगो उनके अंदर नहीं इन्होंने क्या\r\nकिया इन्होंने डांस ड्रामा स्कूल\r\nखोला और उसमें ड्रामा सिखाते थे एक्टिंग\r\nसिखाती थी और यह राइटर\r\nभी ठीक\r\nहै इसके बाद हम आते\r\nहैं धनु राशि अब धनु में यह दशम भाव\r\nमें नीच राशि\r\nमें अब मीन में य कोई नहीं तो मीन को बल\r\nदे दिया सुख सुविधा दे दी\r\nसारी और यहां जो अच्छी बात है राजयोग\r\nबनाने की कि वह बृहस्पति लगन को दृष्ट कर\r\nरहे\r\nहैं जो लग्नेश\r\nहै और चतुर्थेश तो लगन को दृष्ट कर रहे\r\nहैं यह आर्मी में\r\nथे\r\nऔर गवर्नर\r\nरहे एक मिनट नो सीम कॉनरी नहीं आर्मी में\r\nनहीं थे यह गवर्न सीन कनरी का चार्ट है\r\nबहुत बड़े आर्टिस्ट जेम्स बंड में की जो\r\nभूमिका निभाते थे मरकरी दशमेश है वह वहां\r\nवही विराजमान है शुक्र और चंद्रमा दोनों\r\nएक साथ वहां देख रहे हैं बृहस्पति लगन को\r\nदृष्ट कर रहे तो सारे योग यहां मिल\r\nतो सीन कॉनरी और दूसरा क्या सिक्सथ लॉर्ड\r\nडेबिटेड यह भी पराशर राजयो तो कहीं ना\r\nकहीं कम से कम छ छ एसेंडेंट के लिए तो यह\r\nराजयोग बना देते हैं कोई भी\r\nग्रह इसके बाद हम आते मकर\r\nमें यह आर्मी की कुंडली है अब यहां ये नवम\r\nभाव में\r\nविराजमान\r\nहै और\r\nये पायस को द्वितीय भाव को दृष्ट कर रहे\r\nहैं और राजयोग क्या है नवमेश\r\nऔर दशमेश का एक्सचेंज\r\nहै नवमेश और दशमेश का एक्सचेंज है थर्ड\r\nहाउस बहुत स्ट्रांग हो गया है शनि लगन में\r\nही विराजमान\r\nअभय एस्ट्रो डाटा बैंक की कुंडलिया है तो\r\nफेमस लोगों की है तो वहां से य निकालते\r\nहैं तो यह सारे योग हमारे फिट हो रहे हैं\r\nकिसलिए यह फेमस बने यह आर्मी कमांडर थे\r\nगवर्नर रहे मोंटाना\r\nके शनि महाराज लगन में खुद विराजमान है अब\r\nइसके बाद एक्वेरियस कुंभ\r\nमें कुंभ में इस कुंडली में फिर से शनि\r\nलगन को देख रहे\r\nहैं ठीक है अब यहां वो पराशर वाला राजयोग\r\nनहीं लग\r\nरहा ये अष्टम भाव में अब\r\nयह नीच राशि में बैठ\r\nगए और यह भी एक डांसर थे\r\nएक्टर एक्टर डांसर थे\r\nसक्सेस का राज शनि का लगन को देखना जबकि\r\nएक ग्रह नीच राशि\r\nमें वैसे तो होता ही है जब एक ग्रह नीच\r\nराशि में हो तब ज्यादा अच्छा फल देता है\r\nइसके बाद मीन अब ये मीन का तो हमने खास\r\nजिक्र किया ही था पहले कि शुक्र सप्तम भाव\r\nमें नीच राशि में होंगे तो लगन को देखेंगे\r\nही\r\nदेखेंगे यहां पर\r\nडबल बढ़िया बेनिफिट हो गया है कि बृहस्पति\r\nजो लग्नेश है वह भी देख रहे हैं लगन\r\nकुंडली हो गई इंप्रूव जबरदस्त इंप्रूव हो\r\nगई यह भी टीवी वर्कर\r\nथे पर यहां पर सिर्फ शुक्र क्या करता\r\nहै कि अब शुक्र जो है वह अष्टमेश है\r\nराजयोग तो\r\nदेंगे शुक्र देख भी रहे हैं लगन को\r\nअष्टमेश होकर के पराशर राजयोग भी बना रहे\r\nहैं थर्ड लॉर्ड वो नीच के हैं वह भी\r\nराजयोग बना रहे हैं परंतु इस केस में क्या\r\nहोता है ज य अष्टमेश आकर के सप्तम भाव में\r\nआ जाते हैं नीच राशि\r\nमें तो यह विवाह में थोड़ी सी तकलीफ दे\r\nदेते हैं देखना तो हमें नवांश ही चाहिए\r\nफिर पर इसको तकलीफ दे देते हैं तो यह\r\nहमारा शुक्र का विश्लेषण था\r\nहर ग्रह का हम देखते हैं कि कोई नीच राशि\r\nमें ग्रह होने से बिल्कुल नहीं घबराना है\r\nराद इट इज ए\r\nब्लेसिंग क्योंकि गर्ग जी का भी कहना है\r\nकि कुंडली में चाहे तीन ग्रह उच्च राशि के\r\nहो अगर एक ग्रह नीच का नहीं है तो उसका\r\nपूरा फल नहीं मिलता\r\nहै तो आज के लिए इतना ही\r\nअब एक आखिरी सीरीज जो बची है शनि की उसके\r\nलिए फिर मिलेंगे एक दो दिन में तब तक के\r\nलिए नमस्कार और धन्यवाद"},{"topic":"नीच राशि केचंद्रमा से फलित","text":"नमस्कार\r\nमित्रों आज हम\r\nफिर नीच ग्रह की सीरीज\r\nमें आपके पास फिर से उपस्थित हुए\r\nहैं और हमने पिछले वीडियो\r\nमें सूर्य का विश्लेषण किया\r\nथा आज हम चंद्रमा को\r\nलेंगे और चंद्रमा का हर 12 राशि में\r\nनीच राशि में होने का क्या विश्लेषण होता\r\nहै चंद्रमा के नीच होने का एक बहुत\r\nही महत्त्वपूर्ण सूत्र\r\nहै यह सबसे अलग है सिर्फ चंद्रमा के\r\nलिए के\r\nचंद्रमा अपनी राशि से एक ही राशि का\r\nस्वामी है कर्क का\r\nचंद्रमा और वह अपनी राशि से\r\nपांचवी राशि\r\nमें नीच राशि में होता\r\nहै यह चंद्रमा में पॉसिबल\r\nहै उससे\r\nएक बहुत ही महत्त्वपूर्ण सूत्र आता\r\nहै कि वह जब अपने से पांचवी राशि में नीचे\r\nराशि में होता\r\nहै यहां थोड़ा सा मैं जमनी यूज कर रहा हूं\r\nकि वह कर्क राशि\r\nको अर्गला देगा दृष्टि भी देगा और कर्क\r\nराशि का व स्वामी भी\r\nहै तो अति सुंदर सबसे स्ट्रांग\r\nअर्गला कर्क राशि को मिल जाती\r\nहै और कर्क राशि को पूर्ण बल प्राप्त होता\r\nहै चाहे वह कोई भी लगन हो और कर्क भी जिस\r\nभाव में भी होता है उसको पूर्ण बल मिल\r\nजाता है ये बहुत ही बड़ा पॉइंट मैंने आपको\r\nबता दिया\r\nहै और चंद्रमा के नीच के विश्लेषण का यही\r\nएक तरीका\r\nहै तो हम\r\nदेखेंगे बाकी सब वार्तालाप जैसे सूर्य में\r\nदेखा था वोह अपनी राशि से तीसरी राशि\r\nमें नीच राशि में होता है तो वहां यह\r\nसूत्र नहीं लग पा रहा था इसलिए वहां नहीं\r\nबताया दूसरा\r\nपॉइंट\r\nके नीच का कैंसिलेशन कैसे होता है यह हम\r\nपहले वीडियो में बात कर चुके हैं इसलिए वह\r\nदोबारा मैं रिपीट नहीं\r\nकरूंगा तो अब हम केवल सीधे-सीधे कुंडलियों\r\nपर जाएंगे एक एक राशि के लिए उसका\r\nविश्लेषण करेंगे उसको आप ध्यान से देखिए\r\nमेन पॉइंट मैं पहले ही बता चुका हूं वही\r\nपॉइंट आपको सब जगह देखने\r\nमें ठीक है चलिए शुरू करते\r\nहैं सबसे पहले हम\r\nलेंगे मेश लगन\r\nअब मेष लगन\r\nमें\r\nचंद्रमा अष्टम भाव में अपनी नीच राशि में\r\nहोते हैं अब देखिए बाकी भी और आपको बहुत\r\nकनेक्शन मिलेंगे परंतु यहां एक उस पॉइंट\r\nको ही देखते\r\nचले चंद्रमा य चतुर्थेश\r\nहै और अष्टम भाव में नीच राशि\r\nमें तो हमारा जैसे प्रिंसिपल था\r\nचतुर्थ भाव अत्यंत बली हो\r\nगया और भी मिल रहे हैं मंगल भी देख रहे\r\nहैं बृहस्पति इसको देख रहे हैं मंगल उच्च\r\nके है दिग बली है सब\r\nहै पर सिर्फ चंद्रमा से मैं कह सकता हूं\r\nके\r\nकैरेक्टर बहुत अच्छा हो स्ट्रांग हो जो भी\r\nकैरेक्टर होगा स्ट्रांग\r\nहोगा बहुत ही अच्छे पद पे ये रहेंगे सुखी\r\nरहेंगे\r\nये एक सुप्रीम कोर्ट के जज\r\nथे और काफी अच्छे मान जाने माने जज\r\nथे इवन यूएस के होते हुए भी पोरली\r\nवेजिटेरियन\r\nथे और इनका सरलता का कैरेक्टर का शादी\r\nविवाह इन्होंने किया\r\nनहीं मकान आलीशान सब ये अपने रहते थे\r\nतो यह चरम पर इनको सुख प्राप्त\r\nहुआ मेन पॉइंट आप याद रखिए जो मैंने बताया\r\nअब हम दूसरा टोरस लगन के लिए लेते हैं अब\r\nयहां वृषभ लगन के लिए यह सप्तम भाव में\r\nनीच राशि में\r\nहोंगे और कौन होंगे यह\r\nतृतीय अब एक तरह से देखा जाए तो तृत्य में\r\nशनि विराजमान है\r\nउसको भी यह चंद्रमा अर्गला दे रहे हैं\r\nबहुत अच्छी अर्गला दे रहे\r\nहैं ये किनकी कुंडली है यह यूएस के\r\nप्रेसिडेंट के लिए नॉमिनेट\r\nहुए सीनेटर रहे गवर्नर\r\nरहे तो अब आप देख लीजिए इस चंद्रमा ने\r\nक्या कर दिया है\r\nकमाल शनि जो आपके योग कारक है दशम भाव के\r\nस्वामी हैं उसको भी चंद्रमा ने पूर्ण बल\r\nदे दिया\r\nऔर यह अच्छी पोजीशन पर वहां\r\nपहुंचे ठीक है अब तीसरी मिथुन राशि का\r\nदेखते\r\nहैं मिथुन राशि में चंद्रमा द्वितीय\r\nहो दत्य भाव कुटुंब का है धन का है वाणी\r\nका\r\nहै उसको बल मिल रहा\r\nहै और इस कुंडली में द्वितीय भाव पर और\r\nकोई एस्पेक्ट नहीं है\r\nतो वाणी अच्छी\r\nहै परिवार अच्छा है परिवार में सब सुखी\r\nहै और धन भी है द्वितीय भाव होता है धन\r\nसंचय\r\nका तो यह आप देख ही लीजिए किसकी कुंडली है\r\nउसमें\r\nआप जब भी मिथुन लगन में अगर चंद्रमा नीच\r\nका होगा चंद्रमा की दशा में उसको बोल दो\r\nकि भाई साहब तेरे पास धन इकट्ठा\r\nहोगा चाहे तू कुछ भी\r\nकर ठीक है जी अब नेक्स्ट लेते हैं कर्क अब\r\nकर्क राशि में\r\nचंद्रमा स्वयं लग्नेश है और कहां चले गए\r\nपांच बुद्धिमता दे दी जबरदस्त बुद्धिमता\r\nदे\r\nदी और यह चंद्रमा अब इस कुंडली में अब\r\nयहां\r\nपर बुद्धि तो दी ही दी\r\nपांचवे भाव\r\nको और ज्यादा आगे बढ़ा\r\nदिया यह फिक्शन राइटर थ बुध देख\r\nरहा चंद्रमा कौर मंगल देख रहा पांचवे भाव\r\nमें बैठे हुए और लगन को बली कर\r\nदिया तो यह फिक्शन\r\nराइटर नवल्स लिखना यह करना और उसमें बड़ी\r\nसफलता इनको मिली\r\nठीक है अब हम नेक्स्ट पर आते\r\nहैं लियो\r\nलगन मेन पॉइंट पकड़ते जाओ\r\nबस अब\r\nयह बवे भाव\r\nके बवे भाव को बली कर\r\nगया 12वां भाव होता है\r\nअननोन थिंग्स अननोन सीक्रेट\r\nथिंग्स और एक और बहुत बड़ा रूल होता है के\r\nजब\r\nभी इसका संबंध अब तीसरा\r\nपांचवा नाइ इनका अगर संबंध आ जाए तो वह\r\nस्वपन जिसको कहते हैं ना सपने दिखा देता\r\nहै तो यह कुंडली भी राइटर की है सपने दिखा\r\nदिए इन्होंने भी फिक्शन\r\nलिखी ठीक है जी और सबसे बड़ी बात क्या है\r\nकि यहां पर\r\nमंगल खुद कर्क राशि में है तो चंद्रमा और\r\nमंगल का वि परिवर्तन योग हो\r\nरहा और\r\nदशमेश खुद उच्च के\r\nहै तो को अच्छी पोजीशन राइटिंग में दिला द\r\nइसके बाद नेक्स्ट चार्ट लेते हैं विर्गो\r\nका विर्गो विर्गो में अब यहां\r\nदेखो थ हाउस आ गया वो बली हो गया तो धन\r\nबहुत आएगा गेस बहुत होंगे लाइफ में सेकंड\r\nहाउस धन संचय का है यह गेन कराता है\r\nऔर थ लड के साथ भी है थर्ड हाउस में बैठा\r\nहुआ\r\nहै यह चार्ट है रॉक हडसन का जिन्होंने\r\n70 फिल्मों में काम\r\nकिया और चंद्रमा की दशा\r\n1977 में शुरू हुई और यह अपने पीक पर\r\nथे अपनी पीक कैरियर में इन्होंने ज वो रखा\r\nतो लाभ इतना ना दिला दिया इतना ज्यादा यह\r\nचार्ज करते थे कि उसको कोई सोच नहीं\r\nसकता इसके बाद हम\r\nआएंगे तुला\r\nलगन अब यहां थोड़ी सी गड़बड़ है तुला लगन\r\nमें दशम भाव में कर्क राशि पड़ रही\r\nहै तो प्रोफेशन तो बहुत जबरदस्त दे दिया\r\nबहुत राइज किया\r\nऔर बहुत ही यंग एज\r\nमें इनका जो\r\nथा देहांत हो\r\nगया शुक्र की\r\nदशा जो 91 का अटैक हुआ यह उसमें मारे गए\r\nचंद्रमा से कोई लेना देना नहीं है उसका यह\r\nमत समझो कि वोह चंद्रमा का फल था शुक्र की\r\nदशा में क्या हुआ यह देखो\r\nमंगल प्रबल मार्क\r\nहै और वह शुक्र को देख दृष्ट कर रहे\r\nहैं इसी कारण से\r\nइनका टेरर अटैक में देहांत हो गया चंद्रमा\r\nने बहुत अच्छी पोजीशन दिलाई है मैं फिर\r\nरिपीट कर रहा हूं अगर चंद्रमा सेकंड हाउस\r\nमें नीच राशि में हो जाता है अच्छी पोजीशन\r\nदिलाएगा\r\nइसके बाद हम आएंगे\r\nस्कॉर्प वृश्चिक अ वृश्चिक में क्या होता\r\nहै यह\r\nनाइंथ के स्वामी है\r\nचंद्रमा और इस कुंडली में यह राजयोग में\r\nभी है दशमेश के साथ नवमेश और दशमेश दोनों\r\nका संबंध आ रहा है अब नाइंथ हाउस है का\r\nउसको बढ़ावा दे\r\nदिया तो यह चर्च के पादरी\r\nथे सर्मन दिया करते थे अच्छी पोजीशन पर\r\nइनको अच्छे अच्छे चर्च में मेरे को पूरा\r\nयाद नहीं अच्छी पोजीशन पर यह पहुंचे अपने\r\nपादरी या धर्म के कार्य में इन्होंने यह\r\nकाम किया तो चंद्रमा ने नवम भाव को आगे\r\nबढ़ा दिया\r\nबहुत सिंपल रूल दे रहा हूं मैं आपको बहुत\r\nसिंपल रूल अब इसके बाद न पर आ जाते हैं अब\r\nयहां जो चंद्रमा\r\nहै यह अष्टमेश\r\nहै और यह बवे भाव में जाकर के नीच राशि\r\nमें अब यहां यह द्वादश के साथ और पंचमेश\r\nके साथ भी विराजमान\r\nहै एडवेंचर\r\nचंद्रमा चतुर्थ अष्टम भाव का स्वामी होकर\r\nके बवे भाव में नीच का हो तब वह एडवेंचर\r\nदेता है सडन स देता है बहुत एडवेंचरस लाइफ\r\nरही यह स्पेस यात्री रॉकेट में स्पेस में\r\nमून की और स्पेस की ट्रेवल इन्होंने की है\r\nबहुत लंबे समय तक ये स्पेस में\r\nरहे खैर हमें तो मतलब कि यह एडवेंचर देता\r\nहै एथ उस का मरने से नहीं डरता समाधि दे\r\nदेता एथ लड होकर के बवे में नीच का हो यह\r\nसमाधि जैसी पोजीशन पर ला देता\r\nहै इसके बाद हम\r\nआएंगे मकर राशि\r\nपर मकर राशि में अब यह सप्तमेश है सप्तम\r\nभाव को बढ़ा द सीध सीधी बात है और 11थ\r\nहाउस में जाकर के नीच राशि में हो गए\r\nसप्तम को बढ़ावा दे रहे\r\nहैं तो\r\nयह एक्ट्रेस भी\r\nथी पब्लिक का बहुत अनोले जमेंट इनको\r\nमिला और बहुत इन्होंने फिल्में बनाई बहुत\r\nअवार्ड\r\nमिले 2010 में चंद्रमा की दशा शुरू हुई तो\r\nपब्लिक एडमिरेशन और थ हाउस में है\r\nअवार्ड्स\r\nबे हताशा इनको अवार्ड मिले बहुत\r\nजदा मैं पूरी कुंडली का विश्लेषण नहीं\r\nकरवाना चाह रहा हूं मैं तो आपको सिर्फ एक\r\nबिंदु यह पकड़ना सिखा रहा हूं चंद्रमा का\r\nकि किसको वह बली कर देता\r\nहै अब यह चंद्रमा छठे भाव के स्वा छे भाव\r\nको ब\r\nकरेंगे सीधी बात है\r\nयह बैरिस्टर थे लॉयर थे छठे भाव का प्रभाव\r\nपूरा\r\nलॉ देखिए छठे भाव से जो प्रोफेशन आता है\r\nजब सिक्सथ लड थ में गया और नीच का हो गया\r\nवैसे ही राजयोग हैय पराशर जी का कि सिक्सथ\r\nलॉर्ड डेबिटेड हो तो सिक्सथ लॉर्ड यह ऋण\r\nरिपु रोग इनके थ्रू धन कमाता है थ हाउस धन\r\nमानेगा तो वह चाहे वकील हो चाहे डॉक्टर हो\r\nवो दूसरों के कष्ट से धन\r\nकमाए एजेंट हो प्रॉपर्टी डीलर होते हैं यह\r\nसब इस तरह के काम पर छटे\r\nका जो और नेगेटिव पॉइंट है धन कमाने का तो\r\nहमने देख लिया अब जो सिक्सथ लॉर्ड है वो\r\nकेतु एक्सेस में भी है और थ लॉर्ड के साथ\r\nभी है तो थोड़ा हानि दे रहा है शनि जो है\r\nथ हाउस को भी दृष्ट कर रहे हैं तोय टैक्स\r\nचोरी के मामले में पकड़े गए और दो साल की\r\nसजा\r\nभी ठीक है हालांकि इतना धन\r\nकमाया कि इनका बेवरली हिल में 38 कमरों\r\nवाला बंगलो\r\nथा इतने पैसे भी थे और 96 में इनको दो साल\r\nकी जेल भी\r\nहो बुढ़ापे की जेल\r\nमें ठीक है जी अब हम लास्ट उस परे आते\r\nहैं यहां पर चंद्रमा पंचमेश\r\nहै तो पंचम भाव इंटेलिजेंस का अत्यंत बली\r\nहो\r\nगया तो ये भी राइटर\r\nबहुत अच्छे स्केल के स्ट्रांग राइटर\r\nऔर पांचवा भाव\r\nसे यह नवम में आ रहे\r\nहैं तो\r\nबुद्धि\r\nरिलीजन कर्म कर्तव्य कर्म नहीं कर्तव्य की\r\nतरफ ज्यादा जा रही है और चंद्रमा को और\r\nज्यादा बल मिल गया कर्तव्य पालन करने का\r\nवो मंगल की की दृष्टि\r\nसे हालांकि अपने कर्तव्य पालन में\r\nइन्होंने फैमिली को छोड़ दिया उसके लिए\r\nदूसरे योग है फैमिली ने इनको त्याग दिया\r\nथा वो फोर्थ लॉर्ड बवे में\r\nवक्री उससे उसका कुछ कनेक्शन आ सकता है खर\r\nहमारे जो बात\r\nथी मैं आपको जो पॉइंट बताना चाह रहा था\r\nचंद्रमा के\r\nउसमें कि चंद्रमा कहीं पर भी अगर नीच राशि\r\nमें होता\r\nहै तो जहां भी कर्क राशि पड़ती है कुंडली\r\nमें उसको बली कर\r\nदेगा अगर कोई पाप संबंध आता है पाप भाव का\r\nसंबंध आता है तो उस भाव को तो बलि करेगा\r\nही कर्क वाले को\r\nपर उससे कुछ थोड़ी सी कमी या हानि भी ला\r\nदेता है वो पाप संबंध अगर केवल शुभ संबंध\r\nहै या कोई संबंध शुभ संबंध तो बचा लेगा\r\nअगर शुभ संबंध नहीं है कोई संबंध नहीं है\r\nतो भी उस भाव का तो व थोड़ा सा हानि करता\r\nहै जहां पर\r\nचंद्रमा नीच राशि में होते हैं उस भाव को\r\nथोड़ा हानि करता है परंतु कर्त राशि जहां\r\nपड़ है उस कर्क राशि को बहुत बल दे देता\r\nहै यह आज का निचोड़\r\nहै तो यह चंद्रमा के लिए है आगे हम फिर और\r\nकिसी पर बात करेंगे इसके बाद चंद्रमा के\r\nबाद हम मंगल\r\nलेंगे ठीक है इसके बाद हम नीच राशि के\r\nमंगल को बात\r\nकरेंगे और इसी तरह ये सातों ग्रह को हम\r\nलेंगे राहु और केतु को नहीं ले\r\nठीक है जी तो आज के लिए यही सूत्र है और\r\nइसको पकड़ेंगे"},{"topic":"नीचभंग को राजयोग क्यों कहा जाता है","text":"नमस्कार\r\nमित्रों आज फिर आपके\r\nसाथ एक और रोचक विषय लेकर के फिर से\r\nप्रस्तुत हुआ हूं और आज का विषय\r\nहै के नीच भंग कब राजयोग हो जाता\r\nहै हमने आज तक यही सुनते आए\r\nहैं इस योग के नाम को के नीच भंग राज योग\r\nअरे\r\nवाह के नीच भंग\r\nहुआ और राजयोग बन\r\nगया तो यह बात थोड़ी सी समझ में नहीं आती\r\nबहुत दफे तो इसीलिए य वीडियो बना रहा हूं\r\nके नीच भंग होने से ही क्या राजयोग हो\r\nजाता\r\nहै पहले तो हम समझे\r\nके नीच भंग राज योग में क्या-क्या शब्द\r\nहै नीच मतलब कि कोई ग्रह अपनी नीच राशि\r\nमें\r\nहो अब नीच के बहुत सारे मीनिंग निकालते\r\nहैं अपनी नीच राशि में\r\nहो भंग\r\nहो अब उस नीच का भंग हो रहा है\r\nक्या भंग हो रहा\r\nहै निचव भंग हो रहा है और तीसरा शब्द\r\nराजयोग जहां नीच भंग हुआ और उसके बाद\r\nतुरंत\r\nराजयोग पर ऐसा हम देखते नहीं\r\nहै मैंने अपनी सरल टू में लिखा\r\nहै के 94 से 95\r\nपर जो जो नीच के ग्रह होते\r\nहैं उनका नीच भंग हो जाता\r\nहै क्या वह हर एक का राजयोग बन जाता\r\nहै ऐसा देखने में तो नहीं आता\r\nभाई कितनी कुलियों में नीच मिलता\r\nहै पर राजयोग नहीं\r\nबनता तो आज हम इसी पर बात कर\r\nरहे अब ये आप देखो क्लास पहले तो नीच को\r\nसमझ लो वह आपको सबको पता है कि भाई सूर्य\r\nतुला में होता है चंद्रमा वृश्चिक में नीच\r\nका होता है मंगल कर्क में नीच का होता है\r\nबुध मीन में नीच का होता है और\r\nशुक्र बृहस्पति मकर में नीच का होता\r\nहै और शुक्र मीन कन्या में नीच का होता है\r\nऔर\r\nशनि मेष राशि में नीच का होता\r\nहै इसके हमें यह भी दिए गए हैं के परम नीच\r\nस्थान क्या है परम नीच डिग्रीज क्या\r\nहै परंतु हम अपनी ज्यादातर ज्योतिष\r\nमें हम पूरे साइन को पूरी राशि को जो उसकी\r\nनीच राशि है उसको नीच राशि मानते हैं और\r\nउसमें अगर ग्रह होता है तब वो नीच राशि\r\nमें माना जाता है अब जैसे सूर्य है 10\r\nडिग्री पर नीच परम नीच\r\nका अगर वो 10 डिग्री से निकल गया तो क्या\r\nहम उसको नीच नहीं मांगे मानेंगे\r\nनीच तो मानेंगे शास्त्र के हिसाब से सब\r\nजगह सारे क्लासिक में सारे शास्त्रों में\r\nयही लिखा हुआ है परंतु एक यह जरूर राइडर\r\nहै थोड़ा सा कि जितना दूर चला जाता है\r\nउसका उच्च बल बढ़ता चला जाता है यह ल में\r\nलिखा तो बल तो बढ़ता जाता है अच्छा अब हम\r\nआते हैं के शास्त्रों\r\nमें नीच भंग के नियम क्या\r\nहै सबसे पहले तो वो डिसाइड करते\r\nहैं कि ग्रह जिस राशि में नीच का\r\nहै वो देख लो भाई किस राशि में नीच का हो\r\nगया वहा पर बै बात कर\r\nचुके तो उसका ग्रह\r\nका उच्च राशि का स्वामी और जिस ग्रह\r\nजिसमें वह बैठा है वह नीच राशि का\r\nस्वामी अब यहां बहुत से हमारे विद्वानों\r\nने उसके लिए चेश और उच्चे\r\nशब्द प्रयोग करना शुरू किया है और उसमें\r\nएक और नया एंगल जोड़\r\nदिया अब बहुत से कहते हैं\r\nचेश ग्रह का\r\nचेश वह कौन है इस पर डिबेट शुरू हो\r\nगई शास्त्रों में लिखा है कि भाई जिस राशि\r\nमें वो नीच राशि का होता है उसका स्वामी\r\nको नीचे बोलते\r\nहैं अब वो कहते\r\nनहीं जिस राशि में वह चेश का हो रहा\r\nहै उस राशि का स्वामी नहीं अब जैसे सूर्य\r\nहै वो नीच का हो रहा है तुला में\r\nहै तो शुक्र जो है उसका नीचे\r\nहुआ वो कहते नहीं अब शुक्र में शुक्र जहां\r\nनीच का होता है उसको नीचे\r\nबाने दूसरा ले लो वो बोलते हैं\r\nशनि मेष में नीच का होता है तो हमारी\r\nपरिभाषा से तो उसका नीचे मंगल हुआ वो कहते\r\nनहीं\r\nजो ग्रह\r\nइसमें नीच का नहीं उच्च का मतलब जहां वह\r\nजो मंगल है वहां नीच का होता है वह नीचे\r\nमाना जाएगा नहीं भैया हम इसको नहीं मानते\r\nहैं क्योंकि य लॉजिक नहीं\r\nलगता क्यों पूछ पकड़नी है यार इतनी दूर तक\r\nतो हम तो सीधा सधा कहते हैं कि भाई सूर्य\r\nका नीचे\r\nशुक्र है और\r\nउच्चे वो मंगल है क्योंकि सूर्य मंगल की\r\nराशि में उच्च का उच्च\r\nराशि अब आ जाओ नीच भंग के\r\nनियम पहला पहला नियम\r\nहै\r\nके\r\nयदि ग्रह जो नीच की राशि में है उसका चेश\r\nया\r\nउच्चे लगन से या चंद्रमा\r\nसे केंद्र में तो नीच भंग हो\r\nजाएगा पर क्या यह राजयोग\r\nबनेगा मेरे हिसाब से तो नहीं\r\nबनता क्योंकि एग्जांपल से देख लो भाई\r\nबृहस्पति मंगल\r\nमंगल का नीचे चंद्रमा खुद\r\nहै तो व चंद्रमा से हमेशा केंद्र में तो\r\nक्या हमेशा नीच भंग हो जाए मंगल\r\nका बृहस्पति के\r\nउच्चे चंद्रमा\r\nहै वह खुद स्वयं चंद्रमा\r\nहै तो वह अपने से तो लगन में है ही ना\r\nकेंद्र में\r\nहै तो इस तरह से क्या मंगल और बृहस्पति का\r\nकभी नीच भंग कभी नीच हो का फल दे ही नहीं\r\nसकता वो तो राजयोग\r\nदेगा तो क्यों घबरा रहे हो भाई अगर मंगल\r\nया बृहस्पति नीच राशि में है तो ऑटोमेटिक\r\nउसका नीच भंग हो रहा है हम क्यों घबरा रहे\r\nहैं\r\nखैर अब नीच भगन के और नियम में आए ये\r\nकेंद्र का तो हमने कर\r\nलिया के लगन से या चंद्रमा से\r\nकेंद्र अब नियम\r\nहै के उसका चेश या\r\nउच्चे उस ग्रह के साथ युति में हो या उस\r\nग्रह को दृष्ट कर रहा\r\nहो\r\nया दोनों में परिवर्तन योग\r\nतब यह नीच भंग हो जाता\r\nहै और यही असली नीच भंग\r\nहै इसी को राजयोग बोलते\r\nहैं यही दोनों अगर कंडीशन मिलती है तो वह\r\nराजयोग बनता\r\nहै एक और कंडीशन है नीच भंग की के दो नीच\r\nग्रह आपस में एक दूसरे को दृष्ट कर\r\nरहे अब ये कहां पॉसिबल होता है मान लो\r\nचंद्रमा और\r\nशनि तो इस नियम में वह भी आ जाते\r\nहैं सूर्य और शनि चंद्रमा में गलत बोल गया\r\nसूर्य और\r\nशनि\r\nसूर्य तुला में और शनि मेष\r\nमें अब अब जो यह नियम हमने बताया कि चेश\r\nया\r\nउच्चे उस ग्रह\r\nको दृष्ट कर रहे हो तो राजयोग बन\r\nजा तो सूर्य\r\nके\r\nचेश उच्चे शनि नहीं\r\nहै शनि के\r\nउच्चे या नीचे\r\nवो मेश\r\nऔर तुला है यह भी नहीं हो रहा\r\nहै ठीक है यह कहां से आई फिलॉसफी यह दूसरी\r\nडेफिनेशन से\r\nआई कि चेश किसको कहते हैं उच्चे किसको\r\nकहते\r\nहैं मेरा अनुभव जो है कि यदि\r\nदो नीच ग्रह\r\nआपस में दृष्ट कर रहे\r\nहो उसको ठीक है आप नीच भंग कर लो जो मर्जी\r\nकर लो राजयोग नहीं\r\nबनता वो उन भाव को हानि पहुंचाएंगे\r\nकिन भावों\r\nको एक तो पहला जिन भाव के वो स्वामी है या\r\nजिन भाव में विराजमान है बैठे हुए उनको\r\nहानि पहुंचाएंगे\r\nतो यह हमारे नियम है और जो राज योग बनने\r\nका नियम है वह उस जिस राशि में उच्च के\r\nहोते हैं या जिस राशि में नीच के होते हैं\r\nयदि\r\nवह उस ग्रह\r\nसे पूर्ण संबंध\r\nबनाए एक दूसरे के साथ हो एक दूसरे को स्ट\r\nकर रहे हो\r\nया परिवर्तन\r\nयोग तब वह नीच भग राज योग होता\r\nहै अथवा\r\nनहीं अब बहुत से और भी कहते हैं नक्षत्र\r\nपरिवर्तन हो इन दोनों जो नीच का हो रहा है\r\nउसके उच्चे या नीचे से नी नक्षत्र\r\nपरिवर्तन है तो भी काम हो\r\nजाएगा नहीं भाई अभी न तक तो हम जा ही नहीं\r\nरहे हम तो राशि पर ही देख ले उतना ही काम\r\nकरले तो बहुत है ठीक है इसलिए व नक्षत्र\r\nपर मैं नहीं जा र अब इसके लिए मैं आपके\r\nसाथ कुछ चार्ट भी शेयर\r\nकरूंगा यह पहला चार्ट है\r\nभाई अब यहां अब ढूंढते\r\nहैं यहां पर शनि महाराज\r\nअपनी नीच राशि में वि\r\nबैठे तो\r\nइसके जो नीच राशि के स्वामी हैं वह मंगल\r\nहै और शनि जिस राशि\r\nमें उच्च के होते हैं उसके स्वामी शुक्र\r\nहै अब यहां कोइंसिडेंस देखो शनि को शुक्र\r\nऔर मंगल दोनों दृष्ट कर\r\nरहे परस्पर पूरा संबंध आ रहा\r\nहै इसको\r\nराजयोग यह नहीं के शनि के मंगल जो है\r\nकेंद्र में हो गए या शुक्र केंद्र में हो\r\nगए लगन से या चंद्रमा से यहां पर चंद्रमा\r\nसे केंद्र में दिख रहे\r\nहैं पर उतना सफिशिएंट नहीं\r\nहै यह कुंडली शरद पवार की\r\nअभी तक एक्टिव\r\nहै इसको कहते हैं\r\nराजी ठीक है अब दूसरी कुंडली एक और\r\nलेते अब यह बहुत ही जबरदस्त कुंडली है\r\nभा यहां पर\r\nदेखिए गुरु नीच के है नीच राशि\r\nमें और उस नीच राशि के\r\nस्वामी\r\nशनि वो भी उनके साथ ही बैठे\r\nहुए तो अब यहां कहने को कहेंगे हां भाई\r\nठीक है इसका जो नी नीच राशि का स्वामी है\r\nवह लगन से केंद्र में है तो राजी हो ग आप\r\nचेक कर लीजिए और के बहुतों के मिलेंगे\r\nआपको कि वो केंद्र है चंद्रमा से या लगन\r\nसे और सब नीच भंग हो जाता है पर राजयोग\r\nनहीं\r\nबनता अब यह राजयोग\r\nबना यह ओबामा की कुंडली\r\nहै जो अमेरिका जैसे राष्ट्र के उसके\r\nप्रेसिडेंट रहे और प्रेसिडेंट कहां रहे कब\r\nरहे बृहस्पति में बने\r\nप्रेसिडेंट और शनि में छोड़ दि\r\nशनि में टर्म खत्म हो गई ये नहीं कि वो\r\nभगाया गया पर टर्म खत्म हो गई अपनी टर्म\r\nपूरी की है ठीक है अब इसके बाद एक कुंडली\r\nऔर लेता हूं एक और ले लेना ठीक है जी अब\r\nयह हमारी वही जानी\r\nपहचानी कुंडली है य चंद्रमा नीच के नीच\r\nराशि में\r\nहै और चंद्रमा के साथ मंगल खुद बैठे हुए\r\nजो इसके नीच के स्वामी अब यहां भी यह\r\nकंडीशन पूरी हो जाती है कि भाई जो इनके\r\nनीच के स्वामी हैं वह लगन से या चंद्रमा\r\nसे केंद्र\r\nमें अब यहां शुक्र को देख लो तो वह भी\r\nशुक्र भी चंद्रमा से केंद्र में है ठीक है\r\nतो\r\nअब यहां भी वो कंडीशन भी लगती है परंतु\r\nराजयोग कब बन रहा\r\nहै क्योंकि मंगल और चंद्रमा की युति है और\r\nइन्होंने\r\nराजयोग के फल भी दिए\r\nहैं चंद्रमा से भी द है मंगल की दशा ने भी\r\nद ठीक है अब इसके बाद एक और\r\nहै मुझे लगता है कि ज्यादा चार्ट में\r\nइसलिए\r\nबोर तो ना हो जाओ अब यहां आप\r\nदेखो\r\nसूर्य नीच राशि\r\nमें अब सूर्य के नीच राशि के\r\nस्वामी शुक्र\r\nहै यह चंद्रमा से केंद्र में नहीं है\r\nपरंतु सूर्य के\r\nसाथ नीच भंग करके राजयोग भी दिया है\r\nऔर जो सूर्य के उच्च उच्च राशि के स्वामी\r\nहैं\r\nमंगल वह आपके चंद्रमा से और लगन से दोनों\r\nसे केंद्र में परंतु केवल\r\nयही कंडीशन यही पूरा होना पूरी नीच राजयोग\r\nनहीं बनाता है नीच भंग कह लो उस राजयोग\r\nनहीं बनाता है\r\nतो आज का\r\nजो आज का मैंने जो यह टॉपिक देखा\r\nहै वह इसीलिए किया\r\nहै कि क्वेरी आती है कि जी मेरा नीच भंग\r\nहो रहा\r\nहै पर राजयोग\r\nनहीं मैं तकलीफ में हूं कोई राजयोग जिंदगी\r\nमें मिला ही\r\nनहीं तो उसके लिए पराशर जी ने और कुछ नियम\r\nदिए हैं जो हम एक पहले वीडियो में बना\r\nचुके हैं पराशर जी के ग्रेट\r\nअवधान जो वो छ आ\r\n12 की बात करते हैं तीन छ आ तीन छ आठ की\r\nबात करते हैं कि उसमें नीच का ग्रह बैठा\r\nहो तो वो राजयोग का फल देता है पर वो\r\nलिमिटेड\r\nवह अपनी दशा में जरूर फल\r\nदे जो आज हमने बात की\r\nहै यह उस ग्रह\r\nके दशा\r\nऔर जहां के भी वह है उनका फल देता है जैसे\r\nलास्ट कुंडली\r\nथी\r\nशुक्र उसमें आप यह देखो यह बिल गेट्स की\r\nकुली अच्छे अमीर आदमी\r\nठीक है बुद्धि से पैसा कमाया\r\nहै तो यह आज का हमारा टॉपिक था के बहुत से\r\nलोग हताश हो जाते हैं कि जी मेरा नीच भंग\r\nहो रहा है परंतु राजयोग नहीं बना इसीलिए\r\nआज का य वीडियो बनाया\r\nहै उम्मीद है कि आपको अच्छा लगा होगा साथ\r\nसाथ उसके नमस्कार करता हूं धन्यवाद"},{"topic":"बंधन योग 1 आपराधिक प्रवृत्ति","text":"नमस्कार\r\nमित्रों आज फिर आपके साथ आज बहुत\r\nही इंपॉर्टेंट बहुत ज्यादा आवश्यक और बहुत\r\nकाम आने वाला सूत्र लेकर के हम आए\r\nहैं आज हम करेंगे बंधन योग पर\r\nबात और बंधन योग की पहली कड़ी\r\nउसके बारे में बात करेंगे वह है क्रिमिनल\r\nटेंडेंसी या अपराधिक\r\nप्रवृति बहुत लोगों में मिल जाता\r\nहै कम हो ज्यादा हो पहले हम बंधन योग की\r\nबात करते\r\nहैं\r\nबंधन ऐसा होता है जब आप अपनी इच्छा\r\nअनुसार कोई काम या इधर उधर आना जाना य\r\nनहीं कर सकते उसको बंधन बोलते हैं चाहे वह\r\nबीमारी से\r\nहो किडनैप हो जाते हैं\r\nलोग या जेल की सजा हो गई हाउस अरेस्ट हो\r\nगए तो यह बहुतों के मिल जाता है अब हमेशा\r\nयह नहीं है कि बंधन योग आपको कोई क्राइम\r\nकरने से कोई अपराध करने से ही मिलता है\r\nनहीं\r\nबहुत सी\r\nदफे आप मजबूरी में कहीं आ जा नहीं सकते आप\r\nचलने लायक नहीं रहते सेहत खराब हो जाती है\r\nतो उस बंधन योग को\r\nऔर कानून से अपराध की वजह से सजा मिलना यह\r\nदो अलग\r\nपहलू तो\r\nइसीलिए\r\nहमें पहले प्रकृति देख\r\nपड़ेगी कि वह क्या अपराध कर सकता है बहुत\r\nसी दफे अपराध करता है तो भी सजा नहीं\r\nहोती\r\nपरंतु जब भी अपराधिक प्रवृत्ति आती\r\nहै तो एक तरह का कन्फाइनमेंट जरूर हो जाता\r\nहै समाज उसको अलग थलक कर देता है आपने\r\nसुना होगा\r\nपहले कि गांव की पंचायत होती थी\r\nऔर भाई इसने ठीक काम नहीं किया इसका\r\nहुक्का पानी बंद\r\nकर उसका बड़ा जबरदस्त मतलब होता थाका पानी\r\nबंद कर दो के कोई उससे बात नहीं कर सकता\r\nमिलजुल नहीं सकता जब तक वह बन नहीं हटेगा\r\nकोई उससे रिश्ता कायम नहीं कर सकता कोई\r\nउसके साथ बात नहीं कर तो यह सब होता\r\nथा अब यह जो\r\nहै अपराधिक प्रवृत्ति के\r\nइसके जो सबसे बड़े\r\nनियम हमको मिलते हैं जातक अलंकार एक छोटी\r\nसी पुस्तिका है उस जातक अलंकार में चार\r\nनियम दिए\r\nगए हम और भी जोड़ेंगे जो हमने बाकी\r\nएक्सपीरियंस से लिए और वह चार नियम में\r\nजातक अलंकार कहता है यदि एक नियम भी हो\r\nरहा है तो कुछ ना कुछ कुछ ना कुछ परेशानी\r\nजरूर\r\nहै कहीं भी\r\nउसको शरीर से होगी मन से होगी कहीं से कुछ\r\nपरेशानी जरूर और इन चारों में से कोई ना\r\nकोई मिल जाता है और अगर चारों मिल गए तब\r\nतो भैया भगवान बचा\r\nहै यह जो आज का हमारा डिस्कशन\r\nहै इसको हम वर्ग पर भी लगा कर के देख सकते\r\nऔर जिस वर्ग में भी यह योग मिल जाते हैं\r\nयह चार\r\nयोग तो उस वर्ग के कारक में भी वह व्यक्ति\r\nअपराधी होता है मतलब सीधा ऑनेस्ट नहीं\r\nहो सीधे से काम नहीं करेगा कहीं ना कहीं\r\nकुछ ना कुछ उसकी प्रवृत्ति धोखा देने की\r\nहो जाती है मैं इसको यही कहूंगा धोखा देने\r\nकी\r\nमान लो 9 में आ\r\nगया d10 में आ गया डी3 में आ गया वहा धोखा\r\nदेगा वो टे में अपने कारोबारियों पार्टनर\r\nसे काम के उसम धोखा\r\nदेगा पर यह जो हम नियम है ये सबसे पहले\r\nजन्म कुंडली पर ही लगाते\r\nहैं वहीं पर अगर दिख जाता\r\nहै तो वो हर जगह प्रभावित करेगा\r\nजन्म कुंडली में अगर यह योग मिल जाता\r\nहै और उसके साथ साथ जन्म कुंडली में है और\r\nफिर वह किसी वर्ग में भी मिल जाता है जैसे\r\nटे में\r\nमिल तब उसका इफेक्ट ज्यादा हो जाता\r\nहै अगर जन्म कुंडली में यह योग नहीं है तो\r\nआप यह कह सकते हैं कि वो थोड़ा\r\nसरकमस्टेंसस में कहीं वो कार्य क्षेत्र\r\nमें टे में प्रॉब्लम में आएगा परंतु वह\r\nअपने मन से या दिल से वो काम नहीं करता\r\nहै तो पहले हम देखते हैं वो चार\r\nयोग उसमें सबसे बड़ा इंपॉर्टेंट योग होता\r\nहै इंपॉर्टेंट\r\nकंडीशन वो होती है\r\nलग्नेश अब ये लग्नेश हम जन्म कुंडली का ले\r\nरहे हैं आप किसी भी वर्क कुंडली में देख\r\nसकते\r\nहैं जातक अलंकार क्या कहता है\r\nके\r\nलग्नेश का\r\nसंबंध या लग्नेश पर केवल पाप ग्रहों का\r\nप्रभाव\r\nआए पहली कंडीशन शुभ प्रभाव कोई भी नहीं\r\nहोगा यह नैसर्गिक\r\nशुभ और अशुभ लिए फंक्शनल नहीं लिए इस\r\nकुंडली के शुभ अशुभ नहीं जो\r\nनेचुरल जो वो है उनको लिया गया\r\nहै यह सबसे पहला और सबसे\r\nइंपॉर्टेंट नियम दिया\r\nहै दूसरा नियम\r\nहै के\r\nसूर्य या\r\nचंद्रमा पाप करतरी में\r\nहो हम कर्तरी देख चुके हैं और कब\r\nकरतरी प्रबल हो जाता\r\nहै जबकि आगे वाला ग्रह वक्री हो और पीछे\r\nवाला ग्रह डायरेक्ट खैर इस जातक अलंकार\r\nमें यह डिस्टिंक्शन नहीं दी है वहां वह\r\nसीधा सधा बोलता है पाप करतरी में\r\nहो दूसरा\r\nनियम तीसरा नियम है\r\nकि\r\nसूर्य या चंद्रमा\r\nसे\r\nमंगल सप्तम भाव\r\nमें सूर्य या चंद्रमा से मंगल सप्तम भाव\r\nइन दोनों से लिखा\r\nहै और चौथा लिखा\r\nहै के बुध बुद्ध आपकी दुनियादारी की\r\nइंटेलिजेंस है\r\nबुध पृष्ठ उदय साइन में होना\r\nचाहिए जन्म कुंडली में या किसी भी जो वर्ग\r\nहम देख रहे अब सबको आपको पता है पोद सान\r\nक्या क्या होते\r\nहैं रिपीट कर दू एक दो\r\nचार न द मतलब मेश टारस मेष वृषभ कर्क धनु\r\nऔर मकर\r\nयह चार पृष्ठ पांच ये पृष्ठ उदय साइन होते\r\nहैं ठीक है इसमें होना चाहिए अब अब हम\r\nजातक अलंकार से बाहर आकर के कुछ और नियम\r\nदेखते हैं वोह हमारी जनरल प्रेडिक्शन से\r\nआता\r\nहै चतुर्थ भाव या चतुर्थ\r\nलॉर्ड भी\r\nकेवल उसका भी पाप संबंध\r\nहो ठीक है\r\nजी चतुर्थ लॉर्ड या दशम\r\nलॉर्ड चौथे भाव में\r\nहो तब भी वह फ्रड होता है यह मुझे पछता\r\nनहीं है अब लिखा हुआ है कि दशम\r\nलॉर्ड चौथे भाव में हो चौथा भाव चौथा ल\r\nचौथे भाव में उसको तो बलि करेगा व दशम को\r\nभी करेगा परंतु यह में लिखा हुआ है के बलि\r\nतो करेगा परंतु उसके\r\nतरीके जिससे वह सुख प्राप्त करता है या\r\nअपने कर्म में वह कोई सीधे तरीके नहीं\r\nहोते डिस होनेस डिस\r\nहोने दिखती\r\nहै एक जिसको मैं पूरा एंडोर्स करता हूं खल\r\nयोग कि खल योग अगर है\r\nतो वह व्यक्ति खल है आप खल योग से मतलब\r\nसमझ ही रहे हैं खल है और खल योग आपको पता\r\nहै के तीसरे भाव का स्वामी का किसी भी भाव\r\nसे परिवर्तन योग हो तो वह खल योग बन जाता\r\nहै एक और आता है\r\nके तीसरा भाव\r\nबली होना\r\nचाहिए तभी तो करे जाएगा\r\nना कुछ करने का और\r\nबुध नवांश में पीड़ित हो इसमें मैं बुध के\r\nसाथ-साथ\r\nचंद्रमा भी जोड़ देता हूं एक्चुअली मैंने\r\nअपने कई पिछले वीडियो में मैंने य कहा था\r\nकि संस्कार कैसे देखते\r\nहैं तो ज कुंडली के वितेश को हम नवांश में\r\nदेख लेते हैं वो संस्कार का फाइनल वर्ड है\r\nदती भाव हमारा संस्कार का है अगर वो\r\nसंस्कार पीड़ित है सेकंड लड तो उसके\r\nसंस्कार अच्छे नहीं\r\nहै उसको वहीं\r\nसे आ जाता है तो ये मोटे मोटे ये\r\nप्रिंसिपल है एक और प्रिंसिपल हम देख सकते\r\nहैं वो है द्रेश कांड\r\nक्योंकि बंधन योग में आगे हम दृश कांड का\r\nभी प्रयोग\r\nकरेंगे सर्प दृश कांड वगैरा जो है वह आते\r\nहैं वो जब बली हो जाता है दृश कांड\r\nमें बुध की राशि उदय हो रही\r\nहो या बुध द्रेश कांड के लगन में\r\nहो द्रेश कांड के लगन में हो और चंद्रमा\r\nसे दृष्ट\r\nहो चंद्रमा बुद्धि मन है\r\nआपका वर्डली बुद्धि इंटेलिजेंस जो है वह\r\nमरकरी है अब इतने से काम मेरे ख्याल से\r\nनहीं चलता है इन पर पाप प्रभाव आना चाहिए\r\nतब वह काम चलता है ठीक है जी तो यह हमारे\r\nनियम\r\nहुए बाकी आप अप्लाई करते रहिए बाकी चार्ट\r\nमें मैं नहीं करूंगा अभी आपको बता दि आप\r\nदेखते रए अब जो भी आप किसी को दोस्ती करते\r\nहैं सिलेक्शन करते हैं तो यह जो पहले चार\r\nनियम है जातक अलंकार\r\nके इनको जरूर चेक कर लो\r\nभाई इसके बगैर आप डिसीजन मत लो अब मैं आप\r\nदो कुंडलियों पर वर्ग लेकर के जिन वर्गों\r\nपर यह लग रहा है नियम उसको देख कर के हम\r\nउस वर्ग के बारे में भी बात करें तो मैं\r\nआपसे चार्ट अप शेयर करता\r\nहूं ये भैया पहली\r\nकुंडली सद्दाम हुसैन जी की\r\nहै पहले हमने जन्म कुंडली\r\nली पहला नियम\r\nथा लग्नेश लगन नहीं देखना है\r\nलग्नेश का केवल\r\nपाप ग्रहों से संबंध\r\nहो अब यहां लग्नेश\r\nब अगर शुभ संबंध आ जाता है तो इंप्रूवमेंट\r\nहो\r\nजाती दिमाग में तो रहेगा पर वह फायदे के\r\nलिए करेगा अब य बुध\r\nहै केतु के साथ\r\nहै मंगल से दृष्ट\r\nहै और चंद्रमा से\r\nदृष्ट चंद्रमा को हम शुभ मान\r\nरहे ठीक है क्योंकि चंद्रमा पक्ष बली\r\nहै और अच्छी बात क्या हो गई कि बृहस्पति\r\nभी उसको दृष्ट कर बुध को तो यहां यह पूरी\r\nतरह से पहला वाला नियम नहीं लगा थोड़ा सा\r\nतसल्ली हो रही है क्लियर मतलब शनि भी कर\r\nरहा है एस्पेक्ट मतलब पाप भी संबंध है शु\r\nसंबंध भी तो अलंकार बोलता है कि यह शुभ\r\nसंबंध नहीं होना चाहिए पर यहां आ\r\nगया दूसरा है कि सूर्य या\r\nचंद्रमा\r\nआपके पाप करतरी में\r\nहो अब यहां देख रहे हैं डिग्रीज मैंने\r\nनहीं दी है सूर्य के भी आगे पीछे ग्रह है\r\nचंद्रमा के भी आगे पीछे ग्रह है परंतु\r\nमंगल वक्री है चंद्रमा से दूर जा रहा है\r\nऔर राहु वक्री है वो आ रहा है चंद्रमा की\r\nतरफ तो यह हमें मिल\r\nगया सूर्य या चंद्रमा से आठवे में मंगल वो\r\nनहीं मिल रहा\r\nहै फिर है बुध पृष्ठ उदय साइन में\r\nहो वो हमें मिल रहा है बुध जो है पृष्ठ\r\nसाइ तो यह हमें जन्म कुंडली में दिखाता है\r\nकि अपराधिक प्रवृत्ति रही\r\nहै यह भी टेररिस्ट ग्रुप में भर्ती हो गए\r\nथे और 16 साल की उम्र में ही इन्होंने\r\nटेररिस्ट एक्टिविटी में पार्टिसिपेट किया\r\nजेल भी और वहां से जेल से छूट के य आ गए\r\nठीक है जी तो यह इनका जन्म कुंडली देखा अब\r\nमैं इनकी और कुंडलिया देखता जो रूल है अब\r\nरूल से देखते\r\nअब इनको हमने नवांश\r\nदेखा नवांश में आप देखिए लगन कौन सी उदय\r\nहो रही है\r\nतुला तुला के स्वामी है\r\nशुक्र तो शुक्र जो\r\nहै यह शनि से दृष्ट है\r\nस शुक्र पर कोई शुभ दृष्टि नहीं है\r\nतो नवांश में लगन बिगड़\r\nगई दूसरा है के बुध पृष्ठ उदय साइन में\r\nहै और नवांश में बुध पीड़ित\r\nहै\r\nऔर चंद्रमा भी पीड़ित\r\nहै चंद्रमा पर केवल एक शुभ संबंध बृहस्पति\r\nकी दृष्टि से आ रहा\r\nहै तो इंटेलिजेंस बहुत तेज थी\r\nक्रुक मन इतना क्रुकेट नहीं कह सकते आप पर\r\nबुद्धिमता जो दुनियादारी की है वह ज्यादा\r\nहै तो यहां पर भी हमें अपराधिक प्रवृत्ति\r\nदिख गई है इसके बाद हम आते हैं डी ना था\r\nये अपने संगी साथियों वगैरह से जो रिलेशन\r\nहोते हैं\r\nउसमें परिवार के रिलेशन है अब हम डी 10\r\nदेखते हैं ये ज्यादा जरूरी हो जाता है\r\nकर्म\r\nक्षेत्र इसका लगन देखिए\r\nआप लग्नेश लगन नहीं लग्नेश\r\nदेखो\r\nबुध शनि के साथ है और मंगल से दृष्ट\r\nकोई शुभ संबंध नहीं\r\nहै तो कर्म क्षेत्र\r\nमें कनिंग\r\nहै अपराधिक प्रवृत्ति\r\nहै बुध फिर पृष्ठ द साइन में\r\nहै अब मैं अगर एक और चीज देखू हम डी 10\r\nमें मैं हमेशा बोलता हूं लगन से हम सब समझ\r\nकर्म को देखते हैं और दशम भाव से\r\nप्रोफेशनल कर्म को देखते जिससे आप अपनी\r\nजीविका आपने कर्म करते हैं तो\r\nप्रोफेशनल दशम भाव का जो स्वामी है वह\r\nबृहस्पति अब बृहस्पति को देख लो भाई कितनी\r\nबुरी तरह पिटा\r\nहुआ मंगल के साथ\r\nहै शनि से दष्ट\r\nयहां निजात नहीं\r\nजो कर्म जो अपने प्रोफेशनल कर्म है उसमें\r\nव्यक्ति सीधा नहीं है अपराधिक\r\nहै तो हमने इसको वर्गों तक पर एक्सटेंड कर\r\nदिया अब एक कुंडली और देख\r\nभा यह भी बड़ी जबरदस्त कुंडली है भाई साहब\r\nलग्नेश है\r\nशुक्र ठीक है\r\nजी\r\nशुक्र नवम भाव में बैठे हैं कोई शुभ\r\nदृष्टि नहीं\r\nहै मंगल देख रहे मंगल की दृष्टि है पाप\r\nदृष्टि आ गई और जो शुक्र है ये केतु और\r\nशनि के कर्तरी योग में\r\nकेतु शुक्र की तरफ आ रहे हैं और शनि भी\r\nशुक्र की तरफ आ रहे तो बली करत योग\r\nहै\r\nबुध पृष्ठ उदय साइन में है धनु\r\nमें सूर्य\r\nसे सातव भाव में मंगल\r\nबैठे तो यहां जातक अलंकार के चारों नियम\r\nलग\r\nगए चारों नियम लग\r\nरहे तो जिस भी वर्क कुंडली में अब इनका यह\r\nनियम लग जाएगा उस वर्ग कुंडली का तो यह\r\nबेड़ा पार बेड़ा गरक कर देंगे ठीक है अब\r\nहम इनका नेक्स्ट वर्ग देखते हैं नेक्स्ट\r\nवर्ग हम देखते हैं डी 10 कर्म\r\nका विवाहित जीवन ठीक ठाक सा चल रहा है\r\nबुरा नहीं\r\nहै अब यहां देखो फिर\r\nसे बुध की राशि उदय हो रही\r\nहै बुध सिर्फ राहु के साथ\r\nहै और पृष्ठ दय साइन में है\r\nकोई शुभ दृष्टि नहीं\r\nहै तो व्यवसाय\r\nमें यह हमेशा चीट\r\nकरेंगे\r\nअब अगर मैं दशम हा से दशम भाव से देखता\r\nहूं दशमेश को जो जीविका वाला कर्म\r\nहै उसके स्वामी है\r\nगुरु गुरु भी केवल मंगल से दृष्ट\r\nहै कोई शुभ संबंध नहीं आ रहा है गुरु\r\nपर यह कहोगे भाई गुरु तो शुभ है नहीं पर\r\nगुरु को देख रहे हैं ना उसके ऊपर क्या\r\nसंबंध आ रहा\r\nहै तो यहां भी बेड़ा गर्क हुआ पड़ा है इस\r\nव्यक्ति ने प्रोफेशन में हमेशा चीटिंग और\r\nउसका ही काम किया ना स्टेबल रहे जहां भी\r\nकाम किया वहां पर चीट किया और इसलिए वह\r\nजल्दी से नौकरी से निकाल भी दिए जाते थे\r\nमेहनती बहुत है मेहनती बहुत है मेहनत में\r\nकमी नहीं\r\nहै पर मेहनत गलत डायरेक्शन दिन और रात\r\nमेहनत है कि मैं किस तरह से गुलग पाड़ा\r\nकरू एक चार्ट और ले लेते हैं इनका देखते\r\nहैं भाई वहां क्या कह रहे हैं\r\nयह मैंने लिया द्रेश कांड क्योंकि द्रेश\r\nकांड का नियम हमने दिया था कि भाई चंद्रमा\r\nऔर बुध अगर पीड़ित\r\nहै तो भी वो ठीक\r\nनहीं अब य बुध देखो फिर से पृष्ठ साइन में\r\nलग्नेश है डी3\r\nके राहु के साथ है कोई शुभ संबंध नहीं है\r\nकेवाय सिवाय\r\nबृहस्पति तो डी3 में बृहस्पति से थोड़ा\r\nसा सावना मिल रही है कि थोड़ा तो भाई\r\nअच्छा कर\r\nदेगा सूर्य\r\nसे सप्तम में मंगल बैठे हुए\r\nहैं बुद्ध पोद साइन में\r\nहै चंद्रमा\r\nपाप करतरी में है कहा था ना सूर्य और या\r\nचंद्रमा पाप करतरी में\r\nहो द्रेश कांड में बुध की राशि उदय हो रही\r\nहै अब जो डी3\r\nहै यह तो आपका भाई बहनों का इनका सबका है\r\nचार्ट है तो वहां भी नहीं छोड़ा\r\nइने दोनों बड़े भाई बहन को\r\nइन्होंने खूब चुना\r\nलगाया इनके बड़े भाई बाहर रहते हैं\r\nउन्होंने इसको पावर ऑफ अटॉर्नी पूरी दे दी\r\nकि भाई साहब मेरी प्रॉपर्टी और पैसे ऐसे\r\nआप इंडिया के सारे देख लो आ प्रॉपर्टी\r\nखरीद ली उनके नाम पर वह अच्छा धनी आदमी है\r\nऔर उसको भी नहीं पता बड़े भाई को कि किस\r\nप्रॉपर्टी का क्या\r\nहुआ बड़ी बहन की फैक्ट्री हथिया\r\nली उनको बाहर कर\r\nदिया मां बोल के गई प्रॉपर्टी में शेयर\r\nदेना वह भी खा\r\nगए तो यह भाई\r\nसाहब आज का जो\r\nहमारा तो आज का जो हमारा विषय था ये यह\r\nसिर्फ बंधन योग ही\r\nनहीं परंतु आपके जीवन में\r\nआपको अपने मित्र\r\nचुनने संगी साथी\r\nचुनने\r\nउसको देख कर के आप पहले से चौकन हो सकते\r\nहैं कि भैया यह आदमी ठीक नहीं है इससे हम\r\nदूरी बना करके\r\nरखे और अगर आपकी ही कुंडली में मिल रहा है\r\nतब बड़ा अच्छा\r\nहै तब बहुत अच्छा है वो मत बताना किसी को\r\nभी कि यह ज्योतिषी का नियम है मुझे तो आती\r\nहै ज्योतिष और मेरी कुंडली में\r\nहै तो मैं तो ज्योतिष पढ़ी हुई\r\nहै तो मैं किसी और को नहीं पढ़ने दूंगा वो\r\nबात नहीं तो मेरी कुंडली देख\r\nलेगा अब यह हमने भी बहुत दिनों के बाद आया\r\nहै अकल\r\nमें पढ़ ली थी जातक अलंकार पढ़ ली थी कोई\r\nबात नहीं तीसरा चौथा श्लोक\r\nहै कभ सोचा ही नहीं गौर ही नहीं किया फिर\r\nजब दुनिया में देखते\r\nहैं फिर वो याद आता है कि हां यह\r\nहै और यह चीज मैं शेयर कर भी चुका हूं\r\nपहले पर मैंने कहा कि मेरी अपनी जो ट्यूब\r\nचैनल है उस परे भी मुझे ये जरूर डाल देना\r\nचाहिए और विस्तार से डालना\r\nचाहिए अब इसके\r\nबाद अब हम\r\nदेखो कोशिश करते हैं बहुत डिफिकल्ट टॉपिक\r\nहै आसानी वाला नहीं है बंधन योग किसी के\r\nभी मिल जाएगा क्योंकि कोई भी बीमार तो\r\nपड़ता ही है भाई कभी तो बंधन होता ही\r\nहै तो उसका गलत मीनिंग नहीं लेना है कि\r\nमुझे सजा\r\nहोगी सजा क्यों होगी अपराध की वजह से होगी\r\nतो यह चेक कर अब बहुत सी कुंडलियों में\r\nअपराधिक कुंडली है अपराधिक प्रवृत्ति है\r\nबंधन योग नहीं\r\nहै तो बरी छूट रहा है मजे कर रहा\r\nहै बीमारी की वजह से बंधन योग आ रहा है वह\r\nअलग चीज है वह देखना पड़े तो आज का यह\r\nबहुत अच्छा टॉपिक\r\nहै इसको आप सु सुने देखे और और अप्लाई\r\nकरें क्योंकि मैंने यह गौर किया\r\nहै के जो थोड़े से सीरियस एस्ट्रोलॉजी के\r\nछात्र है स्टूडेंट\r\nहै मजे से करते हैं\r\nएस्ट्रोलॉजी वह पसंद करते\r\nहैं जिनको एस्ट्रोलॉजी से ज्ञान नहीं लेना\r\nऔर बहुत से ऐसे हैं कि मुझे बहुत\r\nएस्ट्रोलॉजी आती\r\nहै तो अब मेरे को और कोई सीखने की जरूरत\r\nनहीं है\r\nआगे तो अगर वह पूरा हो गया है तो वह क्यों\r\nअप्लाई करें\r\nआगे परंतु हमने जो पढ़ा है पुस्तकों में\r\nउसम इवन यही लिखा है वरा मीर साहब ने भी\r\nयही लिखा है के एक जन्म जो सीखने के लिए\r\nकाफी नहीं है पूरा जीवन लगे रहो तो भी\r\nनहीं आएगा तो भैया हम तो ज्योतिष के\r\nविद्यार्थी बनकर यह काम करते रहते हैं\r\nहमें आया है कितना आया है और भी सीखने को\r\nबहुत है तभी तो सीखते\r\nरहते और जो सेटिस्फाई हो गया हां मुझे आ\r\nगई\r\nहै तो वो उसको मुबारक भाई उसको य बढ़िया\r\nहै सेटिस्फाई हो गया है वो उसको भगवान\r\nप्राप्ति हो गई चलिए तो इसी के साथ आज का\r\nयह खत्म करता हूं नमस्कार फिर मिलेंगे"},{"topic":"बंधन योग 2आपराधिक प्रवृत्ति से रहित","text":"नमस्कार\r\nमित्रों आज फिर हम अपने बंधन योग की दूसरी\r\nकड़ी लेकर के आए\r\nहैं और उस योग को और आगे\r\nबढ़ाए बंधन योग वन में हमने अपराधिक\r\nप्रवृत्ति की जांच देखी\r\nथी उसमें बहुत से प्रश्न\r\nऔर उन प्रश्नों\r\nसे मुझे लगा कि शायद या तो मैंने ठीक से\r\nनहीं बताया\r\nहै या समझने समझाने में गलती हुई\r\nहै तो उसका मैं थोड़ा सा क्लेरिफिकेशन\r\nपहले\r\nदूंगा हमने चार बड़े\r\nयोग अपराधिक प्रवृत्ति के बताए\r\nथे जिसमें सबसे पहला योग\r\nथा के लग\r\nका संबंध केवल पाप ग्रहों से हो अशुभ\r\nग्रहों से\r\nहो अब यहां पर या तो केवल शब्द को आप\r\nलोगों ने नहीं पकड़ा है या कैसे छूट गया\r\nक्या हुआ है केवल मुझे बोला\r\nतो तो यह मेन सूत्र\r\nहै के लग्नेश का स ंध केवल अशुभ ग्रहों से\r\nहो राहु\r\nकेतु शनि मंगल\r\nसूर्य उसके बाद के जो सूत्र\r\nथे के चंद्रमा सूर्य से सातव में मंगल पाप\r\nकरतरी में बुध पृष्ठ उदय साइन में द्रेश\r\nकांड का बुध राइज करना यह करना\r\nये फिर अपराधिक प्रवृत्ति नहीं\r\nकहेंगे अपराधिक प्रवृत्ति का सबसे बड़ा\r\nनियम वो लग्नेश का\r\nहै वो अगर नहीं\r\nहै लग्नेश का केवल पाप से संबंध नहीं है\r\nपाप से है और साथ में शुभ से भी\r\nहै तो यह रूल अप्लाई नहीं होगा\r\nफिर क्या हो जाएगा बाकी के लिए यह अब\r\nअर्चन देते हैं यह जो योग है कोई ना कोई\r\nपरेशानी दे देते हैं शरीर में किसी अंग\r\nमें परेशानी दे देते हैं आपके व्यवसाय में\r\nपरेशानी देते\r\nहैं वहां\r\nआप अपराधिक प्रवृत्ति के बगैर भी आप जल्दी\r\nसे लाभ कमाना चाहते हैं पृष्ठ होदय दूसरे\r\nतरीके से विपरीत तरीके से आप कमाना चाहते\r\nहैं तो भैया ये आप वो डाउट उसको निकाल दो\r\nऔर जो पहला सबसे बड़ा रूल है वो है कि\r\nलग्नेश का संबंध\r\nकेवल पाप ग्रह से हो किसी भी शुभ ग्रह से\r\nना हो अब यहां पूछोगे लग्नेश अगर ये पाप\r\nग्रह है तो भैया कैसे अशुभ हो\r\nगए ठीक है ना यह और छोड़\r\nदेंगे और एक यह भी आया कि जी बीमारी की\r\nवजह\r\nसे कैसे बंधन हो जाता है भैया आप बीमार\r\nबनते पड़ते\r\nहो तो जाहिर बात\r\nहै थोड़ा खांसी जुकाम बुखार हो जाएगा दो\r\nचार दिन को बंधन हो गया काम पर नहीं जा\r\nसकते ऑफिस से छुट्टी ले लेते\r\nहो लंबी बीमारी हो गई तो हो गया\r\nया ऐसे भी है कि\r\nजो ऐसी एक्टिविटीज में रहते\r\nहैं और उनको बंधन होता\r\nहै ठीक है तो क्लासिक में क्या-क्या कहा\r\nहै पहले हम ये कहते देखते\r\nहैं कि भाई क्लासिक में पहला सेंटेंस तो\r\nआता है\r\nहमेशा के शनि मंगल राहु और\r\nकेतु यह चार ग्रह जो है बंधन दे सकते हैं\r\nयदि वो बंधन वाले भाव से संबंध रखते हो और\r\nइनका किस किस तरह का बंधन योग होता है वो\r\nभी जान लेना जरूरी है परंतु इतना ज्यादा\r\nअप्लाई वो हम कर नहीं पाते हैं पर हां\r\nहमें जानना\r\nचाहिए पहला होता है अरी\r\nचार प्रकार के बंधन योग क्लासिक में लिखे\r\nहुए पहला होता है अरी अरी मींस एनिमी\r\nशत्रु और यह आता है इसके कारक जो है वो\r\nशनि अरि योग शत्रु की वजह से तो ये शनि जो\r\nहै कर्म के और प्रारब्ध\r\nके करता है तो यह आपके प्रारब्ध और पुराने\r\nकर्मों की वजह से\r\nया इस जन्म में जो आप खराब कर्म करोगे\r\nजैसे बैड कंपनी हो गई उनके साथ ड्रग\r\nट्रैफिकिंग हो गई माफिया रबरी\r\nएडल्ट्री और यह ज्यादातर फ्रेंड्स के साथ\r\nसमाज के साथ करके होती है तब\r\nयह तो इससे हम कहेंगे कि आपके जो फ्रेंड्स\r\nहै उनसे आप छुटकारा पाओ वोह ठीक\r\nनहीं दूसरा टाइप का होता है\r\nवीर वीर मतलब ब्रेव\r\nताकतवर पुरुषार्थ से भरा हुआ और इसके कारक\r\nमंगल\r\nहै अब यह भी कई तरह के हो सकते हैं अब\r\nब्रेव एक तो आर्मी में भाई साहब लड़ाई कर\r\nरहे लड़ाई में प्रिजनर हो गए\r\nयह एक्चुअली एक तरह से यह है कि जहां आपको\r\nलड़ना पड़ता\r\nहै तब आप प्रिजन में\r\nजाते यही अब जो वीर\r\nहै इसी की एक लाइन है जब आप बीमारी की वजह\r\nसे जाते हो क्योंकि लड़ रहे हो उसम बीमारी\r\nसे लड़ रहे हो और उस बीमारी की वजह से\r\nआपको बंधन हुआ इसमें और सेकंड टाइप हो\r\nजाता है सिविल वार में स्ट्रीट फट सड़क प\r\nचाते कार पार्किंग में टक्कर लग गई इधर\r\nउधर हो गई उसमें लड़ाई हो गई\r\nटेररिस्ट यह भी इसी कैटेगरी में आते हैं\r\nवीर में उनको भी वीर क गया ठीक है और वो\r\nउनको पकड़ लेती है पुलिस और उन्ह जेल में\r\nपटक देती है वो भी ीर है ठीक है और जो\r\nतीसरे तरह के होते हैं के बिल्कुल ही जो\r\nवीरता दिखाते मर्डर करने में\r\nमर्डर करा भाग गए नॉन पेमेंट ऑफ टैक्सेस\r\nलोन इससे पैसा कर्जा लिया पैसे वापस नहीं\r\nकर यह सब छ भाव का है\r\nना तो वो यह इस इस कैटेगरी में आते\r\nहैं इसके बाद नाग अब य अरि वीर\r\nनाग नाग सांप आप समझते हैं स्नेक है और\r\nइसके करता है\r\nराहु अब यह जो राहु है\r\nयह माफिया रेसिजम\r\nड्रग्स बमिंग इन सब में इवॉल्व होते हैं\r\nइलीगल\r\nमाइनिंग बहुत सारे सरल थ्री में मैंने सब\r\nलिखा हुआ है इतना पढ़ के तो नहीं बताऊंगा\r\nसारा ठीक है तो यहां पर जो आते\r\nहैं वो पावरफुल पोजीशन अपनी दिखाना\r\nचाहते उसके बाद होता है अही अही है पर\r\nइसके करता है केतु और यह\r\nवर्स्ट राहु केतु आ जाते हैं जहां पर भी\r\nत्रिक भाव\r\nमें वो वर्स्ट हो जाते हैं दूसरी चीज हमें\r\nजो जानने की होती\r\nहै वो ग्रह के द्रेश कांड जानने\r\nकी दो तरह के दश\r\nकांड दो पाश भी मान लेते हैं नहीं तो\r\nसर्प और\r\nआयुध द्रेश कांड में जो भी ग्रह होते\r\nहैं वह बंधन दे सकते\r\nहैं चाहे कैसा भी\r\nबंधन सर्प आयुध और आयु सर्प के साथ ही\r\nस्कॉर्पियो का दूसरा द्रेश कांड उपास भी\r\nकहलाता है तो यह आप किसी भी किताब से\r\nलिस्ट देख सकते हैं अब मैं आता हूं यो जो\r\nक्लासिक में कॉमिनेशन दिए हुए\r\nहैं और हम उनको कैसे\r\nदेखेंगे सबसे पहला कॉमिनेशन जो क्लासिक\r\nमें दिया जाता है वो दिया जाता\r\nहै सेम नंबर ऑफ\r\nप्लेनेट लगन के आजूबाजू दो 12 में तीन 11\r\nमें चार 10 में पाचन में छ आठ में इक्वल\r\nनंबर ऑफ प्लांट्स\r\nसमान नंबर ग्रहो के होने\r\nचाहिए अब\r\nयह दिखता है कहीं कहीं लग जाता है कहीं\r\nकहीं लग जाता है फिर भी देख लेना चाहिए पर\r\nयह कंपल्शन नहीं है बहुत केसेस में हमने\r\nदेखा है यह रूल नहीं लगता है परंतु वो भी\r\nजेल\r\nगए महात्मा गांधी का ही ले लो नरू का ले\r\nलो इसके बाद जो सबसे ज्यादा\r\nप्रचलित रूल आते हैं वो है सिक्सथ\r\nलॉड एथ\r\nलॉर्ड मैं इसको त्रिक लड बोल देता हूं\r\nउसमें छ और आठ का ज्यादा है त्रिक\r\nलड ये यदि केंद्र या त्रिकोण में\r\nहो और राहु केतु और शनि इनके\r\nसाथ तो यह भी एक बंधन योग हो जाता है\r\nपुस्तकों में सिर्फ छ का लिखा है और आठ का\r\nलिखा है 12 मैंने ऐड\r\nकर ठीक है 12 मैंने कहीं पढ़ा था वह भी ऐड\r\nकर दिया\r\nइस अब केतु एक कॉमिनेशन जो और दिया गया\r\nहै कि केतु\r\nथ\r\nलॉर्ड के साथ त्रिक हाउस\r\nमें तो यह बहुत ही लंबे समय का और बहुत ही\r\nवर्स्ट कन्फाइनमेंट होता\r\nहै इसकी मैंने थोड़ा सा क्लासिक का तो यह\r\nहो\r\nगया इसका मैंने देखा भाई ट्रिक में ही\r\nक्यों लिया ट्रिक के स्वामी के साथ क्यों\r\nनहीं लेते केतु\r\nको उसके साथ भी तो केतु आ सकता\r\nहै दूसरा त्रिक भाव मैं लगन से ले रहा\r\nहूं मेरी\r\nऑब्जर्वेशन इसमें है के जो चतुर्थ भाव है\r\nवो आपके घर का भाव है जब आप बंधन में जाते\r\nहैं तो घर से दूर चले जाते हो कई दफे कई\r\nदफ घर में ही बंधन हो जाता है परंतु चौथे\r\nसे आठवा क्यों नहीं लेता मैं\r\nतो मैंने इसमें 11वां भाव और भावेश को ऐड\r\nकिया कि केतु के राहु केतु के\r\nसाथ\r\nअगर गवे का लॉर्ड भी हो थ हाउस का लॉर्ड\r\nउससे संबंध बना रहा हो और वह\r\nत्र लगन से त्र शरीर तो लगन है लगन से\r\nत्रिक हाउस में तो भी यह\r\nबहुत गंदी इंप्रिजनमेंट दे सकता\r\nहै एक और मिलता है क्लासिक का है व उ तरिक\r\nमें नहीं वह कहता है 6 आ 12 छ आ छ और आठ\r\n12 नहीं लिया हुआ है केंद्र त्रिकोण में\r\nराहु केतु के साथ यह पहले वाले काई है दो\r\nअलग अलग किताब से\r\nएक छटा हाउस जो है वह आपके संघर्ष का\r\nहै\r\nऔर छटे लॉर्ड के साथ\r\nसाथ अगर शनि का देखो राहु केतु तो कर नहीं\r\nसकते दृष्ट अगर मंगल दृष्ट कर रहा है व\r\nलगन को स्ट्रंग करेगा सेहत देता\r\nहै तो शनि बच गया\r\nतो छटा लॉर्ड और शनि दोनों मिलकर\r\nके यदि लगन पर इनफ्लुएंस\r\nकरें तो वह एक अच्छा बड़ा योग बन जाता है\r\nबंधन\r\nका यह मैंने क्यों वेरीफाई किया क्योंकि\r\nमेरी कुंडली में\r\nहै छटा लड मंगल है और शनि लगन में बैठे\r\nमंगल दशम भाव से शनि को दृष्ट कर रहे हैं\r\nतो यह सफरिंग देता है कन्फाइनमेंट देता है\r\nतो कई दफे हॉस्पिटल ही\r\nआया यह कॉमिनेशन मैंने कहा हा भाई हो सकता\r\nहै क्योंकि मेरे को लग रहा है आपनी कुबली\r\nदेखनी होती है ना सबसे\r\nपहले ठीक है जी तो अब हम एक दो\r\nकेस स्टडी कर लेंगे आराम आराम से दृश कां\r\nसे भी जो मेन मेन पॉइंट है वह आपको\r\nबताऊंगा क्योंकि यह ऐसा टॉपिक है भाई आसान\r\nटॉपिक नहीं है बंधन योग आसान टॉपिक नहीं\r\nहै लंबा टॉपिक है परंतु हम देखते ज्यादातर\r\nतो हम क्रिमिनल है नहीं ज्यादा से ज्यादा\r\nलालची है स्वार्थी है और क्या\r\nहै ठीक है उसके बाद बीमारी का ही अगर\r\nदेखना है तो डी स है 8 है डी 27 है यार\r\nउनमें देख लो यह टाइमिंग दे देगा बंधन योग\r\nसे टाइमिंग ले लो सर्वद वगैरह से ठीक है\r\nएक ये शॉर्टकट हो सकता है चलिए अब कुंडली\r\nशेयर करते\r\nहैं ठीक है जी अब यह पहली\r\nकुंडली हमने राव साहब की\r\nलिए राव साहब की किसलिए ली है कुंडली\r\nमैंने के जब हमने आचार्य किया\r\nथा तो रिसर्च क्लास हम चार पांच स्टूडेंट\r\nराव साहब के घर जाकर के हम वहां पर रिसर्च\r\nक्लास किया करते\r\nथे क्योंकि उनके पांव में तकलीफ हो गई थी\r\nऔर वह चल फिर नहीं पाते थे तो इसलिए वह घर\r\nपर ही लेटे रहते थे और हम वहां पर क्लास\r\nके टाइम पर वहां पहुंच जाते थे दो तीन बजे\r\nअपने पहुंच गए और शाम को 5 बजे तक वहीं पर\r\nउनसे पढ़ाई करते थे तो इसलिए मुझे वो याद\r\nथा कि भाई राव साहब के साथ वहां पर हम\r\nपढ़ाई करते\r\nथे ठीक है जी तो पहले तो हम\r\nदेखे के\r\nइनके\r\nबृहस्पति सर्प दृश कांड में\r\nहै और शनि और राहु आयुध दशका\r\nयहां पर हमें क्या मिला देखने को कि राहु\r\nछठे भाव में\r\nहै ठीक है यह गड़बड़ कर सकते\r\nहैं और एथ लॉर्ड है शुक्र वो लगन में\r\nबैठे मंगल के साथ है\r\nवीर द्रेश काण मैंने बता दिया नहीं तो\r\nइनका मैं द्रेश काण आपको दिखा भी सकता हूं\r\nआप अगर चाहे तो मैंने द्रेश कांड भी बनाया\r\nहै इनका अब यहां क्यों मैंने बनाया है ये\r\nइसमें पराशर द्रेश कान नहीं\r\nचलेगा पराशर द्रेश कांड इसमें इतना अच्छा\r\nफल नहीं\r\nदेता जो आपका वृति तराय या अयर दश कांड\r\nजिसको बोल देते हैं वो काम करता है\r\nतो वो मैंने दृश कांड यहां\r\nबनाया अब यहां\r\nदेखिए ये कन्फाइनमेंट इनकी हुई थी और भी\r\nहुई बाद में भी\r\nहुई रा शुक्र में\r\nराहु शुक्र में\r\nराहु अब यहां शुक्र देखो सिक्सथ लॉर्ड\r\nहै बवे के स्वामी से दृष्ट है फिर मंगल आ\r\nगया यहां पर ्र\r\nका अब जो दशा चल रही है उसी को तो चेक\r\nकरूंगा मैं और यह सिक्स लट भी द्रेश कान\r\nके और राहु थर्ड हाउस\r\nमें ठीक है थर्ड हाउस फिर से आपको\r\nपुरुषार्थ और वह सब उसका है तो\r\nयह रा शुक्र राहु में यह बीमार रहे 2000\r\nसे 2003 तक ये दशा चली थी उसमें ये बीमार\r\nरहे अब उसके बाद हम आते हैं एक और बड़े\r\nकेस\r\nपे यह केस है\r\nभाई कितनी इन्होंने जेल टर्म देखी है यह\r\nनेलसन मंडेला जी की कुंडली है और यह जेल\r\nमें 1962 में\r\nगए केतु की द\r\n1962 में केतु की दशा में गए और सूर्य की\r\nदशा में 1990 में निकल के आ 28 साल जेल\r\nमें रहे पूरी केतु की दशा फिर उसके बाद\r\nपूरी वीनस की दशा और फिर यह सूर्य की दशा\r\nमें तब यह बाहर\r\nआए अब य पहले जन्म कुंडली में देखता हूं\r\nइसकी जो इंटरेस्टिंग पॉइंट है बहुत ज्यादा\r\nवो है केतु छठे भाव\r\nमें शुक्र के साथ छठे के स्वामी के\r\nसाथ और इनके भी बुध और\r\nशनि जो आठवें भाव में दोनों बैठे हुए हैं\r\nयह सर्प दृश कांड में विपरीत फल देगा\r\nये ठीक है जी तो केतु अब चीज आप देखिए\r\nइसमें क्या देखा दिखा रहा हूं मैं आपको अब\r\nइसके बाद नवांश\r\nदेखो नवांश में\r\nभी केतु शुक्र फिर साथ\r\nमें ठीक\r\nहै उसके बाद आप देखो द्रेश कांड यह भी\r\nप्रवृत्ति तरा है द्रेश कांड पराशर द्रेश\r\nकांड नहीं है यहां भी केतु शुक्र एक साथ\r\nमंगल से\r\nदृष्ट यह नवांश है मंगल से\r\nदृष्ट फिर से पोजीशन खराब हो गई\r\nहै मैं यह बनाने में यह वर्ग नाइन\r\nहै चलो ठीक है जी तो यह\r\nके अब कहां से मैं इसको आपको देख के बता\r\nरहा\r\nहूं जन्म कुंडली में केतु\r\nशुक्र त्रिक भाव\r\nमें मंगल लगन को देख रहे\r\nहैं शुक्र के पीरियड में केतु के पीरियड\r\nसे शुरू हुए\r\nऔर सूर्य के पीरियड तक\r\nयह अब यहां से आप देखो शुक्र अब क्लासिक\r\nअगर वो लेता\r\nहूं तो शुक्र जो है अब देखो यह फोर्थ हाउस\r\nसे आठवे भाव का स्वामी\r\nहै घर से दूर घर की से बिछ हो गया सुख से\r\nदूर बहुत कष्ट में रहे हैं अय शुक्र का\r\nरोल कितना जबरदस्त है\r\nइस इस शुक्र ने ही केतु को के साथ मिलकर\r\nके रिगस इंप्रिजनमेंट\r\nकी इस कुंडली के लिए अगर आप शुक्र को\r\nदेखते हैं तो\r\nवह अच्छा ग्रह नहीं है अशुभ ग्रह\r\nहै और सेफ्टी देखो इनको प्रेसिडेंट बनाया\r\nबाद में सेफ्टी देखो के जन्म कुंडली में\r\nलग्नेश लगन को देख रहे\r\nहैं मंगल लगन को देख रहे\r\nहैं मंगल जब देखते हैं व शरीर को ताकत\r\nदेते हैं रिष्ट पुष्ट करते हैं और\r\nबृहस्पति देख रहे हैं तो 28 साल जेल में\r\nरहने के बाद बावजूद यह फिर भी बाहर आ गए\r\nऔर शादी भी की उसके बाद भाई\r\nसाहब 1918 की जन्म है 90 में बाहर आए थे\r\nये 72 साल की उम्र में बाहर आए थे ठीक है\r\nजी तो यह हमारा आज का था आज का मेरा जो\r\nमेन पर्पस\r\nथा वोह आपको द्रेश कांड से परिचय करा\r\nऔर कुछ क्लासिक रूल 6 आ 12\r\nके उनसे हम कुछ ज्ञान ले सकते\r\nहैं नहीं तो आप बीमारी वगैरह का जो ज्यादा\r\nचिंता लोगों को हो रही है वह आप अपने\r\nदूसरे मेथड से देखे इससे टाइमिंग देख सकते\r\nहैं सबसे अच्छी टाइमिंग आती है जेमिनी\r\nसे जेमिनी एस्ट्रोलॉजी से आती है कारकांश\r\nलगन से आती है फटाफट पता चल जाता है वह\r\nसरल थ्री में हमने दिया हुआ है पढ़ लेना\r\nपर बहुत से तो जमनी नहीं जानते तो मैं\r\nनहीं बोल रहा हूं तो जो जानते हैं वो सरल\r\nथ्री से पढ़ सकते हैं तो आज के लिए इतना\r\nही और फिर मिलेंगे नमस्कार"},{"topic":"बीमारी का समय कैसे जानें","text":"नमस्कार\r\nमित्रों आज एक बहुत ही महत्त्वपूर्ण\r\nविषय लेकर के आए\r\nहैं जो मैं अपनी सरल सेवन\r\nमें लिखा\r\nहै सरल सेवन आने वाली है करेक्शन चल रही\r\nहै एडिटिंग चल रही है\r\nतो उसमें\r\nहमने रोग का समय कब किस दशा में\r\nविमशोत्तरी दशा में रोग आएगा रोग दे सकता\r\nहै तो यह हम प्रत्यंतर तक चेक कर सकते\r\nहैं परंतु सबसे ज्यादा होता है महादशा फिर\r\nअंतर दशा और फिर प्रत्यंतर\r\nदशा इनमें हम इसको चेक करते\r\nहैं और इसका\r\nविश्लेषण हम डी छ शंशा से\r\nकरेंगे अब डी\r\nछ पराशर जी ने तो दिया नहीं\r\nहै जमिनी में दिया गया\r\nहै हमने इस पर पहले वीडियो बनाया\r\nथा\r\nकलक और उसको\r\nहमने डी 27 के साथ यूज किया था डी 27 में\r\nहमने कहा था भाई आपके शरीर का कौन सा\r\nअंग पीड़ित हो सकता है कहां पर बीमारी आ\r\nसकती है और कलक का हमने इस्तेमाल किया था\r\nके कारण और\r\nबीमारी अंदरूनी होगी या बाहर के कारण\r\nएक्सटर्नल इफेक्ट\r\nहोंगे तो यह हमने दो वीडियो बना आए\r\nथे उसमें यह था भाई बीमारी अब कब आती\r\nहै वो कैसे\r\nदेखें तो डी 27 भी बताता है दशाएं\r\nपरंतु टाइमिंग के\r\nलिए डी\r\nस का जांचना उसको देखना बहुत जरूरी\r\nहै और जो डी स है वो रोग का ही लोग कहते\r\nहैं सब सब जगह जो वार्ता होती है व छठे\r\nभाव का एक्सपेंशन है रोग का है और भी\r\nप्रॉब्लम दे सकता है छठे भाव से संबंधित\r\nऔर प्रॉब्लम भी यह दे सकता है पर आज का\r\nहमारा विषय रोग के लिए\r\nहै अब\r\nइसमें एक जो सबसे बड़ी ब्यूटी\r\nहै जेमिनी और पराशर\r\nकी और जिसको\r\nभगवान की कृपा से हनुमान जी की कृपा\r\nसे मैंने इन दोनों को समन्वय किया\r\nहै अपनी सरल\r\nसात के पराशर का चार्ट है वर्क चार्ट है\r\nउसको जमनी से देख सकते\r\nहैं जेमनी का दिया हुआ चार्ट है उसको\r\nपराशर से\r\nदेखे और एग्जामिन करें जमिनी\r\nसे रिजल्ट देखे पराशर की विमशोत्तरी दिशा\r\nदशा\r\nसे है ना भारतीय\r\nज्योतिष संपूर्ण\r\nहै चाहे जेमिनी सिस्टम हो चाहे पराशर\r\nसिस्टम\r\nहो दोनों बड़े विचार से किए गए हैं अब\r\nजमिनी पहले आया या पराशर पहले आया वो\r\nडिबेट तो हम कर चुके हैं कई दफे तो उस\r\nडिबेट में नहीं जा\r\nरहा अब इसके\r\nसिद्धांत कैसे देखना चाहिए क्योंकि डी स\r\nको टाइमिंग के लिए लिखा गया है कि भाई रोग\r\nकब हो सकता है किस दशा में हो सकता है तो\r\nसबसे पहले तो ये देखो जेमनी सिस्टम में कि\r\nएके कौन है\r\nआत्म\r\nकाक जेमिनी में आत्म कारक को आप लग्नेश की\r\nतरह बताया गया है कि वह आप\r\nहै लग्नेश\r\nहै तो पहले तो लग्नेश पर पीड़ा देख\r\nलो जमिनी\r\nएस्पेक्ट टाइमिंग में पराशर से\r\nकरूंगा यह ग्रेटनेस है\r\nतो पहले आप देखो कि भाई कितना रोग आ सकता\r\nहै या नहीं आ सकता\r\nहै तो सबसे पहले तो हम आत्म कारक को\r\nएग्जामिन करेंगे अब यह प्रिंसिपल सुन लो\r\nभाई फिर हम लगाएंगे जल्दी जल्दी अब और\r\nचार्टों\r\nप\r\nअगर वहां\r\nपर किसका संबंध आना चाहिए एक पर तीन ही\r\nप्लेनेट मैं पकडा\r\nराहु\r\nकेतु और ज्ञाती\r\nकारक\r\nजीके क्योंकि जमनी में जीके को\r\nविघे देने वाला बताया गया\r\nहै अगर एक एक\r\nका संबंध उनसे आ रहा\r\nहै तो इसका मतलब है कि वह आपको तकलीफ देगा\r\nइन तीनों में से राहु केतु शनि में\r\nसे राहु केतु जी के राहु केतु\r\nजीके अगर इसमें जीके का आ रहा और राहु\r\nकेतु का भी आ रहा\r\nहै तो फिर वह समस्या गंभीर होती\r\nहै दूसरा\r\nपॉइंट एक को जब हमने लग्नेश मान लिया\r\nहै जमनी सिस्टम में\r\nतो हम एके से छ आठ 12 जो त्रिक भाव है\r\nउनको\r\nदेखें कि किस पर पीड़ा आ रही\r\nहै छ प पीड़ा आ रही है रोक\r\nदेगा एक पीड़ा है दो पीड़ा है वो भी ध्यान\r\nरखना भाई हर एक पीड़ा में एके से अष्टम\r\nभाव पर पीड़ा आ रही\r\nहै और दो पीड़ा आ रही है तो वो तो बहुत ही\r\nलॉन्ग टर्म बीमारी\r\nदेगा छटा भाव बीमारी देगा रोग\r\nदेगा परंतु अगर एक ही संबंध है तो वह\r\nबीमारी ठीक भी हो\r\nजाएगी दो संबंध है तो वह भी बीमारी थोड़ी\r\nलंबे समय चलती है परंतु एर्थ हाउस की जो\r\nबीमारी है और यह दोनों संबंध आ रहे हो तो\r\nवो बहुत लंबी चलती\r\nइसके बाद 12 एक से बावा भाव वो आपके\r\nकन्फाइनमेंट का\r\nहै तो वहां पर अगर आपको पीड़ा आ रही है तो\r\nआप रोग के लिए जाएंगे रोग होगा तकलीफ होगी\r\nपर उससे निकल आे अगर छ आ ठीक है तो वहां\r\nसे आप निकल आ पहला टेस्ट तो हमारा एक से\r\nहोगा\r\nदूसरा टेस्ट हम करेंगे जीके\r\nसे के ज्ञाती\r\nकारक किन-किन\r\nप्लेनेट को किन-किन भाव को किन-किन\r\nप्लेनेट\r\nको प्रभावित करना\r\nहै तो वह\r\nप्लेनेट हमको अपनी दशा में रोग दुख तकलीफ\r\nदे सकते\r\nदूसरा टेस्ट ये\r\nहै तीसरा टेस्ट\r\nहै के कोई भी\r\nग्रह अगर अपनी स्वराशि में है उच्च राशि\r\nमें है स्पेशल पोजीशन में है तो वह ज्यादा\r\nतकलीफ दे सकता\r\nहै उसके साथ साथ अगर राहु केतु का भी आ\r\nजाए संबंध तो वो और ज्यादा तकलीफ दे देता\r\nहै तो यह हमारे बेसिक नियम हो\r\nगए आप इसको आराम से नोट कर\r\nलेना और जिनको जमनी की थोड़ी कम वो है तो\r\nवह मैं जीके बता देता हूं और ए के बता\r\nदेता एक के मतलब आत्म\r\nकारक वो ग्रह होता\r\nहै जिसके\r\nभोगा सर्वाधिक\r\nराशि को छोड़ दो किसी भी राशि में अगर\r\nउसके भोगा सर्वाधिक है तो वह एक हो जाता\r\nहै\r\nऔर इसी तरह से\r\nसात चर कारक हम लेते हैं आखिरी कारक होता\r\nहै जिसके सबसे कम भोगा होते हैं व डीके\r\nहोता\r\nहै डीके से तुरंत जिसके थोड़े से ज्यादा\r\nनेक्स्ट जो भोगा हो\r\nउसको जीके बोते तो हम जीके को पकड़ेंगे\r\nभाई मेनली तो तो यह निय नियम आपको दिख गए\r\nहैं ज्यादा उसके\r\nलिए अब सरल सेवन पर जब आती है किताब को तो\r\nउसमें देख सकते हैं सरल सेवन पर मैं पहले\r\nभी एक वीडियो बनाया\r\nथा तो आज के वीडियो में अब\r\nहम आपके साथ स्क्रीन शेयर करते हैं नियम\r\nआप याद रखिए उनको हम य लगाए तो हम स्क्रीन\r\nशेयर करते\r\nहैं यह\r\nभाई स्क्रीन मैंने शेयर की\r\nहै पहला जो बर्थ चार्ट है उसकी तो हमें\r\nकोई ज्यादा जरूरत है नहीं सिर्फ वोह आप\r\nटाइम वगैरह नोट कर लीजिए यह कमला नेहरू जी\r\nका चार्ट है और कमला नेहरू जी सीरियस\r\nबीमार रही\r\nथी\r\nऔर सैनिटोरियम वगैरा में गई और उसमें उनका\r\nदेहांत भी हो गया था ठीक है तो अब असली\r\nहमारा काम है इनकी डी सि\r\nदेख इसीलिए मैंने कारक डी सि में ही लगाए\r\nअब य देखिए पहला नियम हमारा था\r\nएक एके इनके मून है चंद\r\nठीक है चंद्रमा पर कोई खास पीड़ा नहीं आ\r\nरही\r\nहै सिर्फ एमके उनको दृष्ट\r\nकर अब हम आते हैं चंद्रमा से छटे\r\nभाव छटा भाव है लियो\r\nसिम सिंह पर\r\nमंगल और शु\r\nशुक्र की और सूर्य की दृष्टि आ\r\nरही लियो\r\nसि अब यह किनकी दृष्टि है\r\nभाई मंगल जी के\r\nहैं बज गया बंड\r\nभाई\r\nऔर पंचम भाव पर जीके की दृष्टि आ रही\r\nहै पंचम पंचम भाव नहीं मतलब लियो पर छठे\r\nभाव पर तो यह बीमारी\r\nदेगा अब हम चंद्रमा\r\nसे एक चंद्रमा है चंद्रमा से आठवे भाव को\r\nदेखते\r\nहैं चंद्रमा से आठवे भाव में मंगल है और\r\nशुक्र बैठे हुए स्व राशि\r\nमें शुक्र बहुत बली हो गए हैं स्व राशि\r\nमें डी सडी में स्वराशि\r\nउच्च राशि में कोई भी ग्रह हो वह ज्यादा\r\nपरेशानी दे सकता है अब य आप देखिए आठवे\r\nभाव पर मंगल और शुक्र बैठे हुए हैं जमनी\r\nदृष्टि किसकी है राहु\r\nकेतु और\r\nबृहस्पति तो राहु केतु का भी संबंध आ गया\r\nआठवे भाव पर जीके का भी संबंध आ गया और एक\r\nके चंद्रमा से आठवा भाव है वो खराब हो गया\r\nतो इसने बहुत लॉन्ग टर्म डिजीज दे\r\nदी अब यहां से बावा भाव देखा चंद्रमा से व\r\nशनि महाराज बैठे अपनी स्व राशि\r\nमें फिर गड़बड़ कर\r\nरही स्वराशि में बली हो जाता है बीमारी\r\nदेने के\r\nलिए लंग टर्म परंतु\r\nयहां पर आपको फिर से चंद्र मंगल और शुक्र\r\nकी दृष्टि आ रही है जयमिनी\r\nदृष्टि तो बावा भाव है हमारा\r\nहॉस्पिटलाइजेशन का यह भी भाई बैठ गए लंबे\r\nटाइम शनि है छोड़ता\r\nनहीं इनकी जो मृत्यु\r\nहुई\r\nवो फरवरी 2036 में\r\nउस समय जो विमशोत्तरी दशा\r\nथी अब वो इन्हीं प्लेनेट की\r\nथी ठीक है उस समय जो विमशोत्तरी दशा थी वो\r\nथी के जुपिटर में\r\nकेतु जो 1930 में शुरू हुई थी और इनको\r\nविदेश जाना पड़ गया था जुपिटर में केतु\r\nमें यह विदेश गई और उसी में उनकी डेथ\r\nअब आप\r\nदेखो जुपिटर\r\nकेतु केतु में क्या-क्या अंतरा आए\r\nप्रत्यंतर\r\nआए केतु में नेक्स्ट प्रत्र था शुक्र\r\nका शुक्र जीके के साथ\r\nहै उसके बाद सूर्य का प्रत्यंतर आया उसमें\r\nराहु केतु एस्पेट कर रहे\r\nहैं और सूर्य कौन है वो है आपके बी के\r\nहेल्प और से तो हेल्प मिली हॉस्पिटल वगैरह\r\nकी सूर्य के बाद\r\nचंद्रमा यहां थोड़ा सा कह सकते हैं कि भाई\r\nकुछ ठीक\r\nहुआ क्योंकि चंद्रमा एकही है पर पीड़ित\r\nज्यादा नहीं\r\nहै इसके बाद आई मंगल की प्रत्यंतर\r\nजुपिटर में केतु में\r\nमंगल अब मंगल की हालत देख लो भाई बुरी तरह\r\nचंद्रमा से एके से आठवे में बैठे हैं जीके\r\nके साथ है राहु केतु का एस्पेक्ट है\r\nजुपिटर तो पहले ही पीड़ित था जुपिटर केतु\r\nपीड़ित था इन दोनों से और उसमें जब मंगल\r\nआए ट वास द लास्ट नेल और वो मंगल की\r\nप्रत्यंतर में उनका देहांत हो\r\nगया तो यह हमारा पहला वो था अब एक चार्ट\r\nऔर लेते हैं मैं सिर्फ इसमें वह चार्ट ले\r\nरहा हूं जो आप जानते हैं अब यह राव साहब\r\nका चार्ट\r\nहै बट डिटेल नोट करनी है वो कर लीजिए इनके\r\nमें एक दो केस ही\r\nलूंगा\r\nये अब मैं इनके d6 पे आता हूं और कारक पे\r\nआता हूं वही नियम\r\nलगाएंगे अब यहां पहले इनका देखिए एक सूर्य\r\nहै एक के सूर्य है सूर्य प भाई क्या-क्या\r\nतकलीफ आ रही है राहु केतु की तकलीफ\r\nआ जीके हैं इनके\r\nमून मून की तकलीफ नहीं आरही\r\nराहु केतु की तकलीफ आ रही है एक के ऊपर तो\r\nहम कहेंगे हा भाई बीमारी हो सकती है वो तो\r\nहर के बहुतों के मिलेगा कि बीमारी तो हो\r\nसकती है अब यहां से छठा भाव देखो सूर्य से\r\nछठा भाव सिम\r\nहै सिमम पर\r\nआपको जी के देखो मून है वो एस्पेक्ट नहीं\r\nकर रहा है राहु केतु नहीं कर रहे\r\nहैं तो छोटी मोटी बीमारी ज्यादा नहीं है\r\nयहां से आठवा भाव देखो सूर्य से वो तुला\r\nहै तुला अपने ही स्वामी शुक्र से दृष्ट\r\nहै राहु केतु से दृष्ट नहीं है लंबी आयु\r\nदे रहा\r\nहै ज्यादा बीमारी नहीं दे रहा यहां से 12थ\r\nदेखो 12थ में दो शुभ ग्रह बैठे\r\nहुए अब इनकी आप देखिए विमशोत्तरी\r\nदशा इनकी जो विमशोत्तरी दशा\r\nहै वो अभी जो चल रही\r\nहै जी के भू है अभी इनकी विमो लाइव है\r\nबिल्कुल ठीक ठाक चल रहे हैं ठीक है तो\r\nइनको कोई उस तरह की बहुत लंबे पड़ने वाली\r\nबीमारी नहीं दिख रही है\r\nक्योंकि अष्टम भी ठीक है सूर्य पर भी कोई\r\nवो नहीं है तो चलते रहे ठीक है जी अब\r\nनेक्स्ट लेते\r\nहैं अब नेक्स्ट चार्ट हम लेते\r\nहैं यह भी आप डेट वगैरह नोट कर\r\nलीजिए यह भी जीवित की चार्ट\r\nहै अब इनका आप डी स और कारक देख ली\r\nपहले हम एके को देखेंगे भाई एके शुक्र\r\nहै अब यहां ड्रामा हो\r\nगया शुक्र उच्च के है तो बल मिल रहा है\r\nपरंतु दृष्ट किससे है शनि से जमनी चल रही\r\nहै शनि से दृष्ट है जो जी के है और कोई\r\nदृष्टि है नहीं तो भैया शरीर जो है एक के\r\nहै वो बीमारी से ग्रस्त हो सकता है अब\r\nयहां से छठ भाव\r\nदेखो एक से छटा फिर सिमम आ गया वहा एम के\r\nबैठे हुए हैं और किससे दृष्ट है चंद्रमा\r\nसे और मंगल से राहु केतु से नहीं है और\r\nजीके से नहीं\r\nहै एक से आठवे भाव को देखते\r\nहैं तो वहां पर तुला राशि है इनकी खुद की\r\nराशि है और वहां पर भी राहु केतु या जीके\r\nका एस्पेक्ट नहीं\r\nहै देखा भाई साहब अब जो बुध है शुक्र है\r\nउनसे 12वां\r\nभाव वह आपका एक्वेरियस कुंभ है कुंभ के\r\nस्वामी है\r\nशनि और लग्नेश यहां पर है डी सि के व शनि\r\nहै बुध है तो ये दोनों का जीके के\r\nसाथ इन्होंने स्थान परिवर्तन कर लिया\r\nहै ठीक है और जो 12वां भाव है वह अब राहु\r\nकेतु से दृष्ट\r\nहै शनि से स्थान परिवर्तन है तो यह बीमारी\r\nदेगा परंतु रिकवरी भी दे देगा लॉन्ग टर्म\r\nनहीं है बीमारी कही आएंगी परंतु निकल\r\nले तो यहां से यह तीनों केस मैंने अलग-अलग\r\nदेख कर के आपको दिखाए हैं अब इनका सुन\r\nलो इनका जो पहला एक्सीडेंट हुआ\r\nजबरदस्त वो\r\nएक्सीडेंट\r\n1900 72 में\r\nहुआ ठीक है\r\nमें और एक्सीडेंट हुआ था वीनस सूर्य और\r\nकेतु की\r\nदशा वीनस तो हमने देख लिया भैया पीड़ित है\r\nय तो देगा ही वीनस तो जब भी अंतर दशा दशा\r\nआएगी\r\nयह परेशानियां\r\nदेगा अब सूर्य थे व राहु केतु एक्सेस में\r\nहै परंतु यहां शनि की दृष्टि नहीं\r\nतो यह रिकवर कर गए यह एक्सीडेंट हुआ\r\nथा शुक्र सूर्य केतु केतु भी सूर्य एक साथ\r\nहै दूसरा जो मैं बताना चाहता\r\nहूं\r\nके इनका हार्ट ऑपरेशन\r\nहुआ अक्टूबर\r\n2013 उस समय दशा थी राहु राहु\r\nपरंतु वो भी डबल एफ्लिक्शन में नहीं है तो\r\nसक्सेसफुल हो गया प्रॉब्लम थोड़ी कम हो\r\nगई अब उसके बाद अब जो दशा चल रही है लोग\r\nकहेंगे भाई जीवित है कैसे अब जो दशा चल\r\nरही है वह राहु में शुक्र की चल\r\nरही और जब से राहु में शुक्र की दशा\r\nप्रारंभ\r\nहुई उसने तकलीफ देनी शुरू\r\nऔर यह चलेगी तीन साल की दशा है बीच-बीच\r\nमें जो प्रत्यंतर\r\nआएंगे वह रिलीफ देते रहेंगे अभी जैसे राहु\r\nमें\r\nशुक्र शुक्र में चंद्रमा\r\nचल चंद्रमा राहु केतु एक्सेस में है तो\r\nतकलीफ दे रहा\r\nहै सूर्य का प्रत्यंतर था वो भी तकलीफ दी\r\nअब दिसंबर में मंगल का प्र तर आ जाएगा अब\r\nमंगल पीड़ित नहीं है तो उस प्रत्यंतर में\r\nकुछ ना कुछ रिलीफ मिलना\r\nचाहिए परंतु वीनस दशा तो चालू रहेगी पूरा\r\nनहीं\r\nमिलेगा जब वीनस दशा समाप्त होगी राहु में\r\nवीनस उसके बाद राहु में सूर्य आ जाएंगे तो\r\nभी थोड़ी बहुत प्रॉब्लम होगी राहु में\r\nचंद्रमा होंगे तो भी प्रॉब्लम\r\nहो और जो आखिर है राहु में मंगल छिद्र दशा\r\nयह पीड़ित नहीं\r\nहै तो यहां लगता है कि थोड़ा रिलीफ वहां\r\nतक मिलेगा परंतु शुक्र में तो राहु में\r\nशुक्र में पीड़ा\r\nरहेगी तो यह हमारा हमारा था इन कुंडलियों\r\nका तो यह एक\r\nमिक्सचर पराशर और\r\nजमिनी दोनों को मिलाकर\r\nके किस तरह से हम देख सकते ये शॉर्ट मेथड\r\nहै कि हम विमशोत्तरी को भी जेमिनी मेथड से\r\nअप्लाई कर सकते हैं जैसे मैं हमेशा बोलता\r\nहूं कि मेरी कुंडली\r\nमें द्वितीय चंद्रमा\r\nहै वो नीच के होकर के छठे भाव में बैठे\r\nहैं पूर्ण अर्गला दे रहे हैं तो चंद्रमा\r\nकी दशा धन के लिए अच्छी होनी चाहिए देखिए\r\nदशा विमशोत्तरी\r\nकी योग जेमिनी का तो यह चीज\r\nही एक नया आयाम\r\nहै हमारे भारतीय ज्योतिष में और जो हमने\r\nअपनी सरल सेवन में देने की कोशिश की है\r\nबहुत से चार्टों में दिया\r\nहै तो वह\r\nएक क्या कहते हैं बहुत अच्छा विश्लेषण या\r\nअप्रोच होनी चाहिए\r\nपरंतु जब\r\nआप रूल देख रहे हैं जमनी लगेगी\r\nउसकी दशा विमशोत्तरी लगेगी और जमनी से जो\r\nजो पीड़ित है उस विमो में उसको आप देख\r\nसकते हैं है ना विमशोत्तरी दशा का कितना\r\nसुंदर\r\nविश्लेषण चलिए और शेयर करते रहेंगे आपसे\r\nमुलाकात होती रहेगी तो आपका बहुत-बहुत\r\nनमस्कार धन्यवाद"},{"topic":"माता-पिता एवं पूर्वजों ईश्वर का आशीर्वाद","text":"नमस्कार\r\nमित्रों आप सबको दीपावली के पावन अवसर पर\r\nबहुत-बहुत\r\nशुभकामनाएं भगवान की\r\nकृपा ईश्वर की\r\nकृपा आपके पूर्वजों की कृपा आप पर बनी\r\nरहे मित्रों यही हम प्रार्थना भगवान से\r\nकरते हैं\r\nऔर उनका आशीर्वाद मांगते\r\nहैं अब कितना आशीर्वाद\r\nहमको प्राप्त है प्रारब्ध\r\nने हमको कितना आशीर्वाद दिया\r\nहै और\r\nहम उनके प्रति अपना कितना लगाव रखते\r\nहैं क्योंकि यह\r\nसृष्टि हमारा हिंदू धर्म सनातन धर्म यही\r\nकहता\r\nहै कि यह सृष्टि भगवान की बनाई हुई\r\nहै और हमारे सबसे पहले पूर्वज वही\r\nहै तो आज इसी विषय को लेकर\r\nके आज हम ज्योतिष की उससे चर्चा\r\nकरेंगे कि ज्योतिष\r\nमें हम इस कृपा को कैसे देखे\r\nसबसे पहला\r\nचार्ट हम वर्गों से देखेंगे डिटेल में जा\r\nकर\r\nके सबसे पहला\r\nवर्ग जो पराशर जी ने दिया है वह है डी\r\nबारा\r\nद्वादशा और उस पर कहा है यह हमारे\r\nमाता-पिता का चार्ट है अभ य बहुत सी दफे\r\nबड़ी दुविधा होती है बहुत से स्टूडेंट्स\r\nको हमको भी होती\r\nथी के भाई एक ही व्यक्ति\r\nके कई संतान बीवी रम के नौ\r\nसंतान हम भी आठ भाई बहन है\r\nभाई तो क्या सबका डी वारा एक जैसा है नहीं\r\nहै परंतु माता-पिता तो सेम\r\nहै इस पर कितनी कृपा\r\nहै कितना आशीर्वाद\r\nहै वो डी बारा बताता\r\nहै दूसरा\r\nचार्ट वो आप अगर चाहे तो हम जमनी\r\nएस्ट्रोलॉजी से ले सकते\r\nहैं दूसरा चार्ट हमारा डी फाइ\r\nहै जो जेमिनी एस्ट्रोलॉजी का\r\nहै कहने को पराशर में भी\r\nडी नान है धर्म के\r\nलिए और डी फ जो है पर डी ना जो है वह और\r\nभी चीजें दिखाता है धर्म है विवाह है पूरक\r\nचार्ट कहते\r\nहैं बीज कुंडली बोलते हैं बहुत बहुत नाम\r\nहै\r\nउसके तो जो भगवान का आशीर्वाद और भ किस\r\nभगवान की भक्ति की\r\nजाए क्या किया\r\nजाए दान करें पुण्य कर मंदिर\r\nजाए क्या चीज करें कथा करें भजन करें\r\nसत्संग करें और किसका करे यह डी फ से देखा\r\nजाता\r\nहै पराशर जी ने एक और चार्ट दिया\r\nहै जिसको कहा है डी\r\n45 अक्ष\r\nवेदांश डी 45 चार्ट भी जो\r\nहै उससे पराशर जी ने कहा है सारी चीज देखी\r\nजा सकती है ऑल एस्पेक्ट ऑफ लाइफ सारी\r\nचीज परंतु उससे हमने जो खास मीनिंग निकाला\r\nहै वो\r\nआपके\r\nपूर्वजों और ईश्वर की कृपा है या नहीं\r\nहै यह\r\nविषय मैंने जो आने वाली नई पुस्तक\r\nहै सरल\r\nसात उसमें मैंने यह कवर किया\r\nहै और उसमें\r\nजो पद्धति दी\r\nहै डी 45 की वह पराशर से थोड़ी अलग दी पर\r\nआज हम इस अपने टॉक में हम पराशर पद्धति का\r\nही जिक्र करेंगे और सिर्फ एक रूल ही अभी\r\nऔर वो रूल ही बिल्कुल अप्लाई होता है डी\r\n12 पर भी होता है डी 45 पर भी तो हम पराशर\r\nचार्ट की बात कर रहे\r\nहैं अब कहने को डी बा में सब कहते भाई\r\nमाता के लिए चंद्रमा\r\nदेखो पिता के लिए सूर्य\r\nदेखो पिता के लिए नाइ हाउस देखो माता के\r\nलिए चतुर्थ भाव देखो तो यह भाव जो देखते\r\nहैं\r\nयह देखते हैं उनकी वेल बीइंग के\r\nलिए और सूर्य और चंद्रमा जो देखते हैं यह\r\nउनके कारक\r\nहै तो उनकी ब्यूटी के लिए\r\nदेखते ठीक\r\nहै\r\nहम ब्लेसिंग्स के\r\nलिए उनका धर्म देखते हैं डी बा का धर्म\r\nदेखते\r\nहैं और धर्म के भाव होते हैं एक\r\nपाचन प्रथम भाव पहला भाव पंचम भाव नवम भाव\r\nइसमें पंचम भाव कृपा के लिए पूर्व पुण्य\r\nको भी दर्शाता है तो उसको भी हम थोड़ा सा\r\nबल\r\nदेंगे अगर मैं धर्म के भाव से का\r\nलॉस धर्म का\r\nहानि अगर वो देखता हूं\r\nतो वो भाव बनते हैं चा आ\r\n12 अब देखो यहां पर बहुत से क्वेश्चन हो\r\nजाएंगे कि धर्म का भाव तो एक पान\r\nहै\r\nऔर मोक्ष का भाव चा आ है तो क्या धर्म के\r\nलॉस के बाद मोक्ष मिलता\r\nहै\r\nनहीं धर्म से क्या मतलब नाइंथ हाउस क्या\r\nमतलब है मेन\r\nहाउस के आप अपने कर्तव्यों का पालन कैसे\r\nकरते\r\nहैं और चार आठ भारा समाधि का\r\nहै आठवा भाव जो नवं से 12थ है वो समाधि का\r\nहै जब आप समाधि में होते हैं धर्म का\r\nनिर्वाह करते हैं तब जाकर के आप मोक्ष की\r\nतरफ बढ़ते हैं बवे\r\nभाव तो तो बीच में ये भी आता है नाइंथ\r\nहाउस आता है\r\nर तो हमारा जो प्रिंसिपल\r\nहै के डी बारा में हम\r\nदेखेंगे माता-पिता का आशीर्वाद\r\nशायद ही\r\nऐसा कोई चार्ट मिलेगा जिसमें हमें मां बाप\r\nका आशीर्वाद ना दिख रहा हो कम दिख रहा हो\r\nज्यादा दिख रहा हो बहुत सी जगह पर जीरो भी\r\nदिखता है\r\nमां बाप रखना ही नहीं चाहते तो मां बाप का\r\nआशीर्वाद क्या है आपका भरण पोषण\r\nकरना आपको जीवन\r\nमें जो भी सुख सुविधाएं हैं बचपन की वह\r\nआपको\r\nदे और आपको आगे बढ़ा के लायक\r\nबनाए यह माता-पिता\r\nका रोल है आपको अच्छे संस्कार\r\nदे परंतु बा\r\nसे हमने जो मेथड दिया है वह उसमें हम देख\r\nसकते\r\nहैं\r\nभौतिक चीजें भौतिक सुख कितना दिया\r\nहै तो यह डी बा से हम एक पान का संबंध\r\nदेखेंगे इसी तरह से आपके पूर्वज और सबसे\r\nज्यादा बड़े पूर्वज भगवान\r\nउसको वहां तक हम एक्सटेंड कर सकते हैं\r\nआपके\r\nपूर्वज तो उनका कितना आशीर्वाद है\r\nआपके और डी 45 का आशीर्वाद\r\nहोना अत्यंत आवश्यक है यह\r\nआपको गलत परिस्थितियों में आप किसी कठिनाई\r\nमें फस\r\nजाए और वह आशीर्वाद आपके पास है तो आप\r\nकठिनाई से निकल के बाहर आ\r\nजाएंगे अगर डी 45 का एक पान का कनेक्शन\r\nनहीं\r\nहै तो आपको आशीर्वाद नहीं है या लैक करता\r\nहै डी 45 में डी 12 में अगर कोई ग्रह उच्च\r\nराशि में होता\r\nहै वह अति सुंदर है बहुत हेल्पफुल है\r\nऔर यदि वह उच्च राशि का ग्रह एक पाचन का\r\nभी स्वामी हो\r\nजाए तब सोने में\r\nसोहागा इसका विपरीत भी\r\nहोगा अगर कोई\r\nग्रह डी 45 में नीच राशि में हो खास तौर\r\nसे डी 45 बोल रहा हूं डी 12 में तो हो\r\nसकता है पर नीच भंग भी हो जाएगा\r\nडी 45 में अगर कोई ग्रह नीच का\r\nहै\r\nऔर उसकी\r\nदशा या आठवे भाव से रिलेटेड\r\nदशा तब वह आपके पूर्वजों का ईश्वर का\r\nआशीर्वाद को खत्म कर\r\nदेता आठवा भाव ना से बावा हो\r\nगया और कोई नीच का ग्रह\r\nहो और वो अगर\r\nएक पान का स्वामी नीच का है नीच राशि में\r\nहै तब और ज्यादा खराब हो जाता\r\nहै तो इस तरह से हम इसको देखेंगे और जहां\r\nतक राहु केतु का संबंध है वह भी आएगा भाई\r\nएक में भी आएगा पाच में भी आएगा न में भी\r\nआएगा उनके साथ भी आएंगे उस एक्सिस पर भी\r\nआएंगे तो वो देखना पड़ेगा कि वो जो राहु\r\nकेतु त्रिकोण भाव में आ रहे हैं उनका\r\nडिस्पोजिटर क्या करर है वो किस स्थिति में\r\nक्योंकि व उसकी तरह से बिहेव करते हैं नाथ\r\nलड हो जाता है फर और उसी नाइंथ लड की तरह\r\nसे काम भी करता है खुद भी नाइ में बैठता\r\nहै तो यह हमारा आज का टॉपिक क्योंकि\r\nदिवाली के शुभ महूरत पर हम सब मां का\r\nआशीर्वाद मांगते हैं लक्ष्मी का राम का\r\nआशीर्वाद मांगते हैं धन धान्य का आशीर्वाद\r\nमांगते हैं अपने अगला एक साल सुंदर जाए\r\nउसका आशीर्वाद मांगते हैं तो हमने सोचा कि\r\nआज यही एक टॉपिक थोड़ा सा आपके साथ करते\r\nहैं कि भाई कितना आशीर्वाद है सब पर\r\nमिलेगा\r\nभाई कितना बलि है बात वो है\r\nअब जब यह हमने त्रिकोण ले लिए तीन इसमें\r\nसे कम से कम\r\nदो दो त्रिकोण\r\nस्वामी आपस में संबंध\r\nबनाए या दो त्रिकोण के भाव से संबंध\r\nबना एक त्रिकोण का स्वामी उसी त्रिकोण से\r\nसंबंध बना रहा वो भी एक त्रिकोण संबंध\r\nमाना\r\nजाएगा दूसरा त्रिकोण का स्वामी किसी और\r\nत्रिकोण से संबंध बना रहा है वो भी एक\r\nसंबंध माना जाएगा तो अगर दो त्रिकोण संबंध\r\nआते हैं बशर्ते नीच का ग्रह\r\nनहीं नीच राशि में ना हो तब आपको वह\r\nआशीर्वाद प्राप्त होता है तो यह हमारे आज\r\nके नियम अब हम कुछ कुंडलिया देखते हैं\r\nऔर यह पहली कुंडली\r\nहमने बहुत अच्छा आशीर्वाद\r\nभगवान\r\nका पूर्वजों का मिल रहा है उसके लिए राम\r\nकृष्ण परमहंस जी की कुंडली ली\r\nहै यह हमारी कुंडली\r\nहै इसमें तो हम बात वार्तालाप कर नहीं रहे\r\nहैं यहवा आ गया एक\r\nसेकंड डी वन लेता हूं मैं हा ये बर्थ\r\nचार्ट है तो इसमें तो हम कुछ ज्यादा ले\r\nनहीं रहे परंतु बहुत अच्छे कॉमिनेशन है य\r\nभाई आप देखो चार छ सात आठ के लॉड इकट्ठे\r\nलगन में बैठे हुए हैं क्या सुंदर\r\nचीज शनि लग्नेश उच्च राशि में है\r\nमंगल दशमेश फिर उच्च राशि में है योग कारक\r\nशुक्र फिर उच्च राशि में है तो ये इसकी\r\nबात नहीं पर हम अपने टॉपिक पर आते हैं डी\r\nबा डी बा में हमने बोला था\r\nत्रिकोण त्रिकोण है न सा\r\nमरकरी शुक्र और\r\nशनि कोई भी ग्रह नीच राशि में नहीं\r\nहै मरकरी दशम भाव को दृष्ट कर रहे\r\nहैं शुक्र लगन में है दो त्रिकोणीय मिल\r\nरहे\r\nहैं तो एवरेज से ऊपर है माता-पिता का\r\nआशीर्वाद परंतु धन मन नहीं दिख रहा है\r\nउसको छोड़ो हम अपनी बात पर आते हैं धन\r\nनहीं दिख रहा है पर अच्छी बात यह है कि\r\nकोई भी\r\nग्रह नीच राशि में नहीं\r\nहै इसके बाद हम लेंगे इनका डी\r\n45 जो हमारा असली चार्ट\r\nहै अब यहां\r\nदेखो डी 45 चार आ\r\n12 ठीक है लगन से शुरू करते\r\nहैं आठ\r\nमंगल मंगल\r\nमहाराज तीसरे भाव में उच्च राशि में\r\nविराजमान\r\nहै\r\nऔर नवम भाव को दृष्ट कर\r\nरहे\r\nपंचमेश अपनी राशि\r\nको गवे भाव से पंचमेश पंचम भाव को दृष्ट\r\nकर रहे हैं देख रहे हैं वो भी बली हो\r\nग उसके बाद नवम\r\nभाव नवम भाव के स्वामी है\r\nचंद्रमा चंद्रमा\r\nफिर अपनी उच्च राशि में विराजमान है\r\nऔर बृहस्पति से दृष्ट है जो प पंचमेश\r\nहै इसको मैं कहूंगा ईश्वर की पूरी पूरी\r\nब्लेसिंग इसलिए ये एग्जांपल ली है कि\r\nजिसमें हम दिखाए कि पूर्ण ब्लेसिंग\r\nहै हम अगर चार आठ बारे की बात करते हैं तो\r\nवो\r\nबुध शुक्र और शनि है\r\nबुध शुक्र\r\nशनि केवल\r\nशनि बृहस्पति को एस्पेक्ट कर\r\nरहे बाकी उनका प्रभाव और कहीं नहीं है अब\r\nहम आते दूसरे\r\nचार्ट एक चार्ट है आप लोग जानते हैं जाना\r\nमाना चार्ट\r\nहै अब यह बर्थ चार्ट\r\nहै इसमें आप देखो\r\nबुध शुक्र\r\nबृहस्पति तीन शुभ\r\nग्रह लगन में बैठे हुए\r\nहैं\r\nलग्नेश बवे भाव\r\nमें नीच राशि के मंगल के साथ\r\nहैं दूसरे भाव में केतु विराजमान\r\nहै तो तो एक ये बहुत अब याद नहीं किसकी\r\nकिस पुस्तक में है ये मैंने अपनी सरल फ\r\nमें भी यह दिया\r\nहै के तीन शुभ ग्रह यदि केंद्र में\r\nहो और दो और 11 में यदि पाप ग्रह हो केवल\r\nपाप संबंध हो तो वह व्यक्ति\r\nनिर्धन निर्धन किसी भी तरह से हो जाता है\r\nइनम दूसरे हाउस ने विनता दी है धन संचय\r\nवाणी परिवार\r\nकुटुंब हमारा य टॉपिक नहीं था तो हम इस\r\nचार्ट के अब आगे के चार्ट देखते हैं अब\r\nइसका हम डी बा देखते\r\nहैं डी बा\r\nमें\r\nपासस मीन कर्क और वृश्चिक\r\nयह एक पाचन\r\nमें लगन में लग्नेश खुद विराजमान\r\nहै पंचमेश के साथ\r\nहै ठीक है जी तो हमें यह संबंध दो संबंध\r\nमिल गए मां बाप का आशीर्वाद है मां-बाप\r\nसाथ है\r\nमेरे जो नवमेश है\r\nवह दशम भाव में बैठे हुए हैं और उस पर\r\nदृष्टि नहीं\r\nहै ठीक है जी तो मां-बाप का साथ मेरे है\r\nअब मैं भगवान का साथ देखता\r\nहूं यह इनका डी 45 आ\r\nगया अब यहां\r\nपर त्रिक\r\nमें धनु मेश और\r\nसिंह पहले तो धनु को\r\nदेखो धनु\r\nमें सूर्य विराजमान\r\nहै धनु में सूर्य विराजमान\r\nहै जो नवमेश\r\nहै बृहस्पति\r\nजो लग्नेश है वह पंचम भाव को देख रहे\r\nहैं और जो नवमेश है वह लगन में\r\nहै तो यहां भी दो संबंध मुझे मिल रहे\r\nहैं तकलीफ कहां हो रही\r\nहै चार आ 12\r\nलग्नेश चतुर्थेश भी\r\nहै नवमेश\r\nजो सूर्य है उनके साथ अष्टमेश विराजमान\r\nहै चार आ\r\n12 और\r\nजो द्वादश है मंगल वह अपने आराम से बैठे\r\nहैं अपनी राशि\r\nमें नवम भाव को देखें तो वो राहु केतु\r\nएक्सेस में भी है तो नवम भाव सबसे ज्यादा\r\nखराब हुआ पड़ा\r\nहै हमने एक और चीज कही थी कि अष्टमेश\r\nजो है वो सबसे अष्टम भाव अष्टमेश जी सबसे\r\nज्यादा आपके आशीर्वाद का को खत्म करने\r\nवाला होता है और अष्टम से अष्टम\r\nअष्टम में जो ग्रह है शनि है\r\nऔर आपके शुक्र विराजमान\r\nऔर जो अष्टमेश है वो चंद्रमा\r\nहै तो शनि रिपीट हो रहे हैं चंद्रमा रिपीट\r\nहो\r\nर तो शनि और\r\nचंद्रमा यह लगता है कि भाग्य की समाप्ति\r\nआशीर्वाद की समाप्ति हो सकती\r\nहै अभी इनकी शनि की दशा शुरू हुई है शनि\r\nमें शनि चल रहा है और यह तीन साल रहेगा\r\nशनि में शनि 27 तक तो शनि में शनि में\r\nचंद्रमा थोड़ा सा झटका दे सकता है चलिए अब\r\nएक चार्ट और\r\nहै यहां पर ये बड डाटा आप नोट करने के लिए\r\nमैंने यह लगाया है बड डाटा आप नोट कर\r\nलीजिए कोई सेलियन बढ़िया पॉइंट जो दिखते\r\nहैं वह दिख रहे हैं कि देखिए शनि भी उच्च\r\nराशि में\r\nहै चंद्रमा स्वयं की राशि में है बृहस्पति\r\nलग्नेश होकर के लगन को दृष्ट कर रहे\r\nहैं ठीक है कुंडली तो वैसे ठीक ठाक है पर\r\nकहां पर भगवान का आशीर्वाद कम हो रहा है\r\nयह देखते हैं इनका\r\nमें डी 45 लूगा सीधा डी 12 भी है आप देख\r\nसकते\r\nहैं इनके ऊपर माता-पिता का आशीर्वाद था\r\nतीन सा 11 बुध पंचम भाव को देख रहे\r\nहैं ठीक है परंतु शनि जो है जो नवमेश है\r\nवो अष्टम भाव में चले\r\nशुक्र वो\r\nभी दशम भाव में\r\nचले एक बात से कई रिलेशन नहीं बना\r\nरहे शनि से दृष्ट है यह थोड़ा सा संबंध\r\nअच्छा भी है बुरा भी है\r\nमिक्स परंतु शनि इसमें गड़बड़ कर\r\nरहे शनि नवमेश हो कर के अष्टम में बैठे\r\nहैं और चंद्रमा भी तीसरे भाव में विराजमान\r\nहै तो डी 45 में आठवा और तीवा ये भाव\r\nथोड़े से गड़बड़ वाले हो जाते\r\nहैं अब इनका डी 45 देख लो डी 45\r\nमें\r\nलग्नेश शनि नीच राशि में है\r\nखुद ही लग्नेश नीच राशि\r\nमें यह सबसे बड़ी गड़बड़\r\nहै और\r\nचंद्रमा वह अष्टम भाव में है चार\r\nआठ शनि यहां पर द्वादश\r\nभी एक अच्छा योग मिल रहा है कि कितने दिन\r\nतक मेरे को वो रहेगा कि लग्नेश शनि पंचम\r\nभाव को देख रहे\r\nहैं और पंचमेश लगन\r\nमें पर पंचमेश अष्टमेश भी है जो उनकी भूल\r\nत्रिकोण राशि\r\nहै अब इनके\r\nऊपर परिवारवाद में\r\nही झगड़ा\r\nहुआ इनके पुत्र ने\r\nही पुलिस बुला कर के इनको अरेस्ट करा\r\nदिया और इनको जेल भिजवा\r\nदिया 98 में शायद यह वारदात हुई थी इनकी\r\nअच्छी खासी उमर में देखो भाई 74 साल की\r\nउम्र\r\nमें इनको जेल बिचवा\r\nदिया दशा थी चंद्रमा में शनि तो यह लास्ट\r\nकी कुंडली ने ली है कि कब भगवान का\r\nआशीर्वाद\r\nसमाप्त हो जाता है वो डी 45 से आता\r\nहै ठीक है जी तो यह\r\nहमने तीन चार्ट आज\r\nदेखे मेरे को उम्मीद है के डी\r\n45 हमारा अच्छा ही\r\nहोगा और भगवान का आशीर्वाद हमारे ऊपर बना\r\nरहे\r\nसब दशाओं में बना रहे हम जब तक भगवान हमें\r\nय पृथ्वी पर रख रहे हैं तब तक अपने\r\nआशीर्वाद से\r\nरख क्योंकि उनके आशीर्वाद के बगैर तो कोई\r\nरह ही नहीं\r\nसकता अब जब आशीर्वाद\r\nकम हो जाता है तब हम कष्ट में आ जाते हैं\r\nऔर इसीलिए हम भगवान की जय जयकार करते हैं\r\nउनका आशीर्वाद मांगते हैं\r\nऔर यह कहना चाहिए के तकलीफों विपत्तियों\r\nआप दूर रहो क्योंकि भगवान मेरे साथ\r\nहै सिर्फ ज्योतिषी नहीं हम अपने आचरण से\r\nभी भगवान को साथ में रख सकते\r\nहैं तो ये आज का हमारा\r\nभाई प्रोग्राम रहा आपको दोबारा से बहुत\r\nबहुत शुभकामनाएं धनतेरस से शुरू होकर भाई\r\nदूज तक की पांचों दिन की पांचों त्यौहारों\r\nकी आपको बहुत-बहुत\r\nशुभकामनाएं और हम सब भगवान की पूजा करें\r\nउसको याद करें और अपने मन से शांत रहे\r\nबहुत-बहुत धन्यवाद थैंक यू"},{"topic":"मीठी या कड़वी अपनी सासूमां को जानें","text":"नमस्कार\r\nमित्रों आज कई दिनों के\r\nबाद मैं फिर से आपके सामने आया हूं और एक\r\nबहुत ही\r\nरोचक विषय लेकर\r\nके आज का हमारा विषय\r\nहै कि आपके मदर इन\r\nलॉ सास जी को कैसे\r\nदेख उनसे सहायता\r\nमिलेगी कैसा उनका व्यवहार रहेगा क्या\r\nवह उनके\r\nसाथ क्या कोई धन योग बनता है राज योग बनता\r\nहै क्या उनसे धन की प्राप्ति होगी या\r\nआशीर्वाद की प्राप्ति\r\nहोगी या आशीर्वाद नहीं\r\nमिलेगा यह सब बहुत सोचने की\r\nवाली और\r\nज्यादातर लोग चिंतित रहते\r\nहैं हमने शायद पहले एक बनाया था के विवाह\r\nके तुरंत बाद का\r\nअनुभव उसके साथ साथ यह कड़ी भी हम जोड़\r\nसकते\r\nहैं और यह देखने के लिए हम विवाह की\r\nकुंडली का प्रयोग करते\r\nहैं विवाह की कुंडली नवांश\r\nहै नवांश केवल विवाह का नहीं है य शाश्वत\r\nचार्ट है बहुत ज्यादा इसके इस्तेमाल है\r\nबहुत यूज है तो नवाज के बगैर कहते हैं कि\r\nप्रेडिक्शन नहीं करनी\r\nचाहिए अब नवांश में जो लगन है वह आपका\r\nविवाह की लगन\r\nहै\r\nऔर जो सप्तम भाव है विवाह का नवांश का वो\r\nआपका विवाह\r\nहै तो जो सप्तमेश है\r\nवोह\r\nआपके पति या पत्नी का भाव\r\nहै उसके बारे में हम वहां से विश्लेषण\r\nकरते हैं उसके स्वामी से करते\r\nहैं अब अगर मैं नवाज को विवाह का चार्ट\r\nलेता हूं और पार्टनर आपका जो है वह सप्तम\r\nभाव\r\nहै तो एक हम मोटा मटी दशम भाव\r\nको अपने\r\nपार्टनर की मां मान\r\nतो आपके चार्ट में जो दशम भाव\r\nहै वह आपको बहुत ज्यादा कुछ आपकी मदर इन\r\nलॉ सासु मां के बारे में बता\r\nदेगा अब हमारा प्रिंसिपल हमेशा यह है भाव\r\nऔर\r\nभावेश अभ य मां का उसका कारक कौन सा लू\r\nसासु मां\r\nका वो नहीं मैं देख रहा हूं हम भाव और\r\nआवेश पर ही केंद्र\r\nकरेंगे अब दशम भाव जो\r\nहै वो आपकी मदर इन लॉ सासू का हो\r\nगया अब वह कैसे हैं वो दशम भाव का संबंध\r\nबताएगा और उनका आचरण व्यवहार कैसा\r\nरहेगा वो दशमेश बताएगा\r\nदशमेश के क्या संबंध आ रहे\r\nहैं और जो आपके पति या पत्नी है वह सेवंथ\r\nलर्ड उसका कर्म कैसे कार्य करेंगे उनका\r\nनेचर उनका बिहेवियर क्या रहेगा वह सप्तमेश\r\nबताए अ सप्तम भाव खराब है तो मैरिज खराब\r\nहो जाती है ऐसा बोलते\r\nहैं ठीक है जी अब सप्तम भाव दशम भाव को\r\nलेकर\r\nके आप वहां से\r\nकेंद्र त्रिकोण का संबंध देख सकते हैं कि\r\nभाई राजयोग है या\r\nनहीं कि सास जी राजयोग में है या नहीं है\r\nया कोई धन योग बन रहा है दशम\r\nभाव तो वह आपको\r\nके हमारी मदर इन ल के पास धन तो\r\nहोगा अब कैसा धन धन तो लक्ष्मी तो आठ तरह\r\nकी लिखी गई है अब इसको सिर्फ यह नहीं रुपए\r\nपैसे या गोल्ड ज्वेलरी में ही नहीं गिन\r\nसकते एक और इंपॉर्टेंट पॉइंट होता\r\nहै कि क्या हम\r\nपर सासू मां का आशीर्वाद होगा क्या वह\r\nबहुत बड़ी\r\nबात अगर उनका आशीर्वाद हमारे ऊपर है दिल\r\nसे आशीर्वाद\r\nतो आपको ससुराल में क्या वैसे ही आपका\r\nजीवन सफल हो गया\r\nदूसरा क्या होता\r\nहै शनि\r\nमहाराज अच्छा हां मैं वो बता रहा था\r\nआशीर्वाद की बात आशीर्वाद देखते\r\nहैं यह मैं लिख रहा हूं अपनी किताब में\r\nमैंने और लिखा भी\r\nहै यह भगवान का आशीर्वाद\r\nपंचमेश और नवमेश\r\nइन दोनों का आपस में संबंध आ जाए या\r\nएक्सचेंज में आ जाए परिवर्तन योग बन\r\nजाए तो हम दशम भाव से ले रहे हैं पंचमेश\r\nनवमेश अगर केंद्र से भी नहीं\r\nवो जुड़ा हुआ है पंचमेश या नवमेश इन दोनों\r\nमें ही संबंध आ जाता है तो सब दशम भाव का\r\nमतलब सासु\r\nका आपके ऊपर पूरा आशीर्वाद\r\nहोगा ठीक है तो ये हमारे रूल धन योग आप\r\nदेख देख सकते\r\nहैं उसके बाद सासु का\r\nबिहेवियर वह दशमेश से देखा\r\nजाएगा आपके पति या पत्नी अपनी मां से कैसा\r\nव्यवहार करेंगे वह सप्तमेश और दशम भाव दशम\r\nसे देखा जाएगा कि दोनों के बिहेवियर किस\r\nतरह से\r\nठीक है बहुत ही गहराई में है यह बात अगर\r\nभाई जिसकी शादी नहीं हुई है वह कृपया ना\r\nदेखे क्योंकि यह सिर्फ विवाह का ही चार्ट\r\nनहीं है यह भाग्य का भी चार्ट\r\nहै\r\nआपके रिलीजन का धर्म का\r\nचार्ट इसको स्पिरिचुअल चार्ट नहीं है ये\r\nधर्म का चार्ट है जिस रिलीजन में आप पैदा\r\nहुए\r\nहैं उसको कैसे फॉलो करते हो तो व दे देख\r\nलो वहा से अगर आप यह देखते हैं कि भाई\r\nसासु मा नहीं देखनी मेरे\r\nको तो विवाह में आपके कर्म वह 10\r\nहाउ और वही आपकी मदर इन लॉ भी\r\nहै विवाह के कर्म\r\nमें अगर कोई परेशानी आती\r\nहै तो वह इनलॉ की तरफ से भी आ सकती है\r\nअपने पेरेंट्स की तरफ से भी आ\r\nसकती तो यह म्यूचुअल हाउस है य\r\nद ठीक है तो यह हमारा शुरू का विश्लेषण हो\r\nगया अब इसको\r\nहम दो चार कुंडली पर लगाकर देखते हैं भाई\r\nठीक है जी तो यह हम स्क्रीन शेयर करते हैं\r\nपहला चार्ट मैंने इंदिरा गांधी का समझने\r\nके लिए लगाया\r\nहै अब यह दुनिया में तो नहीं\r\nहै अब यहां देखिए दशम भाव का\r\nथस थ हाउस में केतु महाराज\r\nबैठे और कोई\r\nदृष्टि दशम भाव पर नहीं है अब हम उनकी\r\nनेचर कार्य शैली\r\nदेखें दशमेश है\r\nबृहस्पति बृहस्पति भी किसी से दृष्ट नहीं\r\nहै कोई ग्रह नहीं देख रहा और यह शत्रु\r\nराशि\r\nमें अपने से छटे में बैठे\r\nदशम से छठे\r\nमें अब हम देखें इनके पति इंदिरा गांधी जी\r\nका है तो इनके पति का\r\nव्यवहार वह अपनी मां के साथ कैसा था अब\r\nयहां देख लो पति\r\nमहाराज\r\nवो बुद्ध\r\nहै बुध तो भैया अच्छी जगह पर बैठे हुए हैं\r\nअच्छी तरह से बहुत अच्छा ध्यान दे रहे हैं\r\nबुध शुक्र के साथ है जो शुक्र स्वय राशि\r\nके हैं और शनि से\r\nदृष्ट ठीक है तो चुप तो रहते\r\nहैं परंतु मां के साथ अच्छा संबंध नहीं है\r\nऔर शनि चुप भी करा\r\nदेते शांत मतलब कोई नाता नहीं है मुझे कोई\r\nमतलब नहीं\r\nवो एटीट्यूड आ जाता है अब हम देखते कि कोई\r\nराजयोग वगैरह बन रहा है\r\nक्या अब मैं दशम भाव को केंद्र बना रहा\r\nहूं लगन बना रहा\r\nहूं उसको लगन बना कर के हम देखें भाई चौथे\r\nऔर पांचवे भाव मतलब मंगल और बृहस्पति में\r\nकोई संबंध है केंद्र में बैठे हु\r\nठीक दूसरा राजयोग बनता है बुध और सूर्य के\r\nसा बुध और सूर्य का राजयोग नहीं है यह भी\r\nदोनों एक साथ नहीं बैठे\r\nहुए विवाह से लगन से राजयोग देखना वो मेरा\r\nविवाह कैसा है धनी परिवार में है किसम है\r\nवो लगन से देखे आज हम बात कर रहे हैं थ\r\nहाउस की मेरे कर्म और मेरी मदर इन लॉ उनके\r\nपास य धन है\r\nधन होता है दो\r\n11 और पाचन तो दशम भाव को हमने लगन बना\r\nरखा\r\nहै ठीक है जी दशम भाव को लगन बना रखा है\r\nयहां से दो के लड है शनि शनि खुद बैठे हुए\r\nहैं वही\r\nपर और गवे भाव के स्वामी है शुक्र वो भी\r\nवहां बैठे हुए हो स्व राशि\r\nके त्रिकोण के स्वामी मंगल और सूर्य\r\nउनका संबंध नहीं\r\nआर तो इस व्यक्ति को इंदिरा\r\nगांधी अपनी मदर इन लॉ से धन क्या का लाभ\r\nनहीं दिख रहा है हालांकि वह धन है क्योंकि\r\nदविश बली\r\nहै एकादश बली दशम भाव\r\nसे ठीक है जी\r\nतो यहां पर हमने देखा और हम सोच सकते कि\r\nहा ऐसा ही हुआ होगा अब हम दूसरे चार्ट प\r\nआते यह चार्ट भी अब देखिए\r\nनवा सब दशम भाव\r\nमें चंद्रमा विराजमान है\r\nचंद्रमा कौन है सप्तमेश\r\nहै मतलब इस व्यक्ति के पति या पत्नी वह\r\nचंद्रमा है और वह जाकर के मां के घर में\r\nबैठ तो मतलब मां के साथ हूं\r\nमैं इनका जो पति या पत्नी होगी वह अपने\r\nमां के साथ\r\nहै परंतु मां का आचरण और वो सब हम देखेंगे\r\nशुक्र\r\nसे शुक्र\r\nदशमेश कहां विराजमान है भाई पंचम भाव में\r\nमतलब अपने से अष्टम में गए\r\nहैं\r\nसीक्रेसी सीक्रेसी रखते हैं राहु के साथ\r\nहै और मंगल के\r\nसाथ और किसी की दृष्टि नहीं\r\nहै ठीक है भैया तो यह सीक्रेसी मतलब इनकी\r\nजो सासु\r\nहै इनके जो पति या पत्नी है वह मां के साथ\r\nहै मां से अच्छा संबंध है\r\nऔर मां जो है वह सीक्रेसी रखती ए हास में\r\nऔर शुक्र बहुत बली है वहां पर मंगल के\r\nसाथ ठीक है अब इसमें राजयोग देखो भाई कोई\r\nशनि भाव से चतुर्थेश और\r\nपंचमेश शनि बली\r\nहै क्यों बली\r\nहै वैसे तो योग कारक होते तुला के लिए अब\r\nक्यों बल प्राप्त हुआ है क्योंकि यह\r\nबृहस्पति जो इनके डिस्पोजिटर है जिनकी\r\nराशि में बैठे हु शनि वो उसको दृष्ट कर\r\nरहे अब\r\nअगर तो अच्छी पोजीशन है मां की अच्छी\r\nपोजीशन है और अगर हम धन योग देखे तो दशम\r\nभाव\r\nसे दूसरे भाव के स्वामी है मंगल वो खुद\r\nदृष्ट कर रहे हैं दूसरे भाव\r\nको यह भी अच्छा योग बन जाता है\r\nडिपॉजिट पैसे जमा करने\r\nका और जो\r\nगवा भाव है दशम से वो सूर्य\r\nहै सूर्य शनि से दृष्ट\r\nहै शनि पंचमेश\r\nहै दशम भाव से पंचमेश है तो धन योग भी बना\r\nदिया ठीक है जी तो जो इनको इनके पति को और\r\nइनको मदर इन लॉ से धन का लाभ भी होगा\r\nअच्छी पोजीशन में है\r\nपरंतु वह जो शुक्र है वह राहु के साथ और\r\nमंगल के साथ है उसने थोड़ा सा गड़बड़\r\nकरती मंगल ने धन तो दिया\r\nहै परंतु शुक्र को तो खराब कर रहे हैं\r\nना और राहु बैठे हुए हैं तो जैसा हमने\r\nदेखा है राहु तो\r\nहमेशा मटेरियल वर्ल्डली दुनिया के पीछे\r\nरहता है ठीक है जी तो यह हमने इस तरह से\r\nइनको देखा एक और चार्ट लिखते\r\nहैं यह चार्ट भी अब देखिए\r\nआप दशम भाव देखो\r\nपहले दशम भाव में कोई ग्रह नहीं\r\nहै शनि महाराज दृष्ट\r\nकर ठीक\r\nहै और जो दशमेश\r\nहै वो बुद्ध है और बुध देखो किन किन से\r\nदृष्ट हो रहे\r\nहैं सूर्य शनि\r\nमंगल जब भी हमारे अर्गला का प्रल था आपने\r\nशायद सुना\r\nहोगा कि यदि तीन पाप\r\nग्रह इकट्ठे स्थित\r\nहो तो वह जिस मतलब जहां से भी वह तीसरे\r\nभाव में स्थित होते हैं मतलब उससे गवा भाव\r\nअत्यंत बली हो जाता\r\nहै तो\r\nसासु मां\r\nका इनसे 11वां\r\nभाव कर्क से 11वां\r\nभाव टोरस है वृषभ है और वह सासु मा का कौन\r\nसा भाव\r\nहै नवम\r\nभाव और नवमेश उसको देख रहे\r\nहैं तो इनका जो वृषभ है भाग भाव है मदर इन\r\nलॉ का वह बहुत स्ट्रांग\r\nहै बहुत भाग्यशाली सासु मां\r\nहै ठीक है और यह\r\nबहुत अब यहां से राजयोग देख लो भाई कोई\r\nराजयोग बन रहा है दशम भाव को हम लगन बना\r\nकर के राजयोग देख लेते\r\nहैं योग नहीं बन\r\nरहा तो पोजीशन अच्छी नहीं है मतलब कहीं पद\r\nप्राप्ति नहीं है\r\nपरंतु भाग्यशाली और धनवान\r\nहै धनवान कैसे अब\r\nदेखो दशम भाव से द्वितीय भाव जो है वोह\r\nतुला\r\nहै तुला में च चंद्रमा और\r\nबृहस्पति\r\nबैठे चंद्रमा दशम भाव से एकादश\r\nहै और दशम भाव\r\nसे एकादश सेकंड हाउस में चला गया अा धन\r\nयोग बना\r\nदेते तो इस व्यक्ति\r\nको अपनी सास\r\nसे धन योग\r\nमिलेगा अब इनका चरण देखे सास\r\nका बुद्ध को\r\nदेखे\r\nऔर इनका जो पति या पत्नी है वह भी बुध\r\nहै तो इनकी\r\nसास और इनके पति या पत्नी वह भी एक साथ\r\nहै और उनके पर भी यह तीन ग्रहों का प्रभाव\r\nआ है बुध दोनों\r\nइनके स्पाउस पर भी\r\nऔर इनकी सास पर\r\nभी\r\nबुध वहीं पर विराजमान है\r\nइकट्ठे सास जी से वह पंचम\r\nमें और जो पति या पत्नी है उससे अष्टम में\r\nहै ठीक\r\nहै तो\r\nइनका सास\r\nसे तो ठीक\r\nहै शनि\r\nकी दृष्टि है मंगल की दृष्टि है सूर्य की\r\nदृष्टि\r\nहै तो बहुत ज्यादा बातचीत या संबंध कह लो\r\nऔर जो\r\nइनकी पति या पत्नी है वो भी आठवी में चली\r\nगई तो सास अमीर रिच है भाग्य दे रही\r\nहै परंतु रिलेशन इतने अच्छे नहीं\r\nहै अब देखो यह बारीकी भी य दिख\r\nजाती ठीक है जी यहां\r\nदेखो मंगल की दृष्टि आ रही है शनि की\r\nदृष्टि आ रही\r\nहै तो कंट्रोल नहीं है बुद्ध इज\r\nवाणी कम बोलना परंतु गुस्से\r\nठीक है भाई अब एक चार्ट\r\nऔर अब यह चार्ट आप\r\nदेखो दशम भाव में बृहस्पति विराजमान है\r\nशुभ ग्रह\r\nवि बहुत अच्छा हो\r\nगया ठीक है\r\nजी तो इन जो सास\r\nहै वो बृहस्पति वाला आचरण\r\nहै अब यहां इस ये चार्ट मैंने किसलिए लिया\r\nहै कि यहां पर दशम भाव को हमके लगन बना के\r\nचलेंगे सास के लिए सासु के लिए के पंचम और\r\nनवम का स्थान परिवर्तन\r\nहै नवम और पंचम का स्थान परिवर्तन\r\nहै शनि और बुध\r\nका तो इनकी मदर इन लॉ का इनके ऊपर पूरा\r\nपूरा आशीर्वाद रहा\r\nहै पूरा आशीर्वाद\r\nअब जो इनके पति या पत्नी है वह\r\nहै\r\nचंद्रमा चंद्रमा का\r\nदशम भाव से वो छठे में\r\nबैठ परंतु शुक्र से दशम\r\nमें शुक्र से दशम में\r\nहै तो शुक्र है मदर इन लॉ इनकी और चंद्रमा\r\nहै इनके हस्बैंड या\r\nवाइफ तो हस्बैंड या वाइफ को मां ने\r\nसुख दिया\r\nहै इन्होंने सुख नहीं दिया\r\nहै इनके पति या पत्नी इनके जो भी इस\r\nकुंडली की स्पाउस है पार्टनर है उन्होंने\r\nमां को सुख नहीं दिया मां ने सुख\r\nदिया मा इनके सुख में बैठी है जाकर के\r\nनवाज शादी के बाद\r\nठीक है भैया तो यह हमारा आज का टॉपिक था\r\nऔर जिन्होंने\r\nअगर जिनका विवाह नहीं हुआ\r\nहै वह अपनी कुंडली देखे हमने एक वीडियो\r\nबनाया था के बहुत जल्दी विवाह\r\nहोना या विवाह ना होना या बहुत देरी से यह\r\nभी हम देख चुके नवाज बहुत पावरफुल\r\nचार्ट है\r\nकी बहुत चीजें आपको दिखा देगा आपके इवन\r\nधर्म के बारे में भी बता देगा अल्टीमेट\r\nरिजल्ट किसी भी ग्रह का शाश्वत फल क्या\r\nमिलने वाला है वो भी नवाच\r\nबताए तो मुझे उम्मीद है आशा करता हूं कि\r\nये गलत तरीके से इसको मत इस्तेमाल करना\r\nभाई इसको देख कर के अगर रिलेशन ठीक नहीं\r\nहै\r\nतो और बिगाड़ने की जरूरत\r\nनहीं और अगर आपके रिलेशन अच्छे हैं तो\r\nउसको और अच्छा\r\nकर\r\nऔर मैं तो यह मान के चलता हूं कि भाई अपने\r\nआप को ठीक\r\nरखो तो सारी चीज ठीक हो जाती\r\nहै बस इसी के अनुस बाद मैं अपनी ये आज का\r\nवीडियो खत्म करता हूं फिर मिलेंगे नमस्कार"},{"topic":"वर्ग चार्ट का लग्न","text":"नमस्कार\r\nमित्रों आज मेरे ख्याल\r\nमें एक सप्ताह\r\nबाद मैं आपके सामने फिर हाजिर हुआ\r\nहूं यह पिछला एक हफ्ता\r\nशायद मैं कुछ ज्यादा बिजी रहा अपने काम\r\nमें तो इसलिए मैं आपके\r\nसाथ अपनी वार्ता शेयर नहीं कर\r\nपाया आज मैंने कहा कि कुछ करना चाहिए\r\nनवरात्रि के भी दिन चल रहे\r\nहैं तो आज हमने कहा वर्ग कुंडलियों\r\nप एक कोई स्पेशल चीज बताना चाहते\r\nहैं यह जो आज हम वार्ता\r\nकरेंगे\r\nयह प्रत्येक वर्ग पर हम लगा के देख सकते\r\nहैं\r\nकिस तरह से\r\nलगाएंगे उसके\r\nलिए हम उस किसी भी वर्ग\r\nमें कौन सी राशि उदय हो रही\r\nहै उसको हम\r\nदेखेंगे और वह ठीक राशि है नहीं है उसका\r\nहम कैसे निर्णय\r\nकरें तो यह किसी भी वर्ग कुंडली को\r\nएनालाइज करने का देखने का पहला कदम है\r\nहमें पहले यह देखना\r\nचाहिए वर्ग कुंडलिया भी पराशर जी ने और\r\nजमनी में\r\nभी उनके अलग अलग मीनिंग है कुछ अच्छे चीज\r\nदिखाती है कुछ रोग दिखाती है कुछ\r\nस्वास्थ्य दिखाती है कोई अरिष्ट दिखाता\r\nहै तो उस हिसाब से हमको\r\nचलना पड़ेगा कि किसमें\r\nक्या लगन उदय हो रहा है यह हमारा पहला\r\nस्टेप\r\nहै अब हम पहले यह करेंगे कि जन्म कुंडली\r\nमें हम यह निर्णय\r\nलेंगे कि कौन सा ग्रह क्या\r\nहै यह पहला कदम\r\nहै सबसे पहले हम\r\nदेखेंगे के\r\nइस जन्म किसी भी जन्म कुंडली का योग कारक\r\nग्रह कौन है एक तो हम योग कारक\r\nदेखेंगे आपको अच्छी तरह पता है\r\nजैसे तुला लगन के लिए शनि योग कारक होता\r\nहै तो शनि की\r\nअगर राशि उदय हो रही है किसी वर्ग में तो\r\nवो योग कारक की राशि\r\nहै बहुत से\r\nग्रह स्वराशि\r\nवह भी अच्छा होता है स्वराशि में ग्रह\r\nहै तो यह हमारे योग कारक और स्वराशि वगैरा\r\nके उच्च के ग्रह य हो गए अब इसमें कई चीज\r\nआएंगी अब हम लेंगे कि कौन से ग्रह अच्छे\r\nनहीं माने\r\nजाए या परेशानी\r\nदेंगे इस कड़ी में सबसे पहले आता है\r\nअस्त सूर्य से दगद\r\nग्रह वह आपको सबको पता है कितनी डिग्री पर\r\nग्रह दगद होता\r\nहै फिर ग्रह युद्ध में पिटा हुआ\r\nग्रह दगद हो गया ग्रह युद्ध हो गया उसके\r\nबाद वक्री\r\nग्रह अब जो वक्री ग्रह है\r\nवह क्या करते\r\nहैं जिस भी डिविजनल चार्ट में वक्री ग्रह\r\nकी राशि उदय हो रही है तो वक्री वापस भी\r\nले जाता है सडन इवेंट भी देता\r\nहै कुछ ना कुछ मोड़ तोड़ दे देता है उस\r\nडिविजनल चार्ट\r\nमें ठीक है तो योग उसके बाद हम लेते मारक\r\nजन्म कुंडली का मारक ग्रह तो मारग\r\nग्रह की राशियां देखते\r\nहैं तो यह हमने मोटा मोटी उच्च का है\r\nएसॉल्टेड है योग कारक है वक्री\r\nहै ग्रह युद्ध में है मार्ग है यह हमने\r\nग्रहो की पहचान\r\nकरली अब जो मेन रूल है उसको\r\nसु\r\nअगर किसी वर्ग में\r\nडिविजनल चार्ट\r\nमें योग कारक ग्रह की राशि लगन में आई\r\nहै तो उस वर्ग के अच्छे फल\r\nमिलेंगे ठीक है किसी उच्च ग्रह\r\nके की राशि अगर उदय हो रही है वह भी अच्छे\r\nफल\r\nदेगा जतर हम शुभ ग्रह त्रिकोण के\r\nस्वामियों को लघु पराश्री ने बोला है वो\r\nशुभ\r\nहोते उसके बाद जो अस्त\r\nहै जो ग्रह अस्त है वहां के फल पूर्णत\r\nनहीं मिलते हैं उसमें कुछ ना कुछ कमी रह\r\nजाती\r\nहै प्लेनेटरी वार में है वह उसके कारक में\r\nआप चैन से नहीं बैठ\r\nसकते अगर वो\r\nग्रह प्लेनेटरी वार में हार गया\r\nहै तो कष्ट ज्यादा\r\nहो अगर वह प्लेनेटरी वार में जीता हुआ\r\nहै तो आखिर में आपकी जीत होग अब यह कैसे\r\nदेखते हैं कौन जीत रहा है कौन हार रहा है\r\nज्यादातर हमें पढ़ाया जाता है कि भाई\r\nजिसके भोगांव हो वो जीत गया नहीं उत्तर\r\nकाला मृत आप पढ़िए को और वह लटटू के हिसाब\r\nसे आपको बताता है कि कौन सा ग्रह विजय है\r\nजो नॉर्थ की तरफ ज्यादा होता है उत्तर की\r\nतरफ ज्यादा होता है लटटू में वो ग्रह\r\nजीतता\r\nहै मार्ग\r\nग्रह अगर उदय हो रहा है किसी वर्ग कुंडली\r\nमें तो वह ज्यादातर उस कुंडली के अच्छे फल\r\nनहीं\r\nदेता या उसके फल बिल्कुल नहीं मारक हो गया\r\nना उस वर्क कुंडली को वह मारक की तरह से\r\nपल देता है उस कुंडली के पल नहीं\r\nदेता मान लीजिए आपके डी से\r\nमें जो आपका प्रबल\r\nमार्क उसके राशि की लग उदय हो रही है तो\r\nसंतान प्राप्त करना बहुत डिफिकल्ट होता\r\nहै और बहुत से\r\nऐसे वर्ग होते हैं जैसे आप देख लीजिए डी\r\nबारा कहा जाता है कि डी बारा\r\nमें माता-पिता आपको कष्ट नहीं देते अगर डी\r\nबा में कोई अस्त ग्रह\r\nका की राशि उदय हो रही है अब यह तो है\r\nज्यादातर तो नहीं देते हैं तब क्या होता\r\nहै कि वो सेपरेशन दिखा देते उस कुंडलियों\r\nमें हम सूर्य और चंद्रमा को देख लेते हैं\r\nकि भाई वह अच्छे फल दे रहे\r\nहैं तो उनके साथ रहना थोड़ा मुश्किल हो\r\nजाता है या लंबे समय तक उनका साथ नहीं\r\nमिलता अगर जीवित भी रहते हैं तो अलग अलग\r\nऐसी परिस्थितियां बन जाती है तो यह तब इस\r\nतरह के यह पहला स्टेप हम हर वर्ग में पहला\r\nस्टेप देखते हैं असल में क्या होता है जब\r\nहम प्रेडिक्शन करने बैठते\r\nहैं रूल तो हमने बहुत पढ़े हुए होते हैं\r\nपरंतु उसको जब लगाना है व उस कुंडली में\r\nतब वो याद नहीं\r\nआते बाद में सोचते यार तो पढ़ा था यह तो\r\nइस कुंडली में था मेरे दिमाग में नहीं\r\nआया तो यह भी होता है होता है बहुत दफ\r\nक्या\r\nकरा तो खैर अब हम थोड़ा सा चार्ट पे जल्दी\r\nसे देखते हैं\r\nऔर किस तरह से उसको करेंगे यह पहला चार्ट\r\nहमने लिया है\r\nभाई सबको जाना पहचाना चार्ट है ये\r\nइंदिरा गांधी जी का चार्ट है मैं बर्ड\r\nडिटेल भी नहीं दे रहा हूं क्योंकि सबको\r\nपता है बर्ड डिटेल\r\nइनकी तो इसलिए मैं वो नहीं लिख रहा हूं अब\r\nयहां\r\nदेखिए पहले शांति से इसके कौन-कौन से खास\r\nग्रह हमने\r\nबोले उनको देख लेते\r\nहैं कर्क लगन उदय हो रही\r\nहै और कर्क लगन के लिए मंगल योग कारक ग्रह\r\nहै पहला हमें योग कारक मिल गया\r\nय मार्क क्योंकि क्लियर एकदम नहीं है मैं\r\nमार्क नहीं ले\r\nरहा उसके बाद अस्त\r\nग्रह सूर्य के साथ बुध है और बुध अस्त है\r\nक्योंकि सूर्य 4 डिग्री का है और बुध 13\r\nडिग्री\r\nय अस्त\r\nहै तो यह एक अस्त मिल गया हमें इसमें एक\r\nहमें बृहस्पति\r\nमिले बृहस्पति वक्री\r\nहै अब मैं सारी कुंडलियां वर्क कुंडलिया\r\nनहीं लगा रहा हूं आप लोग करके देखेंगे मजा\r\nआएगा तो उसमें\r\nदेखिए अब जैसे इंदिरा गांधी जी की कुंडली\r\nमें मंगल की राशि डी\r\nफ और डी\r\n2 में उदय हो रही है\r\nमेश डी फ आप कहेंगे सुख सुविधा का है सारे\r\nसाधन सुख\r\nसुविधा\r\nऔर प्लेजर सब तो वह इनको मिला सारी इनको\r\nसुख सुविधाए प्राप्त\r\nथी डी\r\n24 यह एजुकेशन का\r\nवर्ग होता\r\nहै अब कहोगे आप कि भाई ये तो ज्यादा पढ़ी\r\nलिखी नहीं थी शांति निकेतन में भी बीच में\r\nछोड़ के आ गई\r\nथी तो ज्यादा पढ़ाई तो हुई नहीं परंतु\r\nपराशर जी ने इसको डिग्री से नहीं जोड़ा है\r\nडी\r\nको बुद्धि से जोड़ा है कितनी अकल है देखिए\r\nबगैर डिग्री के भी लोग बड़े बड़े\r\nइंडस्ट्रियलिस्ट हुए हैं मैं जानता हूं\r\nऐसे कईयों को\r\nऔर बहुत से पढ़े लिखे भी स्कूल की\r\nटीचरीएक्सएक्सएक्स\r\n59 में 60 में ना 10थ में था और वो पीएचडी\r\nकरके बैठे हुए थे तो 1930 का जन्म होगा\r\nउनका तो उन दिनों भी वो नहीं गए तो इंदिरा\r\nगांधी पढ़ी लिखी हुई सोच थी बुद्धि\r\nथी क्योंकि डी चार में और डी 24 में मंगल\r\nकी राशि\r\nउदय अब बुध जो\r\nहै\r\nवो अस्त है\r\nबुध की राशि डी 16 में उदय होती है इनके\r\nचार्ट डी 16\r\nवाहन और खुशी के\r\nक्षण उनके लिए होता\r\nहै तो खुशी के\r\nक्षण मेरे ख्याल में कम ही मिले इतने\r\nइन्होंने कष्ट\r\nले पिता की मां की मृत्यु हुई पहले छोटे\r\nभाई की मृत्यु हुई पिता की मृत्यु हुई खुद\r\nको भी उनको झटके लगे पति की मृत्यु हो गई\r\nदोनों संतान की मृत्यु हो गई खैर राजीव की\r\nतो इनकी डेथ के बाद\r\nहुई इसके बाद हम देखते बृहस्पति की राशि\r\nडी ना और डी 10 में\r\nउदय विवाह में भी झटका लगा\r\nइनको रिवर्सल\r\nहुए मतलब काफी समय के थोड़े समय के बाद ये\r\nज्यादातर अलग ही रहे\r\nहैं टे प्रोफेशन कार्य क्षेत्र में भी\r\nइनको सामना रिवर्सल हुए काफी सेट बैक\r\nहुए देखना पड़ा चाहे कितनी स्ट्रंग\r\nकितनी स्ट्रंग कुंडली है कितने परिवर्तन\r\nयोग है सब है परंतु बृहस्पति की राशि\r\nमें उदय हो रही है बृहस्पति देखने को आप\r\nअगर देखें यह पदवी भी दिलाता है क्योंकि\r\nनाइंथ लड\r\nहै और छठे लड के साथ परिवर्तन योग में भी\r\nहै परंतु झटका जरूर\r\nदे तो बृहस्पति ने इनको झटका भी\r\nदिया ठीक है और आप और वर्गों में भी लगा\r\nकेर देखना अब इसके बाद एक कुंडली और लेते\r\nहैं यह हमने राव साहब की कुंडली ली\r\nहै राव साहब की\r\nकुंडली इसमें\r\nदेखो तुला लगन\r\nहै और तुला लगन का में शनि योग\r\nकारक बृहस्पति उच्च\r\nके उ राशि\r\nमें बुध इनके भी अस्त है राव साब का बुध\r\nजो है वो 21 डिग्री है और सूर्य 25 डिग्री\r\nपर तो बुध अस्त है अब हम देखें कहां कहा\r\nक्या उदय\r\nहोहा शनि की राशि डी 24 में उदय हो रही\r\nहै डी 24 पढ़ाई लिखाई का\r\nहै इंटेलिजेंस का है बुध खा है जो\r\nमतलब जो सीखता है आदमी जो अपने अप्लाई\r\nकरता है एजुकेशन व है जिसको आप अप्लाई कर\r\nसके जैसे इंदिरा गांधी के उसमें है और राव\r\nसाहब\r\nके तो यह उसमें उदय होती\r\nहै कंपटीशन दिया क्लास वन सर्विस में गए\r\nतो पढ़ाई तो अच्छी रही इनकी हमेशा\r\nबुध की राशि डी बा अस्त है डी बा\r\nमाता-पिता का चार्ट\r\nहै तो माता-पिता के साथ यह बहुत कम\r\nरहे डी 27 में उदय हो रही है डी 27\r\nसेहत शारीरिक बल मान शारीरिक बल डी\r\n27 यह पराशर जी ने ता है तो इनको\r\nबीमारियों ने भी घेरा काफी बीमार रहते थे\r\nया अपने को कष्ट देते थे शरीर को तो डी 27\r\nमें भी इनको वो ला लाभ नहीं\r\nमिला द\r\n30 में भी बुध की राशि उदय हो रही अब यहां\r\nदेखिए ये विपरीत फल\r\nहै डी 30 हमारा अरिष्ट का चार्ट है इससे\r\nअरिष्ट\r\nदेखते तो अरिष्ट को नुकसान हो गया पॉजिटिव\r\nहो गया दुनिया से अरिष्ट बहुत कम हो गए\r\nअरिष्ट घटनाएं दुर्घटनाएं कम हो\r\nगई देखिए कैसे इस तरह से यूज करना\r\nहै य कहोगे कि डी 30 अरिष्ट बढ़ गए\r\nनहीं उसकी हानि करता है क्योंकि यह अस्त\r\nहै मंगल की राशि डी ना में उदय हो मंगल\r\nमर्क\r\nहै प्रबल मार्क है कुंडली\r\nका तो मंगल डी नान में जो विवाह का चार्ट\r\nहै उसमें उदय हो रहा है और इनको विवाह\r\nनहीं\r\nदिया बाकी\r\nऔर मैं नहीं जा रहा हूं तो यह एक बेसिक जो\r\nफंडामेंटल था जो हमने वर्गों के\r\nलिए वर्गों के लिए\r\nहम में इसको पहला स्टेप मान कर के के यह\r\nहर कुंडली के लिए हर वर्ग कुंडली के लिए\r\nसबसे पहले आप यह\r\nदेखिए मैंने और भी चीजें लिखी है परंतु वो\r\nइसके बा\r\nपहला यह\r\nहै बहुत से लोग कहते हैं त्रिक भाव के\r\nउसके भैया त्रिक भाव का स्वामी आपका शुभ\r\nका भी तो स्वामी हो सकता है इसलिए मैं\r\nउसको पहले\r\nब्रॉड एक्सेप्शन में नहीं ला रहा जैसे\r\nमिथुन\r\nलगन तो शुक्र जो है पंचमेश भी है योग कारक\r\nमाना गया है परंतु त्रिक का बवे भाव का भी\r\nस्वामी है तो उसको टोटल कैसे नकार\r\nदू वोह तो अच्छा फल देगा परंतु हानि भी दे\r\nसकता है उस वर्ग में दोनों चीज देगा परंतु\r\nयोग कारक का फल भी\r\nदेगा मिथुन के लिए ही जैसे शनि है नवमेश\r\nहै अष्टमेश भी\r\nहै तो मैं उसको उस कैटेगरी में नहीं रख\r\nसकता कि एक ब्रॉड कैटेगरी में जो अभी दो\r\nमैंने की कि योग कारक स्वराशि\r\nऔर मारक अस्त वगैरा इसका इन दो ब्रॉड\r\nदो दो इसमें एगजैक्टली डिवाइड नहीं कर\r\nसकते मैं यह कहना चाहता क्योंकि वो दोनों\r\nरोल दे रहे हैं तो पहले स्टेप में जो\r\nक्लियर आपके अस्त है वक्री है ग्रह युद्ध\r\nमें है वो तो चाहे कोई भी हो दूसरा रोल भी\r\nहो पर ग्रह युद्ध में तो है अस्तव है\r\nमार्क है तो मार्क है क्लियर मार्क चाहिए\r\nयह नहीं कि सप्तमेश हो गया या द हो गया व\r\nक्लियर मार्क नहीं है उसका दूसरा भी रोल\r\nहो सता अब यह क्लियर मार्क जैसे तुला में\r\nहमको मिल गया कि मंगल क्लियर मार्ग साफ\r\nसाफ दोनों मार्क भाव का स्वामी\r\nहै तो वहां\r\nहम बाकी जगह नहीं लेंगे\r\nठीक है या तुला वृषभ में ले लो नहीं वृषभ\r\nमें भी नहीं आएगा तो जहां क्लियर मार्ग\r\nदिखता है तब तो\r\nहम तो यह थोड़ा सा हर एक पर लगाओ जो\r\nक्लियर जिसको हम ग्रह को डिफाइन कर सकते\r\nहैं इन कैटेगरी में उन्हीं ग्रहों की\r\nराशियों को पहले देखेंगे यह पहला स्टेप है\r\nठीक है जी तो आज के\r\nलिए हमारी यह वार्ता मेरे ख्याल में\r\nयूजफुल\r\nहोगी सबके काम में आएगी\r\nक्योंकि वर्गों\r\nपर बहुत कुछ भगवान ने मुझे दिया है वर्गों\r\nपर बहुत काम किया है और कर रहा हूं अभी भी\r\nअभी भी और नए नए तरीके इसके निकल रहे हैं\r\nठीक है वो भी फिर करेंगे तो आज के लिए भया\r\nइतना ही नमस्कार बहुत-बहुत धन्यवाद थैंक\r\nयू नमस्कार\r\nAll\r\nFrom Saral Jyotish by V P Goel"},{"topic":"विवाह ना होना और बहुत जल्दी होना कैसे देखें","text":"नमस्कार\r\nमित्रों आपके साथ फिर\r\nआज हम एक विवाह का जो एक पिछले वीडियो में\r\nहमने आपसे वायदा किया था जो टॉपिक रह गया\r\nथा उसको आज लेकर के फिर\r\nआए पिछले वीडियो\r\nपर कुछ प्रश्न आए\r\nहैं कुछ रिक्वेस्ट आई है बहुत अच्छा लगता\r\nहै आप लोग रिक्वेस्ट कर रहे हो परंतु सारी\r\nरिक्वेस्ट एक साथ पूरा\r\nकरना मुश्किल है अब इसमें रिक्वेस्ट आई है\r\nकि डाइवोर्स\r\nवगैरह पर भी कोई वीडियो\r\nबनाइए प्रोफेशन पर वीडियो\r\nबनाइए एक रिक्वेस्ट आई है कि वक्री ग्रह\r\nके बारे में आप कुछ\r\nबताइए अब ये वक्री ग्रह एक लंबा सब्जेक्ट\r\nहै आसान नहीं है मतलब इसको समझने में है\r\nतो सरल परंतु इसको समझने के लिए टाइम\r\nचाहिए तो उसकी एक खबर मैं आपको देना चाह\r\nरहा\r\nहूं हमारी सहयोगी है निम्मी अरोड़ा आप सब\r\nजानते हैं आप मेंशन भी करते हैं तो निम्मी\r\nअरोड़ा\r\nदो तारीख से एक वेबीनार ऑर्गेनाइज कर रही\r\nहै चार क्लासेस\r\nका जो अगर बहुत इच्छुक है व उसमें जवाइन\r\nकर सकते हैं और उसमें शायद मैं ही\r\nरेट्रोग्रेड वक्री ग्रहों के बारे में बात\r\nवार्ता\r\nकरूंगा दूसरा एक\r\nप्रश्न आपके बहुत लोगों ने लिखा बहुत\r\nसाथियों ने लिखा\r\nहै कि जो हमने नियम\r\nबताया लगन लग्नेश ऑफ नवांश नवांश का लगन\r\nलग्नेश देख कर के हम अपने कैसे इच्छा\r\nव्यक्ति की क्या है इच्छा फुलफिल होगी या\r\nनहीं और उसके हमने अलग अलग भेद भी\r\nबताए तो उसमें एक प्रश्न आप लोगों ने किया\r\nहै कि अगर लगन पर या नेश पर कोई संबंध ना\r\nहो कोई दृष्टि ना हो तो कैसे\r\nदेखे इसी में आया था बकरी का\r\nभी तो अब जब कोई\r\nग्रह किसी के प्रभाव में नहीं\r\nहै कोई\r\nभाव किसी के प्रभाव में नहीं है तो हम\r\nउसको कहेंगे वो\r\nकोई उसको प्रभाव नहीं कर रहा देखिए\r\nदृष्टि और ग्रह का विराजमान होना एक भाव\r\nमें दोनों में बहुत अंतर\r\nहै दृष्टि में यह होता है कि\r\nवह बगैर वहां गए उस भाव में गए जहां जिस\r\nग्रह को वो दृष्ट कर रहे हैं या भाव को\r\nदृष्ट कर रहे हैं वहा गए बगैर\r\nउसको बोलते भाई मेरी इच्छा यह है मैं तेरे\r\nऊपर इपोज कर रहा हूं मैं तेरे को बोल रहा\r\nहूं यह\r\nकर और जब ग्रह वहा बैठा हुआ होता है\r\nदृष्टि नहीं युति में होता\r\nहै तब होता है कि मैं तेरा संगी साथी\r\nहूं\r\nअब अगर दोनों आपस में\r\nठीक संबंध रखते हैं तो कहेंगे भाई चल ठीक\r\nहै मैं तेरा काम करूंगा तू मेरा काम\r\nकर तो यह फर्क होता है इसीलिए पराशर जी ने\r\nलिखा है कि दृष्टि\r\nसंबंध ज्यादा प्रबल होता\r\nहै ठीक है तो यह मैंने आपके जो प्रश्न आए\r\nहैं उनका मैंने थोड़ा सा जवाब देने की\r\nकोशिश की है अब हम आते हैं आज के\r\nटॉपिक हमने पिछले वीडियो\r\nमें\r\nअर्ली ठीक टाइम ठीक टाइम पर शादी लेट शादी\r\nउस पर वार्ता की\r\nथी तो यह भी प्रश्न आया था कि\r\nभाई शादी ना होने के योग क्या होते\r\nहैं और शादी\r\nसमय से पहले हो जाए उम्र शादी की उम्र\r\nहोने से पहले ही शादी हो\r\nजाए तो उसके क्या योग होते दोनों\r\nएक्सट्रीम है\r\nये एक बिल्कुल\r\nअब अक्षय तृतीया की राजस्थान की शादी की\r\nबात कर रहे हैं और दूसरा कि जिसकी शादी\r\nनहीं\r\nहोती और हमने इसलिए यह नहीं दिया था\r\nक्योंकि इसको जांच के\r\nलिए एक और पराशर जी का\r\nवर्ग डी3\r\nत्रिशांश आता\r\nहै जो काफी निर्णायक\r\nहै इसको प्रशर जी ने मिसफॉर्चून अ भाग्य\r\nका चार्ट लिखा है\r\nभाग्य तो उसको भी हम इन केसेस में\r\nत्रिशांश की मदद लेते हैं नवांश को नहीं\r\nछोड़ेंगे नवांश के जो हमने नियम आपसे\r\nवार्ता की\r\nहै वह नियम रहेंगे उसकी कन्फर्मेशन\r\nपुष्टि के लिए हम त्रिशांश को भी प्रयोग\r\nमें लाते हैं इसलिए यह अलग से मैंने\r\nवीडियो\r\nबनाया अब आप\r\nत्रिशांश मिस फॉर्च्यून का चार्ट लिया गया\r\nहै यहां\r\nपर जब हम विवाह की बात करते\r\nहैं तो प्राय यह देखा गया\r\nहै के एक और सात\r\nएक्सेस वन और सेवन हाउस त्र शमशा\r\nका और दो और आठ भाव\r\nदो एक्सेस ये हम लेते हैं दो अक्ष लेते\r\nहैं इनमें अगर पाप प्रभाव ज्यादा\r\nहो तो विवाह की संभावना कम हो\r\nजाती नवांश और त्रिशांश दोनों को मिलाकर\r\nहम फलित करेंगे दोनों का सहारा\r\nले अगर त्रिशांश\r\nमें\r\nलगन और सात न सेवन एक्सेस और दो आठ एक्सेस\r\nइनमें केवल पाप ग्रह\r\nहो तो वह विवाह में रुकावट डालते\r\nहैं एक और नियम जो हम पहले अपनी कार को\r\nभाव नाश में जिक्र कर चुके\r\nहैं कि यदि\r\nकिसी वर्ग चार्ट\r\nमें उस वर्ग का\r\nकारक लगन में\r\nहो और पीड़ित\r\nहो तब वह कार को भाव नाशय होता\r\nहै\r\nजैसे मेल पुरुष के चार्ट\r\nमें शुक्र लगन\r\nमें और पीड़ित कोई शुभ संबंध नहीं है\r\nऔर स्त्रियों की कुंडली में बृहस्पति लगन\r\nमें केवल अशुभ संबंध के साथ हो तो यह भी\r\nविवाह ना होने का एक योग होता\r\nहै तो हम जो आज चर्चा\r\nकरेंगे वह नवांश भी लेंगे और त्रिशांश भी\r\nलेंगे मेरे ख्याल से आप\r\nबेसिक पॉइंट समझ गए\r\nहैं\r\nके हम दोनों कुंडलियों\r\nको का समन्वय करते हैं दोनों को एक साथ\r\nजोड़ते हैं और वहां से देख करके कोशिश\r\nकरते हैं कि भाई क्या फाइनल कंक्लूजन\r\nहै तो अब मैं आपके साथ अपने चार्ट शेयर\r\nकरता हूं और उनकी डिस्कशन करते\r\nअब\r\nयह यह पहला\r\nचार्ट पहला\r\nचार्ट अब मैं थोड़ी सी इंट्रोडक्शन दे दू\r\nकि यह जो चार्ट\r\nहै 1928 का\r\nडॉक्टर है मतलब\r\nपीएचडी बायो केमिस्ट्री में इन्होंने किया\r\nथा मेरे जान पहचान के परिवार की है इसलिए\r\nकुंडली ले ली है\r\nमैंने जान पहचान के परिवार\r\nकी इन्होंने विवाह नहीं\r\nकिया और देखिए इनको नोबल पीस प्राइज के\r\nलिए नोबल प्राइज के लिए साइंस में उसके\r\nलिए भी रिकमेंड किया गया पर मिला\r\nनहीं अब हम देखते हैं अपना पहला प्रिंसिपल\r\nलगाते हैं के लगन में चंद्रमा और बृहस्पति\r\nहै और सूर्य दृष्ट\r\nकर तो विवाह की इच्छा तो रही अब यह बचारी\r\nमतलब मेरे से तो बड़ी थी\r\nबहुत अब दुनिया में नहीं है\r\nतो इच्छा तो थी मां-बाप की इकलौती लड़की\r\nथी और बहुत अच्छी हुनरमंद\r\nअब हम देखे क्यों\r\nनहीं इच्छा थी देखिए पुराने प्रिंसिपल को\r\nयाद करा रहा\r\nहूं परंतु लग्नेश क्या कहते\r\nहैं लग्नेश बुद्ध है प्रबल\r\nहै उच्च राशि में विराज\r\nपरंतु केतु राहु एक्सेस में\r\nहै शनि से दष्ट\r\nतो इच्छा को पूर्ति नहीं होने दी अब हम\r\nइनका हम वो करते हैं डी3 से वार्ता\r\nलाभ अब आपने ना नोट कर लिया अब डी3 आप\r\nदेखिए डी3\r\nमें मैंने 1 से और 28 एक्सेस की बात\r\nकी यहां पर राहु केतु न सेन एक्सेस में\r\nहै सूर्य भी विराजमान\r\nहै मंगल से दृष्ट है तो न से एक्सस\r\nपर अच्छा पाप प्रभाव है\r\nऔर\r\nबृहस्पति\r\nइनके बवे स्थान में वक बैठे हैं अब मैं\r\nआपको पहली इनका जो नवांश देखा था उसमें व\r\nबात कहना भूल\r\nगया के इनकी नवांश लगन में\r\nबृहस्पति वक बैठे हुए हैं और उनके\r\nऊपर केवल सूर्य दृष्टि\r\nहै जो इस कुंडली के लिए त्रि शनाय के\r\nस्वामी भी है मैं मानता नहीं हूं\r\nये मानता नहीं हूं मैं नेचुरल मेलिफ या\r\nबेनिफ लेता हूं तो इन्होंने विवाह नहीं\r\nकिया अब हम दूसरी कुंडली लिखते हैं यह\r\nकुंडली 30 जनवरी\r\n1965 अब हम नवा हम तो नवाच पर जोर दे रहे\r\nहैं नवांश\r\nको मंगल की दृष्टि है लगन\r\nपर तो क्या कह रहा है\r\nमंगल पाप ग्रह की दृष्टि है कि भाई मेरी\r\nशादी की इच्छा नहीं\r\nहै अपने आप नहीं है मेरी\r\nशादी क्या वो पूरी होगी या नहीं\r\nहोगी उसके लिए लग्नेश\r\nदेखते तो\r\nलग्नेश हमारे शुक्र से दृष्ट\r\nहै कोई पाप दृष्टि नहीं आ रही\r\nहै तो बेटे तेरी इच्छा में पूरी करा रहा\r\nहूं नवांश यह कह रहा है नवांश का लग्नेश\r\nकि तेरी इच्छा मैं पूरी करा रहा हूं\r\nइन्होंने भी शादी नहीं की\r\nअब इनका हम देखते\r\nहैं\r\nत्रिशांश अब य त्रिशांश में आप\r\nदेखो लगन में फिर राहु केतु\r\nएक्सस\r\nमंगल अब यह मंगल लग्नेश भी है लगन को बली\r\nकर रहे यह कह सकते हैं कि यह तो शुभ है\r\nदो और आठ\r\nएक्सेस इसमें भी शनि का प्रभाव है\r\nबृहस्पति अपनी राशि को देख रहे हैं मानता\r\nहूं परंतु यहां पर लगन एक और सात पर पाप\r\nप्रभाव ज्यादा\r\nहै और नवा कह रहा था भाई कि तुम्हारी शादी\r\nकी इच्छा नहीं है तो मैं वोह इच्छा पूरी\r\nकर रहा हूं\r\nउससे पुष्टि हमारे त्रिशान से हो\r\nजाती अब\r\nमैं आगे लूंगा जल्दी\r\nशादी अब\r\nयह कुंडी मां आनंदमई मां की इनकी 11 12\r\nसाल की उम्र में बहुत अरली शादी की बात कर\r\nरहा हूं इसलिए मैंने ले लिए अब य देखो\r\nनवांश में\r\nकिसी ग्रह की दृष्टि नहीं है तो एवरेज है\r\nभैया हो जाए तो ठीक है नहीं होगा मेरे को\r\nकोई लालच नहीं है मैं कोई भाग नहीं रहा\r\nशादी के लिए या मना नहीं\r\nकर अब ऐसे में क्या होता है कि अब लगन लड\r\nअगर शुभ के साथ\r\nहै तो करा देगा जल्दी से अशुभ के साथ है\r\nतो नहीं कराएगा क्योंकि उसकी तो इच्छा\r\nनहीं है\r\nतो यहां पर अब लग्नेश जो है वो सूर्य\r\nमहाराज\r\nहै और सूर्य पे बृहस्पति के साथ संबंध है\r\nशुक्र उच्च के शुक्र दृष्टि कर रहे\r\nहैं अब असली क्लू आएगा\r\nत्रिशा तो मतलब यह है कि नवांश ने तो कह\r\nदिया कि भाई शादी हो जाएगी अब मैं\r\nत्रिशांश दिखाता हूं इनका अब इस त्रिशांश\r\nमें देखो यहां से क्लियर हो\r\nजाती न से एक्सेस\r\nमें केवल शुभ ग्रह\r\nहै दो आठ एक्सेस\r\nमें दो पाप ग्रह भी है अब यह तो\r\nसन्यास अब हम बनाएंगे एक वीडियो\r\nआगे के आठवें भाव से दोनों के नवांश के और\r\nत्रिशांश\r\nके हम क्या निकालते हैं\r\nआठवे केवल नवांश से नहीं होता है नवांश से\r\nभी क्लू लेते हैं और त्रिशांश से भी क्लू\r\nलेते हैं और आठवा भाव हमारा होता है विवाह\r\nकी आयु कितना लंबा विवाह की आयु\r\nचलेगी अब इसके बाद नेक्स्ट कुंडली लेते\r\nहैं यह हमने लास्ट उसम भी ली\r\nथी टाइमली मैरिज प क्योंकि उन दिनों जब\r\nइनकी शादी हुई थी तब 14 13 14 16 साल को\r\nटाइमली माना\r\nजाता अब उसको मैं आज के संदर्भ में ऐसे\r\nअर्ली बोल र नहीं इनकी 13 साल में शादी\r\nहुई अब य पहले नवांश हमने कल डिस्कस कर\r\nलिया था कि शनि बैठे हुए हैं लगन में तो\r\nनहीं है\r\nभाई परंतु\r\nलग्नेश जो है वो मंगल के साथ\r\nहै तेरी इच्छा पूरी नहीं होने दूंगा मैं\r\nयह हमने पिछले कुंडली में पिछले सेशन में\r\nबात की थी अब इसमें मैं त्रिशांश ऐड करना\r\nचाहता इसीलिए मैंने इस कुंडली को दोबारा\r\nलिया\r\nहै अब य त्र देख\r\nन से एक्सेस में देख लो\r\nभाई शुक्र और बृहस्पति\r\nदोनों न से एक्सेस में कोई पाप ग्रह\r\nनहीं दो और आठ एक्सेस में राहु केतु\r\nएक्सेस\r\nहै और एक शुभ ग्रह भी बैठा\r\nहु ठीक है तो इनकी भी विवाह बहुत अर्ली हो\r\nगया\r\nतो आज का जो हमारा टॉपिक\r\nथा आज का हमारा\r\nटॉपिक त्रिशांश को विवाह के संदर्भ में\r\nदेखने का\r\nथा और यह परारी\r\nत्रिशांश हम देख रहे\r\nहैं त्रिशांश में अगर हम अलग से बात\r\nकरें तो त्रिशांश में\r\nअगर पाप ग्रह की लगन उदय हो रही\r\nहो और जिस ग्रह की लगन उदय हो रही है\r\nत्रिशांश\r\nमें वही\r\nग्रह जन्म कुंडली में लगन को प्रभावित कर\r\nरहा हो पाप ग्रह की बात कर\r\nर तो वह एक बहुत बड़ी अड़च हो\r\nजा उसके\r\nविपरीत यदि त्रिशांश\r\nमें शुभ ग्रह की लगन उदय हो रही\r\nहै और वह शुभ\r\nग्रह लगन\r\nको दृष्ट से संबंध बना रहा\r\nहो तो वह बहुत अच्छा हो जाता है त्रिशांश\r\nमिस फॉर्च्यून का चार्ट है\r\nअब यह मत कहना कि साहब इस पर भी एक और\r\nवीडियो बना दो बनाएंगे कभी जब जैसे चलते\r\nरहे तो अभी तो हम विवाह के टॉपिक ले रहे\r\nसमय\r\nमिला और तो\r\nसेपरेशन बाय\r\nडेथ या डाइवोर्स\r\nव हम वैसे थोड़ा सा थोड़ा सा कवर कर चुके\r\nहैं कि एक से अधिक विवाह अनेक\r\nविवाह तो इसमें हम अब जब आठवे भाव की बात\r\nहो रही है जो आयु की बात है आयु विवाह\r\nके तो क्या विवाह की आयु जो विवाह हमने\r\nकिया है उसकी आयु खत्म हो गई दूसरे विवाह\r\nकी आयु दूसरी तरह से देखी\r\nजाए क्या आयु नहीं खत्म हुई है हमारा\r\nसंबंध टूट गया है तो व डावर्स हो\r\nजाता ठीक है तो यह बड़े इंटरेस्टिंग मतलब\r\nरोज की हमारी लाइफ के टॉपिक्स है एंडलेस\r\nहै\r\nबहुत कुछ लोगों ने बोला है कि\r\nहोमोसेक्सुअल लेस्बियन वगैरह उस पर भी आप\r\nबनाइए यह मैं अब जो किताब लिख रहा हूं\r\nउसमें मैंने वो कवर किया है और और बहुत\r\nचार्ट\r\nनिकाले और रूल भी बनाए करेंगे वो भी कभी\r\nशेयर ठीक है जी तो आज के लिए बहुत-बहुत\r\nधन्यवाद नमस्कार"},{"topic":"शकट योग कैसे बनता है राज योग","text":"नमस्कार\r\nमित्रों आज हम फिर से कर्तरी योग\r\nका दूसरा वीडियो लेकर के प्रस्तुत हुए\r\nहैं हमने पहले वीडियो\r\nमें\r\nआपको किसकिस प्रकार से करतरी योग हो सकता\r\nहै वह हमने बात की\r\nथी उसमें जो सब इंपोर्टेंट पॉइंट\r\nथा वो था कि दोनों तरफ से प्रभाव आ रहा हो\r\nकिसी भी भाव पर या ग्रह पर दूसरा\r\nइंपॉर्टेंट पॉइंट जो बहुत से हमारे मित्र\r\nपूछ रहे\r\nहैं वह है कि यह शुभ करतरी है या पाप\r\nकरतरी है या क्या है भाई यह डिपेंड करता\r\nहै कौन ग्रह\r\nकरतरी दे रहे\r\nहैं वह\r\nअपने नैसर्गिक कार कत्व के हिसाब से\r\nज्यादा फल देते\r\nहैं यहां पर मैं एक चीज क्लेरिफाई करना\r\nचाहता\r\nहूं हम देख सकते हैं\r\nकि किस ग्रह पर करतरी आ रही है वो ग्रह\r\nकौन\r\nहै तो एक तो उसके नेचुरल कार कत्व जो है\r\nपराशर जी ने जो बोले हैं हम उस पर ध्यान\r\nदेते\r\nहैं दूसरा ध्यान जाता\r\nहै कि वह किस भाव के स्वामी है वह कौन\r\nहै अब यहां थोड़ी सी दुविधा हो\r\nजा क्योंकि सूर्य और चंद्रमा को छोड़ कर\r\nके बाकी सभी\r\nग्रह दो दो भाव के\r\nस्वामी है तो किस भाव के स्वामी पर करतरी\r\nहो\r\nरही अब उसमें एक छोटा सा हम यही कह सकते\r\nहैं कि भाई कौन सा भाव मली\r\nहै या कौन सा भाव ज्यादा इंपॉर्टेंट\r\nहै पर मैं ज्यादातर क्या करता\r\nहूं जब तक\r\nभावेश किसी केंद्र त्र वगैरा का ना\r\nहो क्योंकि केंद्र त्रिकोण है दूसरा उसका\r\nदूसरा भाव कहीं और भी हो सकता है 12 में\r\nहो सकता\r\nहै तो वो दोनों चीज देगा बीमारी भी देगा\r\nऔर केंद्र का भी उसका फल देगा पर\r\nस्टार्टिंग में आप उसके कारक को लेकर के\r\nचले और भाव भी लेंगे वो भी मैं आपको\r\nबताऊंगा तो इन दोनों से हम देख कर के बात\r\nकरते\r\nहैं एक और पॉइंट जो सबसे बली अर्गला है\r\nकर्तरी\r\nहै उस पर हम पहले ध्यान\r\nदेंगे बाकी एस्पेक्ट करतरी वगैरह है एक एक\r\nही हाउस\r\nमें अगर बली करतरी बन रही है वो भी हम\r\nइग्नोर नहीं करेंगे उसको ध्यान देना\r\nपड़ेगा तो ये आज करतरी का मैं आपके सामने\r\nप्रैक्टिकल\r\nएग्जांपल\r\nदूंगा और उससे कोशिश करूंगा कि आप उसको\r\nठीक से समझ पाए कि भाई कैसे देखना है\r\nकरतरी करतरी एक अच्छा\r\nइंपॉर्टेंट मेथड है देखने का और अपना फल\r\nदेता है हमेशा\r\nमिलेगा तो अभी हम आपसे पहले\r\nहम स्क्रीन शेयर कर लेते हैं और फिर बात\r\nकरते\r\nहैं यह पहला\r\nचार्ट हम वही ले रहे हैं जो हमने\r\nकल करतरी किसकिस प्रकार के होते हैं वो\r\nदेखने के लिए किया\r\nथा तो यहां पर हमने देखा था लगन कोई\r\nज्यादा जोरदार करतरी नहीं है बृहस्पति\r\nदूसरी तरफ जा रहा है मंगल भी दूसरी तरफ जा\r\nरहा है यहां पर चौथे भाव पर आप देखिए तो\r\nशुक्र डायरेक्ट भी\r\nआ सीधा है चतुर्थ भाव को प्रभावित कर रहा\r\nहै\r\nऔर दूसरी तरफ से सूर्य सबसे बली है निकटतम\r\nचतुर्थ भाव के तो हम इसको मानेंगे कि\r\nशुक्र की और सूर्य की\r\nकरतरी चतुर्थ भाव पर आ र पर सूर्य चतुर्थ\r\nभाव की तरफ नहीं जा\r\nरहा तो चतुर्थ भाव पर किसका प्रभाव ज्यादा\r\nआ रहा है व शुक्र\r\nका शुक्र का नेचुरल कार कत्व\r\nजो है वह स्पाउस\r\nहै पति है स्त्री का चार्ट है जुपिटर भी\r\nहै\r\nपरंतु\r\nशुक्र पति का भी कारक हो सक होता है\r\nक्योंकि वह एंजॉयमेंट का सुख का कारक है\r\nऔर वह चौथे भाव\r\nको प्रभाव दे रहा है तो इसका मतलब यह है\r\nकि\r\nशुक्र जो हमारा स्पाउस भी हो सकता है वो\r\nहमारे सुख घर सुविधा सब में प्रभाव डालता\r\nहै उसके ऊपर बहुत चीज डिपेंड करती\r\nहै ठीक है तो इस तरह से हम देखते हैं अभी\r\nकुछ मित्रों\r\nने यह बताया कि इसमें\r\nतीसरे और पांचवे भाव का परिवर्तन योग है\r\nउसका क्या फल होता\r\nहै अ भाइयों एक परिवर्तन योग का एक मीनिंग\r\nतो हो सकता\r\nहै\r\nऔर मैं इस\r\nपर आगे भी लिखने की कोशिश कर रहा हूं\r\nप्रत्येक भाव\r\nका भावे\r\nदूसरे भावेश से परिवर्तन क्या फल होता है\r\nतो यह मैं कोशिश कर रहा हूं लिखने की\r\nइकट्ठा कर रहा हूं कुछ कुछ जो अपने पास\r\nथोड़ा बहुत पढ़ लिख के जो ज्ञान आया है तो\r\nवह भी मैं आपसे साथ शेयर कर र आज का टॉपिक\r\nहमारा करतरी था तो इस पर मैंने कतरी बताया\r\nऔर जो लयो जो तीसरे भाव से किसी का भी\r\nग्रह किसी भी भावेश का एक्सचेंज योग होता\r\nहै उसको ल योग बोलते\r\nपरिवर्तन तो\r\nपंचमेश के साथ तृत का खल\r\nयोग और\r\nतृतीय नीच राशि के होकर के पंचम भाव में\r\nबैठ गए हैं और ज्यादा खराब कर तो इसका\r\nमतलब यह है\r\nके पांचवा भाव किसका\r\nकारक ज्यादातर हम लेते हैं भाई य बच्चों\r\nका संतान का कारक है तो इसने संतान में\r\nतकलीफ इनको दे\r\nदी उसमें खाली योग\r\nदे इन्होंने दो संतान अडॉप्ट की हुई है\r\nइनका कोई खुद की संतान नहीं\r\nहै ठीक है ये आएंगे इसको भी करेंगे हम कभी\r\nटॉपिक अब दूसरा चार्ट में लेता\r\nहूं यह हमारा वही जाना पहचाना मोदी जी का\r\nचार्ट\r\nहै अब यहां स्ट्रांग आप देखिए कहां कहा\r\nकर्तरी बन रहा है अभी गवे बवे भाव\r\nमें मुझे पांच ग्रह दिख रहे हैं केतु\r\nसमय तो एक तो भाई बुध के ऊपर करतरी बन है\r\nबुध वक्री है\r\nऔर केतु भी बकरी है तो बुध के\r\nऊपर बुध कौन\r\nहै मित्र गण है दोस्त है और यहां पर स्वय\r\nराशि के द्वादश भाव में बै तो जो द्वादश\r\nभाव है वह\r\nआपका\r\nसीक्रेट छुपे\r\nहुए शत्रुओं का होता\r\nहै अ कहेंगे वो तो आठवा भाव है जी नहीं\r\nआठवा भाव वो होता है जो शत्रु आप\r\nजानते 12वां भाव वो होता है एक और भी बहुत\r\nचीज है बवे भाव की के जो छुपे हुए शत्रु\r\nहोते हैं जो आपके सामने लाइन लाइट में\r\nनहीं आ रहे पीछे से काम कर रहे\r\nहैं उनका\r\nभाव तो बुध\r\nउसमें फसा हुआ\r\nहै यह गुप्त शत्रुओं\r\nका स्वामी भी है बुद्धि का स्वामी भी\r\nहै उस पर सूर्य और केतु की अच्छी करतरी आ\r\nरही\r\nहै तो\r\nइनको\r\nबुध छुपे हुए शत्रु देने की काबिलियत रखता\r\nहै\r\nदूसरी एक स्ट्रंग\r\nअर्गली\r\nकरतरी सूर्य के\r\nऊपर सूर्य के पीछे शनि\r\nहै जो सीधी मोशन में है डायरेक्ट मोशन में\r\nऔर आखिरी डिग्री पर बैठे हुए और सूर्य\r\nपहली डिग्री पर बैठे हुए ज्यादा दूर\r\nनहीं तो एक तरफ से तो शनि धक्का मार रहा\r\nहै सूर्य को और दूसरी तरफ से मरकरी\r\nजो छिपे हुए शत्रु हैं वो कर्तरी मार रहे\r\nहैं तो सूर्य के ऊपर पूर्ण करतरी आ गई भाई\r\nबड़ी बली करतरी\r\nआई अब आप देखो सूर्य की दशा में क्या हुआ\r\nये गुजरात के चीफ मिनिस्टर थे इनके ऊपर\r\nकेसेस\r\nलगे पाच छ साल तक जब तक सूर्य की दशा\r\nरही यह उन केसों में ही उलझे\r\nरहे और भगवान की कृपा या जो भी है इनका\r\nभाग्य था के बरी हो गए\r\nउस पर इस करतरी ने इतना\r\nस टेंशन वाला समय इनको दिखाया कितनी क्लोज\r\nकरते रही तो हम मेरा यही है क्लोज करते\r\nबाकी जो है आप देखते रहो इग्नोर कर दो या\r\nमत करो अब जैसे लगन के\r\nऊपर एक तरफ मंगल है वही नियरेस्ट है लगन\r\nके दूसरी तरफ कौन है नियरेस्ट सूर्य है\r\nसिर्फ सूर्य दे रहा है लगन\r\nको कर्तरी और सूर्य फसा पड़ा\r\nहै तो शरीर को मन को हमको वो तकलीफ दे रहा\r\nहै ठीक है जी तो ये हमने इस कुंडली में\r\nदेखा अब एक कुंडली और लेता\r\nहूं यहां भी मैंने इसलिए सेलेक्ट की है कि\r\nइसमें खास खास करतरी मिल रही\r\nहै ठीक है जी अब यहां देखिए लगन पे भी\r\nराहु वापस आ रहा\r\nहै लगन को देख रहा है बृहस्पति भी लगन की\r\nतरफ जा रहा\r\nहै तो लगन के ऊपर\r\nराहु और बृहस्पति की कर्तरी लगन में कोई\r\nग्रह नहीं है शरीर\r\nहै तो राहु का इफेक्ट तो आ गया वहां पर\r\nयहां पर मैं शनि को नहीं\r\nमानूंगा कि शनि प्रभाव क्योंकि शनि और लगन\r\nके बीच में बृहस्पति\r\nआया ठीक है जी 11वें भाव पर नहीं ले रहा\r\nहूं मैं कर्तव्य क्योंकि बृहस्पति सबसे\r\nपास है वो आगे जा रहे हैं 11वें भाव को\r\nनहीं देख रहे और सबसे पास बुध है जो वक्री\r\nहै वो उससे पीछे जा र तो गवे पाव पर\r\nप्रबल नहीं है अब देखिए हमारे पास मंगल\r\nमहाराज\r\nहै मंगल के पीछे सूर्य है जो\r\nडायरेक्ट मंगल की तरफ जा रहे\r\nहैं और दूसरी तरफ बुद्ध है जो वक्री होकर\r\nके\r\nमंगल की तरफ जा अब मंगल कौन\r\nहै मंगल अष्टमेश है तेश है अभी हमने\r\nबोला त्रिश और अष्टमेश पाप ग्रह है मंगल\r\nइस समय य\r\nपर तो\r\nये तकलीफ दे कौन तकलीफ में आ रहे हैं मंगल\r\nतकलीफ में आ रहे\r\nहैं अब ये देखो इसको शुभ कहेंगे अशुभ\r\nकहेंगे मैं कहूंगा कि भाई एक तरफ लग्नेश\r\nहै दूसरी तरफ अज्ञात शत्रु है\r\nसूर्य उसने मंगल को पकड़ रखा\r\nहै तो जो ओपन शत्रु\r\nहै मंगल अष्टमेश है वो ओपन शत्रु\r\nहै उनको यह पकड़ के रखते अपना प्रभाव डाल\r\nकर के टर्न पूरी\r\nकी अब ये नरसिंहा राव की कुंडली है अब एक\r\nऔर आप\r\nदेखो अष्टम भाव\r\nमें शुक्र 27 डिग्री 40\r\nमिनट और केतु उनसे पीछे है और वक्री\r\nहै ठीक\r\nहै चंद्रमा\r\nसीधी चाल से हैं तो वो शुक्र की तरफ आ रहे\r\nहैं तो शुक्र को\r\nचंद्रमा की करतरी मिल रही\r\nहै बाकी और भी चीज है वो नहीं जा रहा हूं\r\nपरंतु यहां चंद्रमा कौन है अब मैं इसको\r\nशुभ करतरी बोलूंगा या पाप करतरी\r\nबोलूंगा अब यहां चंद्रमा देखो एकादश\r\nत्रि शड के स्वामी\r\nहै मन\r\nहै ठीक है और यह शुक्र को प्रभावित कर रहे\r\nहैं शुक्र पत्नी भी कह सकते\r\nहैं ठीक है तो उनका साथ इनको बहुत ज्यादा\r\nनहीं मिला चंद्रमा की वजह\r\nसे दूसरा शुक्र के ऊपर प्रभाव है शुक्र\r\nकेतु के साथ केतु हालाकि वापस जा रहा है\r\nअब लग्नेश को मैं फिर से देखता हूं\r\nदोबारा लग्नेश\r\nवक्री इनके ऊपर कोई अर्गला नहीं है\r\nपरंतु मंगल उनकी तरफ आ रहा है दूसरी तरफ\r\nसे अर्गला नहीं मिल र सॉरी करतरी रगला\r\nदिमाग में चढ़ा हुआ है करतरी नहीं मिल रही\r\nऔर मंगल\r\nलग्नेश तो इनकी\r\nमृत्यु मंगल की वजह से यह पीड़ित हुए और\r\nइन्हें\r\nकैंसर डायरेक्टली नहीं आ रहा है करतरी से\r\nपर और चीज अगर मैं जोडा जब वहां लगाता हूं\r\nतब जाकर के यह पता चलता\r\nहै ठीक है जी क्योंकि यहां पर बुध स्व\r\nराशि में ही लग्नेश है और फिर से स्व राशि\r\nमें इस बुध ने इनको राइज भी\r\nदिया लग्नेश इंटें अपनी स्वय राशि\r\nमें परंतु यह पीड़ित हुए अष्टमेश\r\nसे\r\nऔर द्वादश\r\nसे तो करतरी का इस पर इतना ज्यादा असर\r\nनहीं दिख रहा है एक्सेप्ट\r\nमंगल तो मैंने यह आपको डिफरेंट प्रैक्टिकल\r\nएग्जांपल्स दी\r\nहै तो इससे मैं उम्मीद करता हूं आशा है कि\r\nप्रैक्टिकल आप देखना जहां कहीं\r\nभी आपको पूर्ण कर्तरी मिले किसी ग्रह पर\r\nकिसी भाव\r\nपर के आगे वाला ग्रह वक्री होकर उसकी तरफ\r\nआ रहा है और पीछे वाला ग्रह डायरेक्ट आ\r\nरहा\r\nहै तब उसका प्रभाव सबसे ज्यादा\r\nहोगा तो शुरू की उसमें अब बाकी करतरी को\r\nछोड़ सकते\r\nहैं सिर्फ इस प्रबल कतरी को आप ध्यान में\r\nरख\r\nके शास्त्रों में तो बहुत कुछ लिखा है\r\nहमने भी किताब में बहुत कुछ लिख दिया है\r\nहर तरह की करतरी लिख दी है\r\nव ज्ञान के लिए है नॉलेज के लिए है पर जब\r\nहम\r\nप्रैक्टिकल ज्योतिष करने बैठते\r\nहैं तो जो प्रत्यक्ष एकदम दिख रहा\r\nहै उसको ज्यादा ध्यान दो\r\nभाई ठीक है दूर के एस्पेक्ट करतरी वगैरा\r\nलगाते रहोगे तो उसमें हमें ज्यादा सफलता\r\nनहीं\r\nमिलेगी ठीक है तो आज के लिए मैं सोचता हूं\r\nकि अब करतरी का यह हमारा\r\nचैप्टर पूरा होगा और आप इससे कुछ भ्रम तो\r\nदूर होंगे करतर करतरी हम हमेशा रोज करते\r\nरहते हैं कितने जोगियों को क्लास में\r\nपढ़ाते टाइम वैसे करतरी जरूर बोल देते\r\nहैं तो इसलिए मैंने यह आपका आपके साथ यह\r\nवीडियो शेयर किया है बहुत-बहुत धन्यवाद\r\nहैप्पी न्यू ईयर हैप्पी गुड नाइट मजे करो\r\nथैंक यू"},{"topic":"शरीर में रोग का पता लगाने के तरीके","text":"नमस्कार मित्रों आज फिर आपके साथ सन्मुख हूं और आज\r\nआप सबके इच्छा अनुसार एक ऐसा टॉपिक लेकर के\r\nआए हैं जिसके बारे में जानना हर व्यक्ति चाहता\r\nहै के वह है रोग\r\nहर कोई स्वस्थ रहना चाहता है और आराम देही जिंदगी अपनी जीना चाहता है और इसमें\r\nज्योतिष हमारी काफी मदद करता है क्योंकि केवल ज्योतिष ही ऐसी साइंस\r\nहै कि जो फ्यूचर को देख सकती है आप अगर डॉक्टर के पास जाते हैं अपने\r\nसिमम बताते हैं कि भाई मुझे यहां परेशानी हो रही है यहां दर्द हो रहा है ये कमजोरी\r\nहो रही है भूख नहीं लग रही वो उसकी दवाई पकड़ा देता है\r\nऔर वो ये नहीं देखता ये किसलिए हो रहा है ये जो शास्त्र था यह हमारा आयुर्वेद भी\r\nहै और एस्ट्रोलॉजी भी है आयुर्वेद एक पूरी कंप्लीट साइंस है और\r\nएस्ट्रोलॉजी के साथ काफी जुड़ी हुई आजकल\r\nमुझे खबर है के कई हॉस्पिटल्स\r\nमें एस्ट्रोलॉजी के ज्ञाता लोग वहां पर रखने\r\nशुरू कर दिए ताकि वह देख सके कि रोग कहां है कैसे\r\nहै कितना सीरियस है कहां उसकी जड़\r\nहै तो यह हम ज्योतिष से जान सकते हैं बहुत\r\nस क्या होता है आप जो चीज की कंप्लेंट लेकर के हॉस्पिटल गए हैं वह आपके सारे\r\nटेस्ट कराएंगे और उसको देखेंगे भाई कहां पर क्या प्रॉब्लम फिर भी वह रूट कॉज नहीं पकड़\r\nसकते बहुत दफे ऐसा होता है जैसे हमारा एक मैंने अपनी पुस्तक में भी लिखा है हमारे\r\nएक मित्र थे उनको आख की तकलीफ थी इंजेक्शन लगता था हथ तीसरे हफ्ते\r\nऔर आंख उनकी खुल नहीं पा रही थी उन्होंने कुंडली दिखाई यह मैंने अपनी पुस्तक में भी\r\nलिखा है कुंडली दिखाई तो मैंने उनसे कहा भाई आपके पाचन शक्ति पाचन क्रिया में\r\nतकलीफ है आपकी इंटेस्टाइन में प्रॉब्लम है और वहां से यह जनरेट हो रहा है तो\r\nउन्होंने डाइजेशन पर उस पर अपना वर्कआउट किया काम किया\r\nऔर चार महीने के अंदर उनका इंजेक्शन लगना बंद हो गया और उनकी आंखें ठीक\r\nहोई तो ये है दूसरा एक क्या है के ज्योतिष\r\nका हमारा हर व्यक्ति का ज्योतिष सीखने\r\nका क्या कारण होता है इसमें कुछ तो बुद्धिजीवी\r\nहै तो उसमें क्या वो देखते हैं मैं सबसे पहले कहता हूं कि ज्योतिष\r\nमें यह देखो कि भाई मेरी वीकनेस कहां है कहां पर मेरे को प्रॉब्लम\r\nहै उससे लड़ना नहीं है उसको सुधारना है मैं उस प्रॉब्लम से कैसे ठीक हो सकता हूं\r\nउससे कैसे निकल के आऊं मान लीजिए व्यवसाय में प्रॉब्लम दिख रही है\r\nविवाह में प्रॉब्लम दिख रही है तो उसका आप सलूशन ढूंढ\r\nकि मैं इससे कैसे निकल सकता अब जैसे एक योग\r\nहै के बुध अगर लगन में स्पेशली वैसे तो बुध कहीं पर भी हो और बृहस्पति से\r\nदृष्ट तो उस व्यक्ति का अपनी वाणी पर कंट्रोल नहीं\r\nरहता अब ज्योतिष्य हमने देख लिया अगर किसी के मिलता है तो उसको कहो भाई अपनी वाणी पर\r\nथोड़ा कंट्रोल कर सोच समझ के बोला करो नहीं तो प्रॉब्लम\r\nमें ठीक है अब मेडिकल में भी अगर किसी के\r\nहमें दिखता है प्रॉब्लम कि भाई यह सूर्य की व से है तो चाहे वह शरीर में हार्ट का\r\nहो चाहे बोनस की वजह से हो सूर्य बोनस को भी देखता है तो भाई वो उसका केयर करलो कुछ\r\nतो इफेक्ट होगा तो इन्हीं दो चीजों के लिए हम करते हैं कि\r\nमेरी जो वीकनेस है उसको मैं कैसे ओवरकम कर और इस वीकनेस में ही हमारी शरीर की\r\nवीकनेस एकदम सबसे पहले आती है अब इसके लिए पराशर जी\r\nने डी 27 को खास बनाया है कि यह\r\nस्ट्रेंथ देखने के लिए यूज करते हैं इसको अब यह अगर स्ट्रेंथ\r\nमैंने क्या इसका कंक्लूजन निकाला कि अगर यह बल देखने के लिए है स्ट्रेंथ देखने के\r\nलिए है तो इसको निर्बलता भी बतानी पड़ेगी वीकनेस भी बतानी\r\nपड़ेगी तो जहां जो एफ्लिक्ट हो रहा है वहां हमारी\r\nवीकनेस वो शरीर शरीर की स्ट्रेंथ नहीं है शरीर की स्ट्रेंथ कैसे आप वो भी बताया\r\nपरंतु इसका विश्लेषण कैसे करें वह एक बहुत बड़ी गुंडी थी क्योंकि सब\r\nकहते थे य डी 27 है और 27 नक्षत्र होते हैं तो नक्षत्रों पर\r\nआधारित इसको देखना चाहिए पर ऐसा नहीं है\r\nमैंने बहुत कोशिश की है नक्षत्र से रिलेट करने की शायद और रिसर्च की जरूरत है तब वो\r\nनक्षत्र भी देख करके कुछ बता सकते और भी वर्ग दिए है जैसे आपका थ है\r\nद शरीर के पार्ट अब वो अलग अलग 3 दश कांड\r\nके अलग अलग पार्ट दिए हुए हैं और उसको जब ट्राई करो तो वह ठीक से नहीं\r\nबैठते इसी तरह से भविष्य पुराण में हर नक्षत्र का\r\nआपको एक शरीर का हिस्सा दिया गया है वह भी अप्लाई करके\r\nदेखा फिर वह समझ में आया कि यह जो भविष्य पुराण में लिखा है के इस नक्षत्र का यह\r\nअंग है और इसकी पूजा या उपाय करने पर हमको\r\nशांति मिल सकती है यह लिखा है उपाय नहीं दिए उसम आज हमने अपनी जो पुस्तक लिखी है उसमें\r\nहमने उपाय मैं उपाय नहीं बताता हूं पर उसमें मैंने उपाय लिखे हैं वो उपाय कहां\r\nसे लिए मेरे दिए हुए नहीं है उसमें जो पराशर जी ने बृहत पराशर हो रा\r\nशास्त्र में हर महादशा और अंतर दशा के लिए जो दान\r\nऔर जप बताए हैं कोई मोती मूंगा नहीं बताए उन्होने\r\nजप और दान जो बताए हैं वह मैंने इस पुस्तक में बृहत पराशर से लेकर के लिख दिए ताकि\r\nआपको हर दशा में ना ढूंढना पड़े मैंने ढूंढ के इकट्ठा एक जगह लिख\r\nदिया तो हम यह वर्क इस्तेमाल करते हैं डी3 है अब बहुत से रोग की किताबे है उसमें डी\r\nसि को लेते हैं डी सि का डायरेक्ट नहीं है वो डी3 का ही आधा पार्ट\r\nहै डी3 डिग्री है और डी स जो है वह 5\r\nडिग्री का होता है तो एक दृश कांड में दो\r\nडी सि के साइन आ जाते हैं डी सि में उसको कलक बोलते\r\nहैं तो वो भी हम इसका क्या इस्तेमाल होता है पहले कलक में हो दूसरे कलक पहला कलक\r\nइंटरनल दूसरा कॉलम एक्सटन यह हमने उसका कंक्लूजन निकाला\r\nखर तो हम यहां पर जो आपसे वार्ता कर रहे हैं इसमें डी\r\n27 सप्त बम शमशा का रोल है यह मेन चार्ट है आपकी बल और निर्बलता को देखने\r\nके अब इसको देखने के लिए हमारे पास क्या\r\nहै मेनली हम इसमें 12 राशियां देखते हैं\r\nऔर पीड़ा देने वाले ग्रह को देखते\r\nहैं दो पॉइंट देखते हैं कौन सा ग्रह पीड़ा दे रहा\r\nहै किस राशि को पीड़ा दे रहा है और जो ग्रह है वह शरीर के किन किन अंग\r\nको गवर्न करते हैं जिस पर रूल करते हैं जैसे चंद्रमा है पपड़ का\r\nपे पड़ों पर रूल करता है पानी पर रूल करता है शुक्र भी पानी पर रूल करता है पर दोनों\r\nका डिफरेंस है\r\nचंद्रमा रूल उस चीज को करता है जो पानी से जीवित रहते हैं पानी में जीवित\r\nर और जो शुक्र रूल करता है जो उसका दायरा है वो जो पानी को अपने पानी का ट्रीटमेंट\r\nकरते पानी को इस्तेमाल करते जैसे मछली\r\nहै वह पानी में जीवित रहती है तो मछली का कारक चंद्रमा\r\nहै अब गुर्दे हैं वह पानी को लेकर के कार्य करते हैं\r\nब्लेडर है वह पानी को ट्रीट करते हैं ब्लेडर में स्टोर करते हैं व निकालते तो ब्लेडर और\r\nकिडनी यह शुक्र के रूल में आएंगे यह सब आप बुक से पढ़ सकते\r\nहैं क्योंकि मैं बहुत बड़े वीडियो नहीं बना रहा\r\nहूं तो इसमें वहां से हम इसको अब डी 27 ही\r\nएग्जामिन करेंगे उसके एग्जामिन करने का तरीका मैं आपको\r\nबताऊ डी 27 में सबसे पहले हम लगन देखते\r\nकि अगर लगन बली है तो आपका शरीर हष्ट पुष्ट रहेगा आप\r\nबीमारी से लड़ सकते हैं और वह ज्यादा कष्ट नहीं दे देखि बीमारी तो हर एक को\r\nआ उसके बाद हम देखते हैं कि कौन सा\r\nग्रह पीड़ा दे सकता है वो पीड़ा नहीं है पीड़ा दे रहा है\r\nवो ज्यादातर क्या होते हैं त्रिक के लड होते हैं तो उसमें बड़ी\r\nलंबी आपकी ज्यादा दिनों की क्रॉनिक बीमारी के लिए\r\nअष्टम और बीमारियों के लिए छटा भाव बावा भाव आपको चारपाई पर डाल\r\nदेगा लॉस करेगा मंगल सर्जरी करा देता\r\nहै शनि और राहु मिल जाते हैं तो कैंसर दे देता है तो ये सब आपको सीखना पड़ेगा मनन\r\nकरना पड़ेगा तो हम कहां से करेंगे हम देखेंगे त्रिक के भाव के\r\nस्वामी डी 27 एक हम नवाज का रूल भी बता चुके हैं और\r\nजन्म कुंडली का भी वहां के जो त्रिक के भाव के स्वामी होते हैं या त्रिक में बैठे हुए ग्रह होते हैं\r\nवो भी रोग दे सकते हैं ठीक है अब हम नेक्स्ट स्टेप हमारा\r\nहोगा के यह जो रोग देने वाले ग्रह हैं एक है या दो है वो किसको पीड़ा दे रहे हैं\r\nरोग वहां आए या किस राशि को पीड़ा दे\r\nरहे अब राशियों का मैंने बताया कि बहुत से\r\nवर्शन दिए हुए हैं परंतु जो सबसे बढ़िया वर्शन लगा और जो\r\nमैंने यूज किया है कि अपना सीधा सधा सिर पर हाथ रखो यह मेश\r\nहै और जो पैर है आपके वह मीन है अब इसको बाटलो बराबर पूरे शरीर को ऊपर\r\nसे लेकर नीचे तक पहला मेश हो गया फिर टोरस है फेस हो\r\nगया सारा आई आ गई उसम फिर तीसरा है गन आ\r\nगई चेस्ट आ गई ऊपर के शोल्डर आ गए सब आ गए चौथा है वो आपके लंग्स आ गए हार्ट का\r\nपोर्शन आ गया सूर्य हार्ट का कारक भी है चंद्रमा भी\r\nकारक है उसके बाद आओ लियो लियो भी उससे चेस्ट\r\nसे नीचे का पोर्शन है वो लियो हो गया फिर विर्गो वो नाभी के पास हो\r\nजाएगा नाभी से नीचे तुला तुला के बाद\r\nवृश्चिक ये आपके गुप्तांग हो गए ट इंटेस्टाइन हो गई पटी की जगह हो गई\r\nयूरिन हो गया ठीक है उसके बाद आपके हिप्स आ\r\nगए जांगे आ गई यह धनु आ जाएगा धनु में पीड़ा है आपके हिप्स जा में\r\nपीठ पर वहा दर्द होता है और मकर वह आपके\r\nघुटने हो गए मकर के नीचे आपके जो पिंडली वगैरह है\r\nयह कुंभ हो गया और मीन हो गया तलवे आपके पैर आसान है तो\r\nइस तरह से इसका क्लासिफिकेशन कर लो अब अप्लाई कैसे करते हैं यह हम अभी जरा एक एक\r\nदो चार्ट आप देखेंगे उसमें आप समझेंगे तो यह\r\nहम यह हम स्क्रीन कर रहे हैं आपके साथ\r\nशेयर जरा इसको अ ध्यान से देखिए यह शरद पवार जी की कुंडली ली है\r\nमैंने क्योंकि सब उनसे वाकिफ है सब उनको देखते हैं टीवी पर कि उनका मुंह का ऑपरेशन\r\nहो चुका है और वो कैंसर का ऑपरेशन हुआ था उनका अप्रैल 2004\r\nअब देखिए इससे यह सब डी 27 हमें बताएगा कि भाई साहब किस दशा में आपको परेशानी आ रही\r\nहै तो ज्योतिष ही ऐसा है जो आपको फोर वार्न कर देगा कि जी यहां प्रॉब्लम आपको\r\nआएगी उसको केयर कर लो भाई ठीक है तो हम यहां से देख के चलते हैं\r\nअब मैंने त्रिक भाव के बताए जन्म कुंडली का देख लो त्रिक भाव में\r\nबुध और सूर्य बैठे हुए य पहला पहला आइडेंटिफिकेशन\r\nइनके लर्ड ले लो चंद्रमा है और शुक्र है अब इसके बाद आ जाओ डी अब यहां थोड़ी सी\r\nआंखें खुली रखनी है और एक एक राशि को देखना है एक एक ग्रह अब यहां पर डी\r\n27 आप देखो अष्टमेश\r\nशनि है और केतु वहा बैठे हुए तो शनि की राशि भी पीड़ित हो गई उनकी\r\nदूसरी राशि में सूर्य बैठे हुए तो शनि हमने निकाले कि यह पीड़ा देने\r\nवाले ग्रह है शनि महाराज पीड़ा\r\nदेंगे ठीक है जी अब हम देखे भाई शनि किस किस को प्रभावित कर रहा है कहां कर रहा है\r\nअब यहां देखिए शनि और मंगल मंगल अष्ट में द्वादश जन्म कुंडली\r\nके शनि और मंगल के बीच में\r\nवृषभ यह जबरदस्त पाप करतरी में है मंगल भी वृषभ की तरफ जा रहे हैं और शनि\r\nभी वृषभ की तरह आ र तो वृषभ राशि हमारी बहुत बुरी तरह पीड़ित हो गई\r\nहै ठीक है और शनि महाराज वह मिथुन में विराजमान\r\nहै तो मिथुन को भी पीड़ा दे रहे हैं अब शनि की\r\nदृष्टि राहु पर है तीसरी दृष्टि दसवी दृष्टि बृहस्पति और चंद्रमा\r\nपर ठीक है जी तोब क्या हुआ बृहस्पति पीड़ित\r\nहो गए चंद्रमा पीड़ित हो\r\nगए चंद्रमा जन्म कुंडली के अष्टमेश भी है लॉन्ग टर्म बीमारी दे सकते\r\nहैं तो हमने क्या चिन्हित किया अब अब हमारा काम जो आ गया ना परेशानी का इनको\r\nदोनों को लिंक करना ग्रह और राशि उस क्या\r\nपीड़ित हो रहा अब हम टोरस तो आपने देख लिया ष के फेस\r\nमाउथ पीड़ित हो रहा और बृहस्पति पीड़ित हो रहे बृहस्पति\r\nक्या है स्पीच बोली वाणी स्पीच और सुनना यह बृहस्पति का है\r\nस्पीच के लिए हम मरकरी भी ले सकते हैं सेकंड उसका वो कारक है मरकरी भी मंगल से\r\nदृष्ट है कोई शुभ दृष्टि नहीं\r\nहै तो हमारी जो पीड़ा आई वृषभ पर सबसे ज्यादा आई स्पीच पर जुपिटर की आई और मरकरी\r\nपर आई तो इनका अप्रैल 2004 में कैंसर की वजह से वो\r\nऑपरेशन हुआ राहु और शनि पीड़ में आ\r\nगए कैंसर का ऑपरेशन हुआ अब यह दशा देखो उस समय जब ऑपरेशन हुआ दशा थी शनि\r\nमरकरी मरकरी सारे ग्रह हो रहे हैं\r\nकनेक्ट शनि मरकरी मरकरी तो हम बता सकते हैं कि भाई यह\r\nप्रॉब्लम आपको कैंसर की हो सकती है और आप इसको अगर पहले से देख ले तो शायद ऑपरेशन\r\nतक जाने की जरूरत नहीं पड़ती जो मरकरी पर मंगल की दृष्टि है मंगल\r\nऑपरेशन कराता ठीक है जी तो यह\r\nहमारा शरद पवार जी का होरोस्कोप था इसके बाद हम दूसरा होरोस्कोप और ले रहे\r\nहैं यह होरोस्कोप हमने लिया बिल क्लिंटन\r\nअब यहां पहले जन्म कुंडली में देख लो बवे भाव में सूर्य है अष्टम भाव में\r\nचंद्र यह प्रॉब्लम क्रिएटर है इस कुंडली में\r\nभी जब हम डी 27 पर आ रहे हैं तो डी 27 में शनि फिर से अष्टमेश\r\nतो शनि को हमें फिर पकड़ के\r\nचलना यहां पर शनि का राहु से संबंध नहीं आ रहा कैंसर\r\nनहीं शनि किसकिस को तकलीफ दे रहे\r\nहैं शनि की दशम दृष्टि सूर्य और मंगल पर\r\nहै और यहां पर भी मिथुन राशि पीड़ित है व\r\nटोरस ज्यादा पीड़ित था मिथुन भी पीड़ित था ठीक है\r\nऔर क्या हुआ चंद्रमा को शनि दृष्ट कर रहे\r\nहैं चंद्रमा लग्नेश है डी 27 के चंद्रमा पर और कोई शुभ संबंध\r\nनहीं है अगर बृहस्पति य देख रहे होते तब अच्छा हो\r\nजा तो इनको क्या हुआ तीसरा मिथुन पीड़ित हुआ\r\nसूर्य मंगल दो ग्रह बैठे हुए हैं शनि से\r\nरिष्ट तो यह दिखाते लंग्स लंग्स पीड़ित हो\r\nगए और लंग्स के साथ हार्ट भी पीड़ित होता है क्योंकि सूर्य पीड़ित हो ग वह हार्ट\r\nमें प्रॉब्लम दे रहे हैं चंद्रमा भी हार्ट का कारक है क्योंकि\r\nशा में लिखा है\r\nएक्वेरियस लगन के लिए चंद्रमा पीड़ादायक वह सब जानते हैं परंतु एक्वेरियस के लिए\r\nसूर्य को नहीं लिखा तो वहां से कंक्लूजन निकलता है कि\r\nचंद्रमा भी हार्ट का रोग दे सकते हैं तो इनको भी दो दफे हॉस्पिटल में गए एक\r\nतो अब यह डॉक्टर का जैसे आप मेडिकल देखते हैं यह पहले हॉस्पिटल गए वहां पर इन्हो को\r\nबोला गया कि भाई आपके इंफेक्शन होए इंफेक्शन की एंटीबायोटिक्स वगैरह दे\r\nदवा दी खत्म हुआ मामला आगे नहीं देखा कि वह इंफेक्शन अगर\r\nजो हो रहा है वो इतना डेवलप ना हो के सर्जरी कर जानी प\r\nतो इनकी लंग्स की सर्जरी 11 फरवरी 2010 को\r\nहुई अब दशा से आपको अंदाजा मिल जाएगा दशा थी शनि में केतु केतु में\r\nजुपिटर शनि में केतु केतु में जुपिटर\r\nजुपिटर भी आपके वाईस पीड़ित है\r\nमिथुन पीड़ित है शनि से जुपिटर पर कोई शुभ दृष्टि नहीं\r\nहै केतु आपके जहां पर केतु बैठते हैं ना\r\nवहा प्रॉब्लम दे देते हैं केतु भी शुक्र के साथ विराजमान\r\nहै और शनि से दृष्ट मेन\r\nपॉइंट तो शनि रोग काक है रोग दे रहे\r\nहैं अब जो द्रेश कांड का मैं बता रहा था चलो इसमें बोल देते हैं के शनि महाराज 9\r\nडिग्री 10 मिनट एक मिनट केयह दूसरे कलक\r\nमें तो शनि का जो रोग दिया है शनि ने वोह\r\nएक्सटर्नल कॉज से है बाहर से लिया है आपने अंदर से पैदा नहीं हुआ ये रोग उसी को\r\nइंफेक्शन बोल दिया था बस डॉक्टर ने तो वो रोग शरीर के अंदर से नहीं आया था बाहर से\r\nआया यह भी ज्योतिष बता देगा इसके बाद इनकी हार्ट सर्जरी\r\nहुई हार्ट सर्जरी इनकी पहले हुई मार्च 2005 में जब दशा थी शनि शनि\r\nशुक्र अब देख लो भाई हार्ट को भी पकड़ रखा है चंद्रमा को\r\nपकड़ रखा है ठीक है और शनि ने शुक्र को भी पकड़ रखा\r\nहै शुक्र तो बहुत अच्छा पीड़ित है केतु के साथ भी शनि से दृष्ट है कोई शुभ दृष्टि नहीं\r\nहै तो हम कह सकते शुक्र रोग दे रहा\r\nहै ठीक है तो इस तरह से देख कर के हम इसको\r\nहम निकाल सकते हैं कि कहां पर रोग होगा कब होगा क्या वह बचपन से होगा यह सब जवाब अब\r\nयह जो पुस्तक लिखी है यह आज तक किसी ने 20 27 प विश्लेषण नहीं किया है तो उसका मैं\r\nआपको लिंक अब यह\r\nपुस्तक हमने खुद अजन पर रिलीज करा दिए\r\nठीक है और अमेजन पर यह किताब की हम फोटो आपको शेयर कर रहे हैं य 2024 का ही एडिशन\r\nहै और आपके अगर रिव्यूज आप इस\r\nपरे अपना मत देंगे कि भाई कैसी लगी और क्या\r\nइंप्रूवमेंट और हो सकती है तो हम अगले वॉल्यूम में उसको ठीक करने की कोशिश\r\nकरेंगे तो इसलिए अपने कमेंट जरूर इस पर लिखिए पुस्तक पढ़िए\r\nकमेंट लिखिए और फिर हम इसको इंप्रूव करने की कोशिश\r\nकरेंगे तो आज के लिए रोग के ऊपर बहुत जरूरी टॉपिक है और इसी तरह से हम टॉपिक\r\nआपसे लेते रहेंगे अब जरूरी टॉपिक लेंगे जो रोज हमारे जीवन में आते हैं\r\nऔर अब मैंने यह भी डिसाइड किया है कि जितनी मेरी पुस्तकें\r\nहैं सबको प्रिंट करके हम ठीक तरह से उसको आप लोगों\r\nको के पास पहुंचा है अब जैसे यह लोकेट डिजीज जो किताब है इंग्लिश में\r\nहै बाजार में य 00 में बिक रही थी बहुत\r\nलोग पायरेसी करके बेच रहे हैं मैंने इसकी कीमत 50 र\r\nरखी कि थोड़ी मेहनत मिल जाए परंतु आप जो ज्योतिष प्रेमी है उनके ऊपर\r\nबोझ ना तो बाकी 300 में मिल रही थी हमने अपना\r\nकॉस्ट निकाल करके इसको 50 में रखा है क्योंकि डीलर को डिस्ट्रीब्यूटर को भी\r\nहमें काफी कमीशन देना पड़ता है तो हम बराबर मतलब कर देंगे अजन पर भी यह है 50\r\nरप की अवेलेबल है आप अगर चाहे तो ले तो यह हमारा आज का आप इसे कमर्शियल\r\nवीडियो कह लो परंतु मेरा एम आप लोगों को रोग से परिचय कराने का था कि रोग कहां हो\r\nसकता है और कब हम उसको देख सकते आप विश्वास करोगे यह देख कर के 201\r\nमें मेरे को कोई हार्ट के सिंटमोबाइल\r\nआ रही होती तो मैं देखता कि यह समय निकल जाएगा मेरे को ऑपरेशन की जरूरत नहीं है पर\r\nज्योतिष इतनी नहीं आती थी उस समय मुझे कि मैं उसको कैसे संभालू कब दशा खत्म\r\nहो रही है उस पर गौर नहीं करा मैं जाकर के मेदांता में ऑपरेशन करा लिया तो अगर आप\r\nजान लेते हैं किय इतने दिन की बीमारी है यहां पर है तो मैं उसको कंट्रोल कर सक तो\r\nमेरा एम यही है कि भाई अपनी वीकनेस को अपनी कमी को पकड़ो और वह कब तक पूरी हो\r\nजाए ठीक है तो इसी के साथ मैं उम्मीद करता हूं कि आप इसका फायदा\r\nउठाए रोग के ज्योतिष का और यही हमारे चार्ट है डी 27 से ही पता चल है\r\nनमस्कार बहुत-बहुत धन्यवाद थैंक यू"},{"topic":"साढ़ेसाती","text":"नमस्कार आज हम एक बहुत ही पॉपुलर\r\nऔर हर कोई उससे डरता है ऐसा एक टॉपिक\r\nजिसको साढे साती बोलते\r\nहैं साढ़े साती पर चर्चा\r\nकरेंगे सबसे पहला सेंटेंस मैं यह बोल\r\nदूं कि साढे साती से डरने की जरूरत\r\nनहीं क्योंकि यह एक सिर्फ गोचर\r\nहै और\r\nगोचर दशा और योग के बाद आता\r\nहै तो दशा ज्यादा इंपॉर्टेंट होती\r\nहै और गोचर जैसा मैं\r\nज्यादातर लिखता हूं कि गोचर जो है वो\r\nसिर्फ सेकंड की सुई है\r\nभाई घंटे की और मिनट सुई पहले अलाइन होनी\r\nचाहिए फिर वो गोचर में फल देता है और साढे\r\nसाती से इतना डरा कर के बहुत से\r\nलोग परेशान हो जाते हैं और जो ज्योतिष सीख\r\nरहे\r\nहैं वह भी साढ़े सा शुरू होने वाली\r\nहै उससे परेशान हो जाते\r\nहैं ढैया से परेशान हो जाते हैं अष्टम शनि\r\nसे परेशान हो जाते हैं तो यह पूरी जिंदगी\r\nमें लगा ही रहता\r\nहै अब साढ़े साती है\r\nक्या यह\r\nचंद्रमा और शनि का गोचर है जन्म का\r\nचंद्रमा और गोचर का\r\nशनि तो जब भी गोचर में\r\nशनि चंद्रमा से बवे चंद्रमा के\r\nऊपर या चंद्रमा से अ भाव में गोचर करता है\r\nतो उसको साढ़े साती बोलते हैं शनि को\r\nतकरीबन एक राशि एक साइन पूरा करने में\r\nगोचर करने में तकरीबन ढाई साल का समय लगता\r\nहै तो यह तीन साइन में जब चलता है तीन\r\nराशियों में चलता है तो इनका टोटल टाइम हो\r\nगया\r\nसाढ़े इसलिए उसको साढ़े साती बोली जाती\r\nहै अब ये पाप ग्रह का गोचर है\r\nऐसा मानना है भाई राहु का\r\nगोचर या मंगल का या और कोई गोचर पाप ग्रह\r\nका क्यों नहीं लेते भाई सिर्फ शनि महाराज\r\nको ही क्यों पकड़ा है उसका भी कारण लोग\r\nबताते हैं के शनि\r\nकाल यह कर्म का मालिक है सारे कर्म यही कर\r\nहै तो इसलिए इसका गोचर सबसे ज्यादा\r\nमहत्वपूर्ण\r\nहै ठीक है मान लिया कि साढ़े सा साल का य\r\nपीरियड आता है और बीच बीच में अष्टम शनि\r\nऔर ैया वगैरा यह भी आती रहती है चतुर्थ\r\nमें आ जाए आठवे में आ जाए तो पाच साल वो\r\nभी जोड़\r\nदो ठीक है तो साढ़े साती और पा साढ़े साल\r\nतो ये हो गए तो ये रिपीट होता\r\nरहता अ साल में 12 1 साल तो आप इसी में\r\nनिकाल\r\nदोगे तो ऐसा नहीं है इसका आज हम आपको एक\r\nऔर तरीका बताएंगे\r\nक्योंकि शनि का गोचर किसी भी पल देने के\r\nलिए पहली रिक्वायरमेंट\r\nहै जिसको लोग कहते हैं\r\nना डबल\r\nगोचर शनि और बृहस्पति का पर वो डबल गोचर\r\nइतना सान भी सीधा सधा नहीं लगता है उसका\r\nभी तरीका आज हम साढ़े साती के संदर्भ में\r\nही उसको भी\r\nदेखें अब एक मॉडिफिकेशन\r\nइसमें और की गई है कुछ विद्वानों\r\nने कि भाई मतलब जो है वह चंद्रमा\r\nसे पीछे और आगे एक साइन ये लिया है तो\r\nमोटा मोटी देखे तो 30 डिग्री का ई साइन\r\nहोता हर साइन होता है तो यह 90 डिग्री\r\nचंद्रमा को सेंटर में रख लो और 45 डिग्री\r\nपहले और 45 डिग्री\r\nबाद वहां तक हम साढ़े साती मानेंगे\r\nयह नहीं के पूरा पूरा साइन ले लिया पहले\r\nवाला फिर शनि का पूरा चंद्रमा का पूरा\r\nसाइन ले लिया राशि लेली फिर उसके आगे पूरा\r\nसाइन अगला ले लिया तो समय ज्यादा भी हो\r\nजाता है\r\n90 डिग्री से ज्यादा का भी वो गोचर हो\r\nसकता\r\nहै खैर जो भी हो पर हम जो मेथड बता रहे\r\nहैं तरीका देख रहे हैं\r\nवो\r\nहमारे जो गोचर के नियम\r\nहै उनके हिसाब से इस शनि के गोचर को भी\r\nदेखना\r\nचाहिए अब बहुत से कहते\r\nहैं के\r\nचंद्रमा अगर शनि की राशि में\r\nहो तो साढ़े साती तंग नहीं\r\nकरती क्योंकि चंद्रमा को लगन भी माना है\r\nजो लगन लॉड है वो शनि हो\r\nगए तो कैप्रीकॉर्न को मकर को क्यों नहीं\r\nमाना कुंभ के लिए लिखा हुआ है ये कि अगर\r\nकुंभ में चंद्रमा हो तो साढ़े साती का\r\nप्रभाव कम होता\r\nहै तो ऐसे तो मकर में भी होना चाहिए\r\nदूसरा लिखा है कि यदि\r\nचंद्रमा सिंह राशि में हो लियो में हो तो\r\nसबसे ज्यादा साढ़े साती का प्रभाव होता\r\nहै अब आप देखोगे भाई सिम के लिए लिखा है\r\nतो कक के लिए भी तो बात है ना माना कि\r\nसिमम के लिए शनि ज्यादा अशुभ ग्रह है\r\nक्योंकि वो छठे और सातव का स्वामी हो जाता\r\nहै छटा त्रि छाय भी है त्रिक भी है और\r\nकर्क से वो सातवे और आठवे का मालिक होता\r\nहै तो आठवा भाव न्यूट्रल है सम है तो\r\nइसलिए मकर\r\nकेय कैंसर के लिए कर्क के लिए शनि उतना\r\nज्यादा पापी नहीं माना शुभ नहीं माना गया\r\nहै जितना सिंह राशि के लिए माना र ये तो\r\nहो गई प्रिलिमनरी\r\nपर साढ़े साती को देखे\r\nकैसे उसका एक बहुत बढ़िया रूल हम\r\nअपने शनि के ट्रांजिट के रूल से\r\nलेते शनि के गोचर का रूल क्या\r\nहै अब शनि के\r\nगोचर हम किसी अच्छे काम के लिए भी देख\r\nसकते हैं और किसी दुर्घटना के लिए भी देख\r\nसकते हैं दोनों में शनि जो है वह पहला बटन\r\nदबाता कार्य का पहला बटन वह दबाता\r\nहै और यह सीधा सधा आपका शनि का ही गोचर\r\nनहीं उसके साथ लोग बृहस्पति भी मान के\r\nचलते हैं हम आज शनि पर ही कंसंट्रेट करते\r\nहैं तो इसके दो नियम\r\nहै एक\r\nहै जब अशुभ गोचर देखा\r\nजाए बड़े ध्यान से आप सुन लो इसको कि ये\r\nसाढ़े\r\nसाती सीधी सधी साढ़े साती में नहीं\r\nएनालाइज करना है इसको कुंडली के हिसाब से\r\nहमें विश्लेषण करना है देखना\r\nहै तो आपको अगर अशुभ घटना देखनी\r\nहै तो जन्म कुंडली के जिस भाव की घटना\r\nदेखनी\r\nहै उससे अष्टम भाव ले\r\nलो मान लीजिए आपको कर्म की दुर्घटना देखनी\r\nहै कर्म में कोई खराब समय आने वाला है तो\r\nदशम भाव से अष्टम मतलब पंचम भाव के स्वामी\r\nको\r\nदेखे और अब उस पंचम भाव के स्वामी को\r\nदेखेंगे\r\nनवांश कि वोह किस राशि में\r\nहै किस साइन में\r\nहै ट्रांजिट हो रहा है बर्थ चार्ट गोचर\r\nवहा देख रहे साइन वहा से पकड़ा हमने\r\nनवांश तो जब भी\r\nशनि उस नवांश राशि\r\nके त्रिकोण\r\nमें या उस राशि को गोचर में प्रभावित\r\nकरेगा तब उस भाव की अशुभ घटना घटेगी\r\nतो अशुभ घटना के लिए हम अष्टम भाव उस भाव\r\nसे ले लेते हैं उसका स्वामी देख\r\nलेते और जब शुभ घटना\r\nघटे तो उसी भाव के स्वामी को न आंच में\r\nदेख\r\nलेते जैसे हम दशम की बात कर रहे थे तो द\r\nको\r\nदेखें और दशमेश\r\nका दशमेश नवांश में किस राशि में स्थित है\r\nफिर वही रूल लगेगा कि शनि जब उस राशि से\r\nत्रिकोण में या उस राशि को गोचर में\r\nप्रभावित\r\nकरेगा तो उस भाव से\r\nसंबंधित फल मिलेंगे\r\nअब य क कहीं मंगल के ही केस में के दशमेश\r\nभी मंगल है और पंचमेश भी मंगल है कर्क लगन\r\nकी अगर कुंडली\r\nहै तो वो दोनों का प्रभाव दे देगा कुछ\r\nउतार चढ़ाव कुछ चेंज लाक के व दे देगा तो\r\nइसके लिए हम एक कुंडली जो बहुत जानी\r\nपहचानी कुंडली\r\nहै इंदिरा गांधी जी की\r\nउनकी एक शुभ और एक\r\nअशुभ दो घटनाएं\r\nदेखें मेरे खल में रूल आप समझ गए\r\nहैं दुर्घटना के\r\nलिए हम उस भाव से अष्टमेश को लेते\r\nहैं और अच्छी घटना के लिए उसी भावेश को\r\nलेते हैं और उसको नवांश की नवांश में वो\r\nकिस राशि में वो देखते हैं यह यूनिवर्स\r\nनियम लगता है और काफी सही मान लगा है और\r\nयह फिर से मैं रिपीट कर रहा हूं के गोचर\r\nदशा के बाद देखा जाता\r\nहै हम अभी गोचर की ही बात कर ठीक है भैया\r\nतो अब हम इंदिरा गांधी के चार्ट पर बात\r\nकरेंगे ये\r\nजी यह इंदिरा गांधी का चार्ट है अब इस\r\nचार्ट में आप देख लो कि चंद्रमा कहां\r\nहै चंद्रमा मकर राशि में\r\nहै यही देखना\r\nहै चंद्रमा मकर राशि में\r\nहै और नवांश की हमें जरूरत पड़ती\r\nरहेगी ठीक है तो हम पहली घटना देखते हैं\r\nपहली घटना जवाहरलाल नेहरू जी का\r\nदेहांत 27 मई 1944\r\nको अब यहां शनि\r\nमहाराज कुंभ में गोचर कर रहे\r\nथे\r\nचंद्रमा हमारे मकर में\r\nथे तो कुंभ में जब यह कर रहे हैं तो साढ़े\r\nसा ही है हम कह सकते हैं भाई दुर्घटना\r\nहुई पर और क्या कारण था जो शनि ने\r\nदुर्घटना\r\nदी अब मैं वापस जन्म कुंडली में अपने उस\r\nप्रिंसिपल पर जाता हूं जो अभी हमने आपको\r\nदे\r\nबताया अब आप देखिए दुर्घटना हम देख रहे\r\nहैं नवम\r\nभाव पिता के लिए नवम भाव हम देखते हैं\r\nनवमेश\r\nनवम भाव से हम अष्टम भाव\r\nदे जो तुला\r\nहुआ नवम भाव से अष्टम भाव\r\nतुला तुला के स्वामी है\r\nशुक्र शुक्र नवांश\r\nमें तुला राशि में ही विराजमान है तुला\r\nराशि में ही बैठे हुए\r\nहैं ठीक है\r\nतो पिता के निधन के लिए पिता के अरिष्ट के\r\nलिए पिता के लिए अशुभ समय के\r\nलिए शुक्र को हमने\r\nपकड़ा अब ट्रांजिट में अगर हम देखे\r\nतो पिता के निधन के समय ट्रांजिट में जो\r\nशुक्र\r\nथे वह शुक\r\nशुक्र शनि शुक्र से त्रिकोण में\r\nठीक\r\nहै तो यह अशुभ ट्रांजिट\r\nप्रूव बृहस्पति का संबंध नहीं आ रहा\r\nहै बृहस्पति का संबंध नहीं आ\r\nरहा ठीक है जी परंतु अगर बृहस्पति को मैं\r\nदेखता हूं तो वो नवम भाव से आपके दूसरे\r\nभाव में विराजमान है\r\nठीक है जी अब हम दूसरी घटना\r\nदेख दूसरी\r\nघटना\r\nजनवरी 22 जनवरी 1966\r\nको यह पहली दफ देश की प्रधानमंत्री\r\nबनी ठीक है यहां पर भी अभी शनि फिर कुंभ\r\nमें है\r\nगोचर में अब ये अभी भी साढ़े साती चल रही\r\nहै साढ़े साती में पिता की मृत्यु हुई और\r\nखुद प्रधानमंत्री भी\r\nबनी अब इसको हम कैसे\r\nदेखें वोह प्रधानमंत्री के लिए हमें यहां\r\nपर दशम भाव देखना\r\nपड़ेगा तो दशम भाव में मेष लगन\r\nहै मेष लगन के स्वामी मंगल\r\nमंगल को हमने नवांश में देखा नवांश में ले\r\nगए तो मंगल जो है वो सिंह राशि में सूर्य\r\nकी राशि में विराजमान है तो हमने सिंह\r\nराशि पकड़ प्रमोशन के लिए अब हम आए गोचर\r\nप यहां पर शनि महाराज गोचर\r\nमें कुंभ में गोचर कर रहे थे 22 जनवरी को\r\nऔर सिमम को दृष्ट कर रहे\r\nथे ठीक\r\nहै तो यह गोचर भी हमारा शनि का इस तरह से\r\nदेखा जाए क्योंकि इस गोचर ने साढ़े साती\r\nने दोनों ही तरह के परिणाम\r\nदिए अब यहां पर बृहस्पति भी आप देखो\r\nतो उसमें संबंध में नहीं आ रहे व और कारण\r\nहै उसको भी हम बात करेंगे कभी के क्यों यह\r\nदिया क्यों\r\nइसने इस गोचर ने पद प्राप्ति भी\r\nदी उसके भी कभी हम वार्तालाप करेंगे वह भी\r\nशनि के ही नियम है शनि के ही गोचर नियम है\r\nजहा पर हम यह वार्ता\r\nकरें कि शनि के और कई इंपॉर्टेंट ट्रांजिट\r\nहै शनि किसी\r\nभी गोचर में स्टार्टिंग पॉइंट होता है\r\nअच्छा गोचर हो\r\nया अशुभ\r\nगोचर तो यह साढ़े साती को हम केवल साढ़े\r\nसाती की वजह से ना देखे\r\nहम उसको शनि के\r\nकैटालिस्ट जिसको कहते हैं व शुरू करता है\r\nबत्ती लगाता है भाई\r\nसाहब अच्छा काम हो चाहे बुरा काम उस तरह\r\nसे हम शनि को देख कि वह गोचर\r\nमें किस किस ग्रह को किस राशि को प्रभावित\r\nकर रहा\r\nहै जिन राशियों को प्रभावित कर रहा है\r\nउन राशियों में जो ग्रह विराजमान है उनको\r\nभी प्रभावित कर रहा\r\nहै जिस राशि में गोचर कर रहा\r\nहै अगर उस राशि में जन्म में कोई ग्रह\r\nविराजमान\r\nहै उनको भी प्रभावित\r\nकरेगा और वह ग्रह कहां के स्वामी\r\nहै नवांश में किस राशि में है\r\nनवांश की राशि को पकड़ना पड़ेगा तो वहां\r\nसे जाकर के यह साढे साती का फल पता चलता\r\nहै एकदम से सीधा सधा इससे पता नहीं चलता\r\nठीक है दोस्तों तो आज इतना\r\nही उम्मीद करता हूं कि आप\r\nइसको समझेंगे और लगाएंगे और साढ़े साती से\r\nबे फजूल परेशान नहीं हो\r\nऔर मैं फिर से रिमाइंड करा दूं मैंने अपनी\r\nपब्लिकेशन शुरू कर दी थी मैंने नहीं मतलब\r\nएक किसी को दिया है तो वह पब्लिश कर रहे\r\nहैं और एक किताब अभी पब्लिश हुई है लोकेट\r\nडिजीज इंग्लिश में\r\nहै\r\nऔर काफी अच्छा मेरे को आप लोगों का\r\nआशीर्वाद क्या सौभाग्य मिल रहा है कि अभी\r\nभी उसको आप लोग पसंद कर कर रहे हैं तो\r\nकिसी को अगर लेना है तो मैं आप दोबारा\r\nसे स्क्रीन शेयर कर देता\r\nहूं ठीक\r\nहै ये लोकेट डिजीज की ये है और इसमें हमने\r\nस्कैन भी दिया हुआ है अन पर है\r\nअवेलेबल तो यह\r\nहमारा अवेलेबल है आप लोग काफी पसंद कर रहे\r\nहैं इसको चलिए तो आज के लिए इतना ही\r\nनमस्कार फिर मिलेंगे"}];
